	public class MPO_File
	{
		private static byte?[] MP_IDENTIFIER = new byte?[8]
		{
			(byte)byte.MaxValue,
			(byte)226,
			null,
			null,
			(byte)77,
			(byte)80,
			(byte)70,
			0
		};

		public MPO_File(string file)
		{
			using FileStream stream = File.OpenRead(file);
			Init(stream);
		}

		public MPO_File(Stream stream)
		{
			Init(stream);
		}

		private void Init(Stream stream)
		{
			new BinaryReader(stream).ReadSequence(MP_IDENTIFIER);
		}
	}
