	public static class AnimJImporter
	{
		public static AnimX ImportFromFile(string file)
		{
			return ImportFromJSON(File.ReadAllText(file));
		}

		public static async ValueTask<AnimX> Import(Stream stream)
		{
			return CreateFrom(await System.Text.Json.JsonSerializer.DeserializeAsync<Animation>(stream, new JsonSerializerOptions
			{
				Converters = { (System.Text.Json.Serialization.JsonConverter)new AnimationTrackConverter() }
			}).ConfigureAwait(continueOnCapturedContext: false));
		}

		public static AnimX ImportFromJSON(string json)
		{
			return CreateFrom(System.Text.Json.JsonSerializer.Deserialize<Animation>(json, new JsonSerializerOptions
			{
				Converters = { (System.Text.Json.Serialization.JsonConverter)new AnimationTrackConverter() }
			}));
		}

		public static AnimX CreateFrom(Animation animation)
		{
			AnimX animX = new AnimX(animation.GlobalDuration, animation.Name);
			float num = 0f;
			foreach (AnimationTrack track in animation.Tracks)
			{
				num = MathX.Max(num, track.AddTo(animX));
			}
			if (animX.GlobalDuration == 0f)
			{
				animX.GlobalDuration = num;
			}
			return animX;
		}
	}
	public class Animation
	{
		[JsonPropertyName("name")]
		public string Name { get; set; }

		[JsonPropertyName("globalDuration")]
		public float GlobalDuration { get; set; }

		[JsonPropertyName("tracks")]
		public List<AnimationTrack> Tracks { get; set; } = new List<AnimationTrack>();
	}
	public class AnimationTrackConverter : System.Text.Json.Serialization.JsonConverter<AnimationTrack>
	{
		public override bool CanConvert(Type typeToConvert)
		{
			return typeof(AnimationTrack).IsAssignableFrom(typeToConvert);
		}

		public override AnimationTrack Read(ref Utf8JsonReader reader, Type typeToConvert, JsonSerializerOptions options)
		{
			if (reader.TokenType != JsonTokenType.StartObject)
			{
				throw new System.Text.Json.JsonException();
			}
			if (!reader.Read() || reader.TokenType != JsonTokenType.PropertyName || reader.GetString() != "trackType")
			{
				throw new System.Text.Json.JsonException();
			}
			if (!reader.Read() || reader.TokenType != JsonTokenType.String)
			{
				throw new System.Text.Json.JsonException();
			}
			TrackType trackType = (TrackType)Enum.Parse(typeof(TrackType), reader.GetString());
			if (!reader.Read() || reader.TokenType != JsonTokenType.PropertyName || reader.GetString() != "valueType")
			{
				throw new System.Text.Json.JsonException();
			}
			if (!reader.Read() || reader.TokenType != JsonTokenType.String)
			{
				throw new System.Text.Json.JsonException();
			}
			Type type = AnimX.ElementNameToType(reader.GetString());
			Type returnType = trackType switch
			{
				TrackType.Raw => typeof(RawAnimationTrack<>).MakeGenericType(type), 
				TrackType.Discrete => typeof(DiscreteAnimationTrack<>).MakeGenericType(type), 
				TrackType.Curve => typeof(CurveAnimationTrack<>).MakeGenericType(type), 
				_ => throw new NotSupportedException(), 
			};
			if (!reader.Read() || reader.GetString() != "data")
			{
				throw new System.Text.Json.JsonException();
			}
			if (!reader.Read() || reader.TokenType != JsonTokenType.StartObject)
			{
				throw new System.Text.Json.JsonException();
			}
			AnimationTrack result = (AnimationTrack)System.Text.Json.JsonSerializer.Deserialize(ref reader, returnType);
			if (!reader.Read() || reader.TokenType != JsonTokenType.EndObject)
			{
				throw new System.Text.Json.JsonException();
			}
			return result;
		}

		public override void Write(Utf8JsonWriter writer, AnimationTrack value, JsonSerializerOptions options)
		{
			writer.WriteStartObject();
			writer.WriteString("trackType", value.TrackType.ToString());
			writer.WriteString("valueType", value.ValueType.GetNiceName());
			writer.WritePropertyName("data");
			System.Text.Json.JsonSerializer.Serialize(writer, value, value.GetType());
			writer.WriteEndObject();
		}
	}
	public abstract class AnimationTrack
	{
		[System.Text.Json.Serialization.JsonIgnore]
		public abstract TrackType TrackType { get; }

		[System.Text.Json.Serialization.JsonIgnore]
		public abstract Type ValueType { get; }

		[JsonPropertyName("node")]
		public string Node { get; set; }

		[JsonPropertyName("property")]
		public string Property { get; set; }

		internal abstract float AddTo(AnimX animx);
	}
	public class CurveAnimationTrack<T> : AnimationTrack
	{
		[System.Text.Json.Serialization.JsonIgnore]
		public override TrackType TrackType => TrackType.Curve;

		[System.Text.Json.Serialization.JsonIgnore]
		public override Type ValueType => typeof(T);

		[JsonPropertyName("keyframes")]
		public List<CurveAnimationKeyframe<T>> Keyframes { get; set; } = new List<CurveAnimationKeyframe<T>>();

		internal override float AddTo(AnimX animx)
		{
			Elements.Core.CurveAnimationTrack<T> curveAnimationTrack = (Elements.Core.CurveAnimationTrack<T>)animx.AddTrack(AnimX.GetTrackType(TrackType, ValueType));
			curveAnimationTrack.Node = base.Node;
			curveAnimationTrack.Property = base.Property;
			foreach (CurveAnimationKeyframe<T> keyframe in Keyframes)
			{
				curveAnimationTrack.InsertKeyFrame(keyframe.Value, keyframe.Time, keyframe.Interpolation, keyframe.LeftTangent, keyframe.RightTangent);
			}
			return curveAnimationTrack.Duration;
		}
	}
	public class CurveAnimationKeyframe<T>
	{
		[JsonPropertyName("time")]
		public float Time { get; set; }

		[JsonPropertyName("value")]
		public T Value { get; set; }

		[JsonPropertyName("leftTangent")]
		public T LeftTangent { get; set; }

		[JsonPropertyName("rightTangent")]
		public T RightTangent { get; set; }

		[JsonPropertyName("interpolation")]
		[System.Text.Json.Serialization.JsonConverter(typeof(JsonStringEnumConverter))]
		public KeyframeInterpolation Interpolation { get; set; }
	}
	public class DiscreteAnimationTrack<T> : AnimationTrack
	{
		[System.Text.Json.Serialization.JsonIgnore]
		public override TrackType TrackType => TrackType.Discrete;

		[System.Text.Json.Serialization.JsonIgnore]
		public override Type ValueType => typeof(T);

		[JsonPropertyName("keyframes")]
		public List<DiscreteAnimationKeyframe<T>> Keyframes { get; set; } = new List<DiscreteAnimationKeyframe<T>>();

		internal override float AddTo(AnimX animx)
		{
			Elements.Core.DiscreteAnimationTrack<T> discreteAnimationTrack = (Elements.Core.DiscreteAnimationTrack<T>)animx.AddTrack(AnimX.GetTrackType(TrackType, ValueType));
			discreteAnimationTrack.Node = base.Node;
			discreteAnimationTrack.Property = base.Property;
			foreach (DiscreteAnimationKeyframe<T> keyframe in Keyframes)
			{
				discreteAnimationTrack.InsertKeyFrame(keyframe.Value, keyframe.Time);
			}
			return discreteAnimationTrack.Duration;
