	public class RawAnimationTrack<T> : AnimationTrack
	{
		[System.Text.Json.Serialization.JsonIgnore]
		public override TrackType TrackType => TrackType.Raw;

		[System.Text.Json.Serialization.JsonIgnore]
		public override Type ValueType => typeof(T);

		[JsonPropertyName("interval")]
		public float Interval { get; set; }

		[JsonPropertyName("keyframes")]
		public List<T> Keyframes { get; set; } = new List<T>();

		internal override float AddTo(AnimX animx)
		{
			Elements.Core.RawAnimationTrack<T> rawAnimationTrack = (Elements.Core.RawAnimationTrack<T>)animx.AddTrack(AnimX.GetTrackType(TrackType, ValueType));
			rawAnimationTrack.Node = base.Node;
			rawAnimationTrack.Property = base.Property;
			rawAnimationTrack.Interval = Interval;
			foreach (T keyframe in Keyframes)
			{
				rawAnimationTrack.AppendFrame(keyframe);
			}
			return Interval;
		}
	}
	public static class SubtitleImporter
	{
		public const float CONVERSION_RATIO = 0.001f;

		public const string DEFAULT_NODE = "Subtitle";

		public const string DEFAULT_PROPERTY = "Text";

		public static AnimX Import(string file)
		{
			using FileStream stream = File.OpenRead(file);
			return Import(stream, Path.GetFileName(file));
		}

		public static AnimX Import(Stream stream, string name)
		{
			AnimX animX = new AnimX(float.MaxValue, name);
			Import(stream, animX, "Subtitle", "Text");
			return animX;
		}

		public static void Import(Stream stream, AnimX anim, string node, string property)
		{
			List<SubtitleItem> list = new SubParser().ParseStream(stream);
			float globalDuration = (float)list.GetLast().EndTime * 0.001f;
			anim.GlobalDuration = globalDuration;
			DiscreteStringAnimationTrack discreteStringAnimationTrack = anim.AddTrack<DiscreteStringAnimationTrack>();
			discreteStringAnimationTrack.Node = node;
			discreteStringAnimationTrack.Property = property;
			int num = list[0].StartTime;
			if (num != 0)
			{
				discreteStringAnimationTrack.InsertKeyFrame(null, 0f);
			}
			for (int i = 0; i < list.Count; i++)
			{
				SubtitleItem subtitleItem = list[i];
				if (subtitleItem.StartTime > num)
				{
					discreteStringAnimationTrack.InsertKeyFrame(null, (float)num * 0.001f);
				}
				string value = string.Join("\n", subtitleItem.Lines);
				discreteStringAnimationTrack.InsertKeyFrame(value, (float)subtitleItem.StartTime * 0.001f);
				num = subtitleItem.EndTime;
			}
		}
	}
