	public static class AssetHelper
	{
		private readonly struct ImportExtension
		{
			public readonly string ext;

			public readonly bool primary;

			public ImportExtension(string ext, bool autoImport)
			{
				this.ext = ext;
				primary = autoImport;
			}

			public static implicit operator ImportExtension(string ext)
			{
				return new ImportExtension(ext, autoImport: true);
			}

			public override string ToString()
			{
				return ext;
			}
		}

		private static Dictionary<AssetClass, List<ImportExtension>> associatedExtensions;

		private static bool IsLinux
		{
			get
			{
				int platform = (int)Environment.OSVersion.Platform;
				if (platform != 4 && platform != 6)
				{
					return platform == 128;
				}
				return true;
			}
		}

		private static ImportExtension Secondary(this string ext)
		{
			return new ImportExtension(ext, autoImport: false);
		}

