			UniLog.Log("Supported subtitle formats: " + string.Join(", ", list3));
		}

		public static bool IsVideoStreamingService(Uri url)
		{
			if (url.Host.Contains("youtube.") || url.Host.Contains("youtu.be"))
			{
				return true;
			}
			if (url.Host.Contains("vimeo."))
			{
				return true;
			}
			if (url.Host.Contains("twitch.tv"))
			{
				return true;
			}
			if (url.Host.Contains("bsky.app") && url.PathAndQuery.Contains("post"))
			{
				return true;
			}
			if (url.Host.Contains("twitter.") || url.Host.StartsWith("x."))
			{
				return true;
			}
			if (url.Host.Contains("soundcloud."))
			{
				return true;
			}
			if (url.Host.Contains("reddit."))
			{
				return true;
			}
			if (url.Host.Contains("dropbox."))
			{
				return true;
			}
			if (url.Host.Contains("mixer."))
			{
				return true;
			}
			if (url.Host.Contains("dailymotion."))
			{
				return true;
			}
			if (url.Host.Contains("streamable."))
			{
				return true;
			}
			if (url.Host.Contains("drive.google."))
			{
				return true;
			}
			if (url.Host.Contains("tiktok."))
			{
				return true;
			}
			if (url.Host.Contains("niconico.") || url.Host.Contains("nicovideo."))
			{
				return true;
			}
			if (url.Host.Contains("lbry.tv"))
			{
				return true;
			}
			if (url.Host.Contains("nicovideo.jp"))
			{
				return true;
			}
			if (url.Host.Contains("instagram.com"))
			{
				return true;
			}
			if (url.Host.Contains("picarto.tv"))
			{
				return true;
			}
			return false;
		}

		public static AssetClass IdentifyClass(string path, bool primary = true)
		{
			if (path == null)
			{
				return AssetClass.Unknown;
			}
			if (Directory.Exists(path))
			{
				return AssetClass.Folder;
			}
			try
			{
				if (!Uri.TryCreate(path, UriKind.Absolute, out Uri result))
				{
					if (Path.IsPathRooted(path))
					{
						return ClassifyExtension(Path.GetExtension(path), primary);
					}
					return AssetClass.Unknown;
				}
				if (IsVideoStreamingService(result) || IsStreamingProtocol(result))
				{
					return AssetClass.Video;
				}
				AssetClass assetClass = ClassifyExtension(Path.GetExtension(result.LocalPath), primary);
				if (assetClass != AssetClass.Unknown)
				{
					return assetClass;
				}
				if (!string.IsNullOrEmpty(result.Query))
				{
					foreach (KeyValuePair<string, string> item in StringHelper.ParseQueryString(result.Query))
					{
						assetClass = ClassifyExtension(Path.GetExtension(item.Value), primary);
						if (assetClass != AssetClass.Unknown)
						{
							return assetClass;
						}
					}
				}
			}
			catch (Exception)
			{
			}
			return AssetClass.Unknown;
		}

		public static AssetClass ClassifyExtension(string ext, bool primary = true)
		{
			if (string.IsNullOrWhiteSpace(ext))
			{
				return AssetClass.Unknown;
			}
			ext = ext.Replace(".", "");
			if (string.IsNullOrEmpty(ext))
			{
				return AssetClass.Unknown;
			}
			ext = ext.ToLower();
			foreach (KeyValuePair<AssetClass, List<ImportExtension>> associatedExtension in associatedExtensions)
			{
				if (associatedExtension.Key != AssetClass.Unknown && associatedExtension.Value.Any((ImportExtension e) => e.ext == ext && e.primary == primary))
				{
					return associatedExtension.Key;
				}
			}
			return AssetClass.Unknown;
		}

		public static AssetClass ClassifyMime(string mime)
		{
			if (string.IsNullOrWhiteSpace(mime))
			{
				return AssetClass.Unknown;
			}
			mime = mime.ToLower();
			if (mime.Contains("image"))
			{
				return AssetClass.Texture;
			}
			if (mime.Contains("audio"))
			{
				return AssetClass.Audio;
			}
			if (mime.Contains("video"))
			{
				return AssetClass.Video;
			}
			return AssetClass.Unknown;
		}

		public static colorX GetClassColor(AssetClass assetClass)
		{
			return assetClass switch
			{
				AssetClass.Audio => colorX.Cyan, 
				AssetClass.Document => colorX.Red, 
				AssetClass.Text => colorX.Red, 
				AssetClass.Model => colorX.Yellow, 
				AssetClass.Object => colorX.Blue, 
				AssetClass.Texture => colorX.Green, 
				AssetClass.Video => colorX.Purple, 
				_ => new colorX(0.25f), 
			};
		}

		public static bool IsStreamingProtocol(Uri uri)
		{
			return IsStreamingProtocol(uri.Scheme);
		}

		public static bool IsStreamingProtocol(string scheme)
		{
			switch (scheme.ToLower())
			{
			case "rtp":
			case "mms":
			case "rtsp":
			case "rtmp":
				return true;
			default:
				return false;
			}
		}
	}
	public delegate float RawSampleFilter(int index, int channel, float amplitude);
	public delegate void RawSampleHandler(int index, int channel, float amplitude);
	public delegate void SampleHandler<S>(int index, S sample) where S : unmanaged, IAudioSample<S>;
	public delegate S SampleFilter<S>(int index, S sample) where S : unmanaged, IAudioSample<S>;
	public delegate void SampleChunkFilter<S>(ref Span<S> chunk, bool isLastChunk) where S : unmanaged, IAudioSample<S>;
	public class AudioX : IDisposable
	{
		private readonly ref struct SourceData<S> where S : unmanaged, IAudioSample<S>
		{
			public readonly Span<S> data;

			public readonly BufferBlock block;

			public SourceData(Span<S> data, BufferBlock block = null)
			{
				this.data = data;
				this.block = block;
			}

			public void Dispose()
			{
				if (block != null)
				{
					AudioBufferPool.Instance.ReturnBlock(block);
				}
			}
		}

		public const int DEFAULT_BUFFER_SIZE = 4096;

		private AudioEncodeSettings encodeSettings;

		private ISampleDecoder sampleDecoder;

		private ISampleEncoder sampleEncoder;

		private float[] samples;

		public bool IsFullyDecoded => samples != null;

		public ChannelConfiguration Channels { get; private set; }

		public int ChannelCount => Channels.ChannelCount();

		public Type SampleType => Channels.SampleType();

		public int SampleRate { get; private set; }

		public int SampleCount { get; private set; }

		public double Duration { get; private set; }

		public bool IsReadable { get; private set; }

		public bool IsWriteable { get; private set; }

		public AudioEncodeSettings EncodeSettings => encodeSettings;

		public float[] RawSamples => samples;

		public AudioX(ChannelConfiguration channels, int sampleRate)
		{
			samples = new float[4096];
			Channels = channels;
			SampleCount = 0;
			SampleRate = sampleRate;
			IsReadable = true;
			IsWriteable = true;
		}

		public AudioX(AudioEncodeSettings encodeSettings, Stream writeStream = null)
		{
			this.encodeSettings = encodeSettings;
			Channels = encodeSettings.Channels;
			SampleRate = encodeSettings.SampleRate;
			sampleEncoder = CreateEncoder(writeStream ?? new MemoryStream(), encodeSettings);
			IsReadable = false;
			IsWriteable = true;
		}

		public AudioX(float[] data, ChannelConfiguration channels, int sampleRate, bool writeable = false)
		{
			samples = data;
			Channels = channels;
			SampleCount = data.Length / channels.ChannelCount();
			SampleRate = sampleRate;
			IsReadable = true;
			IsWriteable = writeable;
			ComputeDuration();
		}

		public AudioX(string file)
		{
			FileStream stream = File.OpenRead(file);
			string extension = Path.GetExtension(file);
			LoadFromStream(stream, extension);
		}

		public AudioX(Stream stream, string ext = null)
		{
			LoadFromStream(stream, ext);
		}

		private void LoadFromStream(Stream stream, string extension)
		{
			sampleDecoder = new CSCoreSampleDecoder(stream, extension);
			Channels = sampleDecoder.Channels;
			SampleCount = sampleDecoder.Samples;
			SampleRate = sampleDecoder.SampleRate;
			IsReadable = true;
			IsWriteable = false;
			encodeSettings = sampleDecoder.EncodeSettings;
			ComputeDuration();
		}

		private void ComputeDuration()
		{
			Duration = (double)SampleCount / (double)SampleRate;
		}

		public int Read<T>(Span<T> target, double position, double rate = 1.0, bool loop = false) where T : unmanaged, IAudioSample<T>
		{
			return Channels switch
			{
				ChannelConfiguration.Mono => Read<MonoSample, T>(target, position, rate, loop), 
				ChannelConfiguration.Stereo => Read<StereoSample, T>(target, position, rate, loop), 
				ChannelConfiguration.Quad => Read<QuadSample, T>(target, position, rate, loop), 
				ChannelConfiguration.Surround51 => Read<Surround51Sample, T>(target, position, rate, loop), 
				ChannelConfiguration.Surround71 => Read<Surround71Sample, T>(target, position, rate, loop), 
				_ => throw new Exception("Unsupported channel configuration: " + Channels), 
			};
		}

		private int Read<S, T>(Span<T> target, double position, double rate = 1.0, bool loop = false) where S : unmanaged, IAudioSample<S> where T : unmanaged, IAudioSample<T>
		{
			CheckReadable();
			if (MathX.Approximately(rate, 0.0))
			{
				target.Fill(default(T));
				return target.Length;
			}
			bool flag = false;
			if (rate < 0.0)
			{
				rate = 0.0 - rate;
				flag = true;
				double num = (double)(target.Length - 1) * rate;
				position -= num;
				if (position < 0.0)
				{
					if (loop)
					{
						position = MathX.Repeat(position, SampleCount);
					}
					else
					{
						double num2 = 0.0 - position;
						position += (double)MathX.CeilToInt(num2);
						target = target.Slice(0, MathX.Max(0, target.Length - MathX.CeilToInt(num2 / rate)));
					}
				}
			}
			Span<T> span = target;
			int num3 = (int)position;
			double sourcePosition = position - (double)num3;
			S lastSample = default(S);
			if (num3 >= SampleCount)
			{
				if (!loop)
				{
					return 0;
				}
				num3 %= SampleCount;
			}
			int value = -1;
			try
			{
				while (target.Length > 0)
				{
					SourceData<S> source = GetSource<S>(num3, MathX.CeilToInt((double)target.Length * rate));
					try
					{
						value = source.data.Length;
						if (source.data.Length == 1 && sourcePosition > 0.0)
						{
							sourcePosition -= 1.0;
							num3++;
							lastSample = source.data[0];
						}
						else
						{
							if (source.data.Length == 0)
							{
								throw new Exception($"Source has no data! Source.Length: {source.data.Length}, block userCount: {source.block?.userCount}, StartPosition: {sourcePosition}, Offset: {num3}, Rate: {rate}, Target.Length: {target.Length}, Loop: {loop}");
							}
							int num4 = source.data.CopySamples(target, ref sourcePosition, ref lastSample, rate);
							if (num4 <= 0)
							{
								throw new Exception($"Written 0 samples! Source.Length: {source.data.Length}, block userCount: {source.block?.userCount}, StartPosition: {sourcePosition}, Offset: {num3}, Rate: {rate}, Target.Length: {target.Length}, Loop: {loop}");
							}
							target = target.Slice(num4);
							if (sourcePosition <= (double)source.data.Length)
							{
								sourcePosition -= (double)source.data.Length;
								num3 += source.data.Length;
							}
							else
							{
								int num5 = (int)sourcePosition;
								sourcePosition -= (double)num5;
								num3 += num5;
							}
						}
					}
					finally
					{
						source.Dispose();
					}
					if (num3 >= SampleCount)
					{
						if (!loop)
						{
							break;
						}
						num3 %= SampleCount;
					}
				}
			}
			catch (Exception innerException)
			{
				throw new Exception($"Exception reading samples! StartPosition: {sourcePosition}, Offset: {num3}, Rate: {rate}, Target.Length: {target.Length}, Source.Length: {value}, Loop: {loop}", innerException);
			}
			if (target.Length > 0 && sourcePosition < 0.0 && !loop)
			{
				if (sourcePosition < -1.0)
				{
					sourcePosition = 0.0 - sourcePosition;
					sourcePosition %= 1.0;
					sourcePosition = 0.0 - sourcePosition;
				}
				int start = SampleHelper.TransitionSampleBlock(target, ref sourcePosition, lastSample, lastSample, rate);
				target = target.Slice(start);
			}
			if (flag)
			{
				span.Reverse();
			}
			return span.Length - target.Length;
		}

		private SourceData<S> GetSource<S>(int offset, int count) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			if (IsFullyDecoded)
			{
				Span<S> data = MemoryMarshal.Cast<float, S>(samples.AsSpan()).Slice(0, SampleCount).Slice(offset);
				if (data.Length > 4096)
				{
					data = data.Slice(0, 4096);
				}
				return new SourceData<S>(data);
			}
			AudioBufferPool instance = AudioBufferPool.Instance;
			int num = 2048 / ChannelCount;
			int num2 = offset / num;
			num2 *= num;
			BufferBlock bufferBlock = instance.RequestBlock(this, num2);
			if (!bufferBlock.isDecoded)
			{
				lock (sampleDecoder)
				{
					if (!bufferBlock.isDecoded)
					{
						long num3 = (long)num2 * (long)Channels.ChannelCount();
						if (sampleDecoder.Position != num3)
						{
							sampleDecoder.Position = num3;
						}
						int num4 = MathX.Min(num, SampleCount - num2);
						num4 *= ChannelCount;
						if (num4 > bufferBlock.buffer.Length || num4 < 0)
						{
							throw new Exception($"Wanting to read {num4} samples, but buffer length is {bufferBlock.buffer.Length}. Position: {num2}, DecoderPosition: {num3}. BufferSamplesLength: {num}");
						}
						int num5 = sampleDecoder.Read(bufferBlock.buffer, 0, num4);
						if (num5 == 0)
						{
							throw new Exception($"Decoded 0 samples! Offset: {offset}, count: {count}, target decoderPosition: {num3}, position: {num2}, sampleDecoder.Position: {sampleDecoder.Position}, sampleDecoder.Samples: {sampleDecoder.Samples}");
						}
						bufferBlock.decodedSamples = num5;
						bufferBlock.isDecoded = true;
					}
				}
			}
			Span<S> data2 = MemoryMarshal.Cast<float, S>(bufferBlock.buffer.AsSpan().Slice(0, bufferBlock.decodedSamples));
			data2 = data2.Slice(offset - num2);
			return new SourceData<S>(data2, bufferBlock);
		}

		public Span<S> GetRawBuffer<S>() where S : unmanaged, IAudioSample<S>
		{
			CheckReadable();
			CheckWritable();
			CheckSampleType<S>();
			return MemoryMarshal.Cast<float, S>(samples.AsSpan());
		}

		public unsafe void WriteSample<S>(S sample) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			if (sampleEncoder != null)
			{
				Span<float> span = MemoryMarshal.Cast<S, float>(new Span<S>(&sample, 1));
				sampleEncoder.Write(span);
			}
			else
			{
				IncreaseSampleCount(1);
				GetRawBuffer<S>()[SampleCount - 1] = sample;
			}
		}

		public void WriteSamples(Span<float> newRawSamples)
		{
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
				WriteSamples(MemoryMarshal.Cast<float, MonoSample>(newRawSamples));
				break;
			case ChannelConfiguration.Stereo:
				WriteSamples(MemoryMarshal.Cast<float, StereoSample>(newRawSamples));
				break;
			case ChannelConfiguration.Quad:
				WriteSamples(MemoryMarshal.Cast<float, QuadSample>(newRawSamples));
				break;
			case ChannelConfiguration.Surround51:
				WriteSamples(MemoryMarshal.Cast<float, Surround51Sample>(newRawSamples));
				break;
			case ChannelConfiguration.Surround71:
				WriteSamples(MemoryMarshal.Cast<float, Surround71Sample>(newRawSamples));
				break;
			default:
				throw new Exception("Unsupported channel configuration: " + Channels);
			}
		}

		public void WriteSamples<S>(Span<S> newSamples) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			if (sampleEncoder != null)
			{
				sampleEncoder.Write(MemoryMarshal.Cast<S, float>(newSamples));
				SampleCount += newSamples.Length;
				return;
			}
			IncreaseSampleCount(newSamples.Length);
			Span<S> destination = GetRawBuffer<S>();
			destination = destination.Slice(SampleCount - newSamples.Length);
			newSamples.CopyTo(destination);
		}

		public void FinishEncode()
		{
			if (sampleEncoder == null)
			{
				throw new Exception("AudioX is not currently encoding");
			}
			FinishEncode(sampleEncoder, encodeSettings);
			sampleEncoder = null;
		}

		private void FinishEncode(ISampleEncoder encoder, AudioEncodeSettings encodeSettings)
		{
			Stream outputStream = encoder.OutputStream;
			encoder.Dispose();
			if (outputStream is MemoryStream memoryStream)
			{
				byte[] buffer = memoryStream.GetBuffer();
				long length = memoryStream.Length;
				MemoryStream stream = new MemoryStream(buffer, 0, (int)length, writable: false, publiclyVisible: true);
				IsWriteable = false;
				LoadFromStream(stream, encodeSettings.Extension);
				this.encodeSettings = encodeSettings;
			}
			else
			{
				outputStream.Dispose();
				IsWriteable = false;
			}
		}

		public void SetSampleCount(int count)
		{
			CheckWritable();
			SampleCount = count;
			EnsureCapacity(SampleCount);
			ComputeDuration();
		}

		public void IncreaseSampleCount(int count)
		{
			SetSampleCount(SampleCount + count);
		}

		public void SetDuration(float duration)
		{
			SetSampleCount(MathX.CeilToInt((float)SampleRate * duration));
		}

		private void EnsureCapacity(int capacity)
		{
			capacity *= ChannelCount;
			if (samples.Length < capacity)
			{
				samples = samples.EnsureSize(MathX.Max(capacity, samples.Length * 2), keepData: true);
			}
		}

		private void CheckWritable()
		{
			if (!IsWriteable)
			{
				throw new InvalidOperationException("AudioX is not writeable");
			}
		}

		private void CheckReadable()
		{
			if (!IsReadable)
			{
				throw new InvalidOperationException("AudioX is not readable");
			}
		}

		private void CheckSampleType<S>() where S : unmanaged, IAudioSample<S>
		{
			if (typeof(S) != SampleType)
			{
				throw new ArgumentException("Expected sample type " + SampleType);
			}
		}

		public void Save(string file)
		{
			if (sampleEncoder != null)
			{
				FinishEncode();
			}
			AudioEncodeSettings audioEncodeSettings = encodeSettings;
			if (audioEncodeSettings == null)
			{
				audioEncodeSettings = new WavEncodeSettings();
				audioEncodeSettings.UpdateFrom(this);
			}
			Encode(file, audioEncodeSettings);
		}

		public static string SetExtension(string file, AudioEncodeSettings settings)
		{
			file = ((!string.IsNullOrEmpty(Path.GetExtension(file))) ? Path.ChangeExtension(file, settings.Extension) : (file + "." + settings.Extension));
			return file;
		}

		public static ISampleEncoder CreateEncoder(Stream stream, AudioEncodeSettings settings)
		{
			if (!(settings is WavEncodeSettings settings2))
			{
				if (!(settings is VorbisEncodeSettings settings3))
				{
					if (settings is FlacEncodeSettings settings4)
					{
						return new FlacEncoder(stream, settings4);
					}
					throw new Exception("Unsupported encode settings: " + settings);
				}
				return new VorbisEncoder(stream, settings3);
			}
			return new WavEncoder(stream, settings2);
		}

		public void Encode(string file, AudioEncodeSettings settings)
		{
			file = SetExtension(file, settings);
			using FileStream stream = File.OpenWrite(file);
			Encode(stream, settings);
		}

		public void Encode(Stream stream, AudioEncodeSettings settings)
		{
			settings.UpdateFrom(this);
			if (encodeSettings != null && sampleDecoder?.InputStream != null && settings.Equals(encodeSettings) && sampleDecoder.InputStream is MemoryStream memoryStream)
			{
				byte[] buffer = memoryStream.GetBuffer();
				stream.Write(buffer, 0, (int)memoryStream.Length);
				return;
			}
			using ISampleEncoder encoder = CreateEncoder(stream, settings);
			Encode(encoder);
		}

		private void Encode(ISampleEncoder encoder)
		{
			if (IsFullyDecoded)
			{
				encoder.Write(samples.AsSpan().Slice(0, SampleCount * ChannelCount));
				return;
			}
			int num = 0;
			while (num < SampleCount)
			{
				switch (Channels)
				{
				case ChannelConfiguration.Mono:
				{
					SourceData<MonoSample> source5 = GetSource<MonoSample>(num, 4096);
					try
					{
						encoder.Write(MemoryMarshal.Cast<MonoSample, float>(source5.data));
						num += source5.data.Length;
					}
					finally
					{
						source5.Dispose();
					}
					break;
				}
				case ChannelConfiguration.Stereo:
				{
					SourceData<StereoSample> source4 = GetSource<StereoSample>(num, 4096);
					try
					{
						encoder.Write(MemoryMarshal.Cast<StereoSample, float>(source4.data));
						num += source4.data.Length;
					}
					finally
					{
						source4.Dispose();
					}
					break;
				}
				case ChannelConfiguration.Quad:
				{
					SourceData<QuadSample> source3 = GetSource<QuadSample>(num, 4096);
					try
					{
						encoder.Write(MemoryMarshal.Cast<QuadSample, float>(source3.data));
						num += source3.data.Length;
					}
					finally
					{
						source3.Dispose();
					}
					break;
				}
				case ChannelConfiguration.Surround51:
				{
					SourceData<Surround51Sample> source2 = GetSource<Surround51Sample>(num, 4096);
					try
					{
						encoder.Write(MemoryMarshal.Cast<Surround51Sample, float>(source2.data));
						num += source2.data.Length;
					}
					finally
					{
						source2.Dispose();
					}
					break;
				}
				case ChannelConfiguration.Surround71:
				{
					SourceData<Surround71Sample> source = GetSource<Surround71Sample>(num, 4096);
					try
					{
						encoder.Write(MemoryMarshal.Cast<Surround71Sample, float>(source.data));
						num += source.data.Length;
					}
					finally
					{
						source.Dispose();
					}
					break;
				}
				default:
					throw new Exception("Unsupported channel format: " + Channels);
				}
			}
		}

		public void EnsureFullyDecoded()
		{
			if (!IsFullyDecoded)
			{
				FullyDecode();
			}
		}

		public void FullyDecode()
		{
			if (IsFullyDecoded)
			{
				throw new InvalidOperationException("Audio is already fully decoded");
			}
			float[] array = new float[sampleDecoder.Samples * Channels.ChannelCount()];
			lock (sampleDecoder)
			{
				sampleDecoder.Position = 0L;
				for (int i = 0; i < array.Length; i += 4096)
				{
					int count = MathX.Min(4096, array.Length - i);
					sampleDecoder.Read(array, i, count);
				}
				samples = array;
				sampleDecoder.Dispose();
				sampleDecoder = null;
			}
		}

		public void ForEachRawSample(RawSampleHandler onRead)
		{
			if (IsFullyDecoded)
			{
				int channelCount = ChannelCount;
				for (int i = 0; i < SampleCount * channelCount; i++)
				{
					onRead(i / channelCount, i % channelCount, samples[i]);
				}
				return;
			}
			for (int num = 0; num < SampleCount; num = Channels switch
			{
				ChannelConfiguration.Mono => num + ForeachRawSampleInBlock<MonoSample>(num, onRead), 
				ChannelConfiguration.Stereo => num + ForeachRawSampleInBlock<StereoSample>(num, onRead), 
				ChannelConfiguration.Quad => num + ForeachRawSampleInBlock<QuadSample>(num, onRead), 
				ChannelConfiguration.Surround51 => num + ForeachRawSampleInBlock<Surround51Sample>(num, onRead), 
				ChannelConfiguration.Surround71 => num + ForeachRawSampleInBlock<Surround71Sample>(num, onRead), 
				_ => throw new Exception("Unsupported channel configuration: " + Channels), 
			})
			{
			}
		}

		private int ForeachRawSampleInBlock<S>(int offset, RawSampleHandler onRead) where S : unmanaged, IAudioSample<S>
		{
			int channelCount = ChannelCount;
			int num = offset * channelCount;
			SourceData<S> source = GetSource<S>(offset, int.MaxValue);
			try
			{
				Span<float> span = MemoryMarshal.Cast<S, float>(source.data);
				for (int i = 0; i < span.Length; i++)
				{
					int num2 = num + i;
					onRead(num2 / channelCount, i % channelCount, span[i]);
				}
				return source.data.Length;
			}
			finally
			{
				source.Dispose();
			}
		}

		public void ForeachSample<S>(SampleHandler<S> onRead) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			if (IsFullyDecoded)
			{
				Span<S> span = RawSamples.AsAudioBuffer<S>();
				span = span.Slice(0, SampleCount);
				for (int i = 0; i < span.Length; i++)
				{
					onRead(i, span[i]);
				}
			}
			else
			{
				for (int j = 0; j < SampleCount; j += ForeachSampleInBlock(j, onRead))
				{
				}
			}
		}

		private int ForeachSampleInBlock<S>(int offset, SampleHandler<S> onRead) where S : unmanaged, IAudioSample<S>
		{
			SourceData<S> source = GetSource<S>(offset, int.MaxValue);
			try
			{
				for (int i = 0; i < source.data.Length; i++)
				{
					onRead(offset + i, source.data[i]);
				}
				return source.data.Length;
			}
			finally
			{
				source.Dispose();
			}
		}

		public void Trim(int start, int count)
		{
			TrimAndProcess(start, count, null);
		}

		public void ProcessSamplesAndTrim<S>(int start, int count, SampleFilter<S> filter) where S : unmanaged, IAudioSample<S>
		{
			TrimAndProcess(start, count, filter, null, null);
		}

		public void ProcessSamples<S>(SampleFilter<S> filter) where S : unmanaged, IAudioSample<S>
		{
			TrimAndProcess(0, SampleCount, filter, null, null);
		}

		public void ProcessSamples<S>(SampleChunkFilter<S> chunkFilter) where S : unmanaged, IAudioSample<S>
		{
			TrimAndProcess(0, SampleCount, null, chunkFilter, null);
		}

		public void ProcessRawSamples(Func<float, float> filter)
		{
			TrimAndProcess(0, SampleCount, (int i, int ch, float s) => filter(s));
		}

		public void ProcessRawSamples(RawSampleFilter filter)
		{
			TrimAndProcess(0, SampleCount, filter);
		}

		private void TrimAndProcess(int start, int count, RawSampleFilter rawFilter)
		{
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
				TrimAndProcess<MonoSample>(start, count, null, null, rawFilter);
				break;
			case ChannelConfiguration.Stereo:
				TrimAndProcess<StereoSample>(start, count, null, null, rawFilter);
				break;
			case ChannelConfiguration.Quad:
				TrimAndProcess<QuadSample>(start, count, null, null, rawFilter);
				break;
			case ChannelConfiguration.Surround51:
				TrimAndProcess<Surround51Sample>(start, count, null, null, rawFilter);
				break;
			default:
				throw new NotImplementedException("Unsupported channel type: " + Channels);
			}
		}

		private void TrimAndProcess<S>(int start, int count, SampleFilter<S> sampleFilter, SampleChunkFilter<S> chunkFilter, RawSampleFilter rawFilter) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			int channelCount = ChannelCount;
			if (IsFullyDecoded)
			{
				SampleCount = count;
				start *= channelCount;
				count *= channelCount;
				Array.Copy(samples, start, samples, 0, count);
				if (rawFilter != null)
				{
					for (int i = 0; i < SampleCount * channelCount; i++)
					{
						samples[i] = rawFilter(i / channelCount, i % channelCount, samples[i]);
					}
				}
				if (sampleFilter != null)
				{
					Span<S> span = samples.AsAudioBuffer<S>().Slice(0, SampleCount);
					for (int j = 0; j < span.Length; j++)
					{
						span[j] = sampleFilter(j, span[j]);
					}
				}
				if (chunkFilter != null)
				{
					Span<S> chunk = samples.AsAudioBuffer<S>().Slice(0, SampleCount);
					chunkFilter(ref chunk, isLastChunk: true);
					SampleCount = chunk.Length;
				}
				return;
			}
			AudioEncodeSettings audioEncodeSettings = encodeSettings ?? new WavEncodeSettings();
			if (audioEncodeSettings is VorbisEncodeSettings && (SampleRate < 32000 || Duration < 2.0))
			{
				audioEncodeSettings = new WavEncodeSettings();
			}
			audioEncodeSettings.UpdateFrom(this);
			ISampleEncoder sampleEncoder = CreateEncoder(new MemoryStream(), audioEncodeSettings);
			Span<float> buffer = stackalloc float[1024];
			int num = start;
			while (num < SampleCount)
			{
				int num2 = Channels switch
				{
					ChannelConfiguration.Mono => Read(buffer.AsMonoBuffer(), num), 
					ChannelConfiguration.Stereo => Read(buffer.AsStereoBuffer(), num), 
					_ => throw new Exception("Unsupported channel configuration: " + Channels), 
				};
				count -= num2;
				if (count < 0)
				{
					num2 += count;
					buffer = buffer.Slice(0, buffer.Length + count * ChannelCount);
				}
				int num3 = num2 * channelCount;
				if (rawFilter != null)
				{
					int num4 = num * channelCount;
					for (int k = 0; k < num3; k++)
					{
						int num5 = num4 + k;
						buffer[k] = rawFilter(num5 / ChannelCount, num5 % ChannelCount, buffer[k]);
					}
				}
				if (sampleFilter != null)
				{
					Span<S> span2 = buffer.AsAudioBuffer<S>().Slice(0, num2);
					for (int l = 0; l < num2; l++)
					{
						span2[l] = sampleFilter(num + l, span2[l]);
					}
				}
				Span<float> buffer2 = buffer.Slice(0, num3);
				if (chunkFilter != null)
				{
					Span<S> chunk2 = buffer2.AsAudioBuffer<S>();
					chunkFilter(ref chunk2, count <= 0);
					buffer2 = MemoryMarshal.Cast<S, float>(chunk2);
				}
				sampleEncoder.Write(buffer2);
				num += num2;
				if (count < 0)
				{
					break;
				}
			}
			FinishEncode(sampleEncoder, audioEncodeSettings);
		}

		public void Dispose()
		{
			sampleDecoder?.Dispose();
			sampleEncoder?.Dispose();
			sampleDecoder = null;
			sampleEncoder = null;
			samples = null;
		}

		public override string ToString()
		{
			return $"Audio. Channels: {Channels} ({ChannelCount}), SampleRate: {SampleRate}, Duration: {Duration}s ({SampleCount} samples), Read: {IsReadable}, Write: {IsWriteable}, FullyDecoded: {IsFullyDecoded}";
		}

		public void SkipStartDuration(float duration, out int start, out int count)
		{
			start = MathX.RoundToInt((float)SampleRate * duration);
			start = MathX.Min(SampleCount, start);
			count = SampleCount - start;
		}

		public void SkipEndDuration(float duration, out int start, out int count)
		{
			count = MathX.RoundToInt((float)SampleRate * duration);
			count = MathX.Min(SampleCount, count);
			count = SampleCount - count;
			start = 0;
		}

		public void FindStartAndEnd(float threshold, out int start, out int count)
		{
			int startIndex = -1;
			int endIndex = 0;
			ForEachRawSample(delegate(int i, int ch, float s)
			{
				if (s > threshold)
				{
					if (startIndex < 0)
					{
						startIndex = i;
					}
					endIndex = i;
				}
			});
			if (startIndex < 0)
			{
				start = 0;
				count = 0;
			}
			else
			{
				start = startIndex;
				count = endIndex - start;
			}
		}

		public float ComputeMaximumAmplitude()
		{
			float maxAmplitude = 0f;
			ForEachRawSample(delegate(int i, int ch, float s)
			{
				maxAmplitude = MathX.Max(maxAmplitude, MathX.Abs(s));
			});
			return maxAmplitude;
		}

		public float ComputeMaximumAmplitude<S>(Func<S, S> sampleFilter) where S : unmanaged, IAudioSample<S>
		{
			float maxAmplitude = 0f;
			ForeachSample(delegate(int i, S s)
			{
				maxAmplitude = MathX.Max(maxAmplitude, sampleFilter(s).AbsoluteAmplitude);
			});
			return maxAmplitude;
		}

		public void Normalize()
		{
			float num = ComputeMaximumAmplitude();
			if (num != 0f)
			{
				AdjustVolume(1f / num);
			}
		}

		public void AdjustVolume(float multiply)
		{
			ProcessRawSamples((int i, int ch, float s) => s * multiply);
		}

		public void TrimSilence(float threshold = 0.002f)
		{
			FindStartAndEnd(threshold, out var start, out var count);
			TrimAndProcess(start, count, null);
		}

		public void TrimStartSilence(float threshold = 0.002f)
		{
			FindStartAndEnd(threshold, out var start, out var count);
			count = SampleCount - start;
			TrimAndProcess(start, count, null);
		}

		public void TrimEndSilence(float threshold = 0.002f)
		{
			FindStartAndEnd(threshold, out var start, out var count);
			start = 0;
			TrimAndProcess(start, count, null);
		}

		public void TrimStart(float duration)
		{
			SkipStartDuration(duration, out var start, out var count);
			TrimAndProcess(start, count, null);
		}

		public void TrimEnd(float duration)
		{
			SkipEndDuration(duration, out var start, out var count);
			TrimAndProcess(start, count, null);
		}

		public void FadeIn(float duration)
		{
			SkipStartDuration(duration, out var start, out var _);
			float increment = 1f / (float)start;
			ProcessRawSamples((int i, int ch, float s) => s * MathX.Min((float)i * increment, 1f));
		}

		public void FadeOut(float duration)
		{
			SkipStartDuration(duration, out var start, out var _);
			float increment = 1f / (float)start;
			ProcessRawSamples((int i, int ch, float s) => s * MathX.Min((float)(SampleCount - i - 1) * increment, 1f));
		}

		public void MakeFadeLoop(float duration)
		{
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
				MakeFadeLoop<MonoSample>(duration);
				break;
			case ChannelConfiguration.Stereo:
				MakeFadeLoop<StereoSample>(duration);
				break;
			default:
				throw new NotImplementedException("Unsupported channel type: " + Channels);
			}
		}

		private void MakeFadeLoop<S>(float duration) where S : unmanaged, IAudioSample<S>
		{
			CheckSampleType<S>();
			SkipEndDuration(duration, out var start, out var count);
			int num = SampleCount - count;
			S[] buffer = new S[num];
			Read(buffer.AsSpan(), SampleCount - num);
			float increment = 1f / (float)num;
			ProcessSamplesAndTrim(start, count, (int i, S s) => (i < buffer.Length) ? buffer[i].LerpTo(s, (float)i * increment) : s);
		}

		public void Resample(int newSampleRate)
		{
			if (newSampleRate != SampleRate)
			{
				if (!IsFullyDecoded)
				{
					throw new NotImplementedException();
				}
				float num = (float)SampleRate / (float)newSampleRate;
				int num2 = (int)((float)samples.Length / num);
				int num3 = num2 % ChannelCount;
				if (num3 != 0)
				{
					num2 += ChannelCount - num3;
				}
				float[] array = new float[num2];
				switch (Channels)
				{
				case ChannelConfiguration.Mono:
					Read(MemoryMarshal.Cast<float, MonoSample>(array.AsSpan()), 0.0, num);
					break;
				case ChannelConfiguration.Stereo:
					Read(MemoryMarshal.Cast<float, StereoSample>(array.AsSpan()), 0.0, num);
					break;
				case ChannelConfiguration.Quad:
					Read(MemoryMarshal.Cast<float, QuadSample>(array.AsSpan()), 0.0, num);
					break;
				case ChannelConfiguration.Surround51:
					Read(MemoryMarshal.Cast<float, Surround51Sample>(array.AsSpan()), 0.0, num);
					break;
				case ChannelConfiguration.Surround71:
					Read(MemoryMarshal.Cast<float, Surround71Sample>(array.AsSpan()), 0.0, num);
					break;
				default:
					throw new NotSupportedException("Operation not supported for channel configuration: " + Channels);
				}
				samples = array;
				SampleCount = num2 / ChannelCount;
				SampleRate = newSampleRate;
				ComputeDuration();
			}
		}

		public void Denoise()
		{
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
				Denoise<MonoSample>();
				break;
			case ChannelConfiguration.Stereo:
				Denoise<StereoSample>();
				break;
			case ChannelConfiguration.Quad:
				Denoise<QuadSample>();
				break;
			case ChannelConfiguration.Surround51:
				Denoise<Surround51Sample>();
				break;
			case ChannelConfiguration.Surround71:
				Denoise<Surround71Sample>();
				break;
			default:
				throw new NotSupportedException("Operation not supported for channel configuration: " + Channels);
			}
		}

		private void Denoise<S>() where S : unmanaged, IAudioSample<S>
		{
			BufferDenoiser<S> denoiser = new BufferDenoiser<S>();
			try
			{
				ProcessSamples(delegate(ref Span<S> chunk, bool isLast)
				{
					denoiser.Denoise(ref chunk, isLast);
				});
			}
			finally
			{
				if (denoiser != null)
				{
					((IDisposable)denoiser).Dispose();
				}
			}
		}

		public void ExtractSides()
		{
			float mul;
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
				break;
			case ChannelConfiguration.Stereo:
				mul = 1f / ComputeMaximumAmplitude((StereoSample s) => s.ExtractSides());
				ProcessSamples((int i, StereoSample s) => s.ExtractSides().Multiply(mul));
				break;
			case ChannelConfiguration.Quad:
				mul = 1f / ComputeMaximumAmplitude((QuadSample s) => s.ExtractSides());
				ProcessSamples((int i, QuadSample s) => s.ExtractSides().Multiply(mul));
				break;
			}
		}

		public void ApplyZitaFilter(IZitaFilter filter)
		{
			switch (Channels)
			{
			case ChannelConfiguration.Mono:
			{
				BufferReverber<MonoSample> reverb4 = new BufferReverber<MonoSample>(SampleRate, filter);
				try
				{
					ProcessSamples(delegate(ref Span<MonoSample> chunk, bool isLastChunk)
					{
						reverb4.ApplyReverb(chunk);
					});
					break;
				}
				finally
				{
					if (reverb4 != null)
					{
						((IDisposable)reverb4).Dispose();
					}
				}
			}
			case ChannelConfiguration.Stereo:
			{
				BufferReverber<StereoSample> reverb3 = new BufferReverber<StereoSample>(SampleRate, filter);
				try
				{
					ProcessSamples(delegate(ref Span<StereoSample> chunk, bool isLastChunk)
					{
						reverb3.ApplyReverb(chunk);
					});
					break;
				}
				finally
				{
					if (reverb3 != null)
					{
						((IDisposable)reverb3).Dispose();
					}
				}
			}
			case ChannelConfiguration.Quad:
			{
				BufferReverber<QuadSample> reverb2 = new BufferReverber<QuadSample>(SampleRate, filter);
				try
				{
					ProcessSamples(delegate(ref Span<QuadSample> chunk, bool isLastChunk)
					{
						reverb2.ApplyReverb(chunk);
					});
					break;
				}
				finally
				{
					if (reverb2 != null)
					{
						((IDisposable)reverb2).Dispose();
					}
				}
			}
			case ChannelConfiguration.Surround51:
			{
				BufferReverber<Surround51Sample> reverb = new BufferReverber<Surround51Sample>(SampleRate, filter);
				try
				{
					ProcessSamples(delegate(ref Span<Surround51Sample> chunk, bool isLastChunk)
					{
						reverb.ApplyReverb(chunk);
					});
					break;
				}
				finally
				{
					if (reverb != null)
					{
						((IDisposable)reverb).Dispose();
					}
				}
			}
			}
		}
	}
	public class AudioBufferPool
	{
		public static readonly AudioBufferPool Instance = new AudioBufferPool();

		public const int BUFFER_LENGTH = 2048;

		public int MaxBlockCount = 128;

		private Dictionary<BufferBlockKey, BufferBlock> bufferBlocks = new Dictionary<BufferBlockKey, BufferBlock>();

		private Queue<BufferBlockKey> recycleQueue = new Queue<BufferBlockKey>();

		private HashSet<BufferBlockKey> recycleQueuedBlocks = new HashSet<BufferBlockKey>();

		private object _lock = new object();

		public BufferBlock RequestBlock(AudioX clip, int position)
		{
			return RequestBlock(new BufferBlockKey(clip, position));
		}

		public BufferBlock RequestBlock(in BufferBlockKey key)
		{
			lock (_lock)
			{
				if (bufferBlocks.TryGetValue(key, out BufferBlock value))
				{
					value.userCount++;
					return value;
				}
				BufferBlock freshBlock = GetFreshBlock();
				bufferBlocks.Add(key, freshBlock);
				freshBlock.key = key;
				freshBlock.userCount++;
				return freshBlock;
			}
		}

		public void ReturnBlock(BufferBlock block)
		{
			lock (_lock)
			{
				block.userCount--;
				if (block.userCount == 0)
				{
					if (bufferBlocks.Count > MaxBlockCount)
					{
						bufferBlocks.Remove(block.key);
					}
					else if (!recycleQueuedBlocks.Contains(block.key))
					{
						recycleQueuedBlocks.Add(block.key);
						recycleQueue.Enqueue(block.key);
					}
				}
			}
		}

		private BufferBlock GetFreshBlock()
		{
			if (bufferBlocks.Count >= MaxBlockCount)
			{
				while (recycleQueue.Count > 0)
				{
					BufferBlockKey bufferBlockKey = recycleQueue.Dequeue();
					recycleQueuedBlocks.Remove(bufferBlockKey);
					if (bufferBlocks.TryGetValue(bufferBlockKey, out BufferBlock value) && value.userCount == 0)
					{
						bufferBlocks.Remove(bufferBlockKey);
						value.isDecoded = false;
						value.decodedSamples = 0;
						value.key = default(BufferBlockKey);
						return value;
					}
				}
			}
			return new BufferBlock(new float[2048]);
		}
	}
	public class BufferBlock
	{
		public BufferBlockKey key;

		public bool isDecoded;

		public int userCount;

		public int decodedSamples;

		public readonly float[] buffer;

		public BufferBlock(float[] buffer)
		{
			this.buffer = buffer;
		}
	}
	public readonly struct BufferBlockKey : IEquatable<BufferBlockKey>
	{
		public readonly AudioX clip;

		public readonly int position;

		public BufferBlockKey(AudioX clip, int position)
		{
			this.clip = clip;
			this.position = position;
		}

		public override bool Equals(object obj)
		{
			if (obj is BufferBlockKey other)
			{
				return Equals(other);
			}
			return false;
		}

		public bool Equals(BufferBlockKey other)
		{
			if (clip == other.clip)
			{
				return position == other.position;
			}
			return false;
		}

		public override int GetHashCode()
		{
			return (-168850627 * -1521134295 + EqualityComparer<AudioX>.Default.GetHashCode(clip)) * -1521134295 + position.GetHashCode();
		}

		public static bool operator ==(BufferBlockKey left, BufferBlockKey right)
		{
			return left.Equals(right);
		}

		public static bool operator !=(BufferBlockKey left, BufferBlockKey right)
		{
			return !(left == right);
		}
	}
	public struct CircularBufferReadState<S> where S : unmanaged, IAudioSample<S>
	{
		public S lastSample;

		public long lastGlobalPosition;

		public double lastPosition;

		public override string ToString()
		{
			return $"GlobalPos: {lastGlobalPosition}, Pos: {lastPosition}";
		}
	}
	public struct CircularBufferWriteState<S> where S : unmanaged, IAudioSample<S>
	{
		public S lastSample;

		public double lastPosition;
	}
	public abstract class CircularAudioBuffer
	{
		public abstract int Length { get; }

		public long GlobalIndex { get; protected set; }

		public int CurrentHead { get; protected set; }

		public long StartGlobalIndex => MathX.Max(0L, GlobalIndex - Length);

		public int AvailableSamples(long lastIndex)
		{
			return MathX.Min((int)(GlobalIndex - lastIndex), Length);
		}
	}
	public class CircularAudioBuffer<S> : CircularAudioBuffer, IEnumerable<S>, IEnumerable where S : unmanaged, IAudioSample<S>
	{
		private S[] data;

		public override int Length => data.Length;

		public CircularAudioBuffer(int length, CircularAudioBuffer<S> initializeWith = null)
		{
			data = new S[length];
			if (initializeWith != null)
			{
				base.GlobalIndex = initializeWith.GlobalIndex;
				int num = MathX.Min(length, initializeWith.AvailableSamples(initializeWith.StartGlobalIndex));
				base.CurrentHead += num;
				base.CurrentHead %= Length;
				long globalPosition = base.GlobalIndex - num;
				initializeWith.Read(data.AsSpan(), ref globalPosition);
			}
		}

		public void Put<T>(Span<T> source) where T : unmanaged, IAudioSample<T>
		{
			Put((ReadOnlySpan<T>)source);
		}

		public void Put<T>(Span<T> source, ref CircularBufferWriteState<T> state, double rate = 1.0) where T : unmanaged, IAudioSample<T>
		{
			Put((ReadOnlySpan<T>)source, ref state, rate);
		}

		public void Put<T>(Span<T> source, ref double position, ref T lastSample, double rate = 1.0) where T : unmanaged, IAudioSample<T>
		{
			Put((ReadOnlySpan<T>)source, ref position, ref lastSample, rate);
		}

		public void Put<T>(ReadOnlySpan<T> source) where T : unmanaged, IAudioSample<T>
		{
			double position = 0.0;
			T lastSample = default(T);
			Put(source, ref position, ref lastSample);
		}

		public void Put<T>(ReadOnlySpan<T> source, ref CircularBufferWriteState<T> state, double rate = 1.0) where T : unmanaged, IAudioSample<T>
		{
			Put(source, ref state.lastPosition, ref state.lastSample, rate);
		}

		public void Put<T>(ReadOnlySpan<T> source, ref double position, ref T lastSample, double rate = 1.0) where T : unmanaged, IAudioSample<T>
		{
			int length = source.Length;
			double num = (double)source.Length / rate;
			if (num > (double)Length)
			{
				int num2 = MathX.FloorToInt((double)Length * rate);
				source = source.Slice(source.Length - num2);
			}
			Span<S> target = data.AsSpan().Slice(base.CurrentHead);
			int num3;
			try
			{
				num3 = source.CopySamples(target, ref position, ref lastSample, rate);
			}
			catch (Exception innerException)
			{
				throw new Exception($"Exception copying samples to circular buffer. TargetData.Length: {target.Length}, Source.Length: {source.Length}, OrigLength: {length}, PutCount: {num}, position: {position}, rate: {rate}", innerException);
			}
			int num4 = (int)position;
			base.CurrentHead = (base.CurrentHead + num3) % Length;
			base.GlobalIndex += num3;
			if (num4 > source.Length)
			{
				position -= (int)position;
				return;
			}
			source = source.Slice(num4);
			position -= num4;
			if (source.Length > 1)
			{
				try
				{
					Put(source, ref position, ref lastSample, rate);
					return;
				}
				catch (Exception innerException2)
				{
					throw new Exception($"Exception running recursive put on CircularAudioBuffer. TargetData.Length: {target.Length}, Source.Length: {source.Length}, OrigLength: {length}, PutCount: {num}, position: {position}, rate: {rate}", innerException2);
				}
			}
			position -= source.Length;
		}

		public int Read<T>(Span<T> target, ref long globalPosition, double rate = 1.0) where T : unmanaged, IAudioSample<T>
		{
			S lastSample = default(S);
			double position = 0.0;
			return Read(target, ref globalPosition, rate, ref position, ref lastSample);
		}

		public int Read<T>(Span<T> target, ref CircularBufferReadState<S> state, double rate) where T : unmanaged, IAudioSample<T>
		{
			return Read(target, ref state.lastGlobalPosition, rate, ref state.lastPosition, ref state.lastSample);
		}

		public int Read<T>(Span<T> target, ref long globalPosition, double rate, ref double position, ref S lastSample) where T : unmanaged, IAudioSample<T>
		{
			int currentHead = base.CurrentHead;
			long globalIndex = base.GlobalIndex;
			_ = Length;
			long startGlobalIndex = base.StartGlobalIndex;
			if (position < 0.0)
			{
				globalPosition += (long)position;
				position = 1.0 + ((double)(long)position + position);
			}
			else
			{
				globalPosition += (long)position;
				position -= (long)position;
			}
			if (globalPosition >= globalIndex)
			{
				return 0;
			}
			if (globalPosition < startGlobalIndex)
			{
				globalPosition = startGlobalIndex;
				position = 0.0;
			}
			int num = currentHead - (int)(globalIndex - globalPosition);
			if (num == -1)
			{
				num = 0;
				globalPosition++;
				position -= 1.0;
			}
			else if (num < 0)
			{
				num += Length;
			}
			int num2 = (int)(globalIndex - globalPosition);
			Span<S> source = data.AsSpan().Slice(num, MathX.Min(data.Length - num, num2));
			int num3;
			try
			{
				num3 = source.CopySamples(target, ref position, ref lastSample, rate);
			}
			catch (Exception innerException)
			{
				throw new Exception($"Exception copying samples from circular buffer. SourceData.Length: {source.Length}, Target.Length: {target.Length}, position: {position}, rate: {rate}", innerException);
			}
			globalPosition += (long)position;
			position -= (long)position;
			if (num3 < target.Length && num3 > 0 && num2 > num3)
			{
				num3 += Read(target.Slice(num3), ref globalPosition, rate, ref position, ref lastSample);
			}
			return num3;
		}

		public IEnumerator<S> GetEnumerator()
		{
			int head = base.CurrentHead;
			int lenght = Length;
			int count = (int)MathX.Min(base.GlobalIndex, lenght);
			_ = head;
			_ = count;
			if (head < 0)
			{
				head += lenght;
			}
			for (int i = 0; i < count; i++)
			{
				yield return data[(head + i) % lenght];
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
	[DataModelType]
	public enum ChannelConfiguration
	{
		Mono,
		Stereo,
		Quad,
		Surround51,
		Surround71
	}
	public static class ChannelHelper
	{
		public static ChannelConfiguration FromChannelCount(int channelCount)
		{
			return channelCount switch
			{
				1 => ChannelConfiguration.Mono, 
				2 => ChannelConfiguration.Stereo, 
				4 => ChannelConfiguration.Quad, 
				6 => ChannelConfiguration.Surround51, 
				8 => ChannelConfiguration.Surround71, 
				_ => throw new ArgumentOutOfRangeException("channelCount"), 
			};
		}

		public static int ChannelCount(this ChannelConfiguration channelConfiguration)
		{
			return channelConfiguration switch
			{
				ChannelConfiguration.Mono => 1, 
				ChannelConfiguration.Stereo => 2, 
				ChannelConfiguration.Quad => 4, 
				ChannelConfiguration.Surround51 => 6, 
				ChannelConfiguration.Surround71 => 8, 
				_ => throw new ArgumentOutOfRangeException("channelConfiguration"), 
			};
		}

		public static Type SampleType(this ChannelConfiguration channelConfiguration)
		{
			return channelConfiguration switch
			{
				ChannelConfiguration.Mono => typeof(MonoSample), 
				ChannelConfiguration.Stereo => typeof(StereoSample), 
				ChannelConfiguration.Quad => typeof(QuadSample), 
				ChannelConfiguration.Surround51 => typeof(Surround51Sample), 
				ChannelConfiguration.Surround71 => typeof(Surround71Sample), 
				_ => throw new ArgumentOutOfRangeException("channelConfiguration"), 
			};
		}
	}
	public class CSCoreSampleDecoder : ISampleDecoder, IDisposable
	{
		private IWaveSource waveSource;

		private ISampleSource sampleSource;

		public Stream InputStream { get; private set; }

		public int Samples { get; private set; }

		public int SampleRate { get; private set; }

		public ChannelConfiguration Channels { get; private set; }

		public long Position
		{
			get
			{
				return sampleSource.Position;
			}
			set
			{
				sampleSource.Position = value;
			}
		}

		public AudioEncodeSettings EncodeSettings { get; private set; }

		public void Dispose()
		{
			sampleSource?.Dispose();
			sampleSource = null;
			waveSource = null;
		}

		public int Read(float[] buffer, int offset, int count)
		{
			int num = sampleSource.Read(buffer, offset, count);
			if (num < count && offset + num < Samples)
			{
				Array.Clear(buffer, num, buffer.Length - num);
				num = count;
			}
			return num;
		}

		public CSCoreSampleDecoder(string file)
		{
			string extension = Path.GetExtension(file).Replace(".", "");
			Load(File.OpenRead(file), extension);
		}

		public CSCoreSampleDecoder(Stream stream, string extension = null)
		{
			Load(stream, extension);
		}

		private void Load(Stream stream, string extension)
		{
			InputStream = stream;
			if (string.IsNullOrEmpty(extension))
			{
				long position = stream.Position;
				extension = stream.GetFileType()?.Extension;
				if (extension != null && extension.Contains(","))
				{
					extension = extension.Split(',')[0];
				}
				stream.Seek(position, SeekOrigin.Begin);
			}
			if (extension == null)
			{
				throw new Exception("Could not determine audio type");
			}
			if (extension[0] == '.')
			{
				extension = extension.Substring(1);
			}
			this.waveSource = CodecFactory.Instance.GetCodec(stream, extension);
			sampleSource = this.waveSource.ToSampleSource();
			IWaveSource waveSource = this.waveSource;
			if (!(waveSource is WaveFileReader waveFileReader))
			{
				if (waveSource is FlacFile)
				{
					EncodeSettings = new FlacEncodeSettings();
				}
			}
			else
			{
				WavEncodeSettings wavEncodeSettings = new WavEncodeSettings();
				switch (waveFileReader.WaveFormat.WaveFormatTag)
				{
				case AudioEncoding.Pcm:
				{
					WavEncodeSettings wavEncodeSettings2 = wavEncodeSettings;
					wavEncodeSettings2.Format = waveFileReader.WaveFormat.BitsPerSample switch
					{
						8 => WavEncodeSettings.SampleFormat.Byte_8, 
						16 => WavEncodeSettings.SampleFormat.Short_16, 
						24 => WavEncodeSettings.SampleFormat.Int_24, 
						32 => WavEncodeSettings.SampleFormat.Int_32, 
						_ => WavEncodeSettings.SampleFormat.Short_16, 
					};
					break;
				}
				case AudioEncoding.IeeeFloat:
					wavEncodeSettings.Format = WavEncodeSettings.SampleFormat.Float_32;
					break;
				}
				EncodeSettings = wavEncodeSettings;
			}
			if (sampleSource is NVorbisSource nVorbisSource)
			{
				VorbisEncodeSettings vorbisEncodeSettings = new VorbisEncodeSettings();
				vorbisEncodeSettings.Quality = VorbisEncodeSettings.BitrateToQuality((float)MathX.Max(nVorbisSource.NominalBitrate, nVorbisSource.UpperBitrate) * 0.001f);
				if (nVorbisSource.Comments != null)
				{
					string[] comments = nVorbisSource.Comments;
					foreach (string text in comments)
					{
						int num = text.IndexOf('=');
						if (num >= 0)
						{
							string key = text.Substring(0, num);
							string value = text.Substring(num + 1);
							vorbisEncodeSettings.Tags.Add(key, value);
						}
					}
				}
				EncodeSettings = vorbisEncodeSettings;
			}
			Samples = (int)sampleSource.Length;
			SampleRate = sampleSource.WaveFormat.SampleRate;
			switch (sampleSource.WaveFormat.Channels)
			{
			case 1:
				Channels = ChannelConfiguration.Mono;
				break;
			case 2:
				Channels = ChannelConfiguration.Stereo;
				break;
			case 4:
				Channels = ChannelConfiguration.Quad;
				break;
			case 6:
				Channels = ChannelConfiguration.Surround51;
				break;
			case 8:
				Channels = ChannelConfiguration.Surround71;
				break;
			default:
				throw new Exception("Unsupported channel configuration: " + sampleSource.WaveFormat.Channels);
			}
			Samples /= Channels.ChannelCount();
			if (EncodeSettings != null)
			{
				EncodeSettings.SampleRate = SampleRate;
				EncodeSettings.Channels = Channels;
			}
		}
	}
	public class FlacEncoder : ISampleEncoder, IDisposable
	{
		private FlakeWriter writer;

		private AudioBuffer buffer;

		public Stream OutputStream { get; private set; }

		public FlacEncoder(Stream stream, FlacEncodeSettings settings)
		{
			OutputStream = stream;
			settings.EnsureValidSettings();
			AudioPCMConfig pcm = new AudioPCMConfig(settings.BitsPerSample, settings.ChannelCount, settings.SampleRate);
			writer = new FlakeWriter(null, stream, pcm, leaveOpen: true);
			writer.CompressionLevel = settings.CompressionLevel;
			buffer = new AudioBuffer(pcm, 65536);
		}

		public void Dispose()
		{
			writer.Dispose();
			writer = null;
			buffer = null;
		}

		public void Write(Span<float> samples)
		{
			buffer.Prepare(samples.Length / buffer.PCM.ChannelCount);
			float[,] array = buffer.Float;
			switch (buffer.PCM.ChannelCount)
			{
			case 1:
			{
				Span<MonoSample> span4 = samples.AsMonoBuffer();
				for (int l = 0; l < span4.Length; l++)
				{
					array[l, 0] = span4[l];
				}
				break;
			}
			case 2:
			{
				Span<StereoSample> span2 = samples.AsStereoBuffer();
				for (int j = 0; j < span2.Length; j++)
				{
					array[j, 0] = span2[j].left;
					array[j, 1] = span2[j].right;
				}
				break;
			}
			case 4:
			{
				Span<QuadSample> span3 = samples.AsQuadBuffer();
				for (int k = 0; k < span3.Length; k++)
				{
					array[k, 0] = span3[k].leftFront;
					array[k, 1] = span3[k].rightFront;
					array[k, 2] = span3[k].leftRear;
					array[k, 3] = span3[k].rightRear;
				}
				break;
			}
			case 6:
			{
				Span<Surround51Sample> span = samples.AsSurround51Buffer();
				for (int i = 0; i < span.Length; i++)
				{
					array[i, 0] = span[i].leftFront;
					array[i, 1] = span[i].rightFront;
					array[i, 2] = span[i].center;
					array[i, 3] = span[i].subwoofer;
					array[i, 4] = span[i].leftRear;
					array[i, 5] = span[i].rightRear;
				}
				break;
			}
			}
			writer.Write(buffer);
		}
	}
	public class VorbisEncoder : ISampleEncoder, IDisposable
	{
		public const int BUFFER_SIZE = 512;

		private OggStream oggStream;

		private ProcessingState processingState;

		private float[][] buffer;

		public int Channels => buffer.Length;

		public Stream OutputStream { get; private set; }

		public VorbisEncoder(Stream stream, VorbisEncodeSettings settings)
		{
			OutputStream = stream;
			settings.EnsureValidSettings();
			int channelCount = settings.ChannelCount;
			VorbisInfo info = VorbisInfo.InitVariableBitRate(channelCount, settings.SampleRate, settings.Quality);
			int serialNumber = new Random().Next();
			oggStream = new OggStream(serialNumber);
			Comments comments = new Comments();
			if (settings.Tags != null)
			{
				foreach (KeyValuePair<string, string> tag in settings.Tags)
				{
					comments.AddTag(tag.Key, tag.Value);
				}
			}
			OggPacket packet = HeaderPacketBuilder.BuildInfoPacket(info);
			OggPacket packet2 = HeaderPacketBuilder.BuildCommentsPacket(comments);
			OggPacket packet3 = HeaderPacketBuilder.BuildBooksPacket(info);
			oggStream.PacketIn(packet);
			oggStream.PacketIn(packet2);
			oggStream.PacketIn(packet3);
			FlushPages(force: true);
			processingState = ProcessingState.Create(info);
			buffer = new float[channelCount][];
			for (int i = 0; i < channelCount; i++)
			{
				buffer[i] = new float[512];
			}
		}

		public void Write(Span<float> samples)
		{
			while (samples.Length > 0)
			{
				int num = MathX.Min(samples.Length / Channels, 512);
				for (int i = 0; i < num; i++)
				{
					for (int j = 0; j < Channels; j++)
					{
						buffer[j][i] = samples[i * Channels + j];
					}
				}
				processingState.WriteData(buffer, num);
				WritePackets();
				samples = samples.Slice(num * Channels);
			}
		}

		public void Finish()
		{
			if (processingState != null)
			{
				processingState.WriteEndOfStream();
				WritePackets();
				FlushPages(force: true);
				processingState = null;
				oggStream = null;
			}
		}

		public void Dispose()
		{
			Finish();
		}

		private void WritePackets()
		{
			OggPacket packet;
			while (!oggStream.Finished && processingState.PacketOut(out packet))
			{
				oggStream.PacketIn(packet);
				FlushPages(force: false);
			}
		}

		private void FlushPages(bool force)
		{
			OggPage page;
			while (oggStream.PageOut(out page, force))
			{
				OutputStream.Write(page.Header, 0, page.Header.Length);
				OutputStream.Write(page.Body, 0, page.Body.Length);
			}
		}
	}
	public class WavEncoder : ISampleEncoder, IDisposable
	{
		private WaveWriter writer;

		public Stream OutputStream { get; private set; }

		public WavEncoder(Stream stream, WavEncodeSettings settings)
		{
			OutputStream = stream;
			int sampleRate = settings.SampleRate;
			int bitsPerSample = settings.BitsPerSample;
			int channels = settings.Channels.ChannelCount();
			writer = new WaveWriter(stream, new WaveFormat(sampleRate, bitsPerSample, channels, (settings.Format != WavEncodeSettings.SampleFormat.Float_32) ? AudioEncoding.Pcm : AudioEncoding.IeeeFloat));
		}

		public void Write(Span<float> samples)
		{
			for (int i = 0; i < samples.Length; i++)
			{
				writer.WriteSample(samples[i]);
			}
		}

		public void Dispose()
		{
			writer.Dispose();
			writer = null;
		}
	}
