	public class VorbisEncodeSettings : AudioEncodeSettings
	{
		public static float[] QualityBitrates = new float[11]
		{
			64f, 80f, 96f, 112f, 128f, 160f, 192f, 224f, 256f, 320f,
			500f
		};

		public Dictionary<string, string> Tags = new Dictionary<string, string>();

		public float Quality { get; set; } = 0.5f;

		public override string Extension => "ogg";

		public static float BitrateToQuality(float bitrate)
		{
			return MathX.Clamp(MathX.MultiInverseLerp(bitrate, QualityBitrates) * 1.1f, 0f, 10f);
		}

		public static float QualityToBitrate(float quality)
		{
			return MathX.MultiLerp(quality, QualityBitrates);
		}

		public void EnsureValidSettings()
		{
			Quality = MathX.Clamp01(Quality);
		}

		public override bool Equals(object obj)
		{
			if (!base.Equals(obj))
			{
				return false;
			}
			VorbisEncodeSettings vorbisEncodeSettings = (VorbisEncodeSettings)obj;
			if (Quality == vorbisEncodeSettings.Quality)
			{
				return Tags.SequenceEqual(vorbisEncodeSettings.Tags);
			}
			return false;
		}

		public override int GetHashCode()
		{
			return ((-2013432708 * -1521134295 + base.GetHashCode()) * -1521134295 + Quality.GetHashCode()) * -1521134295 + EqualityComparer<Dictionary<string, string>>.Default.GetHashCode(Tags);
		}

		public static bool operator ==(VorbisEncodeSettings left, VorbisEncodeSettings right)
		{
			return EqualityComparer<VorbisEncodeSettings>.Default.Equals(left, right);
		}

		public static bool operator !=(VorbisEncodeSettings left, VorbisEncodeSettings right)
		{
			return !(left == right);
		}

		public override string ToString(bool includeBaseInfo)
		{
			return $"OGG Vorbis {(includeBaseInfo ? ToString() : "")} Quality: {Quality * 10f:F2} (~{QualityToBitrate(Quality)} kbps)";
		}
	}
