	public class AutoDucker<S> where S : unmanaged, IAudioSample<S>
	{
		private int _duckSmoothSamples = 32;

		private int _processFrameSize = 256;

		private float _recoverySpeed = 0.00024414062f;

		public float CurrentMaxPeak { get; private set; } = 1f;

		public int ProcessFrameSize
		{
			get
			{
				return _processFrameSize;
			}
			set
			{
				if (value < 32)
				{
					throw new ArgumentException("ProcessFrameSize must be at least 32");
				}
				_processFrameSize = value;
			}
		}

		public int DuckSmoothSamples
		{
			get
			{
				return _duckSmoothSamples;
			}
			set
			{
				if (value < 0)
				{
					throw new ArgumentOutOfRangeException("DuckSmoothSamples cannot be less than 0");
				}
				_duckSmoothSamples = value;
			}
		}

		public float RecoverySpeed
		{
			get
			{
				return _recoverySpeed;
			}
			set
			{
				if (value <= 0f)
				{
					throw new ArgumentOutOfRangeException("Recovery speed must be positive value");
				}
				_recoverySpeed = value;
			}
		}

		public void AutoDuck(Span<S> buffer)
		{
			while (buffer.Length > 0)
			{
				int num = MathX.Min(ProcessFrameSize, buffer.Length);
				ProcessDuckingFrame(buffer.Slice(0, num));
				buffer = buffer.Slice(num);
			}
		}

		private void ProcessDuckingFrame(Span<S> buffer)
		{
			float num = 1f;
			for (int i = 0; i < buffer.Length; i++)
			{
				num = MathX.Max(num, buffer[i].AbsoluteAmplitude);
			}
			if (num > CurrentMaxPeak)
			{
				if (DuckSmoothSamples > 0)
				{
					float currentMaxPeak = CurrentMaxPeak;
					float num2 = 1f / (float)DuckSmoothSamples;
					int num3 = MathX.Min(buffer.Length, DuckSmoothSamples);
					for (int j = 0; j < num3; j++)
					{
						CurrentMaxPeak = MathX.LerpUnclamped(currentMaxPeak, num, (float)(j + 1) * num2);
						buffer[j] = buffer[j].Multiply(1f / CurrentMaxPeak).Clip(1f);
					}
					buffer = buffer.Slice(num3);
				}
				else
				{
					CurrentMaxPeak = num;
				}
				float value = 1f / CurrentMaxPeak;
				for (int k = 0; k < buffer.Length; k++)
				{
					buffer[k] = buffer[k].Multiply(value);
				}
			}
			else if (CurrentMaxPeak > 1f)
			{
				float lerp = (float)buffer.Length * _recoverySpeed;
				float num4 = MathX.Max(MathX.Lerp(CurrentMaxPeak, 1f, lerp), num);
				float a = 1f / CurrentMaxPeak;
				float b = 1f / num4;
				float num5 = 1f / (float)buffer.Length;
				for (int l = 0; l < buffer.Length; l++)
				{
					buffer[l] = buffer[l].Multiply(MathX.LerpUnclamped(a, b, (float)l * num5));
				}
				CurrentMaxPeak = num4;
				if (CurrentMaxPeak < 1.0001f)
				{
					CurrentMaxPeak = 1f;
				}
			}
		}
	}
	public class BufferDenoiser<S> : IDisposable where S : unmanaged, IAudioSample<S>
	{
		private List<Denoiser> _denoisers = new List<Denoiser>();

		private int ChannelCount => _denoisers.Count;

		public BufferDenoiser()
		{
			int sampleChannelCount = typeof(S).GetSampleChannelCount();
			for (int i = 0; i < sampleChannelCount; i++)
			{
				_denoisers.Add(new Denoiser());
			}
		}

		public void Denoise(ref Span<S> buffer, bool finish)
		{
			if (ChannelCount == 1)
			{
				Span<float> buffer2 = MemoryMarshal.Cast<S, float>(buffer);
				buffer = buffer[.._denoisers[0].Denoise(buffer2, finish)];
				return;
			}
			Span<float> span = stackalloc float[480];
			int channelCount = ChannelCount;
			Span<S> span2 = buffer;
			int num = 0;
			while (span2.Length > 0)
			{
				Span<S> span3 = span2[..MathX.Min(span2.Length, span.Length)];
				bool flag = span3.Length == span2.Length;
				int num2 = 0;
				for (int i = 0; i < channelCount; i++)
				{
					Span<float> buffer3 = span.Slice(0, span3.Length);
					for (int j = 0; j < span3.Length; j++)
					{
						buffer3[j] = span3[j][i];
					}
					num2 = _denoisers[i].Denoise(buffer3, flag && finish);
					for (int k = 0; k < num2; k++)
					{
						int index = k + num;
						buffer[index] = buffer[index].SetChannel(i, buffer3[k]);
					}
				}
				span2 = span2.Slice(span3.Length);
				num += num2;
			}
			buffer = buffer.Slice(0, num);
		}

		public void Dispose()
		{
			foreach (Denoiser denoiser in _denoisers)
			{
				denoiser.Dispose();
			}
			_denoisers.Clear();
		}
	}
	public class BufferPitcher<S> : IPitchShiftFilter where S : unmanaged, IAudioSample<S>
	{
		public const int PITCHSHIFT_COMPUTE_BUFFER_SIZE = 4096;

		private readonly PitchShift[] _shifters;

		private readonly int _channels;

		private readonly SoundPipe _pipe;

		public float SemitoneShift
		{
			get
			{
				return _shifters[0].SemitoneShift;
			}
			set
			{
				int num = _shifters.Length;
				while (num-- > 0)
				{
					_shifters[num].SemitoneShift = value;
				}
			}
		}

		public float RelativeSpeed
		{
			get
			{
				return MathX.Pow(2f, SemitoneShift / 12f);
			}
			set
			{
				SemitoneShift = 12f * MathX.Log(value, 2f);
			}
		}

		public float WindowSize
		{
			get
			{
				return _shifters[0].WindowSize;
			}
			set
			{
				int num = _shifters.Length;
				while (num-- > 0)
				{
					_shifters[num].WindowSize = value;
				}
			}
		}

		public float CrossfadeSamples
		{
			get
			{
				return _shifters[0].CrossfadeSamples;
			}
			set
			{
				int num = _shifters.Length;
				while (num-- > 0)
				{
					_shifters[num].CrossfadeSamples = value;
				}
			}
		}

		public BufferPitcher(int sampleRate, IPitchShiftFilter? pitcherSettings = null)
		{
			_channels = typeof(S).GetSampleChannelCount();
			_shifters = _channels switch
			{
				1 => _shifters = new PitchShift[1], 
				2 => _shifters = new PitchShift[2], 
				4 => _shifters = new PitchShift[4], 
				6 => _shifters = new PitchShift[6], 
				_ => throw new NotSupportedException($"Channel count not supported: {_channels}"), 
			};
			_pipe = new SoundPipe();
			_pipe.SampleRate = sampleRate;
			for (int i = 0; i < _shifters.Length; i++)
			{
				PitchShift pitchShift = new PitchShift(_pipe);
				if (pitcherSettings != null)
				{
					PitchShiftHelpers.FromOther(pitchShift, pitcherSettings);
				}
				_shifters[i] = pitchShift;
			}
		}

		public void ApplyShift(Span<S> buffer)
		{
			switch (_channels)
			{
			case 1:
				ShiftMono(buffer.AsMonoBuffer());
				break;
			case 2:
				ShiftStereo(buffer.AsStereoBuffer());
				break;
			case 4:
				ShiftQuad(buffer.AsQuadBuffer());
				break;
			case 6:
				Shift51(buffer.AsSurround51Buffer());
				break;
			case 3:
			case 5:
				break;
			}
		}

		private void ShiftMono(Span<MonoSample> buffer)
		{
			_shifters[0].Compute(buffer.AsSampleBuffer(), buffer.AsSampleBuffer(), 4096);
		}

		private void ShiftStereo(Span<StereoSample> buffer)
		{
			Span<MonoSample> span = stackalloc MonoSample[4096];
			Span<MonoSample> span2 = stackalloc MonoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<StereoSample> span3 = buffer.Slice(i, num);
				Span<MonoSample> buffer2 = span.Slice(0, num);
				Span<MonoSample> buffer3 = span2.Slice(0, num);
				for (int j = 0; j < num; j++)
				{
					ref StereoSample reference = ref span3[j];
					buffer2[j] = reference.left;
					buffer3[j] = reference.right;
				}
				Span<float> span4 = buffer2.AsSampleBuffer();
				Span<float> span5 = buffer3.AsSampleBuffer();
				_shifters[0].Compute(span4, span4, 4096);
				_shifters[1].Compute(span5, span5, 4096);
				for (int k = 0; k < num; k++)
				{
					span3[k] = new StereoSample(span[k], span2[k]);
				}
			}
		}

		private void ShiftQuad(Span<QuadSample> buffer)
		{
			Span<MonoSample> buffer2 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer3 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer4 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer5 = stackalloc MonoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<QuadSample> span = buffer.Slice(i, num);
				Span<MonoSample> span2 = buffer2.Slice(0, num);
				Span<MonoSample> span3 = buffer3.Slice(0, num);
				Span<MonoSample> span4 = buffer4.Slice(0, num);
				Span<MonoSample> span5 = buffer5.Slice(0, num);
				for (int j = 0; j < num; j++)
				{
					ref QuadSample reference = ref span[j];
					span2[j] = reference.leftFront;
					span3[j] = reference.rightFront;
					span4[j] = reference.leftRear;
					span5[j] = reference.rightRear;
				}
				Span<float> span6 = buffer2.AsSampleBuffer();
				Span<float> span7 = buffer3.AsSampleBuffer();
				Span<float> span8 = buffer4.AsSampleBuffer();
				Span<float> span9 = buffer5.AsSampleBuffer();
				_shifters[0].Compute(span6, span6, 4096);
				_shifters[1].Compute(span7, span7, 4096);
				_shifters[2].Compute(span8, span8, 4096);
				_shifters[3].Compute(span9, span9, 4096);
				for (int k = 0; k < num; k++)
				{
					span[k] = new QuadSample(span6[k], span7[k], span8[k], span9[k]);
				}
			}
		}

		private void Shift51(Span<Surround51Sample> buffer)
		{
			Span<MonoSample> buffer2 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer3 = stackalloc MonoSample[4096];
			Span<MonoSample> span = stackalloc MonoSample[4096];
			Span<MonoSample> span2 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer4 = stackalloc MonoSample[4096];
			Span<MonoSample> buffer5 = stackalloc MonoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<Surround51Sample> span3 = buffer.Slice(i, num);
				Span<MonoSample> span4 = buffer2.Slice(0, num);
				Span<MonoSample> span5 = buffer3.Slice(0, num);
				Span<MonoSample> span6 = span.Slice(0, num);
				Span<MonoSample> span7 = span2.Slice(0, num);
				Span<MonoSample> span8 = buffer4.Slice(0, num);
				Span<MonoSample> span9 = buffer5.Slice(0, num);
				for (int j = 0; j < num; j++)
				{
					ref Surround51Sample reference = ref span3[j];
					span4[j] = reference.leftFront;
					span5[j] = reference.rightFront;
					span6[j] = reference.center;
					span7[j] = reference.subwoofer;
					span8[j] = reference.leftRear;
					span9[j] = reference.rightRear;
				}
				Span<float> span10 = buffer2.AsSampleBuffer();
				Span<float> span11 = buffer3.AsSampleBuffer();
				Span<float> span12 = buffer3.AsSampleBuffer();
				Span<float> span13 = buffer3.AsSampleBuffer();
				Span<float> span14 = buffer4.AsSampleBuffer();
				Span<float> span15 = buffer5.AsSampleBuffer();
				_shifters[0].Compute(span10, span10, 4096);
				_shifters[1].Compute(span11, span11, 4096);
				_shifters[2].Compute(span12, span12, 4096);
				_shifters[3].Compute(span13, span13, 4096);
				_shifters[4].Compute(span14, span14, 4096);
				_shifters[5].Compute(span15, span15, 4096);
				for (int k = 0; k < num; k++)
				{
					span3[k] = new Surround51Sample(span10[k], span11[k], span12[k], span13[k], span14[k], span15[k]);
				}
			}
		}
	}
