		public void ApplyReverb(Span<S> buffer)
		{
			switch (_channels)
			{
			case 1:
				ReverbMono(buffer.AsMonoBuffer());
				break;
			case 2:
				ReverbStereo(buffer.AsStereoBuffer());
				break;
			case 4:
				ReverbQuad(buffer.AsQuadBuffer());
				break;
			case 6:
				Reverb51(buffer.AsSurround51Buffer());
				break;
			case 3:
			case 5:
				break;
			}
		}

		private void ReverbMono(Span<MonoSample> buffer)
		{
			Span<StereoSample> span = stackalloc StereoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<MonoSample> span2 = buffer.Slice(i, num);
				Span<StereoSample> span3 = span.Slice(0, num);
				span2.CopySamples(span3);
				Span<float> span4 = span3.AsSampleBuffer();
				_reverbs[0].Compute(span4, span4, 4096);
				span3.CopySamples(span2);
			}
		}

		private void ReverbStereo(Span<StereoSample> buffer)
		{
			_reverbs[0].Compute(buffer.AsSampleBuffer(), buffer.AsSampleBuffer(), 4096);
		}

		private void ReverbQuad(Span<QuadSample> buffer)
		{
			Span<StereoSample> span = stackalloc StereoSample[4096];
			Span<StereoSample> span2 = stackalloc StereoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<QuadSample> span3 = buffer.Slice(i, num);
				Span<StereoSample> buffer2 = span.Slice(0, num);
				Span<StereoSample> buffer3 = span2.Slice(0, num);
				for (int j = 0; j < num; j++)
				{
					ref QuadSample reference = ref span3[j];
					buffer2[j] = new StereoSample(reference.leftFront, reference.rightFront);
					buffer3[j] = new StereoSample(reference.leftRear, reference.rightRear);
				}
				Span<float> span4 = buffer2.AsSampleBuffer();
				Span<float> span5 = buffer3.AsSampleBuffer();
				_reverbs[0].Compute(span4, span4, 4096);
				_reverbs[1].Compute(span5, span5, 4096);
				for (int k = 0; k < num; k++)
				{
					ref StereoSample reference2 = ref buffer2[k];
					ref StereoSample reference3 = ref buffer3[k];
					span3[k] = new QuadSample(reference2.left, reference2.right, reference3.left, reference3.right);
				}
			}
		}

		private void Reverb51(Span<Surround51Sample> buffer)
		{
			Span<StereoSample> span = stackalloc StereoSample[4096];
			Span<StereoSample> span2 = stackalloc StereoSample[4096];
			Span<StereoSample> span3 = stackalloc StereoSample[4096];
			Span<StereoSample> span4 = stackalloc StereoSample[4096];
			int length = buffer.Length;
			int num;
			for (int i = 0; i < length; i += num)
			{
				num = MathX.Min(length - i, 4096);
				Span<Surround51Sample> span5 = buffer.Slice(i, num);
				Span<StereoSample> buffer2 = span.Slice(0, num);
				Span<StereoSample> buffer3 = span2.Slice(0, num);
				Span<StereoSample> buffer4 = span3.Slice(0, num);
				Span<StereoSample> buffer5 = span4.Slice(0, num);
				for (int j = 0; j < num; j++)
				{
					ref Surround51Sample reference = ref span5[j];
					buffer2[j] = new StereoSample(reference.leftFront, reference.rightFront);
					buffer3[j] = new StereoSample(reference.leftRear, reference.rightRear);
					buffer4[j] = new StereoSample(reference.center);
					buffer5[j] = new StereoSample(reference.subwoofer);
				}
				Span<float> span6 = buffer2.AsSampleBuffer();
				Span<float> span7 = buffer3.AsSampleBuffer();
				Span<float> span8 = buffer4.AsSampleBuffer();
				Span<float> span9 = buffer5.AsSampleBuffer();
				_reverbs[0].Compute(span6, span6, 4096);
				_reverbs[2].Compute(span7, span7, 4096);
				_reverbs[1].Compute(span8, span8, 4096);
				_reverbs[3].Compute(span9, span9, 4096);
				for (int k = 0; k < num; k++)
				{
					ref StereoSample reference2 = ref buffer2[k];
					ref StereoSample reference3 = ref buffer3[k];
					ref StereoSample reference4 = ref buffer4[k];
					ref StereoSample reference5 = ref buffer5[k];
					span5[k] = new Surround51Sample(reference2.left, reference2.right, (float)reference4, (float)reference5, reference3.left, reference3.right);
				}
			}
		}

		public void Dispose()
		{
			ZitaReverb[] reverbs = _reverbs;
			for (int i = 0; i < reverbs.Length; i++)
			{
				reverbs[i].Dispose();
			}
			_pipe.Dispose();
		}
	}
