		public static int TransitionSampleBlock<S, T>(Span<T> target, ref double startOffset, S lastSample, S nextSample, double rate = 1.0) where S : unmanaged, IAudioSample<S> where T : unmanaged, IAudioSample<T>
		{
			int num = 0;
			startOffset += 1.0;
			if (typeof(T) == typeof(S))
			{
				Span<S> span = MemoryMarshal.Cast<T, S>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span[num++] = lastSample.LerpTo(nextSample, (float)startOffset);
					startOffset += rate;
				}
			}
			else if (typeof(T) == typeof(MonoSample))
			{
				Span<MonoSample> span2 = MemoryMarshal.Cast<T, MonoSample>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span2[num++] = lastSample.LerpTo(nextSample, (float)startOffset).ToMono();
					startOffset += rate;
				}
			}
			else if (typeof(T) == typeof(StereoSample))
			{
				Span<StereoSample> span3 = MemoryMarshal.Cast<T, StereoSample>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span3[num++] = lastSample.LerpTo(nextSample, (float)startOffset).ToStereo();
					startOffset += rate;
				}
			}
			else if (typeof(T) == typeof(QuadSample))
			{
				Span<QuadSample> span4 = MemoryMarshal.Cast<T, QuadSample>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span4[num++] = lastSample.LerpTo(nextSample, (float)startOffset).ToQuad();
					startOffset += rate;
				}
			}
			else if (typeof(T) == typeof(Surround51Sample))
			{
				Span<Surround51Sample> span5 = MemoryMarshal.Cast<T, Surround51Sample>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span5[num++] = lastSample.LerpTo(nextSample, (float)startOffset).ToSurround51();
					startOffset += rate;
				}
			}
			else
			{
				if (!(typeof(T) == typeof(Surround71Sample)))
				{
					throw new Exception("Unsupported sample type: " + typeof(T));
				}
				Span<Surround71Sample> span6 = MemoryMarshal.Cast<T, Surround71Sample>(target);
				while (startOffset < 1.0 && num < target.Length)
				{
					span6[num++] = lastSample.LerpTo(nextSample, (float)startOffset).ToSurround71();
					startOffset += rate;
				}
			}
			startOffset -= 1.0;
			return num;
		}

