		}

		public static int CopySamples<S, T>(this ReadOnlySpan<S> source, Span<T> target, ref double sourcePosition, ref S lastSample, double rate = 1.0) where S : unmanaged, IAudioSample<S> where T : unmanaged, IAudioSample<T>
		{
			if (source.Length == 0)
			{
				return 0;
			}
			double num = MathX.Round(sourcePosition);
			bool flag = false;
			if (MathX.Approximately(sourcePosition, num))
			{
				sourcePosition = num;
				flag = true;
			}
			if (source.Length == 1 && sourcePosition == 0.0)
			{
				if (typeof(T) == typeof(MonoSample))
				{
					MemoryMarshal.Cast<T, MonoSample>(target)[0] = source[0].ToMono();
				}
				else if (typeof(T) == typeof(StereoSample))
				{
					MemoryMarshal.Cast<T, StereoSample>(target)[0] = source[0].ToStereo();
				}
				else if (typeof(T) == typeof(QuadSample))
				{
					MemoryMarshal.Cast<T, QuadSample>(target)[0] = source[0].ToQuad();
				}
				else if (typeof(T) == typeof(Surround51Sample))
				{
					MemoryMarshal.Cast<T, Surround51Sample>(target)[0] = source[0].ToSurround51();
				}
				else if (typeof(T) == typeof(Surround71Sample))
				{
					MemoryMarshal.Cast<T, Surround71Sample>(target)[0] = source[0].ToSurround71();
				}
				lastSample = source[0];
				sourcePosition += 1.0;
				return 1;
			}
			if (MathX.Approximately(rate, 1.0) && flag && sourcePosition >= 0.0)
			{
				if (sourcePosition > 0.0)
				{
					source = source.Slice((int)sourcePosition);
				}
				if (target.Length < source.Length)
				{
					source = source.Slice(0, target.Length);
				}
				else if (target.Length > source.Length)
				{
					target = target.Slice(0, source.Length);
				}
				if (typeof(S) == typeof(T))
				{
					source.CopyTo(MemoryMarshal.Cast<T, S>(target));
				}
				else if (typeof(T) == typeof(MonoSample))
				{
					Span<MonoSample> span = MemoryMarshal.Cast<T, MonoSample>(target);
					for (int i = 0; i < source.Length; i++)
					{
						span[i] = source[i].ToMono();
					}
				}
				else if (typeof(T) == typeof(StereoSample))
				{
					Span<StereoSample> span2 = MemoryMarshal.Cast<T, StereoSample>(target);
					for (int j = 0; j < source.Length; j++)
					{
