				else if (typeof(T) == typeof(Surround51Sample))
				{
					Span<Surround51Sample> span4 = MemoryMarshal.Cast<T, Surround51Sample>(target);
					for (int l = 0; l < source.Length; l++)
					{
						span4[l] = source[l].ToSurround51();
					}
				}
				else
				{
					if (!(typeof(T) == typeof(Surround71Sample)))
					{
						throw new Exception("Unsupported target type: " + typeof(T));
					}
					Span<Surround71Sample> span5 = MemoryMarshal.Cast<T, Surround71Sample>(target);
					for (int m = 0; m < source.Length; m++)
					{
						span5[m] = source[m].ToSurround71();
					}
				}
				sourcePosition += source.Length;
				return source.Length;
			}
			if (sourcePosition >= 1.0)
			{
				source.Slice((int)sourcePosition);
				sourcePosition -= (int)sourcePosition;
			}
			int num2 = 0;
			if (sourcePosition < 0.0)
			{
				num2 = TransitionSampleBlock(target, ref sourcePosition, lastSample, source[0], rate);
				target = target.Slice(num2);
			}
			double num3 = (double)(target.Length - 1) * rate + sourcePosition;
			int num4 = MathX.CeilToInt(num3 + 1.0);
			if (source.Length < num4)
			{
				int num5 = MathX.CeilToInt((num3 + 1.0 - (double)source.Length + 1E-06) / rate);
				target = target.Slice(0, target.Length - num5);
			}
			if (typeof(T) == typeof(S))
			{
				Span<S> span6 = MemoryMarshal.Cast<T, S>(target);
				for (int n = 0; n < span6.Length; n++)
				{
					int num6 = (int)(sourcePosition - 1E-06);
					double num7 = sourcePosition - (double)num6;
					S val = source[num6];
					S next = source[num6 + 1];
					span6[n] = val.LerpTo(next, (float)num7);
					sourcePosition += rate;
				}
			}
			else if (typeof(T) == typeof(MonoSample))
			{
				Span<MonoSample> span7 = MemoryMarshal.Cast<T, MonoSample>(target);
				for (int num8 = 0; num8 < span7.Length; num8++)
				{
					int num9 = (int)(sourcePosition - 1E-06);
					double num10 = sourcePosition - (double)num9;
					S val2 = source[num9];
					S next2 = source[num9 + 1];
					span7[num8] = val2.LerpTo(next2, (float)num10).ToMono();
					sourcePosition += rate;
				}
			}
			else if (typeof(T) == typeof(StereoSample))
			{
				Span<StereoSample> span8 = MemoryMarshal.Cast<T, StereoSample>(target);
				for (int num11 = 0; num11 < span8.Length; num11++)
				{
					int num12 = (int)(sourcePosition - 1E-06);
					double num13 = sourcePosition - (double)num12;
					S val3 = source[num12];
					S next3 = source[num12 + 1];
					span8[num11] = val3.LerpTo(next3, (float)num13).ToStereo();
					sourcePosition += rate;
				}
			}
			else if (typeof(T) == typeof(QuadSample))
			{
				Span<QuadSample> span9 = MemoryMarshal.Cast<T, QuadSample>(target);
				for (int num14 = 0; num14 < span9.Length; num14++)
				{
					int num15 = (int)(sourcePosition - 1E-06);
					double num16 = sourcePosition - (double)num15;
					S val4 = source[num15];
					S next4 = source[num15 + 1];
					span9[num14] = val4.LerpTo(next4, (float)num16).ToQuad();
					sourcePosition += rate;
				}
			}
			else if (typeof(T) == typeof(Surround51Sample))
			{
				Span<Surround51Sample> span10 = MemoryMarshal.Cast<T, Surround51Sample>(target);
				for (int num17 = 0; num17 < span10.Length; num17++)
				{
					int num18 = (int)(sourcePosition - 1E-06);
					double num19 = sourcePosition - (double)num18;
					S val5 = source[num18];
					S next5 = source[num18 + 1];
					span10[num17] = val5.LerpTo(next5, (float)num19).ToSurround51();
					sourcePosition += rate;
				}
			}
			else
			{
				if (!(typeof(T) == typeof(Surround71Sample)))
				{
					throw new Exception("Unsupported target type: " + typeof(T));
				}
				Span<Surround71Sample> span11 = MemoryMarshal.Cast<T, Surround71Sample>(target);
				for (int num20 = 0; num20 < span11.Length; num20++)
				{
					int num21 = (int)(sourcePosition - 1E-06);
					double num22 = sourcePosition - (double)num21;
					S val6 = source[num21];
					S next6 = source[num21 + 1];
					span11[num20] = val6.LerpTo(next6, (float)num22).ToSurround71();
					sourcePosition += rate;
				}
			}
			lastSample = source[source.Length - 1];
			return target.Length + num2;
		}

		public static void Multiply<S>(this Span<S> buffer, float gain) where S : unmanaged, IAudioSample<S>
		{
			for (int i = 0; i < buffer.Length; i++)
			{
				buffer[i] = buffer[i].Multiply(gain);
			}
		}

		public static void Add<S>(this Span<S> buffer, Span<S> other) where S : unmanaged, IAudioSample<S>
		{
			if (buffer.Length != other.Length)
			{
				throw new ArgumentException("Other buffer must be the same length as the main buffer");
			}
			for (int i = 0; i < buffer.Length; i++)
			{
				buffer[i] = buffer[i].Add(other[i]);
			}
		}

		/// <summary>
		/// Clips a span of samples to a given amplitude.
		/// </summary>
		/// <typeparam name="S">The type of sample to process.</typeparam>
		/// <param name="buffer">The sample buffer to clip.</param>
		/// <param name="maxAmplitude">The maximum amplitude that is allowed to appear in the buffer.</param>
		public static void Clip<S>(this Span<S> buffer, float maxAmplitude = 1f) where S : unmanaged, IAudioSample<S>
		{
			for (int i = 0; i < buffer.Length; i++)
			{
				buffer[i] = buffer[i].Clip(maxAmplitude);
			}
		}
	}
