			return new MonoSample(a.amplitude + b.amplitude);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		public static MonoSample operator -(MonoSample a, MonoSample b)
		{
			return new MonoSample(a.amplitude - b.amplitude);
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
