	public class VorbisWriter
	{
		private Stream outStream;

		private OggStream oggStream;

		private VorbisInfo info;

		private Comments comments;

		private ProcessingState processingState;

		private float[][] _buffer;

		public bool HeaderWritten { get; private set; }

		public VorbisWriter(Stream stream, int channels, int sampleRate, float quality)
		{
			outStream = stream;
			info = VorbisInfo.InitVariableBitRate(channels, sampleRate, quality);
			oggStream = new OggStream(new Random().Next());
			comments = new Comments();
		}

		public void AddTag(string tag, string content)
		{
			if (HeaderWritten)
			{
				throw new Exception("Cannot add tags after writing the header");
			}
			comments.AddTag(tag, content);
		}

		public void WriteHeader()
		{
			if (HeaderWritten)
			{
				throw new Exception("Header already written");
			}
			OggPacket packet = HeaderPacketBuilder.BuildInfoPacket(info);
			OggPacket packet2 = HeaderPacketBuilder.BuildCommentsPacket(comments);
			OggPacket packet3 = HeaderPacketBuilder.BuildBooksPacket(info);
			oggStream.PacketIn(packet);
			oggStream.PacketIn(packet2);
			oggStream.PacketIn(packet3);
			OggPage page;
			while (oggStream.PageOut(out page, force: true))
			{
				outStream.Write(page.Header, 0, page.Header.Length);
				outStream.Write(page.Body, 0, page.Body.Length);
			}
			processingState = ProcessingState.Create(info);
			HeaderWritten = true;
		}

		public void WriteAudio(float[] buffer)
		{
			WriteAudio(buffer, buffer.Length / info.Channels);
		}

		public void WriteAudio(float[] buffer, int samples)
		{
			if (_buffer == null)
			{
				_buffer = new float[info.Channels][];
			}
			for (int i = 0; i < info.Channels; i++)
			{
				_buffer[i] = _buffer[i].EnsureSize(samples);
			}
			for (int j = 0; j < samples; j++)
			{
				for (int k = 0; k < info.Channels; k++)
				{
					_buffer[k][j] = buffer[j * info.Channels + k];
				}
			}
			WriteAudio(_buffer, samples);
		}

		public void WriteAudio(float[][] data)
		{
			WriteAudio(data, data[0].Length);
		}

		public void WriteAudio(float[][] data, int samples)
		{
			if (data.Length != info.Channels)
			{
				throw new Exception("The number of channels in data doesn't match the number of channels in the encoder");
			}
			if (!HeaderWritten)
			{
				WriteHeader();
			}
			processingState.WriteData(data, samples);
			if (processingState.PacketOut(out var packet))
			{
				oggStream.PacketIn(packet);
				OggPage page;
				while (oggStream.PageOut(out page, force: false))
				{
					outStream.Write(page.Header, 0, page.Header.Length);
					outStream.Write(page.Body, 0, page.Body.Length);
				}
			}
		}

		public void Finish()
		{
			processingState.WriteEndOfStream();
			OggPacket packet;
			while (processingState.PacketOut(out packet))
			{
				oggStream.PacketIn(packet);
				OggPage page;
				while (oggStream.PageOut(out page, force: true))
				{
					outStream.Write(page.Header, 0, page.Header.Length);
					outStream.Write(page.Body, 0, page.Body.Length);
				}
			}
		}
	}
	public class DocumentX : IDisposable
	{
		private IDocumentDataSource documentDataSource;

		public string Name { get; private set; }

		public int PageCount { get; private set; }

		public DocumentX(IDocumentDataSource dataSource)
		{
			InitDataSource(dataSource);
		}

		public DocumentX(string file)
		{
			FileStream fileStream = File.OpenRead(file);
			try
			{
				FileType obj = fileStream.GetFileType() ?? throw new InvalidDataException("Could not determine the file type");
				fileStream.Seek(0L, SeekOrigin.Begin);
				if (obj.Extension.EndsWith("pdf"))
				{
					fileStream.Dispose();
					fileStream = null;
					InitDataSource(new PDF_DataSource(file));
				}
			}
			finally
			{
				if (documentDataSource == null)
				{
					fileStream?.Dispose();
				}
			}
		}

		private void InitDataSource(IDocumentDataSource dataSource)
		{
			if (documentDataSource != null)
			{
				throw new InvalidOperationException("Data source has already been initialized");
			}
			documentDataSource = dataSource;
			Name = dataSource.Name;
			PageCount = dataSource.PageCount;
		}

		public IDocumentPage GetPage(int index)
		{
			return documentDataSource.GetPage(index);
		}

		public void Dispose()
		{
			documentDataSource?.Dispose();
			documentDataSource = null;
		}
	}
