	public class PDF_Page : IDocumentPage
	{
		private readonly struct RenderFormat
		{
			public readonly BitmapFormats format;

			public readonly bool reverseByteOrder;

			public RenderFormat(BitmapFormats format, bool reverseByteOrder)
			{
				this.format = format;
				this.reverseByteOrder = reverseByteOrder;
			}
		}

		private PdfPage _page;

		public int Index => _page.Index;

		public double2 ReferenceSize => new double2(_page.Width, _page.Height);

		public bool HasAlpha => _page.HasTransparency;

		public PDF_Page(PdfPage page)
		{
			_page = page;
		}

		public void RenderTo(Bitmap2D bitmap)
		{
			RenderTo(bitmap, new Rect(0f, 0f, 1f, 1f));
		}

		public unsafe void RenderTo(Bitmap2D bitmap, Rect pageSection)
		{
			RenderFormat? renderFormat = ToPDFium(bitmap.Format);
			if (!renderFormat.HasValue)
			{
				throw new InvalidDataException("Unsupported bitmap format: " + bitmap.Format);
			}
			bitmap.Clear(color.White);
			fixed (byte* value = bitmap.RawData)
			{
				using PDFiumBitmap renderTarget = new PDFiumBitmap(bitmap.Size.x, bitmap.Size.y, renderFormat.Value.format, new IntPtr(value), bitmap.Size.x * bitmap.Format.GetBytesPerPixel());
				RenderingFlags renderingFlags = RenderingFlags.None;
				if (renderFormat.Value.reverseByteOrder)
				{
					renderingFlags |= RenderingFlags.ReverseByteOrder;
				}
				int x = bitmap.Size.x;
				int y = bitmap.Size.y;
				x = MathX.RoundToInt((float)x / pageSection.width);
				y = MathX.RoundToInt((float)y / pageSection.height);
				int item = MathX.RoundToInt((float)x * (0f - pageSection.position.x));
				int item2 = MathX.RoundToInt((float)y * (0f - pageSection.position.y));
				_page.Render(renderTarget, (left: item, top: item2, width: x, height: y), PageOrientations.Normal, renderingFlags);
				if (bitmap.FlipY)
				{
					bitmap.FlipVertical();
				}
			}
		}

		private static RenderFormat? ToPDFium(TextureFormat format)
		{
			return format switch
			{
				TextureFormat.R8 => new RenderFormat(BitmapFormats.Gray, reverseByteOrder: false), 
				TextureFormat.BGRA32 => new RenderFormat(BitmapFormats.BGRA, reverseByteOrder: false), 
				TextureFormat.RGB24 => new RenderFormat(BitmapFormats.BGR, reverseByteOrder: true), 
				TextureFormat.RGBA32 => new RenderFormat(BitmapFormats.BGRA, reverseByteOrder: true), 
				_ => null, 
			};
		}
	}
	public static class FileUtility
	{
		public static string DetectMime(string path)
		{
			string text = Path.GetExtension(path).ToUpper();
			if (text != null)
			{
				int length = text.Length;
				if (length != 3)
				{
					if (length == 4)
					{
						char c = text[1];
						if (c != 'F')
						{
							if (c != 'I')
							{
								if (c == 'P' && text == "JPEG")
								{
									goto IL_0115;
								}
							}
							else if (text == "TIFF")
							{
								goto IL_0121;
							}
						}
						else if (text == "JFIF")
						{
							goto IL_0115;
						}
					}
				}
				else
				{
					char c = text[0];
					if ((uint)c <= 74u)
					{
						if (c != 'G')
						{
							if (c == 'J')
							{
								switch (text)
								{
								case "JPG":
								case "JPE":
								case "JIF":
								case "JFI":
									break;
								default:
									goto IL_0127;
								}
								goto IL_0115;
							}
						}
						else if (text == "GIF")
						{
							return "image/gif";
						}
					}
					else if (c != 'P')
					{
						if (c == 'T' && text == "TIF")
						{
							goto IL_0121;
						}
					}
					else if (text == "PNG")
					{
						return "image/png";
					}
				}
			}
			goto IL_0127;
			IL_0127:
			return "unknown/unknown";
			IL_0121:
			return "image/tiff";
			IL_0115:
			return "image/jpeg";
		}
	}
	public class ClusteredSH_Data
	{
		public readonly int SplatCount;

		public readonly int PaletteCount;

		public readonly byte[] Data;

		public unsafe int PaletteBytes => sizeof(GaussianSH_TableHalf) * PaletteCount;

		public int IndiciesBytes => 2 * SplatCount;

		public int TotalBytes => PaletteBytes + IndiciesBytes;

		public Span<GaussianSH_TableHalf> Palette => MemoryMarshal.Cast<byte, GaussianSH_TableHalf>(Data.AsSpan().Slice(0, PaletteBytes));

		public Span<ushort> Indicies => MemoryMarshal.Cast<byte, ushort>(Data.AsSpan().Slice(PaletteBytes));

		public static int IndiciesOffset(GaussianSHFormat format)
		{
			if (!format.IsClustered())
			{
				throw new ArgumentException("Format must be clustered");
			}
			return IndiciesOffset(GaussianSplatCompressor.GetSHCount(-1, format));
		}

		public unsafe static int IndiciesOffset(int paletteCount)
		{
			return sizeof(GaussianSH_TableHalf) * paletteCount;
		}

		public ClusteredSH_Data(int splatCount, int paletteCount, byte[] data = null)
		{
			SplatCount = splatCount;
			PaletteCount = paletteCount;
			if (data != null)
			{
				if (data.Length < TotalBytes)
				{
					throw new ArgumentException("Provided data doesn't have enough capacity to hold all splats");
				}
				Data = data;
			}
			else
			{
				Data = new byte[TotalBytes];
			}
		}
	}
	public static class GaussianSplatCompressor
	{
		public readonly struct MortonIndex : IEquatable<MortonIndex>, IComparable<MortonIndex>
		{
			public readonly ulong code;

			public readonly int index;

			public MortonIndex(ulong code, int index)
			{
				this.code = code;
				this.index = index;
			}

			public bool Equals(MortonIndex other)
			{
				if (code == other.code)
				{
					return index == other.index;
				}
				return false;
			}

			public int CompareTo(MortonIndex other)
			{
				if (code < other.code)
				{
					return -1;
				}
				if (code > other.code)
				{
					return 1;
				}
				return MathX.Sign(index - other.index);
			}

			public override string ToString()
			{
				return $"[{index}] = {code}";
			}
		}

