				float3 a = float3.PositiveInfinity;
				float3 a2 = float3.NegativeInfinity;
				float3 a3 = float3.PositiveInfinity;
				float3 a4 = float3.NegativeInfinity;
				float4 a5 = float4.PositiveInfinity;
				float4 a6 = float4.NegativeInfinity;
				float3 a7 = float3.PositiveInfinity;
				float3 a8 = float3.NegativeInfinity;
				for (int i = num2; i < num3; i++)
				{
