					ref float3 reference = ref scales[i];
					ref float reference2 = ref alphas[i];
					ref SphericalHarmonicsL3<PixelRGB_Float> reference3 = ref span[i];
					reference = MathX.Pow(in reference, 0.125f);
					reference2 = MathX.SquareCentered01(reference2);
