					a2 = MathX.Max(in a2, in b);
					a3 = MathX.Min(in a3, in reference);
					a4 = MathX.Max(in a4, in reference);
					float4 b2 = new float4(reference3.sh0.RGB, reference2);
					a5 = MathX.Min(in a5, in b2);
					a6 = MathX.Max(in a6, in b2);
					for (int j = 1; j < reference3.CoefficientCount; j++)
					{
