				a4 = MathX.Max(in a4, a3 + 1E-05f);
				a6 = MathX.Max(in a6, a5 + 1E-05f);
				a8 = MathX.Max(in a8, a7 + 1E-05f);
				ref GaussianCloudChunk reference4 = ref chunkData[chunkIndex];
				reference4.MinPos = a;
				reference4.MaxPos = a2;
				reference4.MinScale = a3;
				reference4.MaxScale = a4;
				reference4.MinRGBA = a5;
				reference4.MaxRGBA = a6;
				reference4.MinSH = a7;
				reference4.MaxSH = a8;
				for (int k = num2; k < num3; k++)
				{
					ref float3 reference5 = ref positions[k];
					ref float3 reference6 = ref scales[k];
					ref float reference7 = ref alphas[k];
					ref SphericalHarmonicsL3<PixelRGB_Float> reference8 = ref span[k];
					reference5 = MathX.InverseLerp(in a, in a2, in reference5);
					reference6 = MathX.InverseLerp(in a3, in a4, in reference6);
					reference7 = MathX.InverseLerp(a5.w, a6.w, reference7);
					reference8.sh0.RGB = MathX.InverseLerp(a5.xyz, a6.xyz, reference8.sh0.RGB);
					for (int l = 1; l < reference8.CoefficientCount; l++)
					{
