		public static void ConvertFromChunked(GaussianCloud cloud, GaussianCloudChunk[] chunkData)
		{
			int num = ChunkCount(cloud.SplatCount);
			if (chunkData.Length < num)
			{
				throw new ArgumentException("Not enough chunk data for splats");
			}
			Parallel.For(0, num, delegate(int chunkIndex)
			{
				int num2 = MathX.Min(chunkIndex * 256, cloud.SplatCount);
				int num3 = MathX.Min(num2 + 256, cloud.SplatCount);
				GaussianCloudChunk gaussianCloudChunk = chunkData[chunkIndex];
				Span<float3> positions = cloud.Positions;
				Span<float3> scales = cloud.Scales;
				Span<float> alphas = cloud.Alphas;
				Span<SphericalHarmonicsL3<PixelRGB_Float>> span = cloud.ColorData<SphericalHarmonicsL3<PixelRGB_Float>>();
				for (int i = num2; i < num3; i++)
				{
					ref float3 reference = ref positions[i];
					ref float3 reference2 = ref scales[i];
					ref float reference3 = ref alphas[i];
					ref SphericalHarmonicsL3<PixelRGB_Float> reference4 = ref span[i];
					reference = MathX.LerpUnclamped(gaussianCloudChunk.MinPos, gaussianCloudChunk.MaxPos, in reference);
					reference2 = MathX.LerpUnclamped(gaussianCloudChunk.MinScale, gaussianCloudChunk.MaxScale, in reference2);
					reference3 = MathX.LerpUnclamped(gaussianCloudChunk.MinRGBA.w, gaussianCloudChunk.MaxRGBA.w, reference3);
					reference4.sh0.RGB = MathX.LerpUnclamped(gaussianCloudChunk.MinRGBA.xyz, gaussianCloudChunk.MaxRGBA.xyz, reference4.sh0.RGB);
					for (int j = 1; j < reference4.CoefficientCount; j++)
					{
						float3 lerp = reference4[j].RGB;
						reference4[j] = new PixelRGB_Float(MathX.LerpUnclamped(gaussianCloudChunk.MinSH, gaussianCloudChunk.MaxSH, in lerp));
					}
					reference2 = MathX.Pow(in reference2, 8f);
					reference3 = MathX.InvSquareCentered01(reference3);
				}
			});
		}

		public static color SH0ToColor(in float3 sh0, float alpha)
		{
			return new color(sh0 * 0.282095f + 0.5f, alpha);
		}

		public static int2 ComputeTextureWidth(int splatCount)
		{
			int num = 2048;
			int value = MathX.Max(1, (splatCount + num - 1) / num);
			value = MathX.AlignToNextMultiple(value, 16);
			return new int2(num, value);
		}

		public static int2 SplatIndexToTextureIndex(uint idx)
		{
			uint2 @uint = MathX.DecodeMorton2D_16x16(idx);
			uint num = 128u;
			idx >>= 8;
			uint x = idx % num * 16 + @uint.x;
			uint y = idx / num * 16 + @uint.y;
			return new int2((int)x, (int)y);
		}

		public static Bitmap2D PackColorsToTexture(GaussianCloud cloud)
