		public static byte[] ConvertBuffer(Span<float3> normalizedBuffer, GaussianVectorFormat format)
		{
			byte[] array = new byte[format.TotalBytes(normalizedBuffer.Length)];
			switch (format)
			{
			case GaussianVectorFormat.Float32:
				normalizedBuffer.CopyTo(MemoryMarshal.Cast<byte, float3>(array.AsSpan()));
