				break;
			}
			case GaussianVectorFormat.Norm11:
			{
				Span<uint> span2 = MemoryMarshal.Cast<byte, uint>(array.AsSpan());
				for (int l = 0; l < normalizedBuffer.Length; l++)
				{
					span2[l] = MathX.EncodeFloat3ToNorm11(MathX.Clamp01(in normalizedBuffer[l]));
