				for (int i = 0; i < normalizedBuffer.Length; i++)
				{
					span[i] = MathX.EncodeFloat3ToNorm655(MathX.Clamp01(in normalizedBuffer[i]));
				}
				break;
			}
			default:
				throw new ArgumentException("Invalid vector format: " + format);
			}
			return array;
		}

		public static byte[] EncodeRotationBuffer(Span<floatQ> rotations, GaussianRotationFormat format)
		{
			if (format != GaussianRotationFormat.PackedNorm10)
