		public unsafe static int TotalBytes(this GaussianVectorFormat format, int splatCount)
		{
			return format switch
			{
				GaussianVectorFormat.Float32 => sizeof(float3) * splatCount, 
				GaussianVectorFormat.Norm16 => 6 * splatCount, 
				GaussianVectorFormat.Norm11 => 4 * splatCount, 
				GaussianVectorFormat.Norm6 => 2 * splatCount, 
				_ => throw new ArgumentException("Unsupported format: " + format), 
			};
		}

		public static int TotalBytes(this GaussianRotationFormat format, int splatCount)
		{
			if (format == GaussianRotationFormat.PackedNorm10)
			{
				return 4 * splatCount;
			}
			throw new ArgumentException("Unsupported format: " + format);
		}

		public unsafe static int TotalBytes(this GaussianColorFormat format, int splatCount)
		{
			return format switch
			{
				GaussianColorFormat.Float32x4 => sizeof(float4) * splatCount, 
				GaussianColorFormat.Float16x4 => sizeof(half4) * splatCount, 
				GaussianColorFormat.Norm8x4 => 4 * splatCount, 
				GaussianColorFormat.BC7 => throw new ArgumentException("BC7 size needs to be determined through texture functions"), 
				_ => throw new ArgumentException("Unsupported format: " + format), 
			};
		}

		public unsafe static int TotalBytes(this GaussianSHFormat format, int splatCount)
		{
			switch (format)
			{
			case GaussianSHFormat.Float16:
				return sizeof(GaussianSH_TableHalf) * splatCount;
			case GaussianSHFormat.Norm11:
				return sizeof(GaussianSH_TableNorm11) * splatCount;
			case GaussianSHFormat.Norm6:
				return sizeof(GaussianSH_TableNorm6) * splatCount;
			case GaussianSHFormat.Cluster64k:
			case GaussianSHFormat.Cluster32k:
			case GaussianSHFormat.Cluster16k:
			case GaussianSHFormat.Cluster8k:
			case GaussianSHFormat.Cluster4k:
				return sizeof(GaussianSH_TableHalf) * GaussianSplatCompressor.GetSHCount(splatCount, format) + splatCount * 2;
			default:
				throw new ArgumentException("Unsupported format: " + format);
			}
		}

		public static bool UsesChunks(this GaussianVectorFormat format)
		{
			switch (format)
			{
			case GaussianVectorFormat.Float32:
				return false;
			case GaussianVectorFormat.Norm16:
			case GaussianVectorFormat.Norm11:
			case GaussianVectorFormat.Norm6:
				return true;
			default:
				throw new ArgumentException("Unsupported vector format: " + format);
			}
		}

		public static bool UsesChunks(this GaussianColorFormat format)
		{
			switch (format)
			{
			case GaussianColorFormat.Float32x4:
			case GaussianColorFormat.Float16x4:
			case GaussianColorFormat.BC7:
				return false;
			case GaussianColorFormat.Norm8x4:
				return true;
			default:
				throw new ArgumentException("Unsupported color format: " + format);
			}
		}

		public static bool UsesChunks(this GaussianSHFormat format)
		{
			if (format.IsClustered())
			{
				return false;
			}
			switch (format)
			{
			case GaussianSHFormat.Float16:
				return false;
			case GaussianSHFormat.Norm11:
			case GaussianSHFormat.Norm6:
				return true;
			default:
				throw new ArgumentException("Unsupported sh format: " + format);
			}
		}

		public static bool IsClustered(this GaussianSHFormat format)
		{
			if ((uint)(format - 3) <= 4u)
			{
				return true;
			}
			return false;
		}
