		public void IncreaseCount(int count)
		{
			if (count < 0)
			{
				throw new ArgumentOutOfRangeException("Count cannot be negative");
			}
			if (count < SplatCount)
			{
				throw new InvalidOperationException("Cannot decrease count of splats with this method. Use trim method instead");
			}
			if (count > Positions.Length)
			{
				IBackingMemoryBuffer positionsBuffer = PositionsBuffer;
				IBackingMemoryBuffer rotationsBuffer = RotationsBuffer;
				IBackingMemoryBuffer scalesBuffer = ScalesBuffer;
				IBackingMemoryBuffer alphasBuffer = AlphasBuffer;
				IBackingMemoryBuffer colorDataBuffer = ColorDataBuffer;
				Span<float3> positions = Positions;
				Span<floatQ> rotations = Rotations;
				Span<float3> scales = Scales;
				Span<float> alphas = Alphas;
				Span<byte> rawColorData = RawColorData;
				AllocateCount(count);
				positions.CopyTo(Positions);
				rotations.CopyTo(Rotations);
				scales.CopyTo(Scales);
				alphas.CopyTo(Alphas);
				rawColorData.CopyTo(RawColorData);
				positionsBuffer?.Dispose();
				rotationsBuffer?.Dispose();
				scalesBuffer?.Dispose();
				alphasBuffer?.Dispose();
				colorDataBuffer?.Dispose();
			}
			SplatCount = count;
		}

		public void TrimCount(int count)
