		public color GetBaseColor(int index)
		{
			int num = ColorDataType.BytesForGaussianColorData();
			Span<byte> span = RawColorData.Slice(num * index);
			Type type = ColorDataType.ColorType();
			if (!(type == typeof(PixelRGB_Float)))
