			color result = MemoryMarshal.Cast<byte, PixelRGB_Float>(span)[0].ToColor().MulRGB(0.282095f);
			float x = Alphas[index];
			x = MathX.Sigmoid(x);
			result.SetA(x);
			return result;
		}

