				break;
			case GaussianColorType.SH2_RGB_Float:
				ColorData<SphericalHarmonicsL2<PixelRGB_Float>>()[index] = new SphericalHarmonicsL2<PixelRGB_Float>(pixelRGB_Float, default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float));
				break;
			case GaussianColorType.SH3_RGB_Float:
				ColorData<SphericalHarmonicsL3<PixelRGB_Float>>()[index] = new SphericalHarmonicsL3<PixelRGB_Float>(pixelRGB_Float, default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float), default(PixelRGB_Float));
				break;
			}
		}

		public void SetSplatFrom(int targetIndex, GaussianCloud sourceCloud, int sourceIndex)
		{
			if (sourceCloud.ColorDataType != ColorDataType)
			{
				throw new ArgumentException("Source cloud format needs to match");
			}
			Positions[targetIndex] = sourceCloud.Positions[sourceIndex];
			Rotations[targetIndex] = sourceCloud.Rotations[sourceIndex];
			Scales[targetIndex] = sourceCloud.Scales[sourceIndex];
			Alphas[targetIndex] = sourceCloud.Alphas[sourceIndex];
			int start = targetIndex * _bytesPerColorElement;
			int start2 = sourceIndex * _bytesPerColorElement;
			sourceCloud.RawColorData.Slice(start2, _bytesPerColorElement).CopyTo(RawColorData.Slice(start, _bytesPerColorElement));
		}

		public void ClipWithBoundingBox(Elements.Core.BoundingBox bounds, IProgressIndicator progress = null)
		{
			RemoveGaussians((GaussianTransform t) => bounds.Contains(in t.position), progress);
		}

		public void ClipWithBoundingBox(Elements.Core.BoundingBox bounds, floatQ orientation, IProgressIndicator progress = null)
		{
			floatQ invOrientation = orientation.Inverted;
			Elements.Core.BoundingBox centeredBox = Elements.Core.BoundingBox.CenterSize(float3.Zero, bounds.Size);
			float3 offset = bounds.Center;
			RemoveGaussians(delegate(GaussianTransform t)
			{
				float3 a = t.position;
				a -= offset;
				a = invOrientation * a;
				return centeredBox.Contains(in a);
			}, progress);
		}

		public void ClipWithSphere(float3 center, float radius, IProgressIndicator progress = null)
		{
			RemoveGaussians((GaussianTransform t) => (t.position - center).Magnitude <= radius, progress);
		}

		public void ClipWithCylinder(float3 center, float radius, float height, floatQ orientation, IProgressIndicator progress = null)
		{
			floatQ invOrientation = orientation.Inverted;
			float halfHeight = height * 0.5f;
			RemoveGaussians(delegate(GaussianTransform t)
			{
				float3 a = t.position;
				a -= center;
				a = invOrientation * a;
				if (MathX.Abs(a.y) > halfHeight)
				{
					return false;
				}
				return !(a.xz.Magnitude > radius);
			}, progress);
		}

		public void RemoveGaussians(Predicate<GaussianTransform> filter, IProgressIndicator progress = null)
		{
			GaussianTransform obj = default(GaussianTransform);
			int num = ColorDataType.BytesForGaussianColorData();
			Span<float3> positions = Positions;
			Span<floatQ> rotations = Rotations;
			Span<float3> scales = Scales;
			Span<float> alphas = Alphas;
			Span<byte> rawColorData = RawColorData;
			for (int num2 = SplatCount - 1; num2 >= 0; num2--)
			{
				if (num2 % 10000 == 0 && progress != null)
				{
					int num3 = SplatCount - num2;
					float percent = (float)num3 / (float)SplatCount;
					progress.UpdateProgress(percent, "GaussianSplat.Processing.RemovingSplats".AsLocaleKey(), "GaussianSplat.Processing.SplatProgress".AsLocaleKey(("count", num3), ("total", SplatCount)));
				}
				obj.position = positions[num2];
				obj.rotation = rotations[num2];
				obj.scale = scales[num2];
				if (!filter(obj))
				{
					SplatCount--;
					positions[num2] = positions[SplatCount];
					rotations[num2] = rotations[SplatCount];
					scales[num2] = scales[SplatCount];
					alphas[num2] = alphas[SplatCount];
					int num4 = num2 * num;
					int num5 = SplatCount * num;
					for (int i = 0; i < num; i++)
					{
						rawColorData[num4 + i] = rawColorData[num5 + i];
					}
				}
			}
		}

		public override string ToString()
		{
			return $"GaussianCloud. Splats: {SplatCount}, ColorData: {ColorDataType}";
		}

		public void Dispose()
		{
			allocator = null;
			PositionsBuffer?.Dispose();
			RotationsBuffer?.Dispose();
			ScalesBuffer?.Dispose();
			AlphasBuffer?.Dispose();
			ColorDataBuffer?.Dispose();
			PositionsBuffer = null;
			RotationsBuffer = null;
			ScalesBuffer = null;
			AlphasBuffer = null;
			ColorDataBuffer = null;
		}

		public MeshX ToPointCloud()
		{
			MeshX meshX = new MeshX();
			meshX.Profile = ColorProfile.sRGB;
			meshX.HasColors = true;
			meshX.SetVertexCount(SplatCount);
			meshX.SetupAsPointCloud();
			Span<float3> positions = Positions;
			for (int i = 0; i < SplatCount; i++)
			{
				meshX.positions[i] = positions[i];
				meshX.colors[i] = GetBaseColor(i).ConvertProfile(ColorProfile.Linear, ColorProfile.sRGB);
			}
			return meshX;
		}

		public void ColorSplatsByIndex()
		{
			for (int i = 0; i < SplatCount; i++)
			{
				int rgb = MathX.LerpUnclamped(0, 16777216, (float)i / (float)SplatCount);
				PixelRGB24 pixel = new PixelRGB24((uint)rgb);
				SetSplatSolidColor(i, pixel.ToColor());
			}
		}

		private static float3 LogScaleToLinear(in float3 logScale)
		{
			return MathX.Abs(MathX.Exp(in logScale));
		}

		private static floatQ PLY_RotationToNormalized(in floatQ wxyz)
		{
			return ((floatQ)ILSpyHelper_AsRefReadOnly(wxyz.yzwx)).Normalized;
			static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
			{
				//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
				return ref temp;
			}
		}

		public static GaussianCloud LoadFromPLY(string file, IProgressIndicator progress = null)
		{
			using FileStream stream = File.OpenRead(file);
			return LoadFromPLY(stream, progress);
		}

		public static GaussianCloud LoadFromPLY(Stream stream, IProgressIndicator progress = null, IBackingBufferAllocator allocator = null)
		{
			progress?.UpdateProgress(0f, "Importer.Splat.Progress.Importing".AsLocaleKey(), "Importer.Splat.Progress.ReadingHeader".AsLocaleKey());
			PLY_GaussianLayout pLY_GaussianLayout = Read_PLY_Header(stream);
			if (pLY_GaussianLayout.vertexCount == 0 || pLY_GaussianLayout.vertexStride == 0)
			{
				throw new FileLoadException("Invalid PLY file");
			}
			if (pLY_GaussianLayout.vertexStride > 1024)
			{
				throw new NotSupportedException("Vertex stride cannot be larger than 1024");
			}
			GaussianCloud gaussianCloud = new GaussianCloud(pLY_GaussianLayout.vertexCount, GaussianColorType.SH3_RGB_Float, allocator);
			Span<float3> positions = gaussianCloud.Positions;
			Span<floatQ> rotations = gaussianCloud.Rotations;
			Span<float3> scales = gaussianCloud.Scales;
			Span<float> alphas = gaussianCloud.Alphas;
			Span<SphericalHarmonicsL3<PixelRGB_Float>> span = gaussianCloud.ColorData<SphericalHarmonicsL3<PixelRGB_Float>>();
			byte[] array = new byte[pLY_GaussianLayout.vertexStride];
			Span<float> buffer = MemoryMarshal.Cast<byte, float>(array.AsSpan());
			for (int i = 0; i < pLY_GaussianLayout.vertexCount; i++)
			{
				int num = array.Length;
				while (num > 0)
				{
					int num2 = stream.Read(array, array.Length - num, num);
					if (num2 <= 0)
					{
						throw new InvalidDataException("Unexpected end of file");
					}
					num -= num2;
				}
				float3 @float = Get<float3>(buffer, pLY_GaussianLayout.positionOffset);
				floatQ wxyz = Get<floatQ>(buffer, pLY_GaussianLayout.rotationOffset);
				float3 logScale = Get<float3>(buffer, pLY_GaussianLayout.scaleOffset);
				float x = buffer[pLY_GaussianLayout.opacityOffset];
				PLY_ColorSH3 pLY_ColorSH = Get<PLY_ColorSH3>(buffer, pLY_GaussianLayout.colorOffset);
				positions[i] = @float;
				rotations[i] = PLY_RotationToNormalized(in wxyz);
				scales[i] = LogScaleToLinear(in logScale);
				alphas[i] = MathX.Sigmoid(x);
				span[i] = pLY_ColorSH.SH;
				if (i % 10000 == 0)
				{
					float percent = (float)i / (float)pLY_GaussianLayout.vertexCount;
					progress?.UpdateProgress(percent, "Importer.Splat.Progress.Importing".AsLocaleKey(), "Importer.Splat.Progress.ConvertingSplats".AsLocaleKey(("converted", i), ("total", pLY_GaussianLayout.vertexCount)));
				}
			}
			return gaussianCloud;
			unsafe static T Get<T>(Span<float> span2, int offset) where T : unmanaged
			{
				return MemoryMarshal.Cast<float, T>(span2.Slice(offset, sizeof(T) / 4))[0];
			}
		}

		private static PLY_GaussianLayout Read_PLY_Header(Stream stream)
		{
			PLY_GaussianLayout result = default(PLY_GaussianLayout);
			List<string> list = new List<string>();
			for (int i = 0; i < 1000; i++)
			{
				string text = ReadLine();
				if (string.IsNullOrWhiteSpace(text) || text == "end_header")
				{
					break;
				}
				string[] array = text.Split(' ');
				if (array.Length != 3)
				{
					continue;
				}
				if (array[0] == "element" && array[1] == "vertex")
				{
					if (result.vertexCount > 0)
					{
						throw new FileLoadException("PLY header specifies vertex count more than once");
					}
					result.vertexCount = int.Parse(array[2]);
				}
				else if (array[0] == "property")
				{
					if (array[1] != "float")
					{
						throw new NotSupportedException("Only float properties are supported");
					}
					result.vertexStride += 4;
					list.Add(array[2]);
				}
				else if (!(array[0] == "format"))
				{
					throw new NotSupportedException($"Unexpected token at line {i} - {array[0]}");
				}
			}
			result.positionOffset = list.IndexOf("x");
			if (list[result.positionOffset + 1] != "y" || list[result.positionOffset + 2] != "z")
			{
				throw new NotSupportedException("Position data needs to be continuous");
			}
			result.rotationOffset = list.IndexOf("rot_0");
			if (list[result.rotationOffset + 1] != "rot_1" || list[result.rotationOffset + 2] != "rot_2" || list[result.rotationOffset + 3] != "rot_3")
			{
				throw new NotSupportedException("Rotation data needs to be continuous");
			}
			result.scaleOffset = list.IndexOf("scale_0");
			if (list[result.scaleOffset + 1] != "scale_1" || list[result.scaleOffset + 2] != "scale_2")
			{
				throw new NotSupportedException("Scale data needs to be continuous");
			}
			result.opacityOffset = list.IndexOf("opacity");
			result.colorOffset = list.IndexOf("f_dc_0");
			if (list[result.colorOffset + 1] != "f_dc_1" || list[result.colorOffset + 2] != "f_dc_2")
			{
				throw new NotSupportedException("Color data needs to be continuous");
			}
			for (int j = 0; j < 45; j++)
			{
				if (list[result.colorOffset + 3 + j] != $"f_rest_{j}")
				{
					throw new NotSupportedException("Color data needs to be continuous");
				}
			}
			if (!result.IsValid)
			{
				throw new NotSupportedException("PLY is missing expected data");
			}
			return result;
			unsafe string ReadLine()
			{
				Span<byte> span = stackalloc byte[256];
				int num = 0;
				while (true)
				{
					int num2 = stream.ReadByte();
					if (num2 == -1 || num2 == 10)
					{
						break;
					}
					span[num++] = (byte)num2;
					if (num >= span.Length)
					{
						throw new NotSupportedException($"PLY header line is longer than {span.Length} bytes");
					}
				}
				if (num > 0 && span[num - 1] == 13)
				{
					num--;
				}
				fixed (byte* bytes = span)
				{
					return System.Text.Encoding.UTF8.GetString(bytes, num);
				}
			}
		}

		private static float3 LinearScaleToLog(in float3 linearScale)
		{
			return MathX.Log(in linearScale);
		}

		private static floatQ EngineRotationToPLY(floatQ rot)
		{
			rot = new floatQ(rot.w, rot.x, rot.y, rot.z);
			return rot.Normalized;
		}

		public void WriteToPLY(string file, IProgressIndicator progress = null)
		{
			using FileStream stream = File.OpenWrite(file);
			WriteToPLY(stream, progress);
		}

		public unsafe void WriteToPLY(Stream stream, IProgressIndicator progress = null)
		{
			WritePLY_Header(stream);
			Span<float3> positions = Positions;
			Span<floatQ> rotations = Rotations;
			Span<float3> scales = Scales;
			Span<float> alphas = Alphas;
			Span<SphericalHarmonicsL3<PixelRGB_Float>> span = ColorData<SphericalHarmonicsL3<PixelRGB_Float>>();
			byte[] array = new byte[16384 * sizeof(PLY_Gaussian)];
			Span<PLY_Gaussian> span2 = MemoryMarshal.Cast<byte, PLY_Gaussian>(array.AsSpan());
			int num = SplatCount;
			int num2 = 0;
			while (num > 0)
			{
				int num3 = MathX.Min(num, 16384);
				for (int i = 0; i < num3; i++)
				{
					ref PLY_Gaussian reference = ref span2[i];
					reference.position = positions[num2];
					reference.rotation = EngineRotationToPLY(rotations[num2]);
					reference.scale = LinearScaleToLog(in scales[num2]);
					reference.opacity = MathX.SigmoidInv(alphas[num2]);
					reference.color.SH = span[num2];
					num2++;
				}
				stream.Write(array, 0, num3 * sizeof(PLY_Gaussian));
				float percent = (float)num2 / (float)SplatCount;
				progress?.UpdateProgress(percent, "Importer.Splat.Progress.Exporting".AsLocaleKey(), "Importer.Splat.Progress.ConvertingSplats".AsLocaleKey(("converted", num2), ("total", SplatCount)));
				num -= num3;
			}
		}

		private void WritePLY_Header(Stream stream)
		{
			StreamWriter streamWriter = new StreamWriter(stream, System.Text.Encoding.ASCII);
			streamWriter.WriteLine("ply");
			streamWriter.WriteLine("format binary_little_endian 1.0");
			streamWriter.WriteLine($"element vertex {SplatCount}");
			streamWriter.WriteLine("property float x\r\nproperty float y\r\nproperty float z\r\nproperty float nx\r\nproperty float ny\r\nproperty float nz\r\nproperty float f_dc_0\r\nproperty float f_dc_1\r\nproperty float f_dc_2\r\nproperty float f_rest_0\r\nproperty float f_rest_1\r\nproperty float f_rest_2\r\nproperty float f_rest_3\r\nproperty float f_rest_4\r\nproperty float f_rest_5\r\nproperty float f_rest_6\r\nproperty float f_rest_7\r\nproperty float f_rest_8\r\nproperty float f_rest_9\r\nproperty float f_rest_10\r\nproperty float f_rest_11\r\nproperty float f_rest_12\r\nproperty float f_rest_13\r\nproperty float f_rest_14\r\nproperty float f_rest_15\r\nproperty float f_rest_16\r\nproperty float f_rest_17\r\nproperty float f_rest_18\r\nproperty float f_rest_19\r\nproperty float f_rest_20\r\nproperty float f_rest_21\r\nproperty float f_rest_22\r\nproperty float f_rest_23\r\nproperty float f_rest_24\r\nproperty float f_rest_25\r\nproperty float f_rest_26\r\nproperty float f_rest_27\r\nproperty float f_rest_28\r\nproperty float f_rest_29\r\nproperty float f_rest_30\r\nproperty float f_rest_31\r\nproperty float f_rest_32\r\nproperty float f_rest_33\r\nproperty float f_rest_34\r\nproperty float f_rest_35\r\nproperty float f_rest_36\r\nproperty float f_rest_37\r\nproperty float f_rest_38\r\nproperty float f_rest_39\r\nproperty float f_rest_40\r\nproperty float f_rest_41\r\nproperty float f_rest_42\r\nproperty float f_rest_43\r\nproperty float f_rest_44\r\nproperty float opacity\r\nproperty float scale_0\r\nproperty float scale_1\r\nproperty float scale_2\r\nproperty float rot_0\r\nproperty float rot_1\r\nproperty float rot_2\r\nproperty float rot_3");
			streamWriter.Write("end_header");
			streamWriter.Flush();
		}

		public GaussianCloud(string file, IBackingBufferAllocator allocator = null)
		{
			this.allocator = allocator;
			using FileStream stream = File.OpenRead(file);
			DecodeAuto(stream);
		}

		public GaussianCloud(Stream stream, IBackingBufferAllocator allocator = null)
		{
			this.allocator = allocator;
			DecodeAuto(stream);
		}

		private void DecodeAuto(Stream stream)
		{
			try
			{
				if (CheckFrSplt(stream))
				{
					DecodeFrSplt(stream, skipMagicString: true);
					return;
				}
				if (CheckSPZ(stream))
				{
					DecodeSPZ(stream);
					return;
				}
				throw new NotSupportedException("Unsupported GaussianSplat stream");
			}
			catch
			{
				Dispose();
				throw;
			}
		}

		public void SaveToFile(string file, BinaryEncoding encoding = BinaryEncoding.LZ4, IProgressIndicator progress = null)
		{
			using FileStream stream = new FileStream(file, FileMode.Create, FileAccess.Write);
			Encode(stream, encoding, progress);
		}

		private void Encode(Stream stream, BinaryEncoding encoding = BinaryEncoding.LZ4, IProgressIndicator progress = null)
		{
			progress?.UpdateProgress(0f, "GaussianSplat.Encoding.Title".AsLocaleKey(), "GaussianSplat.Encoding.Metadata".AsLocaleKey());
			BinaryWriter binaryWriter = new BinaryWriter(stream);
			binaryWriter.Write("FrSplt");
			binaryWriter.Write(0);
			binaryWriter.Write7BitEncoded((ulong)SplatCount);
			binaryWriter.WriteEnumString(ColorDataType);
			binaryWriter.WriteEnumBinary(encoding);
			Stream stream2 = encoding switch
			{
				BinaryEncoding.Plain => stream, 
				BinaryEncoding.LZ4 => new LZ4Stream(stream, LZ4StreamMode.Compress, LZ4StreamFlags.HighCompression), 
				_ => throw new Exception("Invalid encoding"), 
			};
			binaryWriter = new BinaryWriter(stream2);
			Span<float3> positions = Positions;
			Span<floatQ> rotations = Rotations;
			Span<float3> scales = Scales;
			Span<float> alphas = Alphas;
			Span<byte> rawColorData = RawColorData;
			for (int i = 0; i < SplatCount; i++)
			{
				binaryWriter.Write(in positions[i]);
				UpdateProgress(0, i, "GaussianSplat.Encoding.EncodingPositions");
			}
			for (int j = 0; j < SplatCount; j++)
			{
				binaryWriter.Write(in rotations[j]);
				UpdateProgress(1, j, "GaussianSplat.Encoding.EncodingRotations");
			}
			for (int k = 0; k < SplatCount; k++)
			{
				binaryWriter.Write(in scales[k]);
				UpdateProgress(2, k, "GaussianSplat.Encoding.EncodingScales");
			}
			for (int l = 0; l < SplatCount; l++)
			{
				binaryWriter.Write(alphas[l]);
				UpdateProgress(3, l, "GaussianSplat.Encoding.EncodingAlphas");
			}
			int num = ColorDataType.BytesForGaussianColorData();
			int num2 = SplatCount * num;
			int num3 = 0;
			while (num3 < num2)
			{
				int num4 = MathX.Min(16384, num2 - num3);
				stream2.Write(rawColorData.Slice(num3, num4));
				num3 += num4;
				float num5 = (float)num3 / (float)num2;
				num5 *= 0.2f;
				num5 += 0.8f;
				progress?.UpdateProgress(num5, "GaussianSplat.Encoding.Title".AsLocaleKey(), "GaussianSplat.Encoding.EncodingColors".AsLocaleKey(("encoded", num3 / num), ("total", num2 / num)));
			}
			progress?.UpdateProgress(1f, "GaussianSplat.Encoding.Title".AsLocaleKey(), "GaussianSplat.Encoding.EncodingFinalizing".AsLocaleKey());
			switch (encoding)
			{
			case BinaryEncoding.LZ4:
				((LZ4Stream)stream2).Flush();
				break;
			default:
				throw new Exception("Invalid encoding");
			case BinaryEncoding.Plain:
				break;
			}
			void UpdateProgress(int phase, int num6, string submessage)
			{
				if (num6 % 10000 == 0)
				{
					float num7 = (float)num6 / (float)SplatCount;
					num7 *= 0.2f;
					num7 += (float)phase * 0.2f;
					progress?.UpdateProgress(num7, "GaussianSplat.Encoding.Title".AsLocaleKey(), submessage.AsLocaleKey(("encoded", num6), ("total", SplatCount)));
				}
			}
		}

		private bool CheckFrSplt(Stream stream)
		{
			long position = stream.Position;
			BinaryReader binaryReader = new BinaryReader(stream);
			bool flag = true;
			if (binaryReader.ReadByte() == "FrSplt".Length)
			{
				for (int i = 0; i < "FrSplt".Length; i++)
				{
					if (binaryReader.ReadChar() != "FrSplt"[i])
					{
						flag = false;
						break;
					}
				}
			}
			else
			{
				flag = false;
			}
			if (flag)
			{
				return true;
			}
			stream.Position = position;
			return false;
		}

		private void DecodeFrSplt(Stream stream, bool skipMagicString = false, IBackingBufferAllocator allocator = null)
		{
			UniLog.Log("Decoding FrSplt");
			UniLog.Flush();
			BinaryReader binaryReader = new BinaryReader(stream);
			if (!skipMagicString && binaryReader.ReadString() != "FrSplt")
			{
				throw new Exception("Invalid magic header");
			}
			if (binaryReader.ReadInt32() > 0)
			{
				throw new Exception("Binary version is higher than supported");
			}
			SplatCount = (int)binaryReader.Read7BitEncoded();
			ColorDataType = binaryReader.ReadEnumString<GaussianColorType>();
			OriginalEncoding = GaussianSplatEncoding.Lossless;
			AllocateCount(SplatCount);
			switch (binaryReader.ReadEnumBinary<BinaryEncoding>())
			{
			case BinaryEncoding.LZ4:
				binaryReader = new BinaryReader(new LZ4Stream(stream, LZ4StreamMode.Decompress));
				break;
			default:
				throw new Exception("Invalid encoding");
			case BinaryEncoding.Plain:
				break;
			}
			Span<float3> positions = Positions;
			Span<floatQ> rotations = Rotations;
			Span<float3> scales = Scales;
			Span<float> alphas = Alphas;
			Span<byte> rawColorData = RawColorData;
			for (int i = 0; i < SplatCount; i++)
			{
				positions[i] = binaryReader.Read3D_Single();
			}
			for (int j = 0; j < SplatCount; j++)
			{
				rotations[j] = binaryReader.ReadSingleQ();
			}
			for (int k = 0; k < SplatCount; k++)
			{
				scales[k] = binaryReader.Read3D_Single();
			}
			for (int l = 0; l < SplatCount; l++)
			{
				alphas[l] = binaryReader.ReadSingle();
			}
			binaryReader.BaseStream.ReadExactly(rawColorData);
		}

		private void DecodeSPZ(Stream stream, IProgressIndicator progress = null)
		{
			progress?.UpdateProgress(0f, "Importer.Splat.Progress.Importing".AsLocaleKey(), "Importer.Splat.Progress.ReadingHeader".AsLocaleKey());
