		}

		public unsafe void WriteToSPZ(Stream stream, IProgressIndicator progress = null)
		{
			int num = ColorDataType.ElementCount();
			Spz.NET.GaussianCloud gaussianCloud = new Spz.NET.GaussianCloud(SplatCount, num - 1);
			Span<float3> positions = Positions;
			Span<floatQ> rotations = Rotations;
			Span<float3> scales = Scales;
			Span<float> alphas = Alphas;
			Span<float> span = MemoryMarshal.Cast<byte, float>(RawColorData);
			int num2 = num * 3;
			Span<float> span2 = stackalloc float[sizeof(GaussianHarmonics) / 4];
			span2.Fill(0f);
			Span<GaussianHarmonics> span3 = MemoryMarshal.Cast<float, GaussianHarmonics>(span2);
			for (int i = 0; i < SplatCount; i++)
			{
				Span<float> span4 = span.Slice(i * num2, num2);
				for (int j = 3; j < num2; j++)
				{
					span2[j - 3] = span4[j];
				}
				gaussianCloud[i] = new Gaussian((Vector3)positions[i], (Vector3)LinearScaleToLog(in scales[i]), (System.Numerics.Quaternion)rotations[i], MathX.SigmoidInv(alphas[i]), new Vector3(span4[0], span4[1], span4[2]), in span3[0]);
				if (i % 32768 == 0)
				{
					float percent = (float)i / (float)SplatCount;
					progress?.UpdateProgress(percent, "Importer.Splat.Progress.EncodingData".AsLocaleKey(), "Importer.Splat.Progress.ConvertingSplats".AsLocaleKey(("converted", i), ("total", SplatCount)));
				}
			}
			progress?.UpdateProgress(1f, "Importer.Splat.Progress.EncodingData".AsLocaleKey(), "Importer.Splat.Progress.EncodingData".AsLocaleKey());
			gaussianCloud.ToSpz(stream);
		}
	}
