	public class LocaleData
	{
		[JsonPropertyName("localeCode")]
		public string LocaleCode { get; set; }

		[JsonPropertyName("authors")]
		public List<string> Authors { get; set; }

		[JsonPropertyName("messages")]
		public Dictionary<string, string> Messages { get; set; }
	}
	public class LocaleResource
	{
		public readonly struct Message
		{
			public readonly string localeCode;

			public readonly string messagePattern;

			public Message(string localeCode, string messagePattern)
			{
				this.localeCode = localeCode;
				this.messagePattern = messagePattern;
			}
		}

		private Dictionary<string, Message> _formatMessages = new Dictionary<string, Message>();

		private Dictionary<string, MessageFormatter> _formatters = new Dictionary<string, MessageFormatter>();

		private Dictionary<string, List<string>> _authors = new Dictionary<string, List<string>>();

		public int MessageCount => _formatMessages.Count;

		public DictionaryEnumerableWrapper<string, Message> Messages => _formatMessages;

		public IEnumerable<KeyValuePair<string, IReadOnlyList<string>>> Authors
		{
			get
			{
				foreach (KeyValuePair<string, List<string>> author in _authors)
				{
					yield return new KeyValuePair<string, IReadOnlyList<string>>(author.Key, author.Value);
				}
			}
		}

		public static string GetMainLanguage(string localeCode)
		{
			int num = localeCode.IndexOf("-");
			if (num < 0)
			{
				return localeCode;
			}
			return localeCode.Substring(0, num);
		}

		public int CountMessages(Predicate<string> filter)
		{
			return _formatMessages.Count<KeyValuePair<string, Message>>((KeyValuePair<string, Message> p) => filter(p.Key));
		}

		public string Format(string key, Dictionary<string, object> arguments)
		{
			if (_formatMessages.TryGetValue(key, out var value))
			{
				return _formatters[value.localeCode].FormatMessage(value.messagePattern, arguments, ignoreMissingVariables: true);
			}
			return null;
		}

		public string GetKeyLocaleCode(string key)
		{
			if (_formatMessages.TryGetValue(key, out var value))
			{
				return value.localeCode;
			}
			return null;
		}

		public bool HasKey(string key)
		{
			return _formatMessages.ContainsKey(key);
		}

		public string GetMessagePattern(string key)
		{
			return _formatMessages[key].messagePattern;
		}

		public async Task LoadAdditively(string file)
		{
			using FileStream stream = File.OpenRead(file);
			LoadDataAdditively(await System.Text.Json.JsonSerializer.DeserializeAsync<LocaleData>((Stream)stream, (JsonSerializerOptions?)null, default(CancellationToken)));
		}

		public void LoadDataAdditively(string json)
		{
			LocaleData data = System.Text.Json.JsonSerializer.Deserialize<LocaleData>(json);
			LoadDataAdditively(data);
		}

		public void LoadDataAdditively(LocaleData data)
		{
			if (!_formatters.ContainsKey(data.LocaleCode))
			{
				_formatters.Add(data.LocaleCode, new MessageFormatter(useCache: true, data.LocaleCode));
			}
			foreach (KeyValuePair<string, string> message in data.Messages)
			{
				if (!_formatMessages.ContainsKey(message.Key))
				{
					_formatMessages.Add(message.Key, new Message(data.LocaleCode, message.Value));
				}
			}
			foreach (string author in data.Authors)
			{
				if (!_authors.TryGetValue(author, out List<string> value))
				{
					value = new List<string>();
					_authors.Add(author, value);
				}
				value.Add(data.LocaleCode);
			}
		}
	}
	public enum TextureType
	{
		Albedo,
		Normal,
		Height,
		Emissive,
		Specular,
		Gloss,
		Roughness,
		AmbientOcclusion,
		UNKNOWN
	}
	public struct ClassifiedTexture
	{
		public readonly TextureType type;

		public readonly string file;
	}
	public static class MaterialHelper
	{
		public static TextureType DetermineTextureType(string filename)
		{
			filename = filename.ToLower();
			if (filename.Contains("diffuse") || filename.Contains("albedo"))
			{
				return TextureType.Albedo;
			}
			if (filename.Contains("normal") || filename.Contains("norm"))
			{
				return TextureType.Normal;
			}
			if (filename.Contains("gloss"))
			{
				return TextureType.Gloss;
			}
			if (filename.Contains("rough"))
			{
				return TextureType.Roughness;
			}
			if (filename.Contains("height"))
			{
				return TextureType.Height;
			}
			if (filename.Contains("emit") || filename.Contains("emiss") || filename.Contains("unlit"))
			{
				return TextureType.Emissive;
			}
			if (filename.Contains("ambient"))
			{
				return TextureType.AmbientOcclusion;
			}
			return TextureType.UNKNOWN;
		}
	}
	public static class MathHelper
	{
		public static void FitPlane(IList<float3> points, out float3 centroid, out float3 normal)
		{
			Vector3 v = new Vector3(points.Average((float3 p) => p.X), points.Average((float3 p) => p.Y), points.Average((float3 p) => p.Z));
			Matrix<double> matrix = Matrix<double>.Build.Dense(3, 3);
			foreach (float3 point in points)
			{
				Vector3 vector = (Vector3)point - v;
				matrix[0, 0] += vector.X * vector.X;
				matrix[0, 1] += vector.X * vector.Y;
				matrix[0, 2] += vector.X * vector.Z;
				matrix[1, 0] += vector.Y * vector.X;
				matrix[1, 1] += vector.Y * vector.Y;
				matrix[1, 2] += vector.Y * vector.Z;
				matrix[2, 0] += vector.Z * vector.X;
				matrix[2, 1] += vector.Z * vector.Y;
				matrix[2, 2] += vector.Z * vector.Z;
			}
			Evd<double> evd = matrix.Evd();
			MathNet.Numerics.LinearAlgebra.Vector<Complex> eigenValues = evd.EigenValues;
			Matrix<double> eigenVectors = evd.EigenVectors;
			int column = 0;
			double real = eigenValues[0].Real;
			for (int num = 1; num < 3; num++)
			{
				if (eigenValues[num].Real < real)
				{
					real = eigenValues[num].Real;
					column = num;
				}
			}
			Vector3 value = new Vector3((float)eigenVectors[0, column], (float)eigenVectors[1, column], (float)eigenVectors[2, column]);
			value = Vector3.Normalize(value);
			centroid = v;
			normal = value;
		}
	}
