					center = float3.Zero;
				}
			}
		}

		public static void ExtractTriangles(MeshX meshx, bool dualSided, BufferPool bufferPool, object bufferLock, Action meshDataExtracted, out Buffer<BepuPhysics.Collidables.Triangle> triangles)
		{
