				}
			}
			if (num >= 16777216)
			{
				meshDataExtracted?.Invoke();
				num = 1;
				bufferPool.Take(num, out triangles);
				triangles[0].A = Vector3.Zero;
				triangles[0].B = Vector3.Zero;
				triangles[0].C = Vector3.Zero;
				return;
			}
			lock (bufferLock)
			{
				bufferPool.Take(num, out triangles);
			}
			int num2 = 0;
			float3[] rawPositions = meshx.RawPositions;
			foreach (Submesh submesh2 in meshx.Submeshes)
			{
				if (!(submesh2 is TriangleSubmesh triangleSubmesh2))
				{
					if (submesh2 is PointSubmesh pointSubmesh2)
					{
						for (int i = 0; i < pointSubmesh2.Count; i++)
						{
							float3 a = rawPositions[pointSubmesh2.RawIndicies[i]];
							if (!a.IsValid())
							{
								a = float3.Zero;
							}
							ref BepuPhysics.Collidables.Triangle reference = ref triangles[num2++];
							reference.A = a + new float3(0f, 1E-06f);
							reference.B = a + new float3(-1E-06f, -1E-06f);
							reference.C = a + new float3(1E-06f, -1E-06f);
