				{
					triangleSubmesh2.GetIndiciesUnsafe(j, out var v, out var v2, out var v3);
					ref BepuPhysics.Collidables.Triangle reference2 = ref triangles[num2++];
					float3 v4 = rawPositions[v];
					float3 v5 = rawPositions[v2];
					float3 v6 = rawPositions[v3];
					if (!v4.IsValid() || !v5.IsValid() || !v6.IsValid())
					{
