				triangles[0].B = Vector3.Zero;
				triangles[0].C = Vector3.Zero;
			}
		}

		public static void ComputeMeshCollider(MeshX meshx, bool dualSided, BufferPool bufferPool, object bufferLock, Action meshDataExtracted, out BepuPhysics.Collidables.Mesh mesh)
		{
			bufferLock = bufferLock ?? new object();
			ExtractTriangles(meshx, dualSided, bufferPool, bufferLock, meshDataExtracted, out var triangles);
			lock (bufferLock)
			{
				mesh = new BepuPhysics.Collidables.Mesh(triangles, Vector3.Zero, bufferPool);
			}
		}

		public static void SerializeMeshCollider(ref BepuPhysics.Collidables.Mesh mesh, Stream stream)
		{
			SerializeTree(ref mesh.Tree, stream);
		}

		public static void SerializeTree(ref Tree tree, Stream stream)
		{
			BinaryWriter binaryWriter = new BinaryWriter(stream);
			binaryWriter.Write(tree.LeafCount);
			binaryWriter.Write(tree.NodeCount);
			for (int i = 0; i < tree.LeafCount; i++)
			{
				ref Leaf reference = ref tree.Leaves[i];
				binaryWriter.Write(reference.NodeIndex);
				binaryWriter.Write(reference.ChildIndex);
			}
			for (int j = 0; j < tree.NodeCount; j++)
			{
				ref BepuPhysics.Trees.Node reference2 = ref tree.Nodes[j];
				SerializeNodeChild(ref reference2.A, binaryWriter);
				SerializeNodeChild(ref reference2.B, binaryWriter);
			}
		}

		public static void DeserializeMeshCollider(MeshX meshx, bool dualSided, MeshCompression compression, Stream stream, BufferPool bufferPool, object bufferLock, Action meshDataExtracted, out BepuPhysics.Collidables.Mesh mesh)
		{
			Decode(compression, stream, delegate(Stream stream2, out BepuPhysics.Collidables.Mesh mesh2)
			{
				DeserializeMeshCollider(meshx, dualSided, stream2, bufferPool, bufferLock, meshDataExtracted, out mesh2);
			}, out mesh);
		}

		public static void DeserializeMeshCollider(MeshX meshx, bool dualSided, Stream stream, BufferPool bufferPool, object bufferLock, Action meshDataExtracted, out BepuPhysics.Collidables.Mesh mesh)
		{
			mesh = default(BepuPhysics.Collidables.Mesh);
			ExtractTriangles(meshx, dualSided, bufferPool, bufferLock, meshDataExtracted, out mesh.Triangles);
			DeserializeTree(stream, bufferPool, ref mesh.Tree);
		}

		public static void DeserializeTree(Stream stream, BufferPool bufferPool, ref Tree tree)
		{
			BinaryReader binaryReader = new BinaryReader(stream);
			int num = binaryReader.ReadInt32();
			int num2 = binaryReader.ReadInt32();
			bufferPool.Take(num, out tree.Leaves);
			bufferPool.Take(num2, out tree.Nodes);
			tree.LeafCount = num;
			tree.NodeCount = num2;
			for (int i = 0; i < num; i++)
			{
				tree.Leaves[i] = new Leaf(binaryReader.ReadInt32(), binaryReader.ReadInt32());
			}
			for (int j = 0; j < num2; j++)
			{
				ref BepuPhysics.Trees.Node reference = ref tree.Nodes[j];
				DeserializeNodeChild(ref reference.A, binaryReader);
				DeserializeNodeChild(ref reference.B, binaryReader);
			}
		}

		private static void SerializeNodeChild(ref NodeChild nodeChild, BinaryWriter writer)
		{
			writer.Write(nodeChild.Index);
			writer.Write(nodeChild.LeafCount);
			writer.Write((float3)nodeChild.Min);
			writer.Write((float3)nodeChild.Max);
		}

		private static void DeserializeNodeChild(ref NodeChild nodeChild, BinaryReader reader)
		{
			nodeChild.Index = reader.ReadInt32();
			nodeChild.LeafCount = reader.ReadInt32();
			nodeChild.Min = reader.Read3D_Single();
			nodeChild.Max = reader.Read3D_Single();
		}

