			for (int i = 0; i < convexHull.FaceVertexIndices.Length; i++)
			{
				ref HullVertexIndex reference = ref convexHull.FaceVertexIndices[i];
				int val = reference.BundleIndex * count + reference.InnerIndex;
				num = MathX.Max(num, val);
			}
			num++;
			int num2 = 0;
			for (int j = 0; j < convexHull.BoundingPlanes.Length; j++)
			{
				ref HullBoundingPlanes reference2 = ref convexHull.BoundingPlanes[j];
				for (int k = 0; k < count; k++)
				{
					Vector3Wide.ReadSlot(ref reference2.Normal, k, out var narrow);
					if (narrow != Vector3.Zero)
					{
