					}
				}
			}
			num2++;
			binaryWriter.Write(in center);
			binaryWriter.Write(num);
			binaryWriter.Write(num2);
			binaryWriter.Write(convexHull.FaceToVertexIndicesStart.Length);
			binaryWriter.Write(convexHull.FaceVertexIndices.Length);
			for (int l = 0; l < num; l++)
			{
				convexHull.GetPoint(l, out var point);
				binaryWriter.Write((float3)point);
			}
			for (int m = 0; m < convexHull.BoundingPlanes.Length; m++)
			{
				ref HullBoundingPlanes reference3 = ref convexHull.BoundingPlanes[m];
				for (int n = 0; n < count; n++)
				{
					Vector3Wide.ReadSlot(ref reference3.Normal, n, out var narrow2);
					float value = reference3.Offset[n];
					if (!(narrow2 == Vector3.Zero))
					{
						binaryWriter.Write((float3)narrow2);
						binaryWriter.Write(value);
					}
				}
			}
			for (int num3 = 0; num3 < convexHull.FaceToVertexIndicesStart.Length; num3++)
			{
