					{
						Vector3Wide.WriteSlot((Vector3)binaryReader.Read3D_Single(), k, ref reference.Normal);
						array[k] = binaryReader.ReadSingle();
						num3++;
					}
					else
					{
						Vector3Wide.WriteSlot(Vector3.Zero, k, ref reference.Normal);
						array[k] = float.MaxValue;
					}
				}
				reference.Offset = new System.Numerics.Vector<float>(array);
			}
			for (int l = 0; l < convexHull.FaceToVertexIndicesStart.Length; l++)
			{
				convexHull.FaceToVertexIndicesStart[l] = binaryReader.ReadInt32();
			}
			for (int m = 0; m < convexHull.FaceVertexIndices.Length; m++)
			{
				int num4 = binaryReader.ReadInt32();
				ref HullVertexIndex reference2 = ref convexHull.FaceVertexIndices[m];
				reference2.BundleIndex = (ushort)(num4 / elementsPerBundle);
				reference2.InnerIndex = (ushort)(num4 % elementsPerBundle);
			}
			convexHullData = new ConvexHullBepuData
			{
				convexHull = convexHull,
				center = center
			};
			int ComputeBundleCount(int elements)
			{
				return (elements + elementsPerBundle - 1) / elementsPerBundle;
			}
		}

		public static ConvexHull BuildEmptyConvexHull(BufferPool bufferPool)
		{
			Span<Vector3> points = stackalloc Vector3[3];
			points[0] = Vector3.Zero;
			points[1] = Vector3.Zero;
			points[2] = Vector3.Zero;
			Vector3 center;
			return new ConvexHull(points, bufferPool, out center);
		}

		public static bool IsValid(Span<Vector3> points)
		{
			for (int i = 0; i < points.Length; i++)
			{
				if (!IsValid(points[i]))
				{
					return false;
				}
			}
			return true;
		}

		public static bool IsValid(Buffer<Vector3> points)
		{
			for (int i = 0; i < points.Length; i++)
			{
				if (!IsValid(points[i]))
				{
					return false;
				}
			}
			return true;
		}

		public static bool IsValid(Vector3 v)
		{
			if (v.X.IsValid() && v.Y.IsValid())
			{
				return v.Z.IsValid();
			}
			return false;
		}

		private static void Decode<T>(MeshCompression compression, Stream stream, Decoder<T> decoder, out T decoded)
		{
			switch (compression)
			{
			case MeshCompression.None:
				decoder(stream, out decoded);
				break;
			case MeshCompression.LZ4:
			{
				using LZ4Stream stream2 = new LZ4Stream(stream, CompressionMode.Decompress, LZ4StreamFlags.HighCompression);
				decoder(stream2, out decoded);
				break;
			}
			case MeshCompression.LZMA:
			{
				using MemoryStream memoryStream = new MemoryStream();
				LZMAHelper.Decompress(stream, memoryStream);
				memoryStream.Seek(0L, SeekOrigin.Begin);
				decoder(memoryStream, out decoded);
				break;
			}
			default:
				throw new NotImplementedException("Unsupported compression: " + compression);
			}
		}
	}
	public class BlendShape
	{
		public readonly MeshX Mesh;

		public readonly string Name;

		private List<BlendShapeFrame> _frames = new List<BlendShapeFrame>();

		private bool _hasNormals;

		private bool _hasTangents;

		public int Index => Mesh.IndexOfBlendShape(this);

		public bool HasNormals
		{
			get
			{
				return _hasNormals;
			}
			set
			{
				_hasNormals = value;
				foreach (BlendShapeFrame frame in _frames)
				{
					Mesh.EnsureVertexArray(value, ref frame.normals);
				}
			}
		}

		public bool HasTangents
		{
			get
			{
				return _hasTangents;
			}
			set
			{
				_hasTangents = value;
				foreach (BlendShapeFrame frame in _frames)
				{
					Mesh.EnsureVertexArray(value, ref frame.tangents);
				}
			}
		}

		public int FrameCount => _frames.Count;

		public BlendShapeFrame this[int frame] => _frames[frame];

		public IEnumerable<BlendShapeFrame> Frames => _frames;

		public BlendShapeFrame AddFrame(float weight)
		{
			return InsertFrame(FrameCount, weight);
		}

		public BlendShapeFrame InsertFrame(int index, float weight)
		{
			BlendShapeFrame blendShapeFrame = new BlendShapeFrame(this, weight);
			_frames.Insert(index, blendShapeFrame);
			return blendShapeFrame;
		}

		public bool RemoveFrame(BlendShapeFrame frame)
		{
			return _frames.Remove(frame);
		}

		public void RemoveFrameAt(int index)
		{
			_frames.RemoveAt(index);
		}

		public void ClearFrames()
		{
			_frames.Clear();
		}

		public void NormalizeFrameWeights()
		{
			if (FrameCount == 0)
			{
				return;
			}
			if (FrameCount == 1)
			{
				_frames[0].Weight = 1f;
				return;
			}
			float num = 1f / (float)(FrameCount - 1);
			for (int i = 0; i < FrameCount; i++)
			{
				_frames[i].Weight = num * (float)i;
			}
		}

		internal BlendShape(MeshX mesh, string name)
		{
			Mesh = mesh;
			Name = name;
		}

		internal void EnsureCapacity(int capacity)
		{
			foreach (BlendShapeFrame frame in _frames)
			{
				Mesh.EnsureArray(state: true, ref frame.positions, capacity);
				Mesh.EnsureArray(HasNormals, ref frame.normals, capacity);
				Mesh.EnsureArray(HasTangents, ref frame.tangents, capacity);
			}
		}

		internal void RemoveElements(int index, int count)
		{
			foreach (BlendShapeFrame frame in _frames)
			{
				Mesh.RemoveElements(frame.positions, index, count, Mesh.VertexCount);
				Mesh.RemoveElements(frame.normals, index, count, Mesh.VertexCount);
				Mesh.RemoveElements(frame.tangents, index, count, Mesh.VertexCount);
			}
		}

		internal void Encode(BinaryWriter bw)
		{
			uint num = MeshX.EncodeFlags(HasNormals, HasTangents);
			bw.Write7BitEncoded(num);
			bw.Write7BitEncoded((ulong)FrameCount);
			foreach (BlendShapeFrame frame in _frames)
			{
				bw.Write(frame.Weight);
				for (int i = 0; i < Mesh.VertexCount; i++)
				{
					bw.Write(in frame.positions[i]);
				}
				if (HasNormals)
				{
					for (int j = 0; j < Mesh.VertexCount; j++)
					{
						bw.Write(in frame.normals[j]);
					}
				}
				if (HasTangents)
				{
					for (int k = 0; k < Mesh.VertexCount; k++)
					{
						bw.Write(in frame.tangents[k]);
					}
				}
			}
		}

		internal void Decode(BinaryReader br)
		{
			uint data = (uint)br.Read7BitEncoded();
			HasNormals = MeshX.ReadFlag(ref data);
			HasTangents = MeshX.ReadFlag(ref data);
			int num = (int)br.Read7BitEncoded();
			for (int i = 0; i < num; i++)
			{
				BlendShapeFrame blendShapeFrame = AddFrame(br.ReadSingle());
				for (int j = 0; j < Mesh.VertexCount; j++)
				{
					blendShapeFrame.positions[j] = br.Read3D_Single();
				}
				if (HasNormals)
				{
					for (int k = 0; k < Mesh.VertexCount; k++)
					{
						blendShapeFrame.normals[k] = br.Read3D_Single();
					}
				}
				if (HasTangents)
				{
					for (int l = 0; l < Mesh.VertexCount; l++)
					{
						blendShapeFrame.tangents[l] = br.Read3D_Single();
					}
				}
			}
		}

		public void RecalculateNormals()
		{
			HasNormals = true;
			foreach (BlendShapeFrame frame in Frames)
			{
				frame.RecalculateNormals();
			}
		}

		public void RecalculateNormalsMerged(double cellSize = 0.001)
		{
			HasNormals = true;
			foreach (BlendShapeFrame frame in Frames)
			{
				frame.RecalculateNormalsMerged(cellSize);
			}
		}

		public void RecalculateTangentsMikktspace(int uvChannel = 0)
		{
			HasTangents = true;
			foreach (BlendShapeFrame frame in Frames)
			{
				frame.RecalculateTangentsMikktspace(uvChannel);
			}
		}
	}
	public class BlendShapeFrame
	{
		public readonly BlendShape BlendShape;

		public float Weight;

		internal float3[] positions;

		internal float3[] normals;

		internal float3[] tangents;

		public MeshX Mesh => BlendShape.Mesh;

		public float3[] RawPositions => positions;

		public float3[] RawNormals => normals;

		public float3[] RawTangents => tangents;

		internal BlendShapeFrame(BlendShape shape, float weight)
		{
			BlendShape = shape;
			Weight = weight;
			Mesh.EnsureArray(state: true, ref positions, Mesh.VertexCapacity);
			if (shape.HasNormals)
			{
				Mesh.EnsureArray(state: true, ref normals, Mesh.VertexCapacity);
			}
			if (shape.HasTangents)
			{
				Mesh.EnsureArray(state: true, ref tangents, Mesh.VertexCapacity);
			}
		}

		public float3 GetPositionDelta(int index)
		{
			Mesh.VerifyVertexIndex(index);
			return positions[index];
		}

		public float3 GetNormalDelta(int index)
		{
			Mesh.VerifyVertexIndex(index);
			return normals[index];
		}

		public float3 GetTangentDelta(int index)
		{
			Mesh.VerifyVertexIndex(index);
			return tangents[index];
		}

		public void SetPositionDelta(int index, float3 delta)
		{
			Mesh.VerifyVertexIndex(index);
			positions[index] = delta;
		}

		public void SetNormalDelta(int index, float3 delta)
		{
			Mesh.VerifyVertexIndex(index);
			BlendShape.HasNormals = true;
			positions[index] = delta;
		}

		public void SetTangentDelta(int index, float3 delta)
		{
			Mesh.VerifyVertexIndex(index);
			BlendShape.HasTangents = true;
			tangents[index] = delta;
		}

		public void SetPositionDeltas(float3[] deltas, int? count = null, int sourceOffset = 0, int targetOffset = 0)
		{
			CopyArray(deltas, positions, count, sourceOffset, targetOffset);
		}

		public void SetNormalDeltas(float3[] deltas, int? count = null, int sourceOffset = 0, int targetOffset = 0)
		{
			BlendShape.HasNormals = true;
			CopyArray(deltas, normals, count, sourceOffset, targetOffset);
		}

		public void SetTangentDeltas(float3[] deltas, int? count = null, int sourceOffset = 0, int targetOffset = 0)
		{
			BlendShape.HasTangents = true;
			CopyArray(deltas, tangents, count, sourceOffset, targetOffset);
		}

		private void CopyArray(float3[] source, float3[] target, int? count, int sourceOffset, int targetOffset)
		{
			int length = count ?? MathX.Min(source.Length, Mesh.VertexCount);
			Array.Copy(source, sourceOffset, target, targetOffset, length);
		}

		public void CalculateDeltaNormalsFromFull()
		{
			float3[] rawNormals = Mesh.RawNormals;
			for (int i = 0; i < Mesh.VertexCount; i++)
			{
				normals[i] = normals[i].Normalized - rawNormals[i].Normalized;
			}
		}

		public void RecalculateNormals()
		{
			if (!BlendShape.HasNormals)
			{
				throw new InvalidOperationException("Blendshape doesn't have normals");
			}
			for (int i = 0; i < Mesh.VertexCount; i++)
			{
				normals[i] = float3.Zero;
			}
			float3[] rawPositions = Mesh.RawPositions;
			foreach (Triangle triangle in Mesh.Triangles)
			{
				int vertex0IndexUnsafe = triangle.Vertex0IndexUnsafe;
				int vertex1IndexUnsafe = triangle.Vertex1IndexUnsafe;
				int vertex2IndexUnsafe = triangle.Vertex2IndexUnsafe;
				if (MathX.TryComputeTriangleNormal(rawPositions[vertex0IndexUnsafe] + positions[vertex0IndexUnsafe], rawPositions[vertex1IndexUnsafe] + positions[vertex1IndexUnsafe], rawPositions[vertex2IndexUnsafe] + positions[vertex2IndexUnsafe], out var normal))
				{
					ref float3 reference = ref normals[vertex0IndexUnsafe];
					reference += normal;
					ref float3 reference2 = ref normals[vertex1IndexUnsafe];
					reference2 += normal;
					ref float3 reference3 = ref normals[vertex2IndexUnsafe];
					reference3 += normal;
				}
			}
			CalculateDeltaNormalsFromFull();
		}

		public void RecalculateNormalsMerged(double cellSize = 0.001)
		{
			if (!BlendShape.HasNormals)
			{
				throw new InvalidOperationException("Blendshape doesn't have normals");
			}
			float3[] basePositions = Mesh.RawPositions;
			float3[] baseNormals = Mesh.RawNormals;
			SmoothNormalsContext smoothNormals = new SmoothNormalsContext(cellSize);
			try
			{
				foreach (Triangle triangle in Mesh.Triangles)
				{
					int vertex0IndexUnsafe = triangle.Vertex0IndexUnsafe;
					int vertex1IndexUnsafe = triangle.Vertex1IndexUnsafe;
					int vertex2IndexUnsafe = triangle.Vertex2IndexUnsafe;
					float3 p = basePositions[vertex0IndexUnsafe] + positions[vertex0IndexUnsafe];
					float3 p2 = basePositions[vertex1IndexUnsafe] + positions[vertex1IndexUnsafe];
					float3 p3 = basePositions[vertex2IndexUnsafe] + positions[vertex2IndexUnsafe];
					if (MathX.TryComputeTriangleNormal(in p, in p2, in p3, out var normal))
					{
						smoothNormals.StoreNormal(in normal, in p);
						smoothNormals.StoreNormal(in normal, in p2);
						smoothNormals.StoreNormal(in normal, in p3);
					}
				}
				foreach (Triangle triangle2 in Mesh.Triangles)
				{
					int vertex0IndexUnsafe2 = triangle2.Vertex0IndexUnsafe;
					int vertex1IndexUnsafe2 = triangle2.Vertex1IndexUnsafe;
					int vertex2IndexUnsafe2 = triangle2.Vertex2IndexUnsafe;
					AssignNormal(vertex0IndexUnsafe2);
					AssignNormal(vertex1IndexUnsafe2);
					AssignNormal(vertex2IndexUnsafe2);
				}
			}
			finally
			{
				if (smoothNormals != null)
				{
					((IDisposable)smoothNormals).Dispose();
				}
			}
			CalculateDeltaNormalsFromFull();
			void AssignNormal(int index)
			{
				float3 position = basePositions[index] + positions[index];
				if (smoothNormals.TryGetNormal(in position, out var normal2))
				{
					normals[index] = normal2;
				}
				else
				{
					normals[index] = baseNormals[index];
				}
			}
		}

		public bool RecalculateTangentsMikktspace(int uvChannel = 0)
		{
			if (!BlendShape.HasTangents)
			{
				throw new InvalidOperationException("Blendshape doesn't have tangents");
			}
			if (!Mesh.HasNormals)
			{
				throw new InvalidOperationException("Mesh doesn't have normals");
			}
			float3[] basePositions = Mesh.RawPositions;
			float3[] baseNormals = Mesh.RawNormals;
			float2[] uvs = Mesh.GetRawUVs(uvChannel);
			float4[] baseTangents = Mesh.RawTangents;
			int totalFaceCount = Mesh.TotalFaceCount;
			VerticesPerFaceHandler getVerticesPerFace = (int face) => Mesh.GetSubmeshForFace(face)?.IndiciesPerElement ?? 0;
			VertexPositionHandler getPosition = delegate(int face, int vert, out float x, out float y, out float z)
			{
				int vertexIndexUnsafe = Mesh.GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
				float3 @float = basePositions[vertexIndexUnsafe] + positions[vertexIndexUnsafe];
				x = @float.x;
				y = @float.y;
				z = @float.z;
			};
			VertexNormalHandler getNormal = ((!BlendShape.HasNormals) ? ((VertexNormalHandler)delegate(int face, int vert, out float x, out float y, out float z)
			{
				int vertexIndexUnsafe = Mesh.GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
				float3 @float = baseNormals[vertexIndexUnsafe];
				x = @float.x;
				y = @float.y;
				z = @float.z;
			}) : ((VertexNormalHandler)delegate(int face, int vert, out float x, out float y, out float z)
			{
				int vertexIndexUnsafe = Mesh.GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
				float3 normalized = (baseNormals[vertexIndexUnsafe] + normals[vertexIndexUnsafe]).Normalized;
				x = normalized.x;
				y = normalized.y;
				z = normalized.z;
			}));
			VertexUVHandler getUV = delegate(int face, int vert, out float x, out float y)
			{
				int vertexIndexUnsafe = Mesh.GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
				float2 @float = uvs[vertexIndexUnsafe];
				x = @float.x;
				y = @float.y;
			};
			BasicTangentHandler setTangentBasic = delegate(int face, int vert, float x, float y, float z, float sign)
			{
				int vertexIndexUnsafe = Mesh.GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
				float3 @float = new float3(x, y, z);
				tangents[vertexIndexUnsafe] = @float.Normalized - baseTangents[vertexIndexUnsafe].xyz.Normalized;
			};
			return MikkGenerator.GenerateTangentSpace(totalFaceCount, getVerticesPerFace, getPosition, getNormal, getUV, setTangentBasic);
		}
	}
	public delegate int HoleVertexGetter(int holeIndex, int vertexIndex);
	public static class MeshX_Triangulation
	{
		public static void TriangulateConstrainedDelaunay(this TriangleSubmesh submesh, in float3 planeCenter, in float3 planeNormal, bool autoRejectDuplicateVertices = true, bool ignoreInvalidTriangles = false, List<int> rejectedVertices = null)
		{
			submesh.TriangulateConstrainedDelaunay(planeCenter, in planeNormal, submesh.Mesh.VertexCount, (int i) => i, 0, null, null, autoRejectDuplicateVertices, ignoreInvalidTriangles, rejectedVertices);
		}

		public static void TriangulateConstrainedDelaunay(this TriangleSubmesh submesh, in float3 planeCenter, in float3 planeNormal, IList<int> vertices, IList<IList<int>> holeVertices, bool autoRejectDuplicateVertices = true, bool ignoreInvalidTriangles = false, List<int> duplicateVertices = null)
		{
			submesh.TriangulateConstrainedDelaunay(planeCenter, in planeNormal, vertices.Count, (int i) => vertices[i], holeVertices?.Count ?? 0, (holeVertices == null) ? null : ((Func<int, int>)((int holeIndex) => holeVertices[holeIndex].Count)), (holeVertices == null) ? null : ((HoleVertexGetter)((int holeIndex, int vertexIndex) => holeVertices[holeIndex][vertexIndex])), autoRejectDuplicateVertices, ignoreInvalidTriangles, duplicateVertices);
		}

		public static void TriangulateConstrainedDelaunay(this TriangleSubmesh submesh, float3 planeCenter, in float3 planeNormal, int vertexCount, Func<int, int> getVertexIndex, int holeCount = 0, Func<int, int> holeVertexCountGetter = null, HoleVertexGetter holeVertexGetter = null, bool autoRejectDuplicateVertices = true, bool ignoreInvalidTriangles = false, List<int> duplicateVertices = null)
		{
			if (holeCount > 0)
			{
				if (holeVertexCountGetter == null)
				{
					throw new ArgumentNullException("holeVertexCountGetter");
				}
				if (holeVertexGetter == null)
				{
					throw new ArgumentNullException("holeVertexGetter");
				}
			}
			MeshX mesh = submesh.Mesh;
			floatQ planeAdjust = floatQ.FromToRotation(in planeNormal, float3.Up);
			Shape shape = BuildShape(vertexCount, getVertexIndex);
			if (shape.Points.Count < 3)
			{
				return;
			}
			if (holeCount > 0)
			{
				int holeIndex;
				for (holeIndex = 0; holeIndex < holeCount; holeIndex++)
				{
					Shape shape2 = BuildShape(holeVertexCountGetter(holeIndex), (int i) => holeVertexGetter(holeIndex, i));
					if (shape2.Points.Count >= 3)
					{
						shape.Holes.Add(shape2);
					}
				}
			}
			List<Elements.Assets.Poly2Tri.Triangle> list = new List<Elements.Assets.Poly2Tri.Triangle>();
			try
			{
				shape.Triangulate(list);
			}
			catch (Exception)
			{
				List<float3> list2 = new List<float3>();
				for (int num = 0; num < vertexCount; num++)
				{
					int index = getVertexIndex(num);
					list2.Add(mesh.GetVertex(index).PositionUnsafe);
				}
				UniLog.Warning("Triangulation failed. Source points: " + string.Join("\n", list2) + "\n\nAdjusted points:\n" + string.Join("\n", shape.Points));
				list.Clear();
			}
			foreach (Elements.Assets.Poly2Tri.Triangle item in list)
			{
				if (item.Points[0].Index < 0 || item.Points[1].Index < 0 || item.Points[2].Index < 0)
				{
					if (!ignoreInvalidTriangles)
					{
						throw new Exception("Failed triangulation! Got invalid triangle");
					}
				}
				else
				{
					submesh.AddTriangle(item.Points[0].Index, item.Points[1].Index, item.Points[2].Index);
				}
			}
			Shape BuildShape(int num2, Func<int, int> func)
			{
				Shape shape3 = new Shape();
				float2 b = float2.NaN;
				for (int i = 0; i < num2; i++)
				{
					int num3 = func(i);
					Vertex vertex = mesh.GetVertex(num3);
					float2 a = (planeAdjust * ILSpyHelper_AsRefReadOnly(vertex.PositionUnsafe - planeCenter)).xz;
					if (autoRejectDuplicateVertices && MathX.Approximately(in a, in b))
					{
						duplicateVertices?.Add(num3);
					}
					else
					{
						b = a;
						shape3.Points.Add(new TriPoint(a, num3));
					}
				}
				return shape3;
				static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
				{
					//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
					return ref temp;
				}
			}
		}
	}
	public class GeometryMask
	{
		private BitArray _vertexMask;

		private BitArray[] _primitiveMasks;

		private int[] _maskedPrimitiveCounts;

		private int[] _remappedIndexes;

		public MeshX Mesh { get; private set; }

		public int MaskedVertexCount { get; private set; }

		public bool AllVerticesMasked => MaskedVertexCount == Mesh.VertexCount;

		public bool ComputedRemappedIndexes { get; private set; }

		public GeometryMask(MeshX mesh)
		{
			Mesh = mesh;
			_vertexMask = new BitArray(Mesh.VertexCount);
		}

		public void MaskVertex(int vertexIndex)
		{
			if (!_vertexMask[vertexIndex])
			{
				_vertexMask[vertexIndex] = true;
				MaskedVertexCount++;
				ComputedRemappedIndexes = false;
			}
		}

		public void ClearVertex(int vertexIndex)
		{
			if (_vertexMask[vertexIndex])
			{
				_vertexMask[vertexIndex] = false;
				MaskedVertexCount--;
			}
		}

		public bool IsVertexMasked(int vertexIndex)
		{
			return _vertexMask[vertexIndex];
		}

		public int MaskedPrimitiveCount(int submeshIndex)
		{
			return _maskedPrimitiveCounts[submeshIndex];
		}

		public bool IsPrimitiveMasked(int submeshIndex, int indiceIndex)
		{
			return _primitiveMasks[submeshIndex][indiceIndex];
		}

		public void MaskPrimitive(int submeshIndex, int indiceIndex)
		{
			BitArray bitArray = _primitiveMasks[submeshIndex];
			if (!bitArray[indiceIndex])
			{
				bitArray[indiceIndex] = true;
				_maskedPrimitiveCounts[submeshIndex]++;
			}
		}

		public void ClearPrimitive(int submeshIndex, int indiceIndex)
		{
			BitArray bitArray = _primitiveMasks[submeshIndex];
			if (bitArray[indiceIndex])
			{
				bitArray[indiceIndex] = false;
				_maskedPrimitiveCounts[submeshIndex]--;
			}
		}

		public void InitializePrimitiveMasks()
		{
			if (_primitiveMasks != null)
			{
				throw new InvalidOperationException("Primitive masks were already initialized");
			}
			_primitiveMasks = new BitArray[Mesh.SubmeshCount];
			_maskedPrimitiveCounts = new int[Mesh.SubmeshCount];
			for (int i = 0; i < _primitiveMasks.Length; i++)
			{
				_primitiveMasks[i] = new BitArray(Mesh.submeshes[i].Count);
			}
		}

		public void EnsureRemappedVertexIndicies()
		{
			if (ComputedRemappedIndexes)
			{
				return;
			}
			if (_remappedIndexes == null)
			{
				_remappedIndexes = new int[Mesh.VertexCount];
			}
			int num = 0;
			for (int i = 0; i < _remappedIndexes.Length; i++)
			{
				if (!IsVertexMasked(i))
				{
					_remappedIndexes[i] = -1;
				}
				else
				{
					_remappedIndexes[i] = num++;
				}
			}
			ComputedRemappedIndexes = true;
		}

		public int GetNewVertexIndex(int vertexIndex)
		{
			return _remappedIndexes[vertexIndex];
		}

		public void MaskPrimitivesFromVertices()
		{
			if (_primitiveMasks == null)
			{
				InitializePrimitiveMasks();
			}
			for (int i = 0; i < Mesh.SubmeshCount; i++)
			{
				Submesh submesh = Mesh.submeshes[i];
				for (int j = 0; j < submesh.Count; j++)
				{
					int num = j * submesh.IndiciesPerElement;
					bool flag = false;
					for (int k = 0; k < submesh.IndiciesPerElement; k++)
					{
						if (_vertexMask[submesh.RawIndicies[num + k]])
						{
							flag = true;
							break;
						}
					}
					if (flag)
					{
						MaskPrimitive(i, j);
					}
				}
			}
		}

		public void MaskVerticesFromMaskedPrimitives()
		{
			for (int i = 0; i < Mesh.SubmeshCount; i++)
			{
				Submesh submesh = Mesh.submeshes[i];
				for (int j = 0; j < submesh.Count; j++)
				{
					if (IsPrimitiveMasked(i, j))
					{
						int num = j * submesh.IndiciesPerElement;
						for (int k = 0; k < submesh.IndiciesPerElement; k++)
						{
							int num2 = num + k;
							int vertexIndex = submesh.RawIndicies[num2];
							MaskVertex(vertexIndex);
						}
					}
				}
			}
		}

		public void ClearVerticesFromUnmarkedPrimitives()
		{
			for (int i = 0; i < Mesh.SubmeshCount; i++)
			{
				Submesh submesh = Mesh.submeshes[i];
				for (int j = 0; j < submesh.Count; j++)
				{
					if (!IsPrimitiveMasked(i, j))
					{
						int num = j * submesh.IndiciesPerElement;
						for (int k = 0; k < submesh.IndiciesPerElement; k++)
						{
							int num2 = num + k;
							int vertexIndex = submesh.RawIndicies[num2];
							ClearVertex(vertexIndex);
						}
					}
				}
			}
		}
	}
	public static class MeshBufferGenerator
	{
		public static void UpdateMeshBufferData(MeshX mesh, MeshBuffer data, IBackingBufferAllocator allocator, ColorProfile targetColorProfile, ref MeshUploadHint hint, MeshMetadata metadata = null, Elements.Core.BoundingBox? overrideBounds = null, object owner = null)
		{
			if (EnsureValidVertexAttributes(mesh, data, hint))
			{
				hint[MeshUploadHint.Flag.VertexLayout] = true;
				hint.SetVertexStreamsFromMesh(mesh);
			}
			else
			{
				hint[MeshUploadHint.Flag.VertexLayout] = false;
			}
			if (hint[MeshUploadHint.Flag.Geometry])
			{
				hint[MeshUploadHint.Flag.SubmeshLayout] = EnsureValidSubmeshes(mesh, data, metadata, overrideBounds);
			}
			else
			{
				hint[MeshUploadHint.Flag.SubmeshLayout] = false;
			}
			if (hint[MeshUploadHint.Flag.BoneWeights])
			{
				EnsureValidBoneLayout(mesh, data);
			}
			if (hint[MeshUploadHint.Flag.Blendshapes])
			{
				EnsureValidBlendshapeLayout(mesh, data);
			}
			data.ComputeBufferLayout();
			if ((data.Data?.SizeBytes ?? 0) < data.TotalBufferLength)
			{
				data.Data?.Dispose();
				data.Data = allocator.Allocate(data.TotalBufferLength, owner ?? data);
				hint.SetFromMesh(mesh);
			}
			FillVertexData(mesh, data, targetColorProfile, hint);
			if (hint[MeshUploadHint.Flag.Geometry])
			{
				FillIndexData(mesh, data);
			}
			if (hint[MeshUploadHint.Flag.BoneWeights])
			{
				FillBoneData(mesh, data);
			}
			if (hint[MeshUploadHint.Flag.Blendshapes])
			{
				FillBlendshapeData(mesh, data);
			}
		}

		public static bool EnsureValidVertexAttributes(MeshX mesh, MeshBuffer data, MeshUploadHint hint)
		{
			bool changed = false;
			if (data.VertexCount != mesh.VertexCount)
			{
				changed = true;
				data.VertexCount = mesh.VertexCount;
			}
			int attributeIndex = 0;
			bool flag = mesh.HasBoneBindings || mesh.HasBlendshapes;
			EnsureAttribute(VertexAttributeType.Position, VertexAttributeFormat.Float32, 3);
			if (mesh.HasNormals)
			{
				EnsureAttribute(VertexAttributeType.Normal, VertexAttributeFormat.Float32, 3);
			}
			if (mesh.HasTangents)
			{
				if (flag || hint[MeshUploadHint.Flag.Dynamic])
				{
					EnsureAttribute(VertexAttributeType.Tangent, VertexAttributeFormat.Float32, 4);
				}
				else
				{
					EnsureAttribute(VertexAttributeType.Tangent, VertexAttributeFormat.Half16, 4);
				}
			}
			if (mesh.HasColors)
			{
				if (hint[MeshUploadHint.Flag.Dynamic])
				{
					EnsureAttribute(VertexAttributeType.Color, VertexAttributeFormat.Float32, 4);
				}
				else
				{
					EnsureAttribute(VertexAttributeType.Color, VertexAttributeFormat.Half16, 4);
				}
			}
			for (int i = 0; i < 8; i++)
			{
				int uV_Dimension = mesh.GetUV_Dimension(i);
				if (uV_Dimension == 0)
				{
					break;
				}
				EnsureAttribute((VertexAttributeType)(4 + (short)i), VertexAttributeFormat.Float32, uV_Dimension);
			}
			if (data.VertexAttributes.Count > attributeIndex)
			{
				changed = true;
				data.VertexAttributes.EnsureExactCount(attributeIndex);
			}
			return changed;
			void EnsureAttribute(VertexAttributeType type, VertexAttributeFormat format, int dimensions)
			{
				VertexAttributeDescriptor vertexAttributeDescriptor = new VertexAttributeDescriptor(type, format, dimensions);
				if (data.VertexAttributes.Count == attributeIndex)
				{
					data.VertexAttributes.Add(new VertexAttributeDescriptor(type, format, dimensions));
					changed = true;
				}
				else if (vertexAttributeDescriptor != data.VertexAttributes[attributeIndex])
				{
					data.VertexAttributes[attributeIndex] = vertexAttributeDescriptor;
					changed = true;
				}
				attributeIndex++;
			}
		}

		public static bool EnsureValidSubmeshes(MeshX mesh, MeshBuffer data, MeshMetadata metadata, Elements.Core.BoundingBox? overrideBounds = null)
		{
			bool result = false;
			if (data.Submeshes.Count != mesh.SubmeshCount)
			{
				data.Submeshes.EnsureExactCount(mesh.SubmeshCount);
				result = true;
			}
			int num = 0;
			for (int i = 0; i < mesh.SubmeshCount; i++)
			{
				Submesh submesh = mesh.GetSubmesh(i);
				SubmeshBufferDescriptor submeshBufferDescriptor = new SubmeshBufferDescriptor
				{
					topology = submesh.Topology,
					indexStart = num,
					indexCount = submesh.IndicieCount
				};
				Elements.Core.BoundingBox boundingBox = ((metadata == null || metadata.SubmeshCount != mesh.SubmeshCount) ? (overrideBounds ?? submesh.CalculateBoundingBox()) : metadata.SubmeshMetadata[i].bounds);
				if (!boundingBox.IsValid)
				{
					boundingBox = new Elements.Core.BoundingBox(float3.Zero);
				}
				submeshBufferDescriptor.bounds = boundingBox;
				if (submeshBufferDescriptor != data.Submeshes[i])
				{
					result = true;
					data.Submeshes[i] = submeshBufferDescriptor;
				}
				num += submesh.IndicieCount;
			}
			if (num > 65535)
			{
				data.IndexBufferFormat = IndexBufferFormat.UInt32;
			}
			else
			{
				data.IndexBufferFormat = IndexBufferFormat.UInt16;
			}
			return result;
		}

		public static void EnsureValidBoneLayout(MeshX mesh, MeshBuffer data)
		{
			if (!mesh.HasBoneBindings)
			{
				data.BoneCount = 0;
				data.BoneWeightCount = 0;
				return;
			}
			data.BoneCount = mesh.BoneCount;
			int num = 0;
			for (int i = 0; i < mesh.VertexCount; i++)
			{
				num += mesh.RawBoneBindings[i].ActiveBoneCount;
			}
			data.BoneWeightCount = num;
		}

		public static bool EnsureValidBlendshapeLayout(MeshX mesh, MeshBuffer data)
		{
			bool changed = false;
			BlendshapeDataFlags blendshapeDataFlags = BlendshapeDataFlags.NONE;
			if (mesh.HasBlendshapes)
			{
				blendshapeDataFlags = BlendshapeDataFlags.Positions;
				if (mesh.HasBlendshapeNormals)
				{
					blendshapeDataFlags |= BlendshapeDataFlags.Normals;
				}
				if (mesh.HasBlendshapeTangents)
				{
					blendshapeDataFlags |= BlendshapeDataFlags.Tangets;
				}
			}
			int frameBufferIndex = 0;
			foreach (BlendShape blendShape in mesh.BlendShapes)
			{
				for (int i = 0; i < blendShape.FrameCount; i++)
				{
					RegisterBlendshapeFrame(blendShape[i], i);
				}
			}
			if (data.BlendshapeBuffers.Count > frameBufferIndex)
			{
				changed = true;
				data.BlendshapeBuffers.EnsureExactCount(frameBufferIndex);
			}
			return changed;
			void RegisterBlendshapeFrame(BlendShapeFrame frame, int frameIndex)
			{
				BlendshapeDataFlags blendshapeDataFlags2 = BlendshapeDataFlags.Positions;
				if (frame.BlendShape.HasNormals)
				{
					blendshapeDataFlags2 |= BlendshapeDataFlags.Normals;
				}
				if (frame.BlendShape.HasTangents)
				{
					blendshapeDataFlags2 |= BlendshapeDataFlags.Tangets;
				}
				BlendshapeBufferDescriptor blendshapeBufferDescriptor = new BlendshapeBufferDescriptor(blendshapeDataFlags2, frame.BlendShape.Index, frameIndex, frame.Weight);
				if (frameBufferIndex >= data.BlendshapeBuffers.Count)
				{
					data.BlendshapeBuffers.Add(blendshapeBufferDescriptor);
					changed = true;
				}
				else if (data.BlendshapeBuffers[frameBufferIndex] != blendshapeBufferDescriptor)
				{
					data.BlendshapeBuffers[frameBufferIndex] = blendshapeBufferDescriptor;
					changed = true;
				}
				frameBufferIndex++;
			}
		}

		public static void FillVertexData(MeshX mesh, MeshBuffer data, ColorProfile targetColorProfile, MeshUploadHint hint)
		{
			Parallel.For(0, data.VertexAttributes.Count, delegate(int a)
			{
				Span<byte> rawBuffer = data.RawBuffer;
				VertexAttributeDescriptor descriptor = data.VertexAttributes[a];
				int attributeOffset = data.VertexAttributeOffset(a);
				switch (descriptor.attribute)
				{
				case VertexAttributeType.Position:
					if (hint[MeshUploadHint.Flag.Positions])
					{
						FillPositions(descriptor, attributeOffset, mesh.RawPositions.AsSpan(0, data.VertexCount), data, rawBuffer);
					}
					break;
				case VertexAttributeType.Normal:
					if (hint[MeshUploadHint.Flag.Normals])
					{
						FillNormals(descriptor, attributeOffset, mesh.RawNormals.AsSpan(0, data.VertexCount), data, rawBuffer);
					}
					break;
				case VertexAttributeType.Tangent:
					if (hint[MeshUploadHint.Flag.Tangents])
					{
						FillTangents(descriptor, attributeOffset, mesh.RawTangents.AsSpan(0, data.VertexCount), data, rawBuffer);
					}
					break;
				case VertexAttributeType.Color:
					if (hint[MeshUploadHint.Flag.Colors])
					{
						FillColors(descriptor, attributeOffset, mesh.RawColors.AsSpan(0, data.VertexCount), mesh.Profile, targetColorProfile, data, rawBuffer);
					}
					break;
				case VertexAttributeType.UV0:
				case VertexAttributeType.UV1:
				case VertexAttributeType.UV2:
				case VertexAttributeType.UV3:
				case VertexAttributeType.UV4:
				case VertexAttributeType.UV5:
				case VertexAttributeType.UV6:
				case VertexAttributeType.UV7:
				{
					int uv = (int)(descriptor.attribute - 4);
					if (hint.GetUVChannel(uv))
					{
						int uV_Dimension = mesh.GetUV_Dimension(uv);
						switch (uV_Dimension)
						{
						case 2:
							FillUV2s(descriptor, attributeOffset, mesh.GetRawUVs(uv).AsSpan(0, data.VertexCount), data, rawBuffer);
							break;
						case 3:
							FillUV3s(descriptor, attributeOffset, mesh.GetRawUVs_3D(uv).AsSpan(0, data.VertexCount), data, rawBuffer);
							break;
						case 4:
							FillUV4s(descriptor, attributeOffset, mesh.GetRawUVs_4D(uv).AsSpan(0, data.VertexCount), data, rawBuffer);
							break;
						default:
							throw new NotSupportedException("Unsupported UV dimension: " + uV_Dimension);
						}
					}
					break;
				}
				case VertexAttributeType.BoneIndicies:
					if (hint[MeshUploadHint.Flag.BoneWeights])
					{
						FillBoneIndicies(descriptor, attributeOffset, mesh.RawBoneBindings.AsSpan(0, data.VertexCount), data, rawBuffer);
					}
					break;
				case VertexAttributeType.BoneWeights:
					if (hint[MeshUploadHint.Flag.BoneWeights])
					{
						FillBoneWeights(descriptor, attributeOffset, mesh.RawBoneBindings.AsSpan(0, data.VertexCount), data, rawBuffer);
					}
					break;
				}
			});
		}

		private static void FillPositions(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float3> positions, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 3)
			{
				throw new NotSupportedException("Positions buffer must have exactly 3 dimensions");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
				data.FillVertexAttributesRaw(buffer, positions, attributeOffset);
				break;
			case VertexAttributeFormat.Half16:
			{
				for (int i = 0; i < positions.Length; i++)
				{
					data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, (half3)positions[i]);
				}
				break;
			}
			default:
				throw new NotSupportedException("Unsupported format for position buffer: " + descriptor.format);
			}
		}

		private static float2 EncodeNormalToTwoComponent(float3 n)
		{
			return MathX.EncodeNormalOctahedron(n);
		}

		private static void FillNormals(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float3> normals, MeshBuffer data, Span<byte> buffer)
		{
			switch (descriptor.dimensions)
			{
			case 2:
				switch (descriptor.format)
				{
				case VertexAttributeFormat.Float32:
				{
					for (int k = 0; k < normals.Length; k++)
					{
						data.SetVertexAttributeAtOffset(buffer, k, attributeOffset, EncodeNormalToTwoComponent(normals[k]));
					}
					break;
				}
				case VertexAttributeFormat.Half16:
				{
					for (int j = 0; j < normals.Length; j++)
					{
						data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, (half2)EncodeNormalToTwoComponent(normals[j]));
					}
					break;
				}
				default:
					throw new NotSupportedException("Unsupported format for normals buffer: " + descriptor.format);
				}
				break;
			case 3:
				switch (descriptor.format)
				{
				case VertexAttributeFormat.Float32:
					data.FillVertexAttributesRaw(buffer, normals, attributeOffset);
					break;
				case VertexAttributeFormat.Half16:
				{
					for (int i = 0; i < normals.Length; i++)
					{
						data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, (half3)normals[i]);
					}
					break;
				}
				default:
					throw new NotSupportedException("Unsupported format for normals buffer: " + descriptor.format);
				}
				break;
			default:
				throw new NotSupportedException("Unsupported number of dimensions for normals buffer: " + descriptor.dimensions);
			}
		}

		private static void FillTangents(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float4> tangents, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 4)
			{
				throw new NotSupportedException("Tangents buffer must have exactly 4 dimensions");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
				data.FillVertexAttributesRaw(buffer, tangents, attributeOffset);
				break;
			case VertexAttributeFormat.Half16:
			{
				for (int j = 0; j < tangents.Length; j++)
				{
					data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, (half4)tangents[j]);
				}
				break;
			}
			case VertexAttributeFormat.UNorm8:
			{
				for (int i = 0; i < tangents.Length; i++)
				{
					float4 @float = tangents[i];
					data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, new byte4(ToUNorm8(@float.x.Pack()), ToUNorm8(@float.y.Pack()), ToUNorm8(@float.z.Pack()), (byte)((!(@float.w >= 0f)) ? 255u : 0u)));
				}
				break;
			}
			default:
				throw new NotSupportedException("Unsupported format for position buffer: " + descriptor.format);
			}
		}

		private static void FillColors(VertexAttributeDescriptor descriptor, int attributeOffset, Span<color> colors, ColorProfile sourceColorProfile, ColorProfile targetColorProfile, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 4)
			{
				throw new NotSupportedException("Colors buffer must have exactly 4 dimensions");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
			{
				if (sourceColorProfile == targetColorProfile)
				{
					data.FillVertexAttributesRaw(buffer, colors, attributeOffset);
					break;
				}
				for (int j = 0; j < colors.Length; j++)
				{
					data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, colors[j].ConvertProfile(sourceColorProfile, targetColorProfile));
				}
				break;
			}
			case VertexAttributeFormat.Half16:
			{
				for (int k = 0; k < colors.Length; k++)
				{
					data.SetVertexAttributeAtOffset(buffer, k, attributeOffset, (half4)ILSpyHelper_AsRefReadOnly((float4)colors[k].ConvertProfile(sourceColorProfile, targetColorProfile)));
				}
				break;
			}
			case VertexAttributeFormat.UNorm8:
			{
				for (int i = 0; i < colors.Length; i++)
				{
					data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, (color32)colors[i].ConvertProfile(sourceColorProfile, targetColorProfile));
				}
				break;
			}
			default:
				throw new NotSupportedException("Unsupported format for position buffer: " + descriptor.format);
			}
			static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
			{
				//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
				return ref temp;
			}
		}

		private static void FillUV2s(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float2> uvs, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 2)
			{
				throw new NotSupportedException($"UV's dimensions mismatch. Expected: 2, got: {descriptor.dimensions}");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
				data.FillVertexAttributesRaw(buffer, uvs, attributeOffset);
				break;
			case VertexAttributeFormat.Half16:
			{
				for (int j = 0; j < uvs.Length; j++)
				{
					data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, (half2)uvs[j]);
				}
				break;
			}
			case VertexAttributeFormat.UNorm8:
			{
				for (int k = 0; k < uvs.Length; k++)
				{
					data.SetVertexAttributeAtOffset(buffer, k, attributeOffset, ToUNorm8(in uvs[k]));
				}
				break;
			}
			case VertexAttributeFormat.UNorm16:
			{
				for (int i = 0; i < uvs.Length; i++)
				{
					data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, ToUNorm16(in uvs[i]));
				}
				break;
			}
			default:
				throw new NotSupportedException("Unsupported format for position buffer: " + descriptor.format);
			}
		}

		private static void FillUV3s(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float3> uvs, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 3)
			{
				throw new NotSupportedException($"UV's dimensions mismatch. Expected: 3, got: {descriptor.dimensions}");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
				data.FillVertexAttributesRaw(buffer, uvs, attributeOffset);
				break;
			case VertexAttributeFormat.Half16:
			{
				for (int j = 0; j < uvs.Length; j++)
				{
					data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, (half3)uvs[j]);
				}
				break;
			}
			case VertexAttributeFormat.UNorm8:
			{
				for (int k = 0; k < uvs.Length; k++)
				{
					data.SetVertexAttributeAtOffset(buffer, k, attributeOffset, ToUNorm8(in uvs[k]));
				}
				break;
			}
			case VertexAttributeFormat.UNorm16:
			{
				for (int i = 0; i < uvs.Length; i++)
				{
					data.SetVertexAttributeAtOffset(buffer, i, attributeOffset, ToUNorm16(in uvs[i]));
				}
				break;
			}
			default:
				throw new NotSupportedException("Unsupported format for position buffer: " + descriptor.format);
			}
		}

		private static void FillUV4s(VertexAttributeDescriptor descriptor, int attributeOffset, Span<float4> uvs, MeshBuffer data, Span<byte> buffer)
		{
			if (descriptor.dimensions != 3)
			{
				throw new NotSupportedException($"UV's dimensions mismatch. Expected: 4, got: {descriptor.dimensions}");
			}
			switch (descriptor.format)
			{
			case VertexAttributeFormat.Float32:
				data.FillVertexAttributesRaw(buffer, uvs, attributeOffset);
				break;
			case VertexAttributeFormat.Half16:
			{
				for (int j = 0; j < uvs.Length; j++)
				{
					data.SetVertexAttributeAtOffset(buffer, j, attributeOffset, (half4)uvs[j]);
				}
				break;
			}
			case VertexAttributeFormat.UNorm8:
			{
				for (int k = 0; k < uvs.Length; k++)
				{
					data.SetVertexAttributeAtOffset(buffer, k, attributeOffset, ToUNorm8(in uvs[k]));
				}
				break;
			}
			case VertexAttributeFormat.UNorm16:
			{
