		public static void FillIndexData(MeshX mesh, MeshBuffer data)
		{
			int num = 0;
			for (int i = 0; i < data.Submeshes.Count; i++)
			{
				_ = data.Submeshes[i];
				Submesh submesh = mesh.GetSubmesh(i);
				Span<uint> span = MemoryMarshal.Cast<int, uint>(submesh.RawIndicies.AsSpan(0, submesh.IndicieCount));
				switch (data.IndexBufferFormat)
				{
				case IndexBufferFormat.UInt16:
				{
					Span<ushort> span2 = data.GetIndexBufferUInt16().Slice(num);
					for (int j = 0; j < span.Length; j++)
					{
						span2[j] = (ushort)span[j];
					}
					break;
				}
				case IndexBufferFormat.UInt32:
				{
					Span<uint> destination = data.GetIndexBufferUInt32().Slice(num);
					span.CopyTo(destination);
					break;
				}
				}
				num += submesh.IndicieCount;
			}
		}

		public static void FillBoneData(MeshX mesh, MeshBuffer data)
		{
			if (data.BoneCount == 0)
			{
				return;
			}
			Span<byte> boneCountsBuffer = data.GetBoneCountsBuffer();
			Span<BoneWeight> boneWeightsBuffer = data.GetBoneWeightsBuffer();
			int num = 0;
			for (int i = 0; i < mesh.VertexCount; i++)
			{
				BoneBinding boneBinding = mesh.RawBoneBindings[i];
				boneCountsBuffer[i] = (byte)boneBinding.ActiveBoneCount;
				for (int j = 0; j < boneCountsBuffer[i]; j++)
				{
					boneWeightsBuffer[num++] = boneBinding[j];
				}
			}
			Span<float4x4> bindPosesBuffer = data.GetBindPosesBuffer();
			for (int k = 0; k < data.BoneCount; k++)
			{
				Bone bone = mesh.GetBone(k);
				bindPosesBuffer[k] = bone.BindPose.Transposed;
			}
		}

		public static void FillBlendshapeData(MeshX mesh, MeshBuffer data)
		{
			if (data.BlendshapeBuffers.Count == 0)
			{
				return;
			}
			Span<float3> destination = data.GetBlendshapeBuffer<float3>();
			foreach (BlendshapeBufferDescriptor blendshapeBuffer in data.BlendshapeBuffers)
			{
				BlendShapeFrame blendShapeFrame = mesh.GetBlendShape(blendshapeBuffer.blendshapeIndex)[blendshapeBuffer.frameIndex];
				if (blendshapeBuffer.dataFlags.HasFlag(BlendshapeDataFlags.Positions))
				{
					blendShapeFrame.RawPositions.AsSpan(0, mesh.VertexCount).CopyTo(destination);
					destination = destination.Slice(mesh.VertexCount);
				}
				if (blendshapeBuffer.dataFlags.HasFlag(BlendshapeDataFlags.Normals))
				{
					blendShapeFrame.RawNormals.AsSpan(0, mesh.VertexCount).CopyTo(destination);
					destination = destination.Slice(mesh.VertexCount);
				}
				if (blendshapeBuffer.dataFlags.HasFlag(BlendshapeDataFlags.Tangets))
				{
					blendShapeFrame.RawTangents.AsSpan(0, mesh.VertexCount).CopyTo(destination);
					destination = destination.Slice(mesh.VertexCount);
				}
			}
		}

		private static byte2 ToUNorm8(in float2 value)
		{
			return new byte2(ToUNorm8(value.x), ToUNorm8(value.y));
		}

		private static byte3 ToUNorm8(in float3 value)
		{
			return new byte3(ToUNorm8(value.x), ToUNorm8(value.y), ToUNorm8(value.z));
		}

		private static byte4 ToUNorm8(in float4 value)
		{
			return new byte4(ToUNorm8(value.x), ToUNorm8(value.y), ToUNorm8(value.z), ToUNorm8(value.w));
		}

		private static ushort2 ToUNorm16(in float2 value)
		{
			return new ushort2(ToUNorm16(value.x), ToUNorm16(value.y));
		}

		private static ushort3 ToUNorm16(in float3 value)
		{
			return new ushort3(ToUNorm16(value.x), ToUNorm16(value.y), ToUNorm16(value.z));
		}

		private static ushort4 ToUNorm16(in float4 value)
		{
			return new ushort4(ToUNorm16(value.x), ToUNorm16(value.y), ToUNorm16(value.z), ToUNorm16(value.w));
		}

		private static byte ToUNorm8(float value)
		{
			value *= 255f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 255f)
			{
				return byte.MaxValue;
			}
			return (byte)value;
		}

		private static ushort ToUNorm16(float value)
		{
			value *= 65535f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 65535f)
			{
				return ushort.MaxValue;
			}
			return (ushort)value;
		}

		private static uint ToUNorm32(float value)
		{
			value *= 4.2949673E+09f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0u;
			}
			if (value >= 4.2949673E+09f)
			{
				return uint.MaxValue;
			}
			return (uint)value;
		}
	}
