	public static class MeshUploadHintHelper
	{
		public static void SetVertexStreamsFromMesh(this ref MeshUploadHint hint, MeshX mesh)
		{
			hint[MeshUploadHint.Flag.Positions] = true;
			hint[MeshUploadHint.Flag.Normals] = mesh.HasNormals;
			hint[MeshUploadHint.Flag.Tangents] = mesh.HasTangents;
			hint[MeshUploadHint.Flag.Colors] = mesh.HasColors;
			for (int i = 0; i < 8; i++)
			{
				hint[MeshUploadHint.GetUVFlag(i)] = mesh.GetUV_Dimension(i) > 0;
			}
		}

		public static void SetFromMesh(this ref MeshUploadHint hint, MeshX mesh)
		{
			hint[MeshUploadHint.Flag.Geometry] = true;
			hint.SetVertexStreamsFromMesh(mesh);
			hint[MeshUploadHint.Flag.Blendshapes] = mesh.HasBlendshapes;
			hint[MeshUploadHint.Flag.BindPoses] = mesh.BoneCount > 0;
			hint[MeshUploadHint.Flag.BoneWeights] = mesh.HasBoneBindings;
		}

		public static void ResetUnusedChannels(this ref MeshUploadHint hint, MeshX mesh)
		{
			hint[MeshUploadHint.Flag.Normals] &= mesh.HasNormals;
			hint[MeshUploadHint.Flag.Tangents] &= mesh.HasTangents;
			hint[MeshUploadHint.Flag.Colors] &= mesh.HasColors;
			for (int i = 0; i < 8; i++)
			{
				hint[MeshUploadHint.GetUVFlag(i)] &= mesh.GetUV_Dimension(i) > 0;
			}
			hint[MeshUploadHint.Flag.Blendshapes] &= mesh.HasBlendshapes;
			hint[MeshUploadHint.Flag.BindPoses] &= mesh.BoneCount > 0;
			hint[MeshUploadHint.Flag.BoneWeights] &= mesh.HasBoneBindings;
		}
	}
