	public struct BoneBinding
	{
		public int boneIndex0;

		public int boneIndex1;

		public int boneIndex2;

		public int boneIndex3;

		public float weight0;

		public float weight1;

		public float weight2;

		public float weight3;

		public static BoneBinding Empty => new BoneBinding
		{
			boneIndex0 = -1,
			boneIndex1 = -1,
			boneIndex2 = -1,
			boneIndex3 = -1,
			weight0 = 0f,
			weight1 = 0f,
			weight2 = 0f,
			weight3 = 0f
		};

		public float TotalWeight => weight0 + weight1 + weight2 + weight3;

		public BoneWeight this[int index]
		{
			get
			{
				return index switch
				{
					0 => new BoneWeight(weight0, boneIndex0), 
					1 => new BoneWeight(weight1, boneIndex1), 
					2 => new BoneWeight(weight2, boneIndex2), 
					3 => new BoneWeight(weight3, boneIndex3), 
					_ => throw new ArgumentOutOfRangeException("index"), 
				};
			}
			set
			{
				switch (index)
				{
				case 0:
					weight0 = value.weight;
					boneIndex0 = value.boneIndex;
					break;
				case 1:
					weight1 = value.weight;
					boneIndex1 = value.boneIndex;
					break;
				case 2:
					weight2 = value.weight;
					boneIndex2 = value.boneIndex;
					break;
				case 3:
					weight3 = value.weight;
					boneIndex3 = value.boneIndex;
					break;
				}
			}
		}

		public int ActiveBoneCount
		{
			get
			{
				int num = 0;
				if (weight0 >= 0f)
				{
					num++;
				}
				if (weight1 >= 0f)
				{
					num++;
				}
				if (weight2 >= 0f)
				{
					num++;
				}
				if (weight3 >= 0f)
				{
					num++;
				}
				return num;
			}
		}

		public int4 PackedIndicies => new int4(boneIndex0, boneIndex1, boneIndex2, boneIndex3);

		public float4 PackedWeights => new float4(weight0, weight1, weight2, weight3);

		public int GetBoneIndex(int index)
		{
			return index switch
			{
				0 => boneIndex0, 
				1 => boneIndex1, 
				2 => boneIndex2, 
				3 => boneIndex3, 
				_ => throw new ArgumentOutOfRangeException("index"), 
			};
		}

		public void SetBoneIndex(int index, int boneIndex)
		{
			switch (index)
			{
			case 0:
				boneIndex0 = boneIndex;
				break;
			case 1:
				boneIndex1 = boneIndex;
				break;
			case 2:
				boneIndex2 = boneIndex;
				break;
			case 3:
				boneIndex3 = boneIndex;
				break;
			default:
				throw new ArgumentOutOfRangeException("index");
			}
		}

		public int AddBone(Bone bone, float weight)
		{
			return AddBone(bone.Index, weight);
		}

		public int AddBone(int index, float weight)
		{
			int num = -1;
			float num2 = float.MaxValue;
			for (int i = 0; i < 4; i++)
			{
				float weight2 = GetWeight(i);
				if (weight2 < num2)
				{
					num2 = weight2;
					num = i;
				}
			}
			if (weight > num2)
			{
				SetBinding(num, index, weight);
				return num;
			}
			return -1;
		}

		public void Sort()
		{
			bool flag;
			do
			{
				flag = false;
				for (int i = 0; i < 3; i++)
				{
					GetBinding(i, out var boneIndex, out var weight);
					GetBinding(i + 1, out var boneIndex2, out var weight2);
					bool flag2 = weight < weight2;
					if (flag2)
					{
						flag = true;
					}
					SetBinding(flag2 ? (i + 1) : i, boneIndex, weight);
					SetBinding(flag2 ? i : (i + 1), boneIndex2, weight2);
				}
			}
			while (flag);
		}

		public void Trim(float threshold)
		{
			bool flag = false;
			for (int i = 1; i < 4; i++)
			{
				GetBinding(i, out var boneIndex, out var weight);
				if (weight < threshold || boneIndex < 0)
				{
					flag = true;
				}
				if (flag)
				{
					SetBinding(i, -1, 0f);
				}
			}
		}

		public void TrimBoneCount(int count)
		{
			for (int i = count; i < 4; i++)
			{
				SetBinding(i, -1, 0f);
			}
		}

		public void Normalize()
		{
			float totalWeight = TotalWeight;
			if (totalWeight > 0f)
			{
				float num = 1f / totalWeight;
				weight0 *= num;
				weight1 *= num;
				weight2 *= num;
				weight3 *= num;
			}
		}

		public void FillInEmpty(int boneIndex)
		{
			if (boneIndex0 < 0 && boneIndex1 < 0 && boneIndex2 < 0 && boneIndex3 < 0)
			{
				boneIndex0 = boneIndex;
				weight0 = 1f;
			}
		}

		public void GetBinding(int index, out int boneIndex, out float weight)
		{
			switch (index)
			{
			case 0:
				boneIndex = boneIndex0;
				weight = weight0;
				break;
			case 1:
				boneIndex = boneIndex1;
				weight = weight1;
				break;
			case 2:
				boneIndex = boneIndex2;
				weight = weight2;
				break;
			case 3:
				boneIndex = boneIndex3;
				weight = weight3;
				break;
			default:
				throw new Exception("Invalid index");
			}
		}

		public void SetBinding(int index, Bone bone, float weight)
		{
			SetBinding(index, bone.Index, weight);
		}

		public void SetBinding(int index, int boneIndex, float weight)
		{
			switch (index)
			{
			case 0:
				boneIndex0 = boneIndex;
				weight0 = weight;
				break;
			case 1:
				boneIndex1 = boneIndex;
				weight1 = weight;
				break;
			case 2:
				boneIndex2 = boneIndex;
				weight2 = weight;
				break;
			case 3:
				boneIndex3 = boneIndex;
				weight3 = weight;
				break;
			}
		}

		public float GetWeight(int index)
		{
			return index switch
			{
				0 => weight0, 
				1 => weight1, 
				2 => weight2, 
				3 => weight3, 
				_ => throw new ArgumentException("Invalid Index"), 
			};
		}

		public void VerifyBoneIndexes(MeshX meshx)
		{
			VerifyBoneIndex(meshx, ref boneIndex0, ref weight0);
			VerifyBoneIndex(meshx, ref boneIndex1, ref weight1);
			VerifyBoneIndex(meshx, ref boneIndex2, ref weight2);
			VerifyBoneIndex(meshx, ref boneIndex3, ref weight3);
		}

		public void ClearBones()
		{
			boneIndex0 = -1;
			boneIndex1 = -1;
			boneIndex2 = -1;
			boneIndex3 = -1;
			weight0 = 0f;
			weight1 = 0f;
			weight2 = 0f;
			weight3 = 0f;
		}

		internal void BoneRemoved(int removedIndex)
		{
			UpdateRemovedIndex(ref boneIndex0, removedIndex);
			UpdateRemovedIndex(ref boneIndex1, removedIndex);
			UpdateRemovedIndex(ref boneIndex2, removedIndex);
			UpdateRemovedIndex(ref boneIndex3, removedIndex);
		}

		private void VerifyBoneIndex(MeshX meshx, ref int index, ref float weight)
		{
			if (index < 0 || index > meshx.bones.Count)
			{
				index = -1;
				weight = 0f;
			}
		}

		private void UpdateRemovedIndex(ref int index, int removed)
		{
			if (index == removed)
			{
				index = -1;
			}
			else if (index > removed)
			{
				index--;
			}
		}

		public Bone GetBone(MeshX meshx, int bindingIndex)
		{
			int boneIndex = GetBoneIndex(bindingIndex);
			if (boneIndex < 0)
			{
				return null;
			}
			return meshx.GetBone(boneIndex);
		}

		public float3 TransformPosition(MeshX meshx, in float3 position, Span<float4x4> boneTransforms)
		{
			float3 a = float3.Zero;
			for (int i = 0; i < 4; i++)
			{
				int boneIndex = GetBoneIndex(i);
				if (boneIndex >= 0)
				{
					float4x4 bindPose = meshx.GetBone(boneIndex).BindPose;
					float3 point = bindPose.TransformPoint3x4(in position);
					a += boneTransforms[boneIndex].TransformPoint3x4(in point) * GetWeight(i);
				}
			}
			float totalWeight = TotalWeight;
			if (totalWeight < 1f)
			{
				a += position * (1f - totalWeight);
			}
			return a;
		}

		public float3 TransformDirection(MeshX meshx, in float3 direction, Span<float4x4> boneTransforms)
		{
			float3 a = float3.Zero;
			for (int i = 0; i < 4; i++)
			{
				int boneIndex = GetBoneIndex(i);
				if (boneIndex >= 0)
				{
					float4x4 bindPose = meshx.GetBone(boneIndex).BindPose;
					float3 direction2 = bindPose.TransformDirection(in direction);
					a += boneTransforms[boneIndex].TransformDirection(in direction2) * GetWeight(i);
				}
			}
			float totalWeight = TotalWeight;
			if (totalWeight < 1f)
			{
				a += direction * (1f - totalWeight);
			}
			return a;
		}

		public override string ToString()
		{
			return $"Bone 0: {boneIndex0} - {weight0}, Bone 1: {boneIndex1} - {weight1}, Bone 2: {boneIndex2} - {weight2}, Bone 3: {boneIndex3} - {weight3}";
		}
	}
