		{
			private List<Submesh>.Enumerator _submeshEnumerator;

			private int _currentIndex;

			private ISubmesh<T> _currentSubmesh;

			public T Current => _currentSubmesh[_currentIndex];

			object IEnumerator.Current => Current;

			public PrimitiveEnumerator(MeshX meshx)
			{
				_submeshEnumerator = meshx.submeshes.GetEnumerator();
				_currentIndex = -1;
				_currentSubmesh = null;
			}

			public void Dispose()
			{
				_submeshEnumerator.Dispose();
				_currentIndex = -1;
			}

			public bool MoveNext()
			{
				while (true)
				{
					if (_currentSubmesh == null)
					{
						if (!_submeshEnumerator.MoveNext())
						{
							return false;
						}
						_currentSubmesh = _submeshEnumerator.Current as ISubmesh<T>;
						if (_currentSubmesh == null)
						{
							continue;
						}
					}
					_currentIndex++;
					if (_currentIndex < _submeshEnumerator.Current.Count)
					{
						break;
					}
					_currentIndex = -1;
					_currentSubmesh = null;
				}
				return true;
			}

			public void Reset()
			{
				_currentIndex = 0;
				((IEnumerator)_submeshEnumerator).Reset();
			}
		}

		public struct VertexEnumerator : IEnumerator<Vertex>, IEnumerator, IDisposable
		{
			private MeshX meshx;

			private int _index;

			public Vertex Current => meshx.GetVertex(_index);

			object IEnumerator.Current => Current;

			public VertexEnumerator(MeshX meshx)
			{
				this.meshx = meshx;
				_index = -1;
			}

			public void Dispose()
			{
				meshx = null;
				_index = -1;
			}

			public bool MoveNext()
			{
				_index++;
				return _index < meshx.VertexCount;
			}

			public void Reset()
			{
				_index = -1;
			}
		}

