		private readonly struct SubmeshMergeKey : IEquatable<SubmeshMergeKey>
		{
			public readonly object key;

			public readonly SubmeshTopology topology;

			public SubmeshMergeKey(object key, SubmeshTopology topology)
			{
				this.key = key;
				this.topology = topology;
			}

			public bool Equals(SubmeshMergeKey other)
			{
				if (key == other.key)
				{
					return topology == other.topology;
				}
				return false;
			}

			public override bool Equals(object obj)
			{
				if (obj is SubmeshMergeKey other)
				{
					return Equals(other);
				}
				return false;
			}

			public override int GetHashCode()
			{
				return (-1231748400 * -1521134295 + EqualityComparer<object>.Default.GetHashCode(key)) * -1521134295 + topology.GetHashCode();
			}

			public static bool operator ==(SubmeshMergeKey left, SubmeshMergeKey right)
			{
				return left.Equals(right);
			}

			public static bool operator !=(SubmeshMergeKey left, SubmeshMergeKey right)
			{
				return !(left == right);
			}
		}

