			set
			{
				if (!value || TrackRemovals)
				{
					return;
				}
				EnsureVertexArray(state: true, ref vertexIDs, 0);
				for (int i = 0; i < VertexCount; i++)
				{
					vertexIDs[i] = _vertexID++;
				}
				foreach (Submesh submesh in submeshes)
				{
					submesh?.EnableTrackRemovals();
				}
			}
		}

