		internal ref UV_Array GetRawUV_Array(int uv)
		{
			if (uv_channels == null || uv < 0 || uv >= uv_channels.Length)
			{
				DefaultInterpolatedStringHandler defaultInterpolatedStringHandler = new DefaultInterpolatedStringHandler(21, 2);
				defaultInterpolatedStringHandler.AppendLiteral("Requested: ");
				defaultInterpolatedStringHandler.AppendFormatted(uv);
				defaultInterpolatedStringHandler.AppendLiteral(", length: ");
				UV_Array[] array = uv_channels;
				defaultInterpolatedStringHandler.AppendFormatted((array != null) ? array.Length : 0);
				throw new ArgumentOutOfRangeException("uv", defaultInterpolatedStringHandler.ToStringAndClear());
			}
			return ref uv_channels[uv];
		}

		internal UV_Array TryGetRawUV_Array(int uv)
		{
			if (uv_channels == null || uv < 0 || uv >= uv_channels.Length)
			{
				return default(UV_Array);
			}
			return uv_channels[uv];
		}

