		public void TrimUVChannels()
		{
			if (uv_channels != null)
			{
				int num = uv_channels.Length;
				while (num > 0 && GetUV_Dimension(num - 1) == 0)
				{
					num--;
				}
				if (num != uv_channels.Length)
				{
					uv_channels = uv_channels.EnsureExactSize(num, keepData: true);
				}
			}
		}

