		public int GetUV_Dimension(int uv)
		{
			return TryGetRawUV_Array(uv).Dimensions;
		}

		public void SetUV_Dimension(int uv, int dimension)
		{
			switch (dimension)
			{
			case 0:
				if (uv_channels != null && uv < uv_channels.Length)
				{
					ref UV_Array rawUV_Array = ref GetRawUV_Array(uv);
					rawUV_Array.uv_2D = null;
					rawUV_Array.uv_3D = null;
					rawUV_Array.uv_4D = null;
				}
				break;
			case 2:
				SetHasUV(uv, state: true);
				break;
			case 3:
				SetHasUV_3D(uv, state: true);
				break;
			case 4:
				SetHasUV_4D(uv, state: true);
				break;
			default:
				throw new ArgumentException("Invalid UV dimension: " + dimension);
			}
		}

