		public void SetHasUV(int uv, bool state, bool throwIfDimensionsMismatch = false)
		{
			if (uv < 0)
			{
				throw new ArgumentOutOfRangeException("uv");
			}
			uv_channels = uv_channels.EnsureSize(uv + 1, keepData: true);
			ref UV_Array rawUV_Array = ref GetRawUV_Array(uv);
			if (throwIfDimensionsMismatch && rawUV_Array.Dimensions != 2)
			{
				throw new InvalidOperationException($"UV channel {uv} is already configured with {rawUV_Array.Dimensions} dimensions");
			}
			EnsureVertexArray(state, ref rawUV_Array.uv_2D);
			rawUV_Array.uv_3D = null;
			rawUV_Array.uv_4D = null;
		}

		public void SetHasUV_3D(int uv, bool state, bool throwIfDimensionsMismatch = false)
		{
			if (uv < 0)
			{
				throw new ArgumentOutOfRangeException("uv");
			}
			uv_channels = uv_channels.EnsureSize(uv + 1, keepData: true);
			ref UV_Array rawUV_Array = ref GetRawUV_Array(uv);
			if (throwIfDimensionsMismatch && rawUV_Array.Dimensions != 3)
			{
				throw new InvalidOperationException($"UV channel {uv} is already configured with {rawUV_Array.Dimensions} dimensions");
			}
			EnsureVertexArray(state, ref rawUV_Array.uv_3D);
			rawUV_Array.uv_2D = null;
			rawUV_Array.uv_4D = null;
		}

		public void SetHasUV_4D(int uv, bool state, bool throwIfDimensionsMismatch = false)
		{
			if (uv < 0)
			{
				throw new ArgumentOutOfRangeException("uv");
			}
			uv_channels = uv_channels.EnsureSize(uv + 1, keepData: true);
			ref UV_Array rawUV_Array = ref GetRawUV_Array(uv);
			if (throwIfDimensionsMismatch && rawUV_Array.Dimensions != 4)
			{
				throw new InvalidOperationException($"UV channel {uv} is already configured with {rawUV_Array.Dimensions} dimensions");
			}
			EnsureVertexArray(state, ref rawUV_Array.uv_4D);
			rawUV_Array.uv_2D = null;
			rawUV_Array.uv_3D = null;
		}

