		public Submesh AddSubmesh(SubmeshTopology topology)
		{
			return topology switch
			{
				SubmeshTopology.Points => AddSubmesh<PointSubmesh>(), 
				SubmeshTopology.Triangles => AddSubmesh<TriangleSubmesh>(), 
				_ => throw new Exception("Unsupported Topology: " + topology), 
			};
		}

		public T AddSubmesh<T>() where T : Submesh
		{
			T val = InstantiateSubmesh<T>();
			submeshes.Add(val);
			return val;
		}

		public T InsertSubmesh<T>(int index) where T : Submesh
		{
			T val = InstantiateSubmesh<T>();
			submeshes.Insert(index, val);
			return val;
		}

		public void RemoveSubmesh(int index)
		{
			submeshes.RemoveAt(index);
		}

		public void RemoveSubmesh(Submesh submesh)
		{
			submeshes.Remove(submesh);
		}

		public T TryGetSubmesh<T>(int index = 0) where T : Submesh
		{
			while (submeshes.Count <= index)
			{
				submeshes.Add(null);
			}
			Submesh submesh = submeshes[index];
			if (submesh is T result)
			{
				return result;
			}
			if (submesh == null || submesh.Count == 0)
			{
				T val = InstantiateSubmesh<T>();
				submeshes[index] = val;
				return val;
			}
			return null;
		}

		public Submesh TryGetSubmesh(SubmeshTopology topology, int index = 0)
		{
			return topology switch
			{
				SubmeshTopology.Points => TryGetSubmesh<PointSubmesh>(index), 
				SubmeshTopology.Triangles => TryGetSubmesh<TriangleSubmesh>(index), 
				_ => throw new ArgumentException("Invalid submesh topology"), 
			};
		}

		private T InstantiateSubmesh<T>() where T : Submesh
		{
			if (typeof(T) == typeof(PointSubmesh))
			{
				return (T)(Submesh)new PointSubmesh(this);
			}
			if (typeof(T) == typeof(TriangleSubmesh))
			{
				return (T)(Submesh)new TriangleSubmesh(this);
			}
			throw new NotSupportedException($"{typeof(T)} submesh isn't supported");
		}

		public BlendShape AddBlendShape(string name)
		{
			return InsertBlendshapeAt(name, BlendShapeCount);
		}

		public BlendShape InsertBlendshapeAt(string name, int index)
		{
			if (blendshapeMap.ContainsKey(name))
			{
				throw new Exception("BlendShape with given key already exists");
			}
			BlendShape blendShape = new BlendShape(this, name);
			blendshapes.Insert(index, blendShape);
			blendshapeMap.Add(name, blendShape);
			return blendShape;
		}

		public BlendShape GetBlendShape(int index)
		{
			return blendshapes[index];
		}

