		}

		public bool HasBlendShape(string name)
		{
			if (!string.IsNullOrEmpty(name))
			{
				return blendshapeMap.ContainsKey(name);
			}
			return false;
		}

		public int BlendShapeIndex(string name)
		{
			if (!HasBlendShape(name))
			{
				return -1;
			}
			return blendshapes.IndexOf(GetBlendShape(name));
		}

		public BlendShape TryGetBlendShape(string name)
		{
			blendshapeMap.TryGetValue(name, out BlendShape value);
			return value;
