		public bool RemoveBlendShape(BlendShape blendshape)
		{
			if (blendshapes.Remove(blendshape))
			{
				blendshapeMap.Remove(blendshape.Name);
				return true;
			}
			return false;
		}

		public MeshX()
		{
			VerticesVersion = -1;
			Triangles = new EnumerableWrapper<Triangle, PrimitiveEnumerator<Triangle>>(() => new PrimitiveEnumerator<Triangle>(this));
			Points = new EnumerableWrapper<Point, PrimitiveEnumerator<Point>>(() => new PrimitiveEnumerator<Point>(this));
			Vertices = new EnumerableWrapper<Vertex, VertexEnumerator>(() => new VertexEnumerator(this));
		}

		public MeshX(MeshX clone)
			: this()
		{
			Copy(clone, (float4x4?)null);
		}

		public void EnsureFreeCapacity(int capacity)
		{
			int num = capacity - FreeCapacity;
			if (num > 0)
			{
				VertexCapacity += num;
			}
		}

		public void Clear()
		{
			ClearSubmeshes();
			ClearVerticesAndIndicies();
		}

		public void ClearVerticesAndIndicies()
		{
			VertexCount = 0;
			VerticesVersion--;
			for (int i = 0; i < SubmeshCount; i++)
			{
				submeshes[i].Clear();
			}
		}

		public void ClearSubmeshes()
		{
			while (SubmeshCount > 0)
			{
				RemoveSubmesh(SubmeshCount - 1);
			}
		}

		public void ClearBlendShapes()
		{
			blendshapes.Clear();
		}

		public void CopyDataChannelFlags(MeshX source)
		{
			HasNormals = source.HasNormals;
			HasTangents = source.HasTangents;
			HasColors = source.HasColors;
			HasBoneBindings = source.HasBoneBindings;
			for (int i = 0; i < source.UV_ChannelCount; i++)
			{
				SetUV_Dimension(i, source.GetUV_Dimension(i));
			}
			HasFlags = source.HasFlags;
		}

		public AppendResult Copy(MeshX source, in float4x4? transform = null, GeometryMask mask = null)
		{
			Clear();
			CopyDataChannelFlags(source);
			return Append(source, appendSubmeshes: true, in transform, null, mask);
		}

		public AppendResult Append(MeshX source, bool appendSubmeshes = true, in float4x4? transform = null, Func<Submesh, int> submeshMapper = null, GeometryMask mask = null)
		{
			AppendResult result = default(AppendResult);
			int vertexCount = VertexCount;
			int num = mask?.MaskedVertexCount ?? source.VertexCount;
			AddVertices(num);
			EnsureNormals(source.HasNormals, default(float3));
			EnsureTangents(source.HasTangents, new float4(1f));
			EnsureColors(source.HasColors, color.White);
			HasBoneBindings |= source.HasBoneBindings;
			for (int i = 0; i < source.UV_ChannelCount; i++)
			{
				SetUV_Dimension(i, source.GetUV_Dimension(i));
			}
			HasFlags |= source.HasFlags;
			if (num > 0)
			{
				if (mask == null)
				{
					Array.Copy(source.RawPositions, 0, RawPositions, vertexCount, num);
					if (source.HasNormals)
					{
						Array.Copy(source.RawNormals, 0, RawNormals, vertexCount, num);
					}
					if (source.HasTangents)
					{
						Array.Copy(source.RawTangents, 0, RawTangents, vertexCount, num);
					}
					else if (HasTangents)
					{
						for (int j = 0; j < num; j++)
						{
							RawTangents[j + vertexCount] = new float4(1f);
						}
					}
					if (source.HasColors)
					{
						Array.Copy(source.RawColors, 0, RawColors, vertexCount, num);
					}
					for (int k = 0; k < source.UV_ChannelCount; k++)
					{
						if (source.HasUV_2D(k))
						{
							Array.Copy(source.GetRawUVs(k), 0, GetRawUVs(k), vertexCount, num);
						}
					}
					if (source.HasFlags)
					{
						for (int l = 0; l < num; l++)
						{
							flags[l + vertexCount] = source.flags[l];
						}
					}
				}
				else
				{
					int num2 = vertexCount;
					for (int m = 0; m < source.VertexCount; m++)
					{
						if (!mask.IsVertexMasked(m))
						{
							continue;
						}
						RawPositions[num2] = source.RawPositions[m];
						if (source.HasNormals)
						{
							RawNormals[num2] = source.RawNormals[m];
						}
						if (source.HasTangents)
						{
							RawTangents[num2] = source.RawTangents[m];
						}
						if (source.HasColors)
						{
							RawColors[num2] = source.RawColors[m];
						}
						for (int n = 0; n < source.UV_ChannelCount; n++)
						{
							if (source.HasUV_2D(n))
							{
								GetRawUVs(n)[num2] = source.GetRawUVs(n)[m];
							}
						}
						if (source.HasColors)
						{
							flags[num2] = source.flags[m];
						}
						num2++;
					}
				}
				if (transform.HasValue)
				{
					float4x4 value = transform.Value;
					for (int num3 = 0; num3 < num; num3++)
					{
						RawPositions[num3 + vertexCount] = value.TransformPoint3x4(in RawPositions[num3 + vertexCount]);
					}
					if (source.HasNormals)
					{
						for (int num4 = 0; num4 < num; num4++)
						{
							RawNormals[num4 + vertexCount] = value.TransformDirection(in RawNormals[num4 + vertexCount]);
						}
					}
					if (source.HasTangents)
					{
						for (int num5 = 0; num5 < num; num5++)
						{
							float4 @float = RawTangents[num5 + vertexCount];
							RawTangents[num5 + vertexCount] = new float4(value.TransformDirection(@float.xyz), @float.w);
						}
					}
				}
			}
			if (source.HasBoneBindings)
			{
				int boneCount = BoneCount;
				int boneCount2 = source.BoneCount;
				List<int> list = (result.boneMapping = new List<int>());
				for (int num6 = 0; num6 < boneCount2; num6++)
				{
					Bone bone = source.GetBone(num6);
					float4x4 bindPose = bone.BindPose;
					if (transform.HasValue)
					{
						bindPose = transform.Value * bindPose;
					}
					Bone bone2 = FindBone((Bone b) => b.Name == bone.Name && MathX.Approximately(in b.BindPose, in bindPose));
					if (bone2 == null)
					{
						bone2 = AddBone(bone.Name);
						bone2.BindPose = bindPose;
					}
					list.Add(bone2.Index);
				}
				if (mask == null)
				{
					Array.Copy(source.RawBoneBindings, 0, RawBoneBindings, vertexCount, num);
				}
				else
				{
					int num7 = vertexCount;
					for (int num8 = 0; num8 < source.VertexCount; num8++)
					{
						if (mask.IsVertexMasked(num8))
						{
							RawBoneBindings[num7] = source.RawBoneBindings[num8];
							num7++;
						}
					}
				}
				if (boneCount > 0)
				{
					for (int num9 = 0; num9 < num; num9++)
					{
						BoneBinding boneBinding = RawBoneBindings[num9 + vertexCount];
						if (boneBinding.boneIndex0 >= 0)
						{
							boneBinding.boneIndex0 = list[boneBinding.boneIndex0];
						}
						if (boneBinding.boneIndex1 >= 0)
						{
							boneBinding.boneIndex1 = list[boneBinding.boneIndex1];
						}
						if (boneBinding.boneIndex2 >= 0)
						{
							boneBinding.boneIndex2 = list[boneBinding.boneIndex2];
						}
						if (boneBinding.boneIndex3 >= 0)
						{
							boneBinding.boneIndex3 = list[boneBinding.boneIndex3];
						}
						RawBoneBindings[num9 + vertexCount] = boneBinding;
					}
				}
			}
			result.blendshapeMapping = new List<int>();
			foreach (BlendShape blendShape2 in source.BlendShapes)
			{
				BlendShape blendShape = TryGetBlendShape(blendShape2.Name);
				if (blendShape == null)
				{
					blendShape = AddBlendShape(blendShape2.Name);
				}
				if (blendShape.FrameCount != 0 && blendShape.FrameCount != blendShape2.FrameCount)
				{
					UniLog.Warning("Cannot append BlendShape " + blendShape2.Name + "! The number of frames between source and target differs");
					RemoveBlendShape(blendShape);
					continue;
				}
				result.blendshapeMapping.Add(blendShape.Index);
				blendShape.HasNormals |= blendShape2.HasNormals;
				blendShape.HasTangents |= blendShape2.HasTangents;
				for (int num10 = 0; num10 < blendShape2.FrameCount; num10++)
				{
					BlendShapeFrame blendShapeFrame = blendShape2[num10];
					BlendShapeFrame blendShapeFrame2 = ((blendShape.FrameCount > num10) ? blendShape[num10] : blendShape.AddFrame(blendShapeFrame.Weight));
					if (mask == null)
					{
						for (int num11 = 0; num11 < num; num11++)
						{
							blendShapeFrame2.RawPositions[num11 + vertexCount] = blendShapeFrame.RawPositions[num11];
						}
						if (blendShape2.HasNormals)
						{
							for (int num12 = 0; num12 < num; num12++)
							{
								blendShapeFrame2.RawNormals[num12 + vertexCount] = blendShapeFrame.RawNormals[num12];
							}
						}
						if (blendShape2.HasTangents)
						{
							for (int num13 = 0; num13 < num; num13++)
							{
								blendShapeFrame2.RawTangents[num13 + vertexCount] = blendShapeFrame.RawTangents[num13];
							}
						}
						continue;
					}
					int num14 = vertexCount;
					for (int num15 = 0; num15 < source.VertexCount; num15++)
					{
						if (mask.IsVertexMasked(num15))
						{
							blendShapeFrame2.RawPositions[num14] = blendShapeFrame.RawPositions[num15];
							if (blendShape2.HasNormals)
							{
								blendShapeFrame2.RawNormals[num14] = blendShapeFrame.RawNormals[num15];
							}
							if (blendShape2.HasTangents)
							{
								blendShapeFrame2.RawTangents[num14] = blendShapeFrame.RawTangents[num15];
							}
							num14++;
						}
					}
				}
			}
			if (appendSubmeshes)
			{
				mask?.EnsureRemappedVertexIndicies();
				result.submeshMapping = new List<int>();
				int submeshCount = source.SubmeshCount;
				for (int num16 = 0; num16 < submeshCount; num16++)
				{
					Submesh submesh = source.GetSubmesh(num16);
					int num17 = ((mask == null || mask.MaskedPrimitiveCount(num16) != 0) ? (submeshMapper?.Invoke(submesh) ?? SubmeshCount) : (-1));
					result.submeshMapping.Add(num17);
					if (num17 < 0)
					{
						continue;
					}
					Submesh submesh2 = TryGetSubmesh(submesh.Topology, num17);
					if (submesh2 == null)
					{
						throw new Exception($"Couldn't map source submesh {submesh2} to target index {num17}. A submesh with different topology already exists.");
					}
					int indicieCount = submesh2.IndicieCount;
					if (mask == null)
					{
						submesh2.IncreaseCount(submesh.Count);
						for (int num18 = 0; num18 < submesh.IndicieCount; num18++)
						{
							submesh2.RawIndicies[indicieCount + num18] = vertexCount + submesh.RawIndicies[num18];
						}
						continue;
					}
					submesh2.IncreaseCount(mask.MaskedPrimitiveCount(num16));
					int num19 = indicieCount;
					for (int num20 = 0; num20 < submesh.Count; num20++)
					{
						if (mask.IsPrimitiveMasked(num16, num20))
						{
							int num21 = num20 * submesh.IndiciesPerElement;
							for (int num22 = 0; num22 < submesh.IndiciesPerElement; num22++)
							{
								int num23 = num21 + num22;
								int vertexIndex = submesh.RawIndicies[num23];
								submesh2.RawIndicies[num19++] = vertexCount + mask.GetNewVertexIndex(vertexIndex);
							}
						}
					}
				}
			}
			return result;
		}

		public bool SetVertexCount(int count)
		{
			int num = count - VertexCount;
			if (num > 0)
			{
				IncreaseVertexCount(num);
			}
			else if (num < 0)
			{
				RemoveVerticesFromEnd(-num);
			}
			return num != 0;
		}

		public void IncreaseVertexCount(int count)
		{
			VertexCount += count;
			if (VertexCapacity < VertexCount)
			{
				EnsureVertexCapacity(MathX.Max(VertexCapacity * 2, VertexCount, 4));
			}
			if (TrackRemovals)
			{
				for (int i = VertexCount - count; i < VertexCount; i++)
				{
					vertexIDs[i] = _vertexID++;
				}
			}
		}

		public void RemoveVerticesFromEnd(int count, bool updateSubmeshes = true)
		{
			RemoveVertices(VertexCount - count, count, updateSubmeshes);
		}

		public void IncreasePointCount(int count)
		{
			TryGetSubmesh<PointSubmesh>().IncreaseCount(count);
		}

		public void IncreaseTriangleCount(int count)
		{
