		}

		public void AddVertices(int count, VertexCollection verts = null)
		{
			IncreaseVertexCount(count);
			if (verts != null)
			{
				verts.Capacity += count;
				for (int i = 0; i < count; i++)
				{
					verts.Add(new Vertex(VertexCount - count + i, this));
				}
			}
		}

		public bool EnsureVertexCount(int count)
		{
			if (count == VertexCount)
			{
				return false;
			}
			if (count > VertexCount)
			{
				AddVertices(count - VertexCount);
			}
			else
			{
				int num = VertexCount - count;
				RemoveVertices(VertexCount - num, num);
			}
			return true;
		}

		public Vertex AddVertex()
		{
			IncreaseVertexCount(1);
			return new Vertex(VertexCount - 1, this);
		}

