		public Triangle GetTriangleByFaceIndex(int faceIndex)
		{
			foreach (Submesh submesh in submeshes)
			{
				if (faceIndex < submesh.Count)
				{
					return (submesh as TriangleSubmesh)?.GetTriangle(faceIndex) ?? default(Triangle);
				}
				faceIndex -= submesh.Count;
			}
			return default(Triangle);
		}

		public Triangle GetTriangleFromAllTriangleSubmeshes(int triangleIndex)
		{
			foreach (Submesh submesh in submeshes)
			{
				if (submesh is TriangleSubmesh triangleSubmesh)
				{
					if (triangleIndex < triangleSubmesh.Count)
					{
						return triangleSubmesh.GetTriangle(triangleIndex);
					}
					triangleIndex -= triangleSubmesh.Count;
				}
			}
			return default(Triangle);
		}

		public void RemoveVertices(int index, int count, bool updateSubmeshes = true, bool throwOnRemovedFromSubmeshes = false)
		{
			VerifyVertexIndex(index);
			if (index + count > VertexCount)
			{
				throw new ArgumentOutOfRangeException("count");
			}
			if (index + count != VertexCount)
			{
				VerticesVersion--;
			}
			RemoveElements(positions, index, count, VertexCount);
			RemoveElements(vertexIDs, index, count, VertexCount, clear: true, int.MaxValue);
			RemoveElements(normals, index, count, VertexCount);
			RemoveElements(tangents, index, count, VertexCount);
			RemoveElements(colors, index, count, VertexCount);
			RemoveElements(boneBindings, index, count, VertexCount);
			for (int i = 0; i < UV_ChannelCount; i++)
			{
				UV_Array uV_Array = uv_channels[i];
				RemoveElements(uV_Array.uv_2D, index, count, VertexCount);
				RemoveElements(uV_Array.uv_3D, index, count, VertexCount);
				RemoveElements(uV_Array.uv_4D, index, count, VertexCount);
			}
			RemoveElements(flags, index, count, VertexCount);
			foreach (BlendShape blendshape in blendshapes)
			{
				blendshape.RemoveElements(index, count);
			}
			VertexCount -= count;
			if (!updateSubmeshes)
			{
				return;
			}
			foreach (Submesh submesh in submeshes)
			{
				submesh?.VerticesRemoved(index, count, throwOnRemovedFromSubmeshes);
			}
		}

