		private void RemoveMixedPrimitives<T>(List<T> list) where T : IMeshXPrimitive
		{
			if (list.Count == 0)
			{
				return;
			}
			Submesh checkSubmesh = list[0].Submesh;
			HashSet<Submesh> hashSet = null;
			for (int i = 1; i < list.Count; i++)
			{
				if (list[i].Submesh != checkSubmesh)
				{
					if (hashSet == null)
					{
						hashSet = new HashSet<Submesh>();
						hashSet.Add(checkSubmesh);
					}
					hashSet.Add(list[i].Submesh);
				}
			}
			if (hashSet == null)
			{
				RemoveElements(list, delegate(int index, int count)
				{
					checkSubmesh.Remove(index, count);
				});
				return;
			}
			List<T> list2 = new List<T>();
			foreach (Submesh submesh in hashSet)
			{
				foreach (T item in list)
				{
					if (item.Submesh == submesh)
					{
						list2.Add(item);
					}
				}
				RemoveElements(list2, delegate(int index, int count)
				{
					submesh.Remove(index, count);
				});
				list2.Clear();
			}
		}

