		public void RemoveGeometry(GeometryMask mask, bool throwOnRemovedFromSubmeshes = false)
		{
			if (mask.Mesh != this)
			{
				throw new ArgumentException("GeometryMask doesn't belong to this mesh");
			}
			for (int i = 0; i < SubmeshCount; i++)
			{
				Submesh submesh = submeshes[i];
				for (int num = submesh.Count - 1; num >= 0; num--)
				{
					if (mask.IsPrimitiveMasked(i, num))
					{
						submesh.Remove(num);
					}
				}
			}
			List<int> list = new List<int>();
			for (int j = 0; j < VertexCount; j++)
			{
				if (mask.IsVertexMasked(j))
				{
					list.Add(j);
				}
			}
			RemoveVertices(list, throwOnRemovedFromSubmeshes);
		}

		internal void RemoveElements<T>(List<T> elements, Action<int, int> remove) where T : IMeshXElement
		{
			RemoveElements(elements.Select((T e) => e.Index).ToList(), remove);
		}

		internal void RemoveElements(List<int> elements, Action<int, int> remove)
		{
			if (elements.Count == 0)
			{
				return;
			}
			elements.Sort((int a, int b) => a.CompareTo(b));
			int num = -1;
			int num2 = -1;
			int num3 = 0;
			for (int num4 = elements.Count - 1; num4 >= -1; num4--)
			{
				if (num4 >= 0)
				{
					num = elements[num4];
					if (num == num2)
					{
						continue;
					}
				}
				if (num2 < 0)
				{
					num2 = num;
				}
				else if (num != num2 - num3 || num4 == -1)
				{
					remove(num2 - num3 + 1, num3);
					if (num4 >= 0)
					{
						num2 = num;
						num3 = 0;
					}
				}
				num3++;
			}
		}

