		{
			bones.RemoveAt(index);
			if (autoUpdateBindings && HasBoneBindings)
			{
				for (int i = 0; i < VertexCount; i++)
				{
					boneBindings[i].BoneRemoved(index);
				}
			}
		}

		public bool RemoveBone(Bone bone, bool autoUpdateBindings = true)
		{
			int num = bones.IndexOf(bone);
			if (num >= 0)
			{
				RemoveBoneAt(num, autoUpdateBindings);
				return true;
			}
			return false;
		}

		public void ClearBones(bool autoUpdateBindings = true)
		{
			bones.Clear();
			if (autoUpdateBindings && HasBoneBindings)
			{
				for (int i = 0; i < VertexCount; i++)
				{
					RawBoneBindings[i].ClearBones();
				}
			}
		}

