				throw new Exception("Mesh doesn't have colors!");
			}
		}

		internal void CheckBoneBindings()
		{
			if (!HasBoneBindings)
			{
				throw new Exception("Mesh doesn't have bone bindings!");
			}
		}

		internal void CheckUV(int uv)
		{
			if (!HasUV_2D(uv))
			{
				throw new Exception($"Mesh doesn't have uv{0}s!");
			}
		}

		internal void CheckFlags()
		{
			if (!HasFlags)
			{
				throw new Exception("Mesh doesn't have flags!");
			}
		}

		internal void VerifyVertexIndex(int index)
		{
			if (index < 0 || index >= VertexCount)
			{
				throw new ArgumentOutOfRangeException($"index = {index}");
			}
		}

		internal void EnsureVertexArray<T>(bool state, ref T[] array, T defaultValue = default(T))
		{
			EnsureArray(state, ref array, VertexCapacity, defaultValue);
		}

		internal void EnsureArray<T>(bool state, ref T[] array, int minSize, T defaultValue = default(T))
		{
			if (state)
			{
				if (array != null && array.Length >= minSize)
				{
					return;
				}
				T[] array2 = array;
				array = new T[minSize];
				int i = 0;
				if (array2 != null)
				{
					for (; i < array2.Length; i++)
					{
						array[i] = array2[i];
					}
				}
				for (; i < array.Length; i++)
				{
					array[i] = defaultValue;
				}
			}
			else
			{
				array = null;
			}
		}

		private void EnsureBitArray(bool state, ref BitArray array, int minSize)
		{
			if (state)
			{
				if (array == null || array.Length < minSize)
				{
					if (array == null)
					{
						array = new BitArray(minSize);
					}
					else
					{
						array.Length = minSize;
					}
				}
			}
			else
			{
				array = null;
			}
		}

		private void EnsureVertexCapacity(int capacity)
		{
			EnsureArray(state: true, ref positions, capacity);
			EnsureArray(TrackRemovals, ref vertexIDs, capacity, 0);
			EnsureArray(HasNormals, ref normals, capacity);
			EnsureArray(HasTangents, ref tangents, capacity);
			EnsureArray(HasColors, ref colors, capacity, color.White);
			EnsureArray(HasBoneBindings, ref boneBindings, capacity, BoneBinding.Empty);
			for (int i = 0; i < UV_ChannelCount; i++)
			{
				ref UV_Array rawUV_Array = ref GetRawUV_Array(i);
				if (rawUV_Array.uv_2D != null)
				{
					EnsureArray(state: true, ref rawUV_Array.uv_2D, capacity);
				}
				else if (rawUV_Array.uv_3D != null)
				{
					EnsureArray(state: true, ref rawUV_Array.uv_3D, capacity);
				}
				else if (rawUV_Array.uv_4D != null)
				{
					EnsureArray(state: true, ref rawUV_Array.uv_4D, capacity);
				}
			}
			EnsureBitArray(HasFlags, ref flags, capacity);
			foreach (BlendShape blendshape in blendshapes)
			{
				blendshape.EnsureCapacity(capacity);
			}
		}

		internal void RemoveElements<T>(T[] array, int index, int count, int length, bool clear = false, T clearVal = default(T))
		{
			if (array == null)
			{
				return;
			}
			Array.Copy(array, index + count, array, index, Math.Max(0, length - (index + count)));
			if (clear)
			{
				for (int i = length - count; i < length; i++)
				{
					array[i] = clearVal;
				}
			}
		}

		private void RemoveElements(BitArray bitArray, int index, int count, int length)
		{
			if (bitArray != null)
			{
				for (int i = index + count; i < length; i++)
				{
					bitArray[i - count] = bitArray[i];
				}
			}
		}

		public void ForEachUV(Func<float4, float4> processAll)
		{
			ForEachUV((float2 xy) => processAll(xy).xy, (float3 xyz) => processAll(xyz).xyz, processAll);
		}

		public void ForEachUV(Func<float2, float2> process2D, Func<float3, float3> process3D, Func<float4, float4> process4D)
		{
			for (int i = 0; i < UV_ChannelCount; i++)
			{
				UV_Array rawUV_Array = GetRawUV_Array(i);
				rawUV_Array.uv_2D?.ForeachProcess(0, VertexCount, process2D);
				rawUV_Array.uv_3D?.ForeachProcess(0, VertexCount, process3D);
				rawUV_Array.uv_4D?.ForeachProcess(0, VertexCount, process4D);
			}
		}

