		public void MergeBlendshapes(List<int> indexes = null, string name = "Merged")
		{
			int num = indexes?.Count ?? BlendShapeCount;
			if (num == 0)
			{
				return;
			}
			int index = indexes?[0] ?? 0;
			BlendShape blendShape = GetBlendShape(index);
			List<int> list = Pool.BorrowList<int>();
			for (int i = 1; i < num; i++)
			{
				int num2 = indexes?[i] ?? i;
				BlendShape blendShape2 = GetBlendShape(num2);
				list.Add(num2);
				foreach (BlendShapeFrame frame in blendShape2.Frames)
				{
					BlendShapeFrame blendShapeFrame = blendShape.AddFrame(1f);
					Array.Copy(frame.positions, blendShapeFrame.positions, VertexCount);
					if (blendShape2.HasNormals)
					{
						blendShape.HasNormals = true;
						Array.Copy(frame.normals, blendShapeFrame.normals, VertexCount);
					}
					if (blendShape2.HasTangents)
					{
						blendShape.HasTangents = true;
						Array.Copy(frame.tangents, blendShapeFrame.tangents, VertexCount);
					}
				}
			}
			blendShape.NormalizeFrameWeights();
			list.Sort();
			for (int num3 = list.Count - 1; num3 >= 0; num3--)
			{
				RemoveBlendShape(list[num3]);
			}
			Pool.Return(ref list);
		}

		public void SortBlendshapesByName(List<int> remapedOrder = null)
		{
			SortBlendshapes((BlendShape a, BlendShape b) => a.Name.CompareTo(b.Name), remapedOrder);
		}

		public void SortBlendshapesByNameLength(List<int> remapedOrder = null)
		{
			SortBlendshapes(delegate(BlendShape a, BlendShape b)
			{
				int num = a.Name.Length.CompareTo(b.Name.Length);
				return (num != 0) ? num : a.Name.CompareTo(b.Name);
			}, remapedOrder);
		}

		public void SortBlendshapes(Comparison<BlendShape> comparison, List<int> remappedOrder = null)
		{
			List<BlendShape> list = null;
			if (remappedOrder != null)
			{
				list = new List<BlendShape>(blendshapes);
			}
			blendshapes.Sort(comparison);
			if (remappedOrder == null)
			{
				return;
			}
			foreach (BlendShape item in list)
			{
				remappedOrder.Add(item.Index);
			}
		}

		public bool RecalculateTangentsMikktspace(TriangleCollection triangles = null, int uvChannel = 0)
		{
			if (!HasNormals || !HasUV_2D(uvChannel))
			{
				return false;
			}
			HasTangents = true;
			float3[] positions = RawPositions;
			float3[] normals = RawNormals;
			float2[] uvs = GetRawUVs(uvChannel);
			float4[] tangents = RawTangents;
			int faceCount = triangles?.Count ?? TotalFaceCount;
			VerticesPerFaceHandler getVerticesPerFace;
			VertexPositionHandler getPosition;
			VertexNormalHandler getNormal;
			VertexUVHandler getUV;
			BasicTangentHandler setTangentBasic;
			if (triangles == null)
			{
				getVerticesPerFace = (int face) => GetSubmeshForFace(face)?.IndiciesPerElement ?? 0;
				getPosition = delegate(int face, int vert, out float x, out float y, out float z)
				{
					int vertexIndexUnsafe = GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
					float3 @float = positions[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
					z = @float.z;
				};
				getNormal = delegate(int face, int vert, out float x, out float y, out float z)
				{
					int vertexIndexUnsafe = GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
					float3 @float = normals[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
					z = @float.z;
				};
				getUV = delegate(int face, int vert, out float x, out float y)
				{
					int vertexIndexUnsafe = GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
					float2 @float = uvs[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
				};
				setTangentBasic = delegate(int face, int vert, float x, float y, float z, float sign)
				{
					int vertexIndexUnsafe = GetTriangleByFaceIndex(face).GetVertexIndexUnsafe(vert);
					tangents[vertexIndexUnsafe] = new float4(x, y, z, sign);
				};
			}
			else
			{
				getVerticesPerFace = (int face) => 3;
				getPosition = delegate(int face, int vert, out float x, out float y, out float z)
				{
					int vertexIndexUnsafe = triangles[face].GetVertexIndexUnsafe(vert);
					float3 @float = positions[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
					z = @float.z;
				};
				getNormal = delegate(int face, int vert, out float x, out float y, out float z)
				{
					int vertexIndexUnsafe = triangles[face].GetVertexIndexUnsafe(vert);
					float3 @float = normals[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
					z = @float.z;
				};
				getUV = delegate(int face, int vert, out float x, out float y)
				{
					int vertexIndexUnsafe = triangles[face].GetVertexIndexUnsafe(vert);
					float2 @float = uvs[vertexIndexUnsafe];
					x = @float.x;
					y = @float.y;
				};
				setTangentBasic = delegate(int face, int vert, float x, float y, float z, float sign)
				{
					int vertexIndexUnsafe = triangles[face].GetVertexIndexUnsafe(vert);
					tangents[vertexIndexUnsafe] = new float4(x, y, z, sign);
				};
			}
			return MikkGenerator.GenerateTangentSpace(faceCount, getVerticesPerFace, getPosition, getNormal, getUV, setTangentBasic);
		}

		public static byte MAGIC_HEADER_BYTE(int index)
		{
			return _magicHeader[index];
		}

		public byte[] SaveToArray(Encoding encoding = Encoding.LZ4)
		{
			using MemoryStream memoryStream = new MemoryStream();
			Encode(memoryStream, encoding);
			return memoryStream.ToArray();
		}

		public void SaveToFile(string file, Encoding encoding = Encoding.LZ4)
		{
			using FileStream stream = new FileStream(file, FileMode.Create, FileAccess.Write);
			Encode(stream, encoding);
		}

		public MeshX(string file)
			: this()
		{
			using FileStream stream = new FileStream(file, FileMode.Open, FileAccess.Read);
			Decode(stream);
		}

		public MeshX(Stream stream)
			: this()
		{
			Decode(stream);
		}

		public void Encode(Stream stream, Encoding encoding = Encoding.LZ4)
		{
			TrimUVChannels();
			BinaryWriter bw = new BinaryWriter(stream);
			bw.Write("MeshX");
			bw.Write(7);
			uint value = EncodeFlags(HasNormals, HasTangents, HasColors, HasBoneBindings);
			bw.Write(value);
			bw.Write7BitEncoded((ulong)VertexCount);
			bw.Write7BitEncoded((ulong)SubmeshCount);
			bw.Write7BitEncoded((ulong)BoneCount);
			bw.Write7BitEncoded((ulong)BlendShapeCount);
			bw.Write7BitEncoded((ulong)UV_ChannelCount);
			for (int i = 0; i < UV_ChannelCount; i++)
			{
				bw.Write((byte)GetUV_Dimension(i));
			}
			bw.WriteEnumString(Profile);
			bw.WriteEnumBinary(encoding);
			Stream stream2 = encoding switch
			{
				Encoding.Plain => stream, 
				Encoding.LZ4 => new LZ4Stream(stream, LZ4StreamMode.Compress, LZ4StreamFlags.HighCompression), 
				Encoding.LZMA => new MemoryStream(), 
				_ => throw new Exception("Invalid encoding"), 
			};
			bw = new BinaryWriter(stream2);
			positions.ForeachGet(0, VertexCount, delegate(float3 v)
			{
				bw.Write(in v);
			});
			normals?.ForeachGet(0, VertexCount, delegate(float3 v)
			{
				bw.Write(in v);
			});
			tangents?.ForeachGet(0, VertexCount, delegate(float4 v)
			{
				bw.Write(in v);
			});
			colors?.ForeachGet(0, VertexCount, delegate(color v)
			{
				bw.Write(in v);
			});
			boneBindings?.ForeachGet(0, VertexCount, delegate(BoneBinding v)
			{
				Write(bw, ref v);
			});
			for (int num = 0; num < UV_ChannelCount; num++)
			{
				switch (GetUV_Dimension(num))
				{
				case 2:
					GetRawUVs(num).ForeachGet(0, VertexCount, delegate(float2 v)
					{
						bw.Write(in v);
					});
					break;
				case 3:
					GetRawUVs_3D(num).ForeachGet(0, VertexCount, delegate(float3 v)
					{
						bw.Write(in v);
					});
					break;
				case 4:
					GetRawUVs_4D(num).ForeachGet(0, VertexCount, delegate(float4 v)
					{
						bw.Write(in v);
					});
					break;
				}
			}
			foreach (Submesh submesh in submeshes)
			{
				if (submesh == null)
				{
					bw.Write("");
					continue;
				}
				bw.Write(submesh.Topology.ToString());
				submesh.Encode(bw);
			}
			foreach (Bone bone in bones)
			{
				bw.Write(bone.Name);
				bw.Write(in bone.BindPose);
			}
			foreach (BlendShape blendshape in blendshapes)
			{
				bw.Write(blendshape.Name);
				blendshape.Encode(bw);
			}
			switch (encoding)
			{
			case Encoding.LZ4:
				((LZ4Stream)stream2).Flush();
				break;
			case Encoding.LZMA:
				stream2.Position = 0L;
				LZMAHelper.Compress(stream2, stream);
				break;
			default:
				throw new Exception("Invalid encoding");
			case Encoding.Plain:
				break;
			}
		}

		private static bool HasMagicHeader(BinaryReader reader)
		{
			for (int i = 0; i < MAGIC_HEADER_LENGTH; i++)
			{
				if (reader.ReadByte() != MAGIC_HEADER_BYTE(i))
				{
					return false;
				}
			}
			return true;
		}

		public void Decode(Stream stream)
		{
			long position = stream.Position;
			BinaryReader br = new BinaryReader(stream);
			if (!HasMagicHeader(br))
			{
				stream.Position = position;
				LZ4Stream input = new LZ4Stream(stream, LZ4StreamMode.Decompress);
				br = new BinaryReader(input);
				if (!HasMagicHeader(br))
				{
					throw new Exception("Invalid MeshX header");
				}
			}
			int num = br.ReadInt32();
			if (num > 7)
			{
				throw new Exception("MeshX version is higher than the supported one");
			}
			uint data = br.ReadUInt32();
			int num2 = 0;
			int num3 = 0;
			ulong num4 = br.Read7BitEncoded();
			if (num4 == 0L)
			{
				return;
			}
			if (num >= 3)
			{
				num3 = (int)br.Read7BitEncoded();
			}
			else
			{
				num2 = (int)br.Read7BitEncoded();
			}
			int num5 = (int)br.Read7BitEncoded();
			int num6 = 0;
			if (num >= 4)
			{
				num6 = (int)br.Read7BitEncoded();
			}
			int num7 = 1;
			if (num >= 1 && num < 3)
			{
				num7 = (int)br.Read7BitEncoded();
			}
			if (num >= 6)
			{
				int num8 = (int)br.Read7BitEncoded();
				for (int i = 0; i < num8; i++)
				{
					SetUV_Dimension(i, br.ReadByte());
				}
			}
			IncreaseVertexCount((int)num4);
			HasNormals = ReadFlag(ref data);
			HasTangents = ReadFlag(ref data);
			HasColors = ReadFlag(ref data);
			HasBoneBindings = ReadFlag(ref data);
			if (num < 6)
			{
				for (int j = 0; j < 4; j++)
				{
					if (ReadFlag(ref data))
					{
						SetUV_Dimension(j, 2);
					}
				}
			}
			ColorProfile profile = ColorProfile.sRGB;
			if (num > 6)
			{
				profile = br.ReadEnumString<ColorProfile>();
			}
			Profile = profile;
			if (num >= 2)
			{
				switch (br.ReadEnumBinary<Encoding>())
				{
				case Encoding.LZ4:
				{
					LZ4Stream input2 = new LZ4Stream(stream, LZ4StreamMode.Decompress);
					br = new BinaryReader(input2);
					break;
				}
				case Encoding.LZMA:
				{
					MemoryStream memoryStream = new MemoryStream();
					LZMAHelper.Decompress(stream, memoryStream);
					memoryStream.Position = 0L;
					br = new BinaryReader(memoryStream);
					break;
				}
				default:
					throw new Exception("Invalid encoding");
				case Encoding.Plain:
					break;
				}
			}
			positions.ForeachSet(0, VertexCount, () => br.Read3D_Single());
			normals?.ForeachSet(0, VertexCount, () => br.Read3D_Single());
			tangents?.ForeachSet(0, VertexCount, () => br.Read4D_Single());
			colors?.ForeachSet(0, VertexCount, () => br.ReadColor());
			boneBindings?.ForeachSet(0, VertexCount, () => ReadBoneBinding(br));
			if (boneBindings != null && num < 5)
			{
				for (int num9 = 0; num9 < VertexCount; num9++)
				{
					RawBoneBindings[num9].Normalize();
				}
			}
			for (int num10 = 0; num10 < UV_ChannelCount; num10++)
			{
				switch (GetUV_Dimension(num10))
				{
				case 2:
					GetRawUVs(num10).ForeachSet(0, VertexCount, () => br.Read2D_Single());
					break;
				case 3:
					GetRawUVs_3D(num10).ForeachSet(0, VertexCount, () => br.Read3D_Single());
					break;
				case 4:
					GetRawUVs_4D(num10).ForeachSet(0, VertexCount, () => br.Read4D_Single());
					break;
				}
			}
			if (num >= 3)
			{
				for (int num11 = 0; num11 < num3; num11++)
				{
					string value = br.ReadString();
					if (!string.IsNullOrEmpty(value))
					{
						SubmeshTopology topology = (SubmeshTopology)Enum.Parse(typeof(SubmeshTopology), value);
						TryGetSubmesh(topology, num11).Decode(br);
					}
				}
			}
			else if (num7 == 1)
			{
				TriangleSubmesh triangleSubmesh = TryGetSubmesh<TriangleSubmesh>();
				triangleSubmesh.IncreaseCount(num2);
				for (int num12 = 0; num12 < num2; num12++)
				{
					int v = br.ReadInt32();
					int v2 = br.ReadInt32();
					int v3 = br.ReadInt32();
					triangleSubmesh.SetTriangle(num12, v, v2, v3);
				}
			}
			else
			{
				trig[] array = new trig[num2];
				int[] array2 = new int[num2];
				int[] array3 = new int[num7];
				TriangleSubmesh[] array4 = new TriangleSubmesh[num7];
				int[] array5 = new int[num7];
				array.ForeachSet(0, num2, () => new trig(br.ReadInt32(), br.ReadInt32(), br.ReadInt32()));
				array2.ForeachSet(0, num2, () => br.ReadInt32());
				for (int num13 = 0; num13 < array2.Length; num13++)
				{
					array3[array2[num13]]++;
				}
				for (int num14 = 0; num14 < array3.Length; num14++)
				{
					array4[num14] = AddSubmesh<TriangleSubmesh>();
					array4[num14].IncreaseCount(array3[num14]);
				}
				for (int num15 = 0; num15 < array.Length; num15++)
				{
					trig trig2 = array[num15];
					int num16 = array2[num15];
					array4[num16].SetTriangle(array5[num16]++, trig2.v0, trig2.v1, trig2.v2);
				}
			}
			for (int num17 = 0; num17 < num5; num17++)
			{
				Bone bone = new Bone(br.ReadString(), this);
				bone.BindPose = br.Read4x4MatrixSingle();
				bones.Add(bone);
			}
			for (int num18 = 0; num18 < num6; num18++)
			{
				string name = br.ReadString();
				AddBlendShape(name).Decode(br);
			}
		}

		internal static uint EncodeFlags(params bool[] flags)
		{
			uint num = 0u;
			int num2 = 0;
			foreach (bool flag in flags)
			{
				num |= (flag ? 1u : 0u) << num2++;
			}
			return num;
		}

		internal static bool ReadFlag(ref uint data)
		{
			ReadFlag(ref data, out var flag);
			return flag;
		}

		private static void ReadFlag(ref uint data, out bool flag)
		{
			flag = (data & 1) != 0;
			data >>= 1;
		}

		private static void Write(BinaryWriter bw, ref BoneBinding binding)
		{
			bw.Write7BitEncoded((ulong)binding.boneIndex0);
			bw.Write7BitEncoded((ulong)binding.boneIndex1);
			bw.Write7BitEncoded((ulong)binding.boneIndex2);
			bw.Write7BitEncoded((ulong)binding.boneIndex3);
			bw.Write(binding.weight0);
			bw.Write(binding.weight1);
			bw.Write(binding.weight2);
			bw.Write(binding.weight3);
		}

		private static BoneBinding ReadBoneBinding(BinaryReader br)
		{
			return new BoneBinding
			{
				boneIndex0 = (int)br.Read7BitEncoded(),
				boneIndex1 = (int)br.Read7BitEncoded(),
				boneIndex2 = (int)br.Read7BitEncoded(),
				boneIndex3 = (int)br.Read7BitEncoded(),
				weight0 = br.ReadSingle(),
				weight1 = br.ReadSingle(),
				weight2 = br.ReadSingle(),
				weight3 = br.ReadSingle()
			};
		}

		public float3 TransformVertex(int index, Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			return boneBindings[index].TransformPosition(this, in positions[index], boneTransforms);
		}

		public void TransformAllVertices(Span<float3> targetPoses, Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			if (targetPoses.Length < VertexCount)
			{
				throw new ArgumentOutOfRangeException("targetPoses");
			}
			for (int i = 0; i < VertexCount; i++)
			{
				targetPoses[i] = boneBindings[i].TransformPosition(this, in positions[i], boneTransforms);
			}
		}

		public void TransformAllNormals(Span<float3> targetNormals, Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			if (targetNormals.Length < VertexCount)
			{
				throw new ArgumentOutOfRangeException("targetNormals");
			}
			if (!HasNormals)
			{
				throw new Exception("Mesh doesn't have normals");
			}
			for (int i = 0; i < VertexCount; i++)
			{
				targetNormals[i] = boneBindings[i].TransformDirection(this, in normals[i], boneTransforms).Normalized;
			}
		}

		public void TransformAllTangents(Span<float4> targetTangents, Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			if (targetTangents.Length < VertexCount)
			{
				throw new ArgumentOutOfRangeException("targetTangents");
			}
			if (!HasTangents)
			{
				throw new Exception("Mesh doesn't have tangents");
			}
			for (int i = 0; i < VertexCount; i++)
			{
				float4 @float = tangents[i];
				targetTangents[i] = new float4(boneBindings[i].TransformDirection(this, @float.xyz, boneTransforms).Normalized, @float.w);
			}
		}

		public void BakeSkinnedMesh(Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			TransformAllVertices(positions, boneTransforms);
			if (HasNormals)
			{
				TransformAllNormals(normals, boneTransforms);
			}
			if (HasTangents)
			{
				TransformAllTangents(tangents, boneTransforms);
			}
			HasBoneBindings = false;
			ClearBones();
		}

		public Elements.Core.BoundingBox ComputeSkinnedBounds(Span<float4x4> boneTransforms)
		{
			VerifySkinnedTransormation(boneTransforms);
			Elements.Core.BoundingBox result = Elements.Core.BoundingBox.Empty();
			for (int i = 0; i < VertexCount; i++)
			{
				float3 point = boneBindings[i].TransformPosition(this, in positions[i], boneTransforms);
				if (!point.IsInfinity && !point.IsNaN)
				{
					result.Encapsulate(in point);
				}
			}
			return result;
		}

		private void VerifySkinnedTransormation(Span<float4x4> boneTransforms)
		{
			if (!HasBoneBindings)
			{
				throw new InvalidOperationException("Mesh doesn't have bone bindings");
			}
			if (boneTransforms.Length < BoneCount)
			{
				throw new ArgumentException("Insufficient number of bone transforms");
			}
		}

		public void GetVertices<T>(T[] array, Func<float3, T> convert)
		{
			if (array.Length < VertexCount)
			{
				throw new ArgumentOutOfRangeException("array.Length");
			}
			for (int i = 0; i < VertexCount; i++)
			{
				array[i] = convert(positions[i]);
			}
		}

		public void GetTriangleIndicies(int[] array, int arrayOffset, TriangleSubmesh triangles)
		{
			if (array.Length - arrayOffset < triangles.IndicieCount)
			{
				throw new ArgumentOutOfRangeException("array.Length");
			}
			if (triangles.IndicieCount > 0)
			{
				Buffer.BlockCopy(triangles.indicies, 0, array, arrayOffset * 4, triangles.IndicieCount * 4);
			}
		}

		public bool CompareTriangleIndicies(int[] array, int arrayOffset, TriangleSubmesh triangles)
		{
			int num = triangles.Count * 3;
			if (array.Length - arrayOffset < num)
			{
				return false;
			}
			for (int i = 0; i < num; i++)
			{
				if (array[arrayOffset + i] != triangles.indicies[i])
				{
					return false;
				}
			}
			return true;
		}

		public void GetTriangleIndicies(int[] array)
		{
			if (array.Length < TotalTriangleCount * 3)
			{
				throw new ArgumentOutOfRangeException("array.Length");
			}
			int num = 0;
			foreach (Submesh submesh in submeshes)
			{
				if (submesh is TriangleSubmesh triangleSubmesh)
				{
					GetTriangleIndicies(array, num, triangleSubmesh);
					num += triangleSubmesh.IndicieCount;
				}
			}
		}

		public bool CompareTriangleIndicies(int[] array)
		{
			if (array.Length != TotalTriangleCount * 3)
			{
				return false;
			}
			int num = 0;
			foreach (Submesh submesh in submeshes)
			{
				if (submesh is TriangleSubmesh triangleSubmesh)
				{
					if (!CompareTriangleIndicies(array, num, triangleSubmesh))
					{
						return false;
					}
					num += triangleSubmesh.IndicieCount;
				}
			}
			return true;
		}

		public Vertex AddVertex(Vertex vertex)
		{
			Vertex result = AddVertex();
			result.Copy(vertex);
			return result;
		}

		public Vertex DuplicateVertex(int index)
		{
			Vertex result = AddVertex();
			result.Copy(GetVertex(index));
			return result;
		}

		public Triangle AddTriangle(Triangle triangle)
		{
			Triangle result = AddTriangle();
			result.Copy(triangle);
			return result;
		}

		public void FlipNormals()
		{
			for (int i = 0; i < VertexCount; i++)
			{
				ref float3 reference = ref normals[i];
				reference *= -1;
			}
			for (int j = 0; j < BlendShapeCount; j++)
			{
				BlendShape blendShape = GetBlendShape(j);
				if (!blendShape.HasNormals)
				{
					continue;
				}
				foreach (BlendShapeFrame frame in blendShape.Frames)
				{
					for (int k = 0; k < VertexCount; k++)
					{
						ref float3 reference2 = ref frame.RawNormals[k];
						reference2 *= -1;
					}
				}
			}
		}

		public void ReverseWinding()
		{
			foreach (Submesh submesh in submeshes)
			{
				if (submesh is TriangleSubmesh triangleSubmesh)
				{
					for (int i = 0; i < triangleSubmesh.IndicieCount; i += 3)
					{
						int num = triangleSubmesh.RawIndicies[i];
						triangleSubmesh.RawIndicies[i] = triangleSubmesh.RawIndicies[i + 2];
						triangleSubmesh.RawIndicies[i + 2] = num;
					}
				}
			}
		}

		public void MakeDualSided()
		{
			int vertexCount = VertexCount;
			AddVertices(vertexCount);
			for (int i = 0; i < vertexCount; i++)
			{
				RawPositions[vertexCount + i] = RawPositions[i];
			}
			if (HasNormals)
			{
				for (int j = 0; j < vertexCount; j++)
				{
					RawNormals[vertexCount + j] = -RawNormals[j];
				}
			}
			if (HasTangents)
			{
				for (int k = 0; k < vertexCount; k++)
				{
					RawTangents[vertexCount + k] = RawTangents[k] * new float4(1f, 1f, 1f, -1f);
				}
			}
			if (HasColors)
			{
				for (int l = 0; l < vertexCount; l++)
				{
					RawColors[vertexCount + l] = -RawColors[l];
				}
			}
			for (int m = 0; m < UV_ChannelCount; m++)
			{
				switch (GetUV_Dimension(m))
				{
				case 2:
				{
					float2[] rawUVs = GetRawUVs(m);
					for (int num = 0; num < vertexCount; num++)
					{
						rawUVs[vertexCount + num] = rawUVs[num];
					}
					break;
				}
				case 3:
				{
					float3[] rawUVs_3D = GetRawUVs_3D(m);
					for (int num2 = 0; num2 < vertexCount; num2++)
					{
						rawUVs_3D[vertexCount + num2] = rawUVs_3D[num2];
					}
					break;
				}
				case 4:
				{
					float4[] rawUVs_4D = GetRawUVs_4D(m);
					for (int n = 0; n < vertexCount; n++)
					{
						rawUVs_4D[vertexCount + n] = rawUVs_4D[n];
					}
					break;
				}
				}
			}
			if (HasBoneBindings)
			{
				for (int num3 = 0; num3 < vertexCount; num3++)
				{
					RawBoneBindings[vertexCount + num3] = RawBoneBindings[num3];
				}
			}
			foreach (Submesh submesh in Submeshes)
			{
				if (submesh is TriangleSubmesh { Count: var count } triangleSubmesh)
				{
					triangleSubmesh.AddTriangles(count);
					for (int num4 = 0; num4 < count; num4++)
					{
						Triangle triangle = triangleSubmesh.GetTriangle(num4);
						triangleSubmesh.SetTriangle(count + num4, triangle.Vertex2IndexUnsafe + vertexCount, triangle.Vertex1IndexUnsafe + vertexCount, triangle.Vertex0IndexUnsafe + vertexCount);
					}
				}
			}
		}

		public void RecalculateNormals()
		{
			HasNormals = true;
			try
			{
				for (int i = 0; i < VertexCount; i++)
				{
					normals[i] = float3.Zero;
				}
				foreach (Triangle triangle in Triangles)
				{
					if (triangle.TryComputeSurfaceNormalUnsafe(out var normal))
					{
						ref float3 reference = ref normals[triangle.Vertex0IndexUnsafe];
						reference += normal;
						ref float3 reference2 = ref normals[triangle.Vertex1IndexUnsafe];
						reference2 += normal;
						ref float3 reference3 = ref normals[triangle.Vertex2IndexUnsafe];
						reference3 += normal;
					}
				}
				for (int j = 0; j < VertexCount; j++)
				{
					normals[j] = normals[j].Normalized;
				}
			}
			catch (Exception innerException)
			{
				throw new Exception("Error recalculating normals. Mesh:\n" + ToString(), innerException);
			}
		}

		public void RecalculateNormalsMerged(double cellSize = 0.001)
		{
			HasNormals = true;
			using (SmoothNormalsContext smoothNormalsContext = new SmoothNormalsContext(cellSize))
			{
				foreach (Triangle triangle in Triangles)
				{
					if (triangle.TryComputeSurfaceNormalUnsafe(out var normal))
					{
						float3 position = triangle.Vertex0.PositionUnsafe;
						float3 position2 = triangle.Vertex1.PositionUnsafe;
						float3 position3 = triangle.Vertex2.PositionUnsafe;
						smoothNormalsContext.StoreNormal(in normal, in position);
						smoothNormalsContext.StoreNormal(in normal, in position2);
						smoothNormalsContext.StoreNormal(in normal, in position3);
					}
				}
				foreach (Triangle triangle2 in Triangles)
				{
					smoothNormalsContext.AssignNormal(triangle2.Vertex0);
					smoothNormalsContext.AssignNormal(triangle2.Vertex1);
					smoothNormalsContext.AssignNormal(triangle2.Vertex2);
				}
			}
			for (int i = 0; i < VertexCount; i++)
			{
				RawNormals[i] = RawNormals[i].Normalized;
			}
		}

		public void RecalculateNormals(TriangleCollection triangles, bool onlyFlagged = false, bool removeFlag = false)
		{
			HasNormals = true;
			triangles.UpdateIndexes();
			foreach (Triangle triangle in triangles)
			{
				if (onlyFlagged)
				{
					if (flags[triangle.Vertex0IndexUnsafe])
					{
						normals[triangle.Vertex0IndexUnsafe] = float3.Zero;
					}
					if (flags[triangle.Vertex1IndexUnsafe])
					{
						normals[triangle.Vertex1IndexUnsafe] = float3.Zero;
					}
					if (flags[triangle.Vertex2IndexUnsafe])
					{
						normals[triangle.Vertex2IndexUnsafe] = float3.Zero;
					}
				}
				else
				{
					normals[triangle.Vertex0IndexUnsafe] = float3.Zero;
					normals[triangle.Vertex1IndexUnsafe] = float3.Zero;
					normals[triangle.Vertex2IndexUnsafe] = float3.Zero;
				}
			}
			foreach (Triangle triangle2 in triangles)
			{
				if (!triangle2.TryComputeSurfaceNormalUnsafe(out var normal))
				{
					continue;
				}
				if (onlyFlagged)
				{
					if (flags[triangle2.Vertex0IndexUnsafe])
					{
						ref float3 reference = ref normals[triangle2.Vertex0IndexUnsafe];
						reference += normal;
					}
					if (flags[triangle2.Vertex1IndexUnsafe])
					{
						ref float3 reference2 = ref normals[triangle2.Vertex1IndexUnsafe];
						reference2 += normal;
					}
					if (flags[triangle2.Vertex2IndexUnsafe])
					{
						ref float3 reference3 = ref normals[triangle2.Vertex2IndexUnsafe];
						reference3 += normal;
					}
				}
				else
				{
					ref float3 reference4 = ref normals[triangle2.Vertex0IndexUnsafe];
					reference4 += normal;
					ref float3 reference5 = ref normals[triangle2.Vertex1IndexUnsafe];
					reference5 += normal;
					ref float3 reference6 = ref normals[triangle2.Vertex2IndexUnsafe];
					reference6 += normal;
				}
			}
			foreach (Triangle triangle3 in triangles)
			{
				if (onlyFlagged)
				{
					if (flags[triangle3.Vertex0IndexUnsafe])
					{
						normals[triangle3.Vertex0IndexUnsafe] = normals[triangle3.Vertex0IndexUnsafe].Normalized;
						if (removeFlag)
						{
							flags[triangle3.Vertex0IndexUnsafe] = false;
						}
					}
					if (flags[triangle3.Vertex1IndexUnsafe])
					{
						normals[triangle3.Vertex1IndexUnsafe] = normals[triangle3.Vertex1IndexUnsafe].Normalized;
						if (removeFlag)
						{
							flags[triangle3.Vertex1IndexUnsafe] = false;
						}
					}
					if (flags[triangle3.Vertex2IndexUnsafe])
					{
						normals[triangle3.Vertex2IndexUnsafe] = normals[triangle3.Vertex2IndexUnsafe].Normalized;
						if (removeFlag)
						{
							flags[triangle3.Vertex2IndexUnsafe] = false;
						}
					}
				}
				else
				{
					normals[triangle3.Vertex0IndexUnsafe] = normals[triangle3.Vertex0IndexUnsafe].Normalized;
					normals[triangle3.Vertex1IndexUnsafe] = normals[triangle3.Vertex1IndexUnsafe].Normalized;
					normals[triangle3.Vertex2IndexUnsafe] = normals[triangle3.Vertex2IndexUnsafe].Normalized;
				}
			}
		}

		public bool RecalculateTangents(TriangleCollection triangles = null, int uvChannel = 0)
		{
			if (!HasNormals || !HasUV_2D(uvChannel))
			{
				return false;
			}
			HasTangents = true;
			float2[] rawUVs = GetRawUVs(uvChannel);
			RawValueList<float3> list = Pool.BorrowRawValueList<float3>();
			if (list.Capacity < VertexCount)
			{
				list.Capacity = VertexCount;
			}
			float3[] elements = list.Elements;
			if (triangles == null)
			{
				for (int i = 0; i < VertexCount; i++)
				{
					tangents[i] = float4.Zero;
					elements[i] = float3.Zero;
				}
			}
			else
			{
				for (int j = 0; j < triangles.Count; j++)
				{
					Triangle triangle = triangles[j];
					tangents[triangle.Vertex0IndexUnsafe] = float4.Zero;
					tangents[triangle.Vertex1IndexUnsafe] = float4.Zero;
					tangents[triangle.Vertex2IndexUnsafe] = float4.Zero;
					elements[triangle.Vertex0IndexUnsafe] = float3.Zero;
					elements[triangle.Vertex1IndexUnsafe] = float3.Zero;
					elements[triangle.Vertex2IndexUnsafe] = float3.Zero;
				}
			}
			if (triangles == null)
			{
				foreach (Triangle triangle2 in Triangles)
				{
					CalcTangentValues(triangle2, rawUVs, elements);
				}
			}
			else
			{
				foreach (Triangle triangle3 in triangles)
				{
					CalcTangentValues(triangle3, rawUVs, elements);
				}
			}
			if (triangles == null)
			{
				for (int k = 0; k < VertexCount; k++)
				{
					tangents[k] = CalcTangent(in normals[k], tangents[k].xyz, in elements[k]);
				}
			}
			else
			{
				foreach (Triangle triangle4 in triangles)
				{
					for (int l = 0; l < 3; l++)
					{
						int vertexIndexUnsafe = triangle4.GetVertexIndexUnsafe(l);
						if (tangents[vertexIndexUnsafe].w == 0f)
						{
							tangents[vertexIndexUnsafe] = CalcTangent(in normals[vertexIndexUnsafe], tangents[vertexIndexUnsafe].xyz, in elements[vertexIndexUnsafe]);
						}
					}
				}
			}
			Pool.Return(ref list);
			return true;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private void CalcTangentValues(Triangle t, float2[] uvs, float3[] binorms)
		{
			float3 b = positions[t.Vertex0IndexUnsafe];
			float3 a = positions[t.Vertex1IndexUnsafe];
			float3 a2 = positions[t.Vertex2IndexUnsafe];
			float2 b2 = uvs[t.Vertex0IndexUnsafe];
			float2 a3 = uvs[t.Vertex1IndexUnsafe];
			float2 a4 = uvs[t.Vertex2IndexUnsafe];
			float3 v = a - b;
			float3 v2 = a2 - b;
			float2 @float = a3 - b2;
			float2 float2 = a4 - b2;
			float num = 1f / (@float.x * float2.y - float2.x * @float.y);
			float3 v3 = (float2.y * v - @float.y * v2) * num;
			float3 b3 = (@float.x * v2 - float2.x * v) * num;
			ref float4 reference = ref tangents[t.Vertex0IndexUnsafe];
			reference += (float4)v3;
			ref float3 reference2 = ref binorms[t.Vertex0IndexUnsafe];
			reference2 += b3;
			ref float4 reference3 = ref tangents[t.Vertex1IndexUnsafe];
			reference3 += (float4)v3;
			ref float3 reference4 = ref binorms[t.Vertex1IndexUnsafe];
			reference4 += b3;
			ref float4 reference5 = ref tangents[t.Vertex2IndexUnsafe];
			reference5 += (float4)v3;
			ref float3 reference6 = ref binorms[t.Vertex2IndexUnsafe];
			reference6 += b3;
		}

		[MethodImpl(MethodImplOptions.AggressiveInlining)]
		private static float4 CalcTangent(in float3 nor, in float3 tan0, in float3 tan1)
		{
			float3 xyz = (tan0 - nor * MathX.Dot(in nor, in tan0)).Normalized;
			float w = ((!(MathX.Dot(MathX.Cross(in nor, in tan0), in tan1) < 0f)) ? 1 : (-1));
			return new float4(in xyz, w);
		}

		public void SortBoneWeights()
		{
			for (int i = 0; i < VertexCount; i++)
			{
				boneBindings[i].Sort();
			}
		}

		public void NormalizeBoneWeights()
		{
			for (int i = 0; i < VertexCount; i++)
			{
				boneBindings[i].Normalize();
			}
		}

		public void SortTrimAndNormalizeBoneWeights(float trimThreshold = 0.0001f, int maxBoneCount = int.MaxValue)
		{
			for (int i = 0; i < VertexCount; i++)
			{
				boneBindings[i].Sort();
				boneBindings[i].TrimBoneCount(maxBoneCount);
				boneBindings[i].Trim(trimThreshold);
				boneBindings[i].Normalize();
			}
		}

		public void FillInEmptyBindings(int boneIndex)
		{
			for (int i = 0; i < VertexCount; i++)
			{
				boneBindings[i].FillInEmpty(boneIndex);
			}
		}

		public void StripEmptyBlendshapes(List<int> removedBlendshapes = null)
		{
			for (int num = BlendShapeCount - 1; num >= 0; num--)
			{
				BlendShape blendShape = GetBlendShape(num);
				bool flag = true;
				for (int i = 0; i < blendShape.FrameCount; i++)
				{
					BlendShapeFrame blendShapeFrame = blendShape[i];
					for (int j = 0; j < VertexCount; j++)
					{
						if (IsValidBlendshapeValue(in blendShapeFrame.positions[j]) || (blendShape.HasNormals && IsValidBlendshapeValue(in blendShapeFrame.normals[j])) || (blendShape.HasTangents && IsValidBlendshapeValue(in blendShapeFrame.tangents[j])))
						{
							flag = false;
							break;
						}
					}
					if (!flag)
					{
						break;
					}
				}
				if (flag)
				{
					RemoveBlendShape(num);
					removedBlendshapes?.Add(num);
				}
			}
		}

		public int StripEmptySubmeshes(List<int> indexRemap)
		{
			for (int i = 0; i < SubmeshCount; i++)
			{
				if (GetSubmesh(i).Count != 0)
				{
					indexRemap.Add(i);
				}
			}
			int result = SubmeshCount - indexRemap.Count;
			submeshes.RemoveAll((Submesh s) => s.Count == 0);
			return result;
		}

		public int StripEmptyBones()
		{
			return StripEmptyBones(new List<int>());
		}

		public int StripEmptyBones(List<int> remapIndex, Predicate<Bone> filter = null)
		{
			return StripEmptyBones(CalculateBoneMetadata(), remapIndex, filter);
		}

		public int StripEmptyBones(IReadOnlyList<BoneMetadata> precomputedMetadata, List<int> remapIndex, Predicate<Bone> filter = null)
		{
			remapIndex.Clear();
			int num = 0;
			for (int i = 0; i < BoneCount; i++)
			{
				BoneMetadata boneMetadata = precomputedMetadata[i];
				if ((filter != null && filter(bones[i])) || boneMetadata.TotalVertexCount > 0)
				{
					remapIndex.Add(num++);
				}
				else
				{
					remapIndex.Add(-1);
				}
			}
			int result = BoneCount - num;
			for (int num2 = remapIndex.Count - 1; num2 >= 0; num2--)
			{
				if (remapIndex[num2] == -1)
				{
					RemoveBoneAt(num2, autoUpdateBindings: false);
				}
			}
			if (HasBoneBindings)
			{
				for (int j = 0; j < VertexCount; j++)
				{
					ref BoneBinding reference = ref boneBindings[j];
					for (int k = 0; k < 4; k++)
					{
						int boneIndex = reference.GetBoneIndex(k);
						if (boneIndex >= 0)
						{
							reference.SetBoneIndex(k, remapIndex[boneIndex]);
						}
					}
				}
			}
			return result;
		}

		public void StripBlendshapeNormals()
		{
			foreach (BlendShape blendShape in BlendShapes)
			{
				blendShape.HasNormals = false;
			}
		}

		public void StripBlendshapeTangents()
		{
			foreach (BlendShape blendShape in BlendShapes)
			{
				blendShape.HasTangents = false;
			}
