		public void BakeBlendShapes(Dictionary<int, float> blendshapes)
		{
			Dictionary<BlendShape, float> dictionary = new Dictionary<BlendShape, float>();
			foreach (KeyValuePair<int, float> blendshape in blendshapes)
			{
				dictionary.Add(GetBlendShape(blendshape.Key), blendshape.Value);
			}
			BakeBlendShapes(dictionary);
		}

		public void BakeBlendShapes(Dictionary<BlendShape, float> blendshapes)
		{
			foreach (KeyValuePair<BlendShape, float> blendshape in blendshapes)
			{
				if (blendshape.Key.Mesh != this)
				{
					throw new ArgumentException("Blendshape doesn't belong to this mesh!");
				}
				if (MathX.Approximately(blendshape.Value, 0f))
				{
					continue;
				}
				if (blendshape.Key.FrameCount > 1)
				{
					throw new NotImplementedException("Baking blendshapes with multiple frames isn't implemented");
				}
				BlendShapeFrame blendShapeFrame = blendshape.Key[0];
				float value = blendshape.Value;
				for (int i = 0; i < VertexCount; i++)
				{
					ref float3 reference = ref RawPositions[i];
					reference += blendShapeFrame.RawPositions[i] * value;
				}
				if (blendshape.Key.HasNormals)
				{
					for (int j = 0; j < VertexCount; j++)
					{
						ref float3 reference2 = ref RawNormals[j];
						reference2 += blendShapeFrame.RawNormals[j] * value;
						RawNormals[j] = RawNormals[j].Normalized;
					}
				}
				if (blendshape.Key.HasTangents)
				{
					for (int k = 0; k < VertexCount; k++)
					{
						float3 xyz = (RawTangents[k].xyz + blendShapeFrame.RawTangents[k] * value).Normalized;
						ref float4 reference3 = ref RawTangents[k];
						reference3 += new float4(in xyz, 0f);
					}
				}
			}
			foreach (KeyValuePair<BlendShape, float> blendshape2 in blendshapes)
			{
				RemoveBlendShape(blendshape2.Key);
			}
		}

		private GeometryMask ComputeGeometryAffectedByBlendShapes(IEnumerable<BlendShape> blendshapes)
		{
			GeometryMask geometryMask = new GeometryMask(this);
			foreach (BlendShape blendshape in blendshapes)
			{
				foreach (BlendShapeFrame frame in blendshape.Frames)
				{
					for (int i = 0; i < VertexCount; i++)
					{
						if (!geometryMask.IsVertexMasked(i) && (IsValidBlendshapeValue(in frame.RawPositions[i]) || (blendshape.HasNormals && IsValidBlendshapeValue(in frame.RawNormals[i])) || (blendshape.HasTangents && IsValidBlendshapeValue(in frame.RawTangents[i]))))
						{
							geometryMask.MaskVertex(i);
						}
					}
				}
			}
			geometryMask.MaskPrimitivesFromVertices();
			geometryMask.MaskVerticesFromMaskedPrimitives();
			return geometryMask;
		}

		public (MeshX splitMesh, AppendResult mapping) SplitBlendShapesIntoStaticMesh(Dictionary<int, float> blendshapes)
		{
			MeshX meshX = new MeshX();
			meshX.CopyDataChannelFlags(this);
			meshX.HasBoneBindings = false;
			GeometryMask geometryMask = ComputeGeometryAffectedByBlendShapes(blendshapes.Select((KeyValuePair<int, float> k) => this.blendshapes[k.Key]));
			if (geometryMask.MaskedVertexCount == 0)
			{
				return (splitMesh: null, mapping: default(AppendResult));
			}
			GeometryMask mask = geometryMask;
			AppendResult item = meshX.Copy(this, (float4x4?)null, mask);
			Dictionary<int, float> dictionary = new Dictionary<int, float>();
			foreach (KeyValuePair<int, float> blendshape in blendshapes)
			{
				dictionary.Add(item.blendshapeMapping[blendshape.Key], blendshape.Value);
			}
			meshX.BakeBlendShapes(dictionary);
			meshX.ClearBlendShapes();
			meshX.ClearBones();
			item.blendshapeMapping = null;
			item.boneMapping = null;
			geometryMask.ClearVerticesFromUnmarkedPrimitives();
			RemoveGeometry(geometryMask, throwOnRemovedFromSubmeshes: true);
			List<int> list = blendshapes.Keys.ToList();
			list.Sort((int a, int b) => -a.CompareTo(b));
			foreach (int item2 in list)
			{
				RemoveBlendShape(item2);
			}
			return (splitMesh: meshX, mapping: item);
		}

		public void TransformVertexByBlendshapes(int vertexIndex, ref float3 pos, ref float3 normal, ref float4 tangent, Span<float> weights)
		{
			if (weights.Length != BlendShapeCount)
			{
				throw new ArgumentException("Blendshape weight count must match the number of blendshapes");
			}
			float3 a = tangent.xyz;
			for (int i = 0; i < weights.Length; i++)
			{
				if (!MathX.Approximately(weights[i], 0f))
				{
					BlendShape blendShape = blendshapes[i];
					BlendShapeFrame blendShapeFrame = blendShape[0];
					pos += blendShapeFrame.RawPositions[vertexIndex] * weights[i];
					if (blendShape.HasNormals)
					{
						normal += blendShapeFrame.RawNormals[vertexIndex] * weights[i];
					}
					if (blendShape.HasTangents)
					{
						a += blendShapeFrame.RawTangents[vertexIndex] * weights[i];
					}
				}
			}
			normal = normal.Normalized;
			tangent = new float4(a.Normalized, tangent.w);
		}

		public void TransformVertexByBones(int vertexIndex, ref float3 pos, ref float3 normal, ref float4 tangent, Span<float4x4> boneTransforms)
		{
			if (boneTransforms.Length != BoneCount)
			{
				throw new ArgumentException("Bone Transform count must much the number of bones");
			}
			float3 direction = tangent.xyz;
			BoneBinding boneBinding = boneBindings[vertexIndex];
			pos = boneBinding.TransformPosition(this, in pos, boneTransforms);
			normal = boneBinding.TransformDirection(this, in normal, boneTransforms).Normalized;
			tangent = new float4(boneBinding.TransformDirection(this, in direction, boneTransforms).Normalized, tangent.w);
		}

		private static bool IsValidBlendshapeValue(in float3 value)
		{
			return MathX.MaxComponent(MathX.Abs(in value)) >= 0.001f;
		}

		public void SplitBlenshapeByAxis(int blendshapeIndex, Axis3D axis, float center, float transition, string negativeSuffix, string positiveSuffix)
		{
			if (blendshapeIndex < 0 || blendshapeIndex >= BlendShapeCount)
			{
				throw new ArgumentOutOfRangeException("blendshapeIndex");
			}
			BlendShape blendShape = GetBlendShape(blendshapeIndex);
			BlendShape blendShape2 = InsertBlendshapeAt(blendShape.Name + positiveSuffix, blendshapeIndex + 1);
			BlendShape blendShape3 = InsertBlendshapeAt(blendShape.Name + negativeSuffix, blendshapeIndex + 1);
			blendShape3.HasNormals = blendShape.HasNormals;
			blendShape2.HasNormals = blendShape.HasNormals;
			blendShape3.HasTangents = blendShape.HasTangents;
			blendShape2.HasTangents = blendShape.HasTangents;
			foreach (BlendShapeFrame frame in blendShape.Frames)
			{
				blendShape3.AddFrame(frame.Weight);
				blendShape2.AddFrame(frame.Weight);
			}
			for (int i = 0; i < VertexCount; i++)
			{
				float num = MathX.Clamp((RawPositions[i].GetElement(axis) - center) / transition, -0.5f, 0.5f) + 0.5f;
				float num2 = 1f - num;
				for (int j = 0; j < blendShape.FrameCount; j++)
				{
					BlendShapeFrame blendShapeFrame = blendShape[j];
					BlendShapeFrame blendShapeFrame2 = blendShape2[j];
					BlendShapeFrame blendShapeFrame3 = blendShape3[j];
					blendShapeFrame2.positions[i] = blendShapeFrame.positions[i] * num;
					blendShapeFrame3.positions[i] = blendShapeFrame.positions[i] * num2;
					if (blendShape.HasNormals)
					{
						blendShapeFrame2.normals[i] = blendShapeFrame.normals[i] * num;
						blendShapeFrame3.normals[i] = blendShapeFrame.normals[i] * num2;
					}
					if (blendShape.HasTangents)
					{
						blendShapeFrame2.tangents[i] = blendShapeFrame.tangents[i] * num;
						blendShapeFrame3.tangents[i] = blendShapeFrame.tangents[i] * num2;
					}
				}
			}
			RemoveBlendShape(blendShape);
		}

		public void Translate(in float3 offset)
		{
			for (int i = 0; i < VertexCount; i++)
			{
				ref float3 reference = ref positions[i];
				reference += offset;
			}
		}

		public void Rotate(in floatQ rotation)
		{
			for (int i = 0; i < VertexCount; i++)
			{
				positions[i] = rotation * positions[i];
				if (HasNormals)
				{
					normals[i] = rotation * normals[i];
				}
				if (HasTangents)
				{
					tangents[i] = new float4(rotation * ILSpyHelper_AsRefReadOnly(tangents[i].xyz), tangents[i].w);
				}
			}
			static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
			{
				//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
				return ref temp;
			}
		}

		public void Scale(float scale)
		{
			Scale(new float3(scale, scale, scale));
		}

		public void Scale(in float3 scale)
		{
			for (int i = 0; i < VertexCount; i++)
			{
				ref float3 reference = ref positions[i];
				reference *= scale;
			}
		}

		public float3 AverageVertexCenter()
		{
			float3 a = float3.Zero;
			for (int i = 0; i < VertexCount; i++)
			{
				a += positions[i];
			}
			return a / VertexCount;
		}

		public Elements.Core.BoundingBox CalculateBoundingBox()
		{
			int invalidVertexCount;
			return CalculateBoundingBox(out invalidVertexCount);
		}

		public Elements.Core.BoundingBox CalculateBoundingBox(out int invalidVertexCount)
		{
			Elements.Core.BoundingBox result = Elements.Core.BoundingBox.Empty();
			invalidVertexCount = 0;
			for (int i = 0; i < VertexCount; i++)
			{
				float3 point = positions[i];
				if (point.IsValid())
				{
					result.Encapsulate(in point);
				}
				else
				{
					invalidVertexCount++;
				}
			}
			return result;
		}

		public void CalculateTriangleLengths(out float smallest, out float largest, out float average, out float median)
		{
			List<float> list = new List<float>();
			foreach (Triangle triangle in Triangles)
			{
				list.Add(MathX.FilterInvalid(triangle.AverageLength));
			}
			if (list.Count > 0)
			{
				smallest = list.Min();
				largest = list.Max();
				average = list.Average();
				median = list.ReoderAndComputeMedian();
			}
			else
			{
				smallest = 0f;
				largest = 0f;
				average = 0f;
				median = 0f;
			}
		}

