				median = 0f;
			}
		}

		public List<SubmeshMetadata> CalculateSubmeshMetadata()
		{
			List<SubmeshMetadata> list = new List<SubmeshMetadata>();
			foreach (Submesh submesh in Submeshes)
			{
				list.Add(submesh.CalculateMetadata());
			}
			return list;
		}

		public List<BoneMetadata> CalculateBoneMetadata()
		{
			if (BoneCount == 0)
			{
				return null;
			}
			List<BoneMetadata> list = new List<BoneMetadata>(BoneCount);
			for (int i = 0; i < BoneCount; i++)
			{
				list.Add(BoneMetadata.CreateEmpty());
			}
			for (int j = 0; j < VertexCount; j++)
			{
				BoneBinding boneBinding = RawBoneBindings[j];
				for (int k = 0; k < 4; k++)
				{
					boneBinding.GetBinding(k, out var boneIndex, out var weight);
					if (weight > 0f)
					{
						BoneMetadata value = list[boneIndex];
						value.SetVertexCount(k, value.GetVertexCount(k) + 1);
						float3 point = RawPositions[j];
						point = GetBone(boneIndex).BindPose.TransformPoint3x4(in point);
						if (point.IsValid())
						{
							value.bounds.Encapsulate(in point);
						}
						list[boneIndex] = value;
					}
				}
			}
			return list;
		}

		public List<ApproximateBoneBounds> CalculateApproximateBoneBounds()
		{
			return CalculateApproximateBoneBounds(CalculateBoneMetadata());
		}

		public List<ApproximateBoneBounds> CalculateApproximateBoneBounds(IReadOnlyList<BoneMetadata> metadata)
		{
			if (metadata == null)
			{
				return null;
			}
			List<ApproximateBoneBounds> list = new List<ApproximateBoneBounds>();
			List<float3> list2 = Pool.BorrowList<float3>();
			for (int i = 0; i < metadata.Count; i++)
			{
				Elements.Core.BoundingBox bounds = metadata[i].bounds;
				if (!bounds.IsValid)
				{
					continue;
				}
				float4x4 affineInverseFast = GetBone(i).BindPose.AffineInverseFast;
				for (int j = 0; j < 8; j++)
				{
					list2.Add(affineInverseFast.TransformPoint3x4(bounds.GetVertexPoint(j)));
				}
				Elements.Core.BoundingSphere bounds2 = Elements.Core.BoundingSphere.RitterBoundingSphere(list2);
				list2.Clear();
				list.Add(new ApproximateBoneBounds(i, bounds2));
				bool flag;
				do
				{
					flag = false;
					ApproximateBoneBounds value = list[list.Count - 1];
					for (int num = list.Count - 2; num >= 0; num--)
					{
						ApproximateBoneBounds approximateBoneBounds = list[num];
						if (value.bounds.Intersects(approximateBoneBounds.bounds))
						{
							value.bounds.Encapsulate(approximateBoneBounds.bounds);
							value.rootBoneIndex = MathX.Min(value.rootBoneIndex, approximateBoneBounds.rootBoneIndex);
							list.RemoveAt(num);
							flag = true;
						}
					}
					list[list.Count - 1] = value;
				}
				while (flag);
			}
			list.Sort((ApproximateBoneBounds a, ApproximateBoneBounds b) => a.rootBoneIndex.CompareTo(b.rootBoneIndex));
			Pool.Return(ref list2);
			for (int num2 = 0; num2 < list.Count; num2++)
			{
				ApproximateBoneBounds value2 = list[num2];
				Bone bone = GetBone(value2.rootBoneIndex);
				float3 center = bone.BindPose.TransformPoint3x4(in value2.bounds.center);
				float magnitude = bone.BindPose.TransformVector(float3.One.Normalized * value2.bounds.radius).Magnitude;
				value2.bounds = new Elements.Core.BoundingSphere(in center, magnitude);
				list[num2] = value2;
			}
			return list;
		}

		public void GenerateFlatShadingTriangles(VertexCollection newVertices = null, VertexCollection originalVertices = null)
		{
			foreach (Submesh submesh in submeshes)
			{
				TriangleSubmesh triangles = submesh as TriangleSubmesh;
				if (triangles != null)
				{
					GenerateFlatShadingTriangles_Internal(triangles.Count, (int i) => triangles.GetTriangle(i), newVertices, originalVertices);
				}
			}
		}

		public void GenerateFlatShadingTriangles(TriangleCollection triangles, VertexCollection newVertices = null, VertexCollection originalVertices = null)
		{
			if (triangles == null)
			{
				GenerateFlatShadingTriangles(newVertices, originalVertices);
				return;
			}
			GenerateFlatShadingTriangles_Internal(triangles.Count, (int i) => triangles[i], newVertices, originalVertices);
		}

		private void GenerateFlatShadingTriangles_Internal(int triangleCount, Func<int, Triangle> getTriangle, VertexCollection newVertices = null, VertexCollection originalVertices = null)
		{
			for (int i = 0; i < triangleCount; i++)
			{
				Triangle triangle = getTriangle(i);
				Vertex vertex = AddVertex(triangle.Vertex0);
				Vertex vertex2 = AddVertex(triangle.Vertex1);
				Vertex vertex3 = AddVertex(triangle.Vertex2);
				if (originalVertices != null)
				{
					originalVertices.Add(triangle.Vertex0);
					originalVertices.Add(triangle.Vertex1);
					originalVertices.Add(triangle.Vertex2);
				}
				if (newVertices != null)
				{
					newVertices.Add(vertex);
					newVertices.Add(vertex2);
					newVertices.Add(vertex3);
				}
				triangle.Set(vertex, vertex2, vertex3);
			}
		}

		public void ConvertToFlatShading()
		{
			int vertexCount = VertexCount;
			GenerateFlatShadingTriangles(null, null, null);
			RecalculateNormals();
			RemoveVertices(0, vertexCount);
		}

		public void MergeSubmeshesByKey(List<object> keys, List<int> sourceIndexes)
		{
			if (keys == null)
			{
				throw new ArgumentNullException("keys");
			}
			if (keys.Count != SubmeshCount)
			{
				throw new ArgumentException("keys");
			}
			List<int> list = new List<int>();
			Dictionary<object, Submesh> dictionary = new Dictionary<object, Submesh>();
			object obj = new object();
			for (int i = 0; i < SubmeshCount; i++)
			{
				Submesh submesh = GetSubmesh(i);
				SubmeshMergeKey submeshMergeKey = new SubmeshMergeKey(keys[i] ?? obj, submesh.Topology);
				if (dictionary.TryGetValue(submeshMergeKey, out var value))
				{
					value.Append(submesh);
					list.Add(i);
				}
				else
				{
					dictionary.Add(submeshMergeKey, submesh);
					sourceIndexes.Add(submesh.Index);
				}
			}
			for (int num = list.Count - 1; num >= 0; num--)
			{
				RemoveSubmesh(list[num]);
			}
		}

		public MeshX SeparateGeometryUnaffectedByBlendshapes()
		{
			if (BlendShapeCount == 0)
			{
				return null;
			}
			GeometryMask geometryMask = ComputeGeometryAffectedByBlendShapes(BlendShapes);
			if (geometryMask.AllVerticesMasked)
			{
				return null;
			}
			MeshX meshX = new MeshX();
			meshX.CopyDataChannelFlags(this);
			foreach (Bone bone in Bones)
			{
				meshX.AddBone(bone.Name).BindPose = bone.BindPose;
			}
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			for (int i = 0; i < SubmeshCount; i++)
			{
				Submesh submesh = GetSubmesh(i);
				Submesh submesh2 = meshX.AddSubmesh(submesh.Topology);
				for (int j = 0; j < submesh.Count; j++)
				{
					if (geometryMask.IsPrimitiveMasked(i, j))
					{
						continue;
					}
					int indicieCount = submesh2.IndicieCount;
					submesh2.IncreaseCount(1);
					for (int k = 0; k < submesh.IndiciesPerElement; k++)
					{
						int num = submesh.RawIndicies[j * submesh.IndiciesPerElement + k];
						if (!dictionary.TryGetValue(num, out var value))
						{
							value = meshX.VertexCount;
							meshX.AddVertex(GetVertex(num));
							dictionary.Add(num, value);
						}
						submesh2.RawIndicies[indicieCount + k] = value;
					}
				}
			}
			dictionary.Clear();
			int num2 = 0;
			for (int l = 0; l < VertexCount; l++)
			{
				if (!geometryMask.IsVertexMasked(l))
				{
					continue;
				}
				if (l != num2)
				{
					GetVertex(num2).Copy(GetVertex(l));
					foreach (BlendShape blendShape in BlendShapes)
					{
						foreach (BlendShapeFrame frame in blendShape.Frames)
						{
							frame.RawPositions[num2] = frame.RawPositions[l];
							if (blendShape.HasNormals)
							{
								frame.RawNormals[num2] = frame.RawNormals[l];
							}
							if (blendShape.HasTangents)
							{
								frame.RawTangents[num2] = frame.RawTangents[l];
							}
						}
					}
				}
				dictionary.Add(l, num2++);
			}
			VertexCount = num2;
			for (int m = 0; m < SubmeshCount; m++)
			{
				Submesh submesh3 = GetSubmesh(m);
				num2 = 0;
				for (int n = 0; n < submesh3.Count; n++)
				{
					if (geometryMask.IsPrimitiveMasked(m, n))
					{
						int num3 = n * submesh3.IndiciesPerElement;
						int num4 = num2 * submesh3.IndiciesPerElement;
						num2++;
						for (int num5 = 0; num5 < submesh3.IndiciesPerElement; num5++)
						{
							int num6 = submesh3.RawIndicies[num3 + num5];
							geometryMask.IsVertexMasked(num6);
							num6 = dictionary[num6];
							submesh3.RawIndicies[num4 + num5] = num6;
						}
					}
				}
				submesh3.SetCount(num2);
			}
			return meshX;
		}

		public List<MeshX> SplitSubmeshes()
		{
			List<MeshX> list = new List<MeshX>();
			Dictionary<int, int> dictionary = new Dictionary<int, int>();
			foreach (Submesh submesh2 in submeshes)
			{
				MeshX meshX = new MeshX();
				meshX.CopyDataChannelFlags(this);
				Submesh submesh = meshX.TryGetSubmesh(submesh2.Topology);
				submesh.SetCount(submesh2.Count);
				foreach (Bone bone in Bones)
				{
					meshX.AddBone(bone.Name).BindPose = bone.BindPose;
				}
				for (int i = 0; i < submesh2.IndicieCount; i++)
				{
					int num = submesh2.RawIndicies[i];
					if (!dictionary.TryGetValue(num, out var value))
					{
						meshX.AddVertex(GetVertex(num));
						value = dictionary.Count;
						dictionary.Add(num, value);
					}
					submesh.RawIndicies[i] = value;
				}
				foreach (BlendShape blendShape2 in BlendShapes)
				{
					BlendShape blendShape = meshX.AddBlendShape(blendShape2.Name);
					blendShape.HasNormals = blendShape2.HasNormals;
					blendShape.HasTangents = blendShape2.HasTangents;
					foreach (BlendShapeFrame frame in blendShape2.Frames)
					{
						BlendShapeFrame blendShapeFrame = blendShape.AddFrame(frame.Weight);
						foreach (KeyValuePair<int, int> item in dictionary)
						{
							blendShapeFrame.RawPositions[item.Value] = frame.RawPositions[item.Key];
							if (blendShape.HasNormals)
							{
								blendShapeFrame.RawNormals[item.Value] = frame.RawNormals[item.Key];
							}
							if (blendShape.HasTangents)
							{
								blendShapeFrame.RawTangents[item.Value] = frame.RawTangents[item.Key];
							}
						}
					}
				}
				dictionary.Clear();
				list.Add(meshX);
			}
			return list;
		}

		public WeightedList<int> ComputeWeightedTriangleList()
		{
			WeightedList<int> weightedList = new WeightedList<int>();
			int num = 0;
			foreach (Submesh submesh in Submeshes)
			{
				if (!(submesh is TriangleSubmesh triangleSubmesh))
				{
					continue;
				}
				for (int i = 0; i < triangleSubmesh.Count; i++)
				{
					float area = triangleSubmesh.GetTriangleUnsafe(i).Area;
					if (area > 0f)
					{
						weightedList.Add(num, area);
					}
					num++;
				}
			}
			return weightedList;
		}

		public MeshX GetConvexHull()
		{
			RawList<float3> list = Pool.BorrowRawList<float3>();
			RawList<int> list2 = Pool.BorrowRawList<int>();
			list.AddRange(RawPositions, VertexCount);
			PointMerger.RemoveRedundantPoints(list);
			Elements.Core.ConvexHullHelper.GetConvexHull(list, list2);
			MeshX meshX = new MeshX();
			TriangleSubmesh triangleSubmesh = meshX.TryGetSubmesh<TriangleSubmesh>();
			triangleSubmesh.SetCount(list2.Count / 3);
			Dictionary<int, int> dictionary = Pool.BorrowDictionary<int, int>();
			for (int i = 0; i < list2.Count; i++)
			{
				int num = list2[i];
				if (!dictionary.TryGetValue(num, out var value))
				{
					value = meshX.VertexCount;
					meshX.AddVertex(list[num]);
					dictionary.Add(num, value);
				}
				triangleSubmesh.RawIndicies[i] = value;
			}
			Pool.Return(ref list);
			Pool.Return(ref list2);
			meshX.ReverseWinding();
			meshX.RecalculateNormals();
			return meshX;
		}

		public MeshX GetMergedDoubles(double cellSize = 0.001)
		{
			Dictionary<int3, int> dictionary = Pool.BorrowDictionary<int3, int>();
			Dictionary<int, int> dictionary2 = Pool.BorrowDictionary<int, int>();
			MeshX meshX = new MeshX();
			for (int i = 0; i < VertexCount; i++)
			{
				float3 v = RawPositions[i];
				int3 key = MathX.FloorToInt(v / cellSize);
				if (dictionary.TryGetValue(key, out var value))
				{
					dictionary2.Add(i, value);
					continue;
				}
				dictionary2.Add(i, meshX.VertexCount);
				dictionary.Add(key, meshX.VertexCount);
				meshX.AddVertex(in v);
			}
			foreach (Submesh submesh2 in Submeshes)
			{
				Submesh submesh = meshX.AddSubmesh(submesh2.Topology);
				submesh.SetCount(submesh2.Count);
				for (int j = 0; j < submesh2.IndicieCount; j++)
				{
					submesh.RawIndicies[j] = dictionary2[submesh2.RawIndicies[j]];
				}
			}
			Pool.Return(ref dictionary);
			Pool.Return(ref dictionary2);
			return meshX;
		}
	}
