		public static void AddTriangleFan<T>(this TriangleSubmesh submesh, IList<T> vertices, int offset, int count, Func<T, int> getIndex, bool reverseOrder = false, TriangleCollection triangles = null)
		{
			TriangleCollection trigs = Pool.Borrow<TriangleCollection>();
			submesh.AddTriangles(count - 2, trigs);
			int trigIndex = 0;
			submesh.ConnectTriangleFan(offset, count, (int i) => getIndex(vertices[i]), () => trigs[trigIndex++].IndexUnsafe, reverseOrder);
			triangles?.AddRange(trigs);
			Pool.Return(ref trigs);
		}

		public static void AddTriangleFan(this TriangleSubmesh submesh, int vertexCount, Func<int, int> getVertexIndex, bool reverseOrder = false)
		{
			TriangleCollection trigs = Pool.Borrow<TriangleCollection>();
			submesh.AddTriangles(vertexCount - 2, trigs);
			int trigIndex = 0;
			submesh.ConnectTriangleFan(0, vertexCount, getVertexIndex, () => trigs[trigIndex++].IndexUnsafe, reverseOrder);
			Pool.Return(ref trigs);
		}

		public static void ConnectTriangleFan(this TriangleSubmesh submesh, IList<int> vertices, Func<int> getNextTriangle, bool reverseOrder = false, TriangleCollection triangles = null)
		{
			submesh.ConnectTriangleFan(0, vertices.Count, (int i) => vertices[i], getNextTriangle, reverseOrder);
		}

		public static void ConnectTriangleFan(this TriangleSubmesh submesh, int vertexOffset, int vertexCount, Func<int, int> getVertexIndex, Func<int> getNextTriangle, bool reverseOrder = false)
		{
			if (vertexCount < 3)
			{
				throw new Exception("Need at least 3 vertices");
			}
			int num = vertexCount - 2;
			int v = getVertexIndex(vertexOffset);
			for (int i = 0; i < num; i++)
			{
				int v2;
				int v3;
				if (reverseOrder)
				{
					int num2 = num - i - 1;
					num2 += vertexOffset;
					v2 = getVertexIndex(num2 + 2);
					v3 = getVertexIndex(num2 + 1);
				}
				else
				{
					int num3 = i + vertexOffset;
					v2 = getVertexIndex(num3 + 1);
					v3 = getVertexIndex(num3 + 2);
				}
				submesh.SetTriangle(getNextTriangle(), v, v2, v3);
			}
		}

