	public class PolarGrid : MeshXShape
	{
		public float RingsRadiusBegin = 0.1f;

		public float RingsRadiusEnd = 4f;

		public float RingWidth = 0.01f;

		public int RingCount = 32;

		public float LinesRadiusBegin = 0.1f;

		public float LinesRadiusEnd = 4f;

		public float LineThickness = 0.01f;

		public int LineCount = 32;

		public readonly int RingSegments;

		private List<Ring> rings = new List<Ring>();

		private List<Quad> lines = new List<Quad>();

		public PolarGrid(MeshX meshx, int ringSegments = 32)
			: base(meshx)
		{
			meshx.TrackRemovals = true;
		}

		public override void Update()
		{
			while (RingCount < rings.Count)
			{
				rings.TakeLast().Remove();
			}
			while (RingCount > rings.Count)
			{
				rings.Add(new Ring(base.Mesh, RingSegments));
			}
			while (LineCount < lines.Count)
			{
				lines.TakeLast().Remove();
			}
			while (LineCount > lines.Count)
			{
				lines.Add(new Quad(base.Mesh));
			}
			for (int i = 0; i < RingCount; i++)
			{
				Ring ring = rings[i];
				ring.Radius = MathX.Lerp(RingsRadiusBegin, RingsRadiusEnd, (float)i / (float)(RingCount - 1));
				ring.Width = RingWidth;
				ring.Update();
			}
			float y = LinesRadiusEnd - LinesRadiusBegin;
			for (int j = 0; j < LineCount; j++)
			{
				Quad quad = lines[j];
				float y2 = 360f * ((float)j / (float)LineCount);
				floatQ q = floatQ.Euler(0f, y2, 0f);
				quad.Size = new float2(LineThickness, y);
				quad.Position = q * ILSpyHelper_AsRefReadOnly(new float3(0f, LinesRadiusBegin));
				quad.Rotation = q;
				quad.Update();
			}
			static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
			{
				//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
				return ref temp;
			}
		}
	}
