	public class PointSubmesh : Submesh, ISubmesh<Point>
	{
		public override SubmeshTopology Topology => SubmeshTopology.Points;

		public override int IndiciesPerElement => 1;

		public Point this[int index] => GetPoint(index);

		public PointSubmesh(MeshX mesh)
			: base(mesh)
		{
		}

		public Point AddPoint()
		{
			IncreaseCount(1);
			return new Point(base.Count - 1, this);
		}

		public Point AddPoint(int vIndex)
		{
			Point result = AddPoint();
			result.VertexIndex = vIndex;
			return result;
		}

		public void AddPoints(int count, PointCollection points = null)
		{
			IncreaseCount(count);
			if (points != null)
			{
				points.Capacity += count;
				for (int i = 0; i < count; i++)
				{
					points.Add(new Point(base.Count - count + i, this));
				}
			}
		}

		public Point GetPoint(int index)
		{
			VerifyIndex(index);
			return new Point(index, this);
		}

		public void SetPoint(int index, int vIndex)
		{
			indicies[index] = vIndex;
		}

		public void Remove(Point p)
		{
			Remove(p.Index);
		}

		public void Remove(PointCollection points)
		{
			if (points.Count > 0)
			{
				Mesh.RemoveElements(points._points, delegate(int index, int count)
				{
					Remove(index, count);
				});
			}
		}
	}
	public class SmoothNormalsContext : IDisposable
	{
		private readonly double cellSize;

		private readonly double multiplier;

		private Dictionary<int3, float3> normals;

		public SmoothNormalsContext(double cellSize = 0.001)
		{
			this.cellSize = cellSize;
			multiplier = 1.0 / cellSize;
			normals = Pool.BorrowDictionary<int3, float3>();
		}

		public float3 GetNormal(in float3 position)
		{
			int3 key = MathX.FloorToInt(position * multiplier);
			return normals[key];
		}

		public bool TryGetNormal(in float3 position, out float3 normal)
		{
			int3 key = MathX.FloorToInt(position * multiplier);
			return normals.TryGetValue(key, out normal);
		}

		public void AssignNormal(Vertex vertex)
		{
			int3 key = MathX.FloorToInt(vertex.PositionUnsafe * multiplier);
			if (normals.TryGetValue(key, out var value))
			{
				vertex.NormalUnsafe = value;
			}
		}

		public void StoreNormal(in float3 normal, in float3 position)
		{
			int3 key = MathX.FloorToInt(position * multiplier);
			if (normals.TryGetValue(key, out var value))
			{
				normals[key] = value + normal;
			}
			else
			{
				normals.Add(key, normal);
			}
		}

		public void Dispose()
		{
			Pool.Return(ref normals);
		}
	}
	[DataModelType]
	[OldTypeName("Elements.Core.Arrow", "Elements.Core")]
	public class Arrow : MeshXShape
	{
		public readonly TriangleSubmesh Submesh;

		public readonly int Sides;

		public float3 Vector = float3.Up;

		public float BodyRadius = 0.1f;

		public float HeadRadius = 0.3f;

		public float HeadLength = 0.3f;

		public float MinimalBodyLength = 0.3f;

		private ConicalFrustum head;

		private ConicalFrustum body;

		public colorX ColorBase
		{
			get
			{
				return body.ColorBase;
			}
			set
			{
				body.ColorBase = value;
			}
		}

		public colorX ColorTop
		{
			get
			{
				return body.ColorTop;
			}
			set
			{
				body.ColorTop = value;
			}
		}

		public colorX ColorHead
		{
			get
			{
				return head.ColorBase;
			}
			set
			{
				head.ColorBase = value;
				head.ColorTop = value;
			}
		}

		public float2 BodyUVScale
		{
			get
			{
				return body.UVScale;
			}
			set
			{
				body.UVScale = value;
			}
		}

		public float2 BodyUVOffset
		{
			get
			{
				return body.UVOffset;
			}
			set
			{
				body.UVOffset = value;
			}
		}

		public float2 HeadUVScale
		{
			get
			{
				return head.UVScale;
			}
			set
			{
				head.UVScale = value;
			}
		}

		public float2 HeadUVOffset
		{
			get
			{
				return head.UVOffset;
			}
			set
			{
				head.UVOffset = value;
			}
		}

		public Arrow(TriangleSubmesh submesh, int sides)
			: base(submesh.Mesh)
		{
			Submesh = submesh;
			Sides = sides;
			body = new ConicalFrustum(submesh, sides, flatShading: false);
			head = new ConicalFrustum(submesh, sides, flatShading: false);
		}

		public override void Update()
		{
			float magnitude = Vector.Magnitude;
			float num = HeadLength + MinimalBodyLength;
			float3 v = ((magnitude > 0f) ? (Vector / magnitude) : float3.Zero);
			float num2 = BodyRadius;
			float num3 = HeadRadius;
			float num4 = HeadLength;
			if (magnitude < num)
			{
				float num5 = magnitude / num;
				num2 *= num5;
				num3 *= num5;
				num4 *= num5;
			}
			float num6 = magnitude - num4;
			body.Radius = num2;
			body.Height = num6;
			head.RadiusBottom = num3;
			head.Height = num4;
			floatQ rotation = floatQ.LookRotation(in Vector, float3.Forward) * floatQ.FromToRotation(float3.Up, float3.Forward);
			body.Rotation = rotation;
			head.Rotation = rotation;
			body.Position = v * num6 * 0.5f;
			head.Position = v * (num6 + num4 * 0.5f);
			body.Update();
			head.Update();
		}

		public override void Remove()
		{
			head.Remove();
			body.Remove();
		}
	}
	[DataModelType]
	[OldTypeName("Elements.Core.BevelBox", "Elements.Core")]
	public class BevelBox : MeshXShape
	{
		public readonly TriangleSubmesh Submesh;

		public float3 Size = float3.One;

		public float Bevel = 0.1f;

		public float3 UVScale = float3.One;

		private int faceVertOffset;

		private int edgeVertOffset;

		private int cornerVertOffset;

		private static color DEBUG_COLOR(int index)
		{
			return index switch
			{
				0 => color.Red, 
				1 => color.Green, 
				2 => color.Blue, 
				3 => color.Yellow, 
				4 => color.Cyan, 
				5 => color.Magenta, 
				6 => color.Orange, 
				7 => color.Purple, 
				8 => color.Black, 
				_ => color.White, 
			};
		}

		public BevelBox(TriangleSubmesh submesh)
			: base(submesh.Mesh)
		{
			Submesh = submesh;
			faceVertOffset = base.AllVertices.Count;
			base.Mesh.AddVertices(24, base.AllVertices);
			for (int i = 0; i < 6; i++)
			{
				int num = i * 4 + faceVertOffset;
				MeshX_Extensions.QuadTriangles quadTriangles = Submesh.AddQuadAsTriangles(base.AllVertices[num], base.AllVertices[num + 1], base.AllVertices[num + 2], base.AllVertices[num + 3]);
				base.AllTriangles.Add(quadTriangles.first);
				base.AllTriangles.Add(quadTriangles.second);
			}
			cornerVertOffset = base.AllVertices.Count;
			base.Mesh.AddVertices(24, base.AllVertices);
			for (int j = 0; j < 8; j++)
			{
				int num2 = j * 3 + cornerVertOffset;
				Triangle v;
				switch (j)
				{
				case 1:
				case 2:
				case 4:
				case 7:
					v = Submesh.AddTriangle(base.AllVertices[num2 + 2], base.AllVertices[num2 + 1], base.AllVertices[num2]);
					break;
				default:
					v = Submesh.AddTriangle(base.AllVertices[num2], base.AllVertices[num2 + 1], base.AllVertices[num2 + 2]);
					break;
				}
