			}
			set
			{
				if (_relief != value)
				{
					_relief = value;
					InvalidateGeometry();
				}
			}
		}

		public override int ProfileVertexCount
		{
			get
			{
				if (!_relief)
				{
					return 3;
				}
				return 4;
			}
		}

		public override bool FlatShading => _flatShading;

		public BevelEdgeBlockBuilder(MeshX meshx, bool flatShading = true)
			: base(meshx)
		{
			_flatShading = flatShading;
		}

		protected override void UpdateVertex(Vertex vert, Point point, int index)
		{
			float3 a = point.Position.xy;
			float3 v = point.Normal.xy;
			switch (index)
			{
			case 0:
				a += (-v + float3.Forward) * Thickness / 2f;
				break;
			case 2:
				a += (-v + float3.Backward) * Thickness / 2f;
				break;
			case 3:
				a += -v * Thickness;
				break;
			}
			vert.Position = a;
		}
	}
