	public struct trig
	{
		public int v0;

		public int v1;

		public int v2;

		public trig(int v0, int v1, int v2)
		{
			this.v0 = v0;
			this.v1 = v1;
			this.v2 = v2;
		}

		public void VerticesRemoved(int index, int count)
		{
			int num = index + count;
			if (v0 >= index && v0 < num)
			{
				v0 = -1;
			}
			if (v1 >= index && v1 < num)
			{
				v1 = -1;
			}
			if (v2 >= index && v2 < num)
			{
				v2 = -1;
			}
			if (v0 >= num)
			{
				v0 -= count;
			}
			if (v1 >= num)
			{
				v1 -= count;
			}
			if (v2 >= num)
			{
				v2 -= count;
			}
		}
	}
	public class TriangleSubmesh : Submesh, ISubmesh<Triangle>
	{
		public override SubmeshTopology Topology => SubmeshTopology.Triangles;

		public override int IndiciesPerElement => 3;

		Triangle ISubmesh<Triangle>.this[int index] => GetTriangle(index);

		public TriangleSubmesh(MeshX mesh)
			: base(mesh)
		{
		}

		public Triangle AddTriangle()
		{
			IncreaseCount(1);
			return new Triangle(base.Count - 1, this);
		}

		public void AddTriangles(int count, TriangleCollection trigs = null)
		{
			IncreaseCount(count);
			if (trigs != null)
			{
				trigs.Capacity += count;
				for (int i = 0; i < count; i++)
				{
					trigs.Add(new Triangle(base.Count - count + i, this));
				}
			}
		}

		public Triangle AddTriangle(int v0, int v1, int v2)
		{
			Triangle result = AddTriangle();
			result.Vertex0IndexUnsafe = v0;
			result.Vertex1IndexUnsafe = v1;
			result.Vertex2IndexUnsafe = v2;
			return result;
		}

		public Triangle AddTriangle(int v0, int v1, int v2, bool reverse)
		{
			if (reverse)
			{
				Triangle result = AddTriangle();
				result.Vertex0IndexUnsafe = v2;
				result.Vertex1IndexUnsafe = v1;
				result.Vertex2IndexUnsafe = v0;
				return result;
			}
			return AddTriangle(v0, v1, v2);
		}

		public Triangle AddTriangle(Vertex v0, Vertex v1, Vertex v2)
		{
			return AddTriangle(v0.Index, v1.Index, v2.Index);
		}

		public void SetTriangle(int index, int v0, int v1, int v2)
		{
			VerifyIndex(index);
			index *= 3;
			indicies[index] = v0;
			indicies[index + 1] = v1;
			indicies[index + 2] = v2;
		}

		public Triangle GetTriangle(int index)
		{
			VerifyIndex(index);
			return new Triangle(index, this);
		}

		public Triangle GetTriangleUnsafe(int index)
		{
			return new Triangle(index, this);
		}

		public void GetIndicies(int index, out int v0, out int v1, out int v2)
		{
			VerifyIndex(index);
			GetIndiciesUnsafe(index, out v0, out v1, out v2);
		}

		public void GetIndiciesUnsafe(int index, out int v0, out int v1, out int v2)
		{
			index *= 3;
			v0 = indicies[index];
			v1 = indicies[index + 1];
			v2 = indicies[index + 2];
		}

		public void Remove(Triangle t)
		{
			Remove(t.Index);
		}

		public void Remove(TriangleCollection triangles)
		{
			if (triangles.Count > 0)
			{
				Mesh.RemoveElements(triangles._triangles, delegate(int index, int count)
				{
					Remove(index, count);
				});
			}
		}
	}
