		internal Vertex(int index, MeshX meshx)
		{
			this.index = index;
			this.meshx = meshx;
			if (meshx.TrackRemovals)
			{
				version = meshx.vertexIDs[index];
			}
			else
			{
				version = meshx.VerticesVersion;
			}
		}

		public void Copy(Vertex v)
		{
			Position = v.Position;
			if (v.Mesh.HasNormals)
			{
				Normal = v.Normal;
			}
			if (v.Mesh.HasTangents)
			{
				Tangent4 = v.Tangent4;
			}
			if (v.Mesh.HasColors)
			{
				Color = v.Color;
			}
			for (int i = 0; i < v.Mesh.UV_ChannelCount; i++)
			{
				SetUV(i, v.GetUV(i));
			}
			if (v.Mesh.HasBoneBindings)
			{
				BoneBinding = v.BoneBinding;
			}
		}

		public float2 GetUV(int uvChannel)
		{
			UpdateIndex();
