		public float4 GetUV_Auto(int uvChannel)
		{
			UpdateIndex();
			MeshX.UV_Array uV_Array = meshx.TryGetRawUV_Array(uvChannel);
			if (uV_Array.uv_2D != null)
			{
				return uV_Array.uv_2D[index];
			}
			if (uV_Array.uv_3D != null)
			{
				return uV_Array.uv_3D[index];
			}
			if (uV_Array.uv_4D != null)
			{
				return uV_Array.uv_4D[index];
			}
			return default(float4);
		}

