		{
			Color = value;
		}

		public void SetFlag(bool value)
		{
			Flag = value;
		}

		internal bool UpdateIndex()
		{
			if (version < 0)
			{
				if (version != meshx.VerticesVersion)
				{
					throw new Exception("Vertex has been invalidated, index: " + index);
				}
			}
			else if (version != meshx.vertexIDs[index])
			{
				int num = index;
				while (index > 0 && meshx.vertexIDs[index] > version)
				{
					index--;
				}
				if (meshx.vertexIDs[index] != version)
				{
					throw new Exception("Vertex has been removed, original index: " + num + ", version: " + version);
				}
				return true;
			}
			return false;
		}

		void IVertex.SetUV(int channel, in float2 uv, bool throwIfDimensionMismatch = false)
		{
			SetUV(channel, in uv, throwIfDimensionMismatch);
		}

		void IVertex.SetBlendShapePositionDelta(string key, in float3 delta, int frame = 0)
		{
			SetBlendShapePositionDelta(key, in delta, frame);
		}

		void IVertex.SetBlendShapeNormalDelta(string key, in float3 delta, int frame = 0)
		{
			SetBlendShapeNormalDelta(key, in delta, frame);
		}

		void IVertex.SetBlendShapeTangentDelta(string key, in float3 delta, int frame = 0)
		{
			SetBlendShapeTangentDelta(key, in delta, frame);
		}
	}
	public class VertexCollection : IEnumerable<Vertex>, IEnumerable, IList<Vertex>, ICollection<Vertex>, IPoolable
	{
		internal List<Vertex> _vertices;

		public readonly Indexer<float3> Positions;

		public readonly Indexer<float3> Normals;

		public readonly Indexer<float3> Tangents;

		public readonly Indexer<float4> Tangents4;

		public readonly Indexer<color> Colors;

		public readonly Indexer<float2> UV0s;

		public readonly Indexer<float2> UV1s;

		public readonly Indexer<float2> UV2s;

		public readonly Indexer<float2> UV3s;

		public readonly Indexer<bool> Flags;

		public int Count => _vertices.Count;

		public int Capacity
		{
			get
			{
				return _vertices.Capacity;
			}
			set
			{
				_vertices.Capacity = value;
			}
		}

		public bool IsReadOnly => false;

		public Vertex this[int index]
		{
			get
			{
				Vertex vertex = _vertices[index];
				if (vertex.UpdateIndex())
				{
					_vertices[index] = vertex;
				}
				return vertex;
			}
			set
			{
				_vertices[index] = value;
			}
		}

		public void UpdateIndexes()
		{
			for (int i = 0; i < _vertices.Count; i++)
			{
				Vertex value = _vertices[i];
				value.UpdateIndex();
				_vertices[i] = value;
			}
		}

		public VertexCollection(int capacity = 4)
		{
			_vertices = new List<Vertex>(capacity);
			Positions = new Indexer<float3>((int i) => this[i].Position, delegate(int i, float3 v)
			{
				this[i].SetPosition(in v);
			});
			Normals = new Indexer<float3>((int i) => this[i].Normal, delegate(int i, float3 v)
			{
				this[i].SetNormal(in v);
			});
			Tangents = new Indexer<float3>((int i) => this[i].Tangent, delegate(int i, float3 v)
			{
				this[i].SetTangent(in v);
			});
			Tangents4 = new Indexer<float4>((int i) => this[i].Tangent4, delegate(int i, float4 v)
			{
				this[i].SetTangent4(in v);
			});
			Colors = new Indexer<color>((int i) => this[i].Color, delegate(int i, color v)
			{
				this[i].SetColor(in v);
			});
			UV0s = new Indexer<float2>((int i) => this[i].UV0, delegate(int i, float2 v)
			{
				this[i].SetUV(0, in v);
			});
			UV1s = new Indexer<float2>((int i) => this[i].UV1, delegate(int i, float2 v)
			{
				this[i].SetUV(1, in v);
			});
			UV2s = new Indexer<float2>((int i) => this[i].UV2, delegate(int i, float2 v)
			{
				this[i].SetUV(2, in v);
			});
			UV3s = new Indexer<float2>((int i) => this[i].UV3, delegate(int i, float2 v)
			{
				this[i].SetUV(3, in v);
			});
			Flags = new Indexer<bool>((int i) => this[i].Flag, delegate(int i, bool v)
			{
				this[i].SetFlag(v);
			});
		}

		public void Add(Vertex v)
		{
			_vertices.Add(v);
		}

		public void AddRange(IEnumerable<Vertex> collection)
		{
			_vertices.AddRange(collection);
		}

		public bool Remove(Vertex v)
		{
			return _vertices.Remove(v);
		}

		public void RemoveAt(int index)
		{
			_vertices.RemoveAt(index);
		}

		public void RemoveRange(int index, int count)
		{
			_vertices.RemoveRange(index, count);
		}

		public List<Vertex>.Enumerator GetEnumerator()
