	public static class BlenderInterface
	{
		private static string[] searchLocations;

		public static bool IsAvailable => File.Exists(Executable);

		public static string RootDir { get; private set; }

		public static string Executable { get; private set; }

		static BlenderInterface()
		{
			searchLocations = new string[3] { "C:\\Program Files", "C:\\Program Files (x86)", "C:\\Program Files (x86)\\Steam\\steamapps\\common\\Blender" };
			try
			{
				string fullPath = Path.GetFullPath("Tools\\Blender\\blender.exe");
				if (File.Exists(fullPath))
				{
					RootDir = PathUtility.GetDirectoryName(fullPath);
					Executable = fullPath;
					return;
				}
				string[] array = searchLocations;
				foreach (string text in array)
				{
					if (!Directory.Exists(text))
					{
						continue;
					}
					string text3;
					if (text.IndexOf("blender", StringComparison.InvariantCultureIgnoreCase) < 0)
					{
						string[] directories = Directory.GetDirectories(text);
						foreach (string path in directories)
						{
							if (!Path.GetFileName(path).ToLower().Contains("blender foundation"))
							{
								continue;
							}
							string[] directories2 = Directory.GetDirectories(path);
							foreach (string text2 in directories2)
							{
								text3 = Path.Combine(text2, "blender.exe");
								if (File.Exists(text3))
								{
									RootDir = text2;
									Executable = text3;
									return;
								}
							}
						}
					}
					text3 = Path.Combine(text, "blender.exe");
					if (File.Exists(text3))
					{
						RootDir = text;
						Executable = text3;
						break;
					}
				}
			}
			catch (Exception ex)
			{
				UniLog.Error("Error when detecting Blender: " + ex);
			}
		}

		public static void ExportToFBX(string input, string output)
		{
			output = output.Replace("/", "\\").Replace("\\", "\\\\");
			output = output.EscapeUnicodeCharacters();
			RunScript("import bpy\r\nbpy.ops.export_scene.fbx(filepath=u\"" + output + "\")", "\"" + input + "\" --background --python \"{0}\"");
		}

		public static void ExportToGLTF(string input, string output)
		{
			output = output.Replace("/", "\\").Replace("\\", "\\\\");
			output = output.EscapeUnicodeCharacters();
			RunScript("import bpy\r\nbpy.ops.export_scene.gltf(filepath=u\"" + output + "\")", "\"" + input + "\" --background --python \"{0}\"");
		}

		private static void RunScript(string script, string arguments = "-b -P \"{0}\"")
		{
			string text = Path.Combine(Path.GetTempPath(), Path.GetTempFileName() + ".py");
			File.WriteAllText(text, script);
			string text2 = string.Format(arguments, text);
			text2 = "--disable-autoexec " + text2;
			Process.Start(new ProcessStartInfo(Executable, text2)
			{
				WindowStyle = ProcessWindowStyle.Hidden,
				CreateNoWindow = true,
				UseShellExecute = false
			}).WaitForExit();
			File.Delete(text);
		}
	}
	public static class FreeCADInterface
	{
		private static string[] searchLocations;

		public static string[] SupportedFormats;

		public static bool IsAvailable => File.Exists(Executable);

		public static string RootDir { get; private set; }

		public static string Executable
		{
			get
			{
				if (RootDir != null)
				{
					return Path.Combine(RootDir, "bin\\FreeCADCmd.exe");
				}
				return null;
			}
		}

		static FreeCADInterface()
		{
			searchLocations = new string[2] { "C:\\Program Files", "C:\\Program Files (x86)" };
			SupportedFormats = new string[11]
			{
				"stp", "step", "inp", "brep", "brp", "frd", "iges", "igs", "iv", "oca",
				"gcad"
			};
			try
			{
				string[] array = searchLocations;
				foreach (string path in array)
				{
					if (!Directory.Exists(path))
					{
						continue;
					}
					string[] directories = Directory.GetDirectories(path);
					foreach (string text in directories)
					{
						if (Path.GetFileName(text).ToLower().Contains("freecad"))
						{
							RootDir = text;
							return;
						}
					}
				}
			}
			catch (Exception ex)
			{
				UniLog.Error("Error when detecting FreeCAD: " + ex);
			}
		}

		public static void Tesselate(string input, string output, float tesselation)
		{
			input = input.Replace("/", "\\").Replace("\\", "\\\\");
			output = output.Replace("/", "\\").Replace("\\", "\\\\");
			input = input.EscapeUnicodeCharacters();
			output = output.EscapeUnicodeCharacters();
			tesselation = MathX.Max(tesselation, 0.01f);
			RunScript($"import Part, Mesh\r\np = Part.read(u\"{input}\")\r\nm = Mesh.Mesh()\r\nm.addFacets(p.tessellate({tesselation.ToString(CultureInfo.InvariantCulture)}))\r\nm.write(u\"{output}\")");
		}

		private static void RunScript(string script)
		{
			string text = Path.Combine(Path.GetTempPath(), Path.GetTempFileName() + ".py");
			File.WriteAllText(text, script);
			Process.Start(new ProcessStartInfo(Executable, "\"" + text + "\"")
			{
				WindowStyle = ProcessWindowStyle.Hidden
			}).WaitForExit();
			File.Delete(text);
		}
	}
	public static class ModelPreimporter
	{
		public const float DEFAULT_TESSELATION = 0.5f;

		public static string Preimport(string model, string tempPath)
		{
			string text = Path.GetExtension(model).Replace(".", "").ToLower();
			if (FreeCADInterface.IsAvailable && FreeCADInterface.SupportedFormats.Contains(text))
			{
				string text2 = Path.Combine(tempPath, Path.ChangeExtension(Path.GetTempFileName(), "obj"));
				FreeCADInterface.Tesselate(model, text2, 0.5f);
				return text2;
			}
			if (text == "blend" && BlenderInterface.IsAvailable)
			{
				string text3 = Path.Combine(tempPath, Path.ChangeExtension(Path.GetTempFileName(), "glb"));
				BlenderInterface.ExportToGLTF(model, text3);
				return text3;
			}
			return null;
		}
	}
