	public static class VHACDInterface
	{
		[DataModelType]
		public enum DecompositionMode
		{
			Voxel,
			Tetrahedron
		}

		public const int MIN_RESOLUTION = 10000;

		public const int MAX_RESOLUTION = 16000000;

		public const int DEFAULT_RESOLUTION = 100000;

		public const int MIN_DEPTH = 1;

		public const int MAX_DEPTH = 32;

		public const int DEFAULT_DEPTH = 20;

		public const float DEFAULT_CONCAVITY = 0.0025f;

		public const int DEFAULT_DOWNSAMPLING = 4;

		public const int MIN_DOWNSAMPLING = 1;

		public const int MAX_DOWNSAMPLING = 16;

		public const float DEFAULT_ALPHA = 0.05f;

		public const float DEFAULT_BETA = 0.05f;

		public const float DEFAULT_GAMMA = 0.00125f;

		public const float DEFAULT_DELTA = 0.05f;

		public const bool DEFAULT_PCA = false;

		public const DecompositionMode DEFAULT_MODE = DecompositionMode.Voxel;

		public const int MIN_MAX_VERTICES = 4;

		public const int MAX_MAX_VERTICES = 1024;

		public const int DEFAULT_MAX_VERTICES = 64;

		public const float MIN_MIN_VOLUME = 0f;

		public const float MAX_MIN_VOLUME = 0.01f;

		public const float DEFAULT_MIN_VOLUME = 0.0001f;

		public const bool DEFAULT_CONVEX_HULL_APPROXIMATION = true;

		public static bool IsAvailable => File.Exists(Executable);

		public static string Executable { get; set; } = "RuntimeData\\vhacd.exe";

		public static Task<List<ComputedConvexHull>> Decompose(MeshX mesh, int resolution = 100000, int depth = 20, float concavity = 0.0025f, int planeDownsampling = 4, int convexHullDownsampling = 4, float alpha = 0.05f, float beta = 0.05f, float gamma = 0.00125f, float delta = 0.05f, bool pca = false, DecompositionMode mode = DecompositionMode.Voxel, int maxVerticesPerHull = 64, float minVolumePerHull = 0.0001f, bool convexHullApproximation = true)
		{
			if (!IsAvailable)
			{
				throw new InvalidOperationException("VHACD decomposition isn't available. Make sure that the vhacd executable is located in the correct folder.");
			}
			TaskCompletionSource<List<ComputedConvexHull>> completionSource = new TaskCompletionSource<List<ComputedConvexHull>>();
			resolution = MathX.Clamp(resolution, 10000, 16000000);
			depth = MathX.Clamp(depth, 1, 32);
			concavity = MathX.Clamp01(concavity);
			planeDownsampling = MathX.Clamp(planeDownsampling, 1, 16);
			convexHullDownsampling = MathX.Clamp(convexHullDownsampling, 1, 16);
			alpha = MathX.Clamp01(alpha);
			beta = MathX.Clamp01(beta);
			gamma = MathX.Clamp01(gamma);
			delta = MathX.Clamp01(delta);
			maxVerticesPerHull = MathX.Clamp(maxVerticesPerHull, 4, 1024);
			minVolumePerHull = MathX.Clamp(minVolumePerHull, 0f, 0.01f);
			CultureInfo invariantCulture = CultureInfo.InvariantCulture;
			string inputFile = Path.Combine(Path.GetTempPath(), Path.GetTempFileName() + ".obj");
			mesh.ExportAsOBJ(inputFile);
			string outputFile = Path.Combine(Path.GetTempPath(), Path.GetTempFileName() + ".wrl");
			string arguments = $"--input \"{inputFile}\" --output \"{outputFile}\" --resolution {resolution} --depth {depth} --concavity {concavity.ToString(invariantCulture)} --planeDownsampling {planeDownsampling} --convexHullDownsampling {convexHullDownsampling} --alpha {alpha.ToString(invariantCulture)} --beta {beta.ToString(invariantCulture)} --gamma {gamma.ToString(invariantCulture)} --delta {delta.ToString(invariantCulture)} --pca {pca} --mode {mode} --maxNumVerticesPerCH {maxVerticesPerHull} --minVolumePerCH {minVolumePerHull.ToString(invariantCulture)} --convexhullApproximation {convexHullApproximation}";
			ProcessStartInfo processStartInfo = new ProcessStartInfo(Path.GetFullPath(Executable), arguments);
			processStartInfo.WindowStyle = ProcessWindowStyle.Hidden;
			processStartInfo.CreateNoWindow = true;
			processStartInfo.UseShellExecute = false;
			Process process = new Process();
			process.StartInfo = processStartInfo;
			process.EnableRaisingEvents = true;
			process.OutputDataReceived += delegate(object sender, DataReceivedEventArgs e)
			{
				UniLog.Log("V-HACD output: " + e.Data);
			};
			process.ErrorDataReceived += delegate(object sender, DataReceivedEventArgs e)
			{
				UniLog.Warning("V-HACD error: " + e.Data);
			};
			process.Exited += delegate
			{
				if (!File.Exists(outputFile))
				{
					completionSource.SetException(new FileNotFoundException("V-HACD output file does not exist: " + outputFile));
				}
				else
				{
					FileStream fileStream = File.OpenRead(outputFile);
					VrmlParser vrmlParser = new VrmlParser(new Vrml97Tokenizer(fileStream));
					VrmlScene vrmlScene = new VrmlScene();
					vrmlParser.Parse(vrmlScene);
					List<ComputedConvexHull> list = new List<ComputedConvexHull>();
					ExtractHulls(vrmlScene.Root.Children, list);
					completionSource.SetResult(list);
					fileStream.Dispose();
					File.Delete(inputFile);
					File.Delete(outputFile);
				}
				process.Dispose();
			};
			process.Start();
			process.PriorityClass = ProcessPriorityClass.BelowNormal;
			return completionSource.Task;
		}

		private static void ExtractHulls(MFNode node, List<ComputedConvexHull> hulls)
		{
			foreach (BaseNode value in node.Values)
			{
				if (!(value is GroupNode groupNode))
				{
					if (!(value is ShapeNode shapeNode))
					{
						continue;
					}
					IndexedFaceSetNode indexedFaceSetNode = shapeNode.Geometry as IndexedFaceSetNode;
					CoordinateNode obj = indexedFaceSetNode.Coord.Node as CoordinateNode;
					MeshX meshX = new MeshX();
					foreach (SFVec3f value2 in obj.Point.Values)
					{
						meshX.AddVertex(new float3(value2.X, value2.Y, value2.Z));
					}
					List<int> list = indexedFaceSetNode.CoordIndex.Values.Select((SFInt32 i) => i.Value).ToList();
					TriangleSubmesh triangleSubmesh = meshX.TryGetSubmesh<TriangleSubmesh>();
					for (int num = 0; num < list.Count; num += 4)
					{
						triangleSubmesh.AddTriangle(list[num], list[num + 1], list[num + 2]);
					}
					ComputedConvexHull computedConvexHull = new ComputedConvexHull();
					computedConvexHull.Mesh = meshX;
					hulls.Add(computedConvexHull);
				}
				else
				{
					ExtractHulls(groupNode.Children, hulls);
				}
			}
		}
	}
	public static class WavefrontExporter
	{
		public static void ExportAsOBJ(this MeshX meshx, string file)
		{
			using FileStream stream = File.OpenWrite(file);
			meshx.ExportAsOBJ(stream);
		}

		public static void ExportAsOBJ(this MeshX meshx, Stream stream)
		{
			CultureInfo invariantCulture = CultureInfo.InvariantCulture;
			StreamWriter streamWriter = new StreamWriter(stream);
			streamWriter.WriteLine("# Exported from MeshX");
			streamWriter.WriteLine();
			for (int i = 0; i < meshx.VertexCount; i++)
			{
				float3 @float = meshx.RawPositions[i];
				streamWriter.WriteLine($"v {@float.x.ToString(invariantCulture)} {@float.y.ToString(invariantCulture)} {@float.z.ToString(invariantCulture)}");
			}
			if (meshx.HasUV0s)
			{
				streamWriter.WriteLine();
				for (int j = 0; j < meshx.VertexCount; j++)
				{
					float2 float2 = meshx.RawUV0s[j];
					streamWriter.WriteLine("vt " + float2.x.ToString(invariantCulture) + " " + float2.y.ToString(invariantCulture));
				}
			}
			if (meshx.HasNormals)
			{
				streamWriter.WriteLine();
				for (int k = 0; k < meshx.VertexCount; k++)
				{
					float3 float3 = meshx.RawNormals[k];
					streamWriter.WriteLine($"vn {float3.x.ToString(invariantCulture)} {float3.y.ToString(invariantCulture)} {float3.z.ToString(invariantCulture)}");
				}
			}
			streamWriter.WriteLine();
			foreach (Submesh submesh in meshx.Submeshes)
			{
				if (submesh is TriangleSubmesh triangleSubmesh)
				{
					for (int l = 0; l < triangleSubmesh.Count; l++)
					{
						Triangle triangle = triangleSubmesh.GetTriangle(l);
						streamWriter.WriteLine($"f {triangle.Vertex0IndexUnsafe + 1} {triangle.Vertex1IndexUnsafe + 1} {triangle.Vertex2IndexUnsafe + 1}");
					}
				}
			}
			streamWriter.Flush();
		}
	}
	public class RecordPackage : IDisposable
	{
		public const string ASSET_SCHEME = "packdb";

		public const string MAIN_RECORD_ID = "R-Main";

		public const string ASSETS_FOLDER = "Assets";

		public const string VARIANTS_FOLDER = "Variants";

		public const string METADATA_FOLDER = "Metadata";

		public const string RECORD_EXTENSION = ".record";

		private ZipArchive _archive;

		private Dictionary<string, Record> _records = new Dictionary<string, Record>();

		private Dictionary<string, ZipArchiveEntry> _assets = new Dictionary<string, ZipArchiveEntry>();

		private Dictionary<string, Dictionary<string, ZipArchiveEntry>> _variants = new Dictionary<string, Dictionary<string, ZipArchiveEntry>>();

		private Dictionary<string, IAssetMetadata> _metadata = new Dictionary<string, IAssetMetadata>();

		public int RecordCount => _records.Count;

		public int AssetCount => _assets.Count;

		public Record MainRecord
		{
			get
			{
				_records.TryGetValue("R-Main", out Record value);
				return value;
			}
		}

		public IEnumerable<Record> Records => _records.Values;

		public IEnumerable<string> Assets => _assets.Keys;

		public IEnumerable<IAssetMetadata> Metadata => _metadata.Values;

		public static Uri GetAssetURL(string signature)
		{
			return new Uri("packdb:///" + signature);
		}

		public static string GetAssetSignature(Uri uri)
		{
			if (uri.Scheme != "packdb")
			{
				throw new ArgumentException("Uri is not a package asset URL");
			}
			if (uri.Segments.Length < 2)
			{
				return null;
			}
			return Path.GetFileNameWithoutExtension(uri.Segments[1]);
		}

		public static RecordPackage Decode(string file)
		{
			return Decode(File.OpenRead(file));
		}

		public static RecordPackage Decode(Stream stream)
		{
			RecordPackage recordPackage = new RecordPackage();
			recordPackage.Load(stream);
			return recordPackage;
		}

		public static RecordPackage Create(Stream writeStream)
		{
			return new RecordPackage
			{
				_archive = new ZipArchive(writeStream, ZipArchiveMode.Create)
			};
		}

		public bool HasAsset(string signature)
		{
			return _assets.ContainsKey(signature?.ToLower());
		}

		public bool HasVariant(string signature, string variantIdentifier)
		{
			signature = signature.ToLower();
			if (!_variants.TryGetValue(signature, out Dictionary<string, ZipArchiveEntry> value))
			{
				return false;
			}
			return value.ContainsKey(variantIdentifier);
		}

		public IEnumerable<string> EnumerateVariantsForAsset(string signature)
		{
			signature = signature.ToLower();
			if (!_variants.TryGetValue(signature, out Dictionary<string, ZipArchiveEntry> value))
			{
				yield break;
			}
			foreach (KeyValuePair<string, ZipArchiveEntry> item in value)
			{
				yield return item.Key;
			}
		}

		public IAssetMetadata TryGetMetadata(string signature)
		{
			if (_metadata.TryGetValue(signature, out IAssetMetadata value))
			{
				return value;
			}
			return null;
		}

		public void WriteRecord(Record record)
		{
			if (record == null)
			{
				throw new ArgumentNullException("record");
			}
			if (string.IsNullOrEmpty(record.RecordId))
			{
				throw new ArgumentException("RecordId is empty");
			}
			_records.Add(record.RecordId, record);
			using Stream utf8Json = _archive.CreateEntry(record.RecordId + ".record", CompressionLevel.Optimal).Open();
			System.Text.Json.JsonSerializer.Serialize(utf8Json, record);
		}

		public void WriteMetadata(IAssetMetadata metadata)
		{
			if (string.IsNullOrEmpty(metadata.AssetIdentifier))
			{
				throw new ArgumentException("Metadata is missing asset identifier");
			}
			if (_metadata.ContainsKey(metadata.AssetIdentifier))
			{
				throw new InvalidOperationException("Metadata for asset " + metadata.AssetIdentifier + " has already been added!");
			}
			_metadata.Add(metadata.AssetIdentifier, metadata);
			if (!(metadata is BitmapMetadata metadata2))
			{
				if (!(metadata is CubemapMetadata metadata3))
				{
					if (!(metadata is VolumeMetadata metadata4))
					{
						if (!(metadata is MeshMetadata metadata5))
						{
							if (!(metadata is ShaderMetadata metadata6))
							{
								if (!(metadata is GaussianSplatMetadata metadata7))
								{
									throw new ArgumentException("Unsupported metadata type: " + metadata);
								}
								WriteMetadata(metadata7, "gaussianSplat");
							}
							else
							{
								WriteMetadata(metadata6, "shader");
							}
						}
						else
						{
							WriteMetadata(metadata5, "mesh");
						}
					}
					else
					{
						WriteMetadata(metadata4, "volume");
					}
				}
				else
				{
					WriteMetadata(metadata3, "cubemap");
				}
			}
			else
			{
				WriteMetadata(metadata2, "bitmap");
			}
		}

		private void WriteMetadata<M>(M metadata, string extension) where M : IAssetMetadata
		{
			using Stream utf8Json = _archive.CreateEntry($"{"Metadata"}/{metadata.AssetIdentifier}.{extension}", CompressionLevel.Optimal).Open();
			System.Text.Json.JsonSerializer.Serialize(utf8Json, metadata);
		}

		private void DecodeMetadata<M>(string signature, ZipArchiveEntry entry) where M : IAssetMetadata
		{
			using Stream utf8Json = entry.Open();
			M val = System.Text.Json.JsonSerializer.Deserialize<M>(utf8Json);
			_metadata.Add(signature, val);
		}

		public void ExtractAsset(string signature, Stream targetStream)
		{
			signature = signature.ToLower();
			Extract(_assets, signature, targetStream);
		}

		public void ExtractVariant(string signature, string variantIdentifier, Stream targetStream)
		{
			Extract(_variants[signature], variantIdentifier, targetStream);
		}

		public void WriteAsset(string signature, string file)
		{
			using FileStream assetData = File.OpenRead(file);
			WriteAsset(signature, assetData);
		}

		public void WriteAsset(string signature, Stream assetData)
		{
			signature = signature.ToLower();
			Write(_assets, "Assets", signature, assetData);
		}

		public Stream ReadAsset(string signature)
		{
			signature = signature.ToLower();
			return Read(_assets, signature);
		}

		public Stream ReadVariant(string signature, string variantIdentifier)
		{
			return Read(_variants[signature], variantIdentifier);
		}

		public void WriteVariant(string signature, string variantIdentifier, string file)
		{
			using FileStream assetData = File.OpenRead(file);
			WriteVariant(signature, variantIdentifier, assetData);
		}

		public void WriteVariant(string signature, string variantIdentifier, Stream assetData)
		{
			if (!_variants.TryGetValue(signature, out Dictionary<string, ZipArchiveEntry> value))
			{
				value = new Dictionary<string, ZipArchiveEntry>();
				_variants.Add(signature, value);
			}
			Write(value, "Variants/" + signature, variantIdentifier, assetData);
		}

		private void Extract(Dictionary<string, ZipArchiveEntry> entries, string identifier, Stream targetStream)
		{
			using Stream stream = Read(entries, identifier);
			stream.CopyTo(targetStream);
		}

		private Stream Read(Dictionary<string, ZipArchiveEntry> entries, string identifier)
		{
			if (!entries.TryGetValue(identifier, out ZipArchiveEntry value))
			{
				throw new KeyNotFoundException("Package doesn't contain asset/variant " + identifier);
			}
			return value.Open();
		}

		private void Write(Dictionary<string, ZipArchiveEntry> entries, string folder, string identifier, Stream sourceData)
		{
			if (entries.ContainsKey(identifier))
			{
				throw new InvalidOperationException("Asset/Variant " + identifier + " has already been written");
			}
			ZipArchiveEntry zipArchiveEntry = _archive.CreateEntry(folder + "/" + identifier, CompressionLevel.NoCompression);
			using (Stream destination = zipArchiveEntry.Open())
			{
				sourceData.CopyTo(destination);
			}
			entries.Add(identifier, zipArchiveEntry);
		}

		private void Load(Stream stream)
		{
			_archive = new ZipArchive(stream);
			foreach (ZipArchiveEntry entry in _archive.Entries)
			{
				if (entry.FullName == null)
				{
					continue;
				}
				if (".record".Equals(Path.GetExtension(entry.FullName), StringComparison.OrdinalIgnoreCase))
				{
					using Stream utf8Json = entry.Open();
					Record record = System.Text.Json.JsonSerializer.Deserialize<Record>(utf8Json);
					_records.Add(record.RecordId, record);
				}
				else if (entry.FullName.StartsWith("Assets", ignoreCase: true, CultureInfo.InvariantCulture))
				{
					string key = Path.GetFileNameWithoutExtension(entry.FullName).ToLower();
					_assets.Add(key, entry);
				}
				else if (entry.FullName.StartsWith("Variants", ignoreCase: true, CultureInfo.InvariantCulture))
				{
					string fileNameWithoutExtension = Path.GetFileNameWithoutExtension(entry.FullName);
					string fileName = Path.GetFileName(Path.GetDirectoryName(entry.FullName));
					if (!_variants.TryGetValue(fileName, out Dictionary<string, ZipArchiveEntry> value))
					{
						value = new Dictionary<string, ZipArchiveEntry>();
						_variants.Add(fileName, value);
					}
					value.Add(fileNameWithoutExtension, entry);
				}
				else if (entry.FullName.StartsWith("Metadata", ignoreCase: true, CultureInfo.InvariantCulture))
				{
					string text = Path.GetExtension(entry.FullName)?.Replace(".", "");
					string fileNameWithoutExtension2 = Path.GetFileNameWithoutExtension(entry.FullName);
					switch (text)
					{
					case "bitmap":
						DecodeMetadata<BitmapMetadata>(fileNameWithoutExtension2, entry);
						break;
					case "cubemap":
						DecodeMetadata<CubemapMetadata>(fileNameWithoutExtension2, entry);
						break;
					case "volume":
						DecodeMetadata<VolumeMetadata>(fileNameWithoutExtension2, entry);
						break;
					case "mesh":
						DecodeMetadata<MeshMetadata>(fileNameWithoutExtension2, entry);
						break;
					case "shader":
						DecodeMetadata<ShaderMetadata>(fileNameWithoutExtension2, entry);
						break;
					case "gaussianSplat":
						DecodeMetadata<GaussianSplatMetadata>(fileNameWithoutExtension2, entry);
						break;
					default:
						UniLog.Warning("Unsupported metadata type in package: " + text);
						break;
					}
				}
			}
		}

		public void Dispose()
		{
			_archive?.Dispose();
			_archive = null;
		}
	}
	public static class PointCloudDecoder
	{
		public static MeshX Decode(string file)
		{
			string text = Path.GetExtension(file).ToLower();
			switch (text)
			{
			case ".laz":
			case ".las":
				return DecodeLAZ(file);
			case ".pts":
				return DecodeASCII_PTS(file);
			default:
				throw new Exception("Unsupported extension: " + text);
			}
		}

		public static MeshX DecodeASCII_PTS(string file)
		{
			using StreamReader streamReader = File.OpenText(file);
			MeshX meshX = new MeshX();
			PointSubmesh pointSubmesh = meshX.AddSubmesh<PointSubmesh>();
			int num = int.Parse(streamReader.ReadLine());
			meshX.IncreaseVertexCount(num);
			meshX.IncreasePointCount(num);
			for (int i = 0; i < num; i++)
			{
				string[] array = streamReader.ReadLine().Split(' ');
				pointSubmesh.RawIndicies[i] = i;
				try
				{
					meshX.RawPositions[i] = new float3(float.Parse(array[0], CultureInfo.InvariantCulture), float.Parse(array[1], CultureInfo.InvariantCulture), float.Parse(array[2], CultureInfo.InvariantCulture));
					if (array.Length >= 6)
					{
						byte r = byte.Parse(array[4]);
						byte g = byte.Parse(array[5]);
						byte b = byte.Parse(array[6]);
						meshX.HasColors = true;
						meshX.RawColors[i] = new color32(r, g, b);
					}
				}
				catch (Exception ex)
				{
					UniLog.Warning($"Error parsing point {i}: " + ex.Message);
				}
			}
			return meshX;
		}

		public static MeshX DecodeLAZ(string file)
		{
			laszip_dll laszip_dll = new laszip_dll();
			bool is_compressed = false;
			laszip_dll.laszip_open_reader(file, ref is_compressed);
			MeshX meshX = new MeshX();
			PointSubmesh pointSubmesh = meshX.AddSubmesh<PointSubmesh>();
			int number_of_point_records = (int)laszip_dll.header.number_of_point_records;
			meshX.IncreaseVertexCount(number_of_point_records);
			meshX.IncreasePointCount(number_of_point_records);
			meshX.Profile = ColorProfile.sRGB;
			double[] array = new double[3];
			for (int i = 0; i < number_of_point_records; i++)
			{
				laszip_dll.laszip_read_point();
				laszip_dll.laszip_get_coordinates(array);
				pointSubmesh.RawIndicies[i] = i;
				meshX.RawPositions[i] = new float3((float)array[0], (float)array[1], (float)array[2]);
				if (laszip_dll.point.rgb != null && laszip_dll.point.rgb.Length >= 3)
				{
					meshX.HasColors = true;
					meshX.RawColors[i] = new color((float)(int)laszip_dll.point.rgb[0] / 65535f, (float)(int)laszip_dll.point.rgb[1] / 65535f, (float)(int)laszip_dll.point.rgb[2] / 65535f);
				}
			}
			laszip_dll.laszip_close_reader();
			return meshX;
		}
	}
	[StructLayout(LayoutKind.Explicit, Size = 48)]
	public struct LightData
	{
		[FieldOffset(0)]
		public float3 point;

		[FieldOffset(12)]
		public floatQ orientation;

		[FieldOffset(28)]
		public color colorAndIntensity;

		[FieldOffset(44)]
		public float range;

		[FieldOffset(48)]
		public float angle;

		public float Intensity
		{
			get
			{
				return colorAndIntensity.a;
			}
			set
			{
				colorAndIntensity = colorAndIntensity.SetA(value);
			}
		}

		public color Color
		{
			get
			{
				return colorAndIntensity.SetA(1f);
			}
			set
			{
				colorAndIntensity = value.SetA(Intensity);
			}
		}
	}
	public class ShaderPackage : IDisposable
	{
		private ZipArchive _archive;

		private Dictionary<string, ShaderSource> _cachedSources;

		public ShaderMetadata Metadata { get; private set; }

		public static string MetadataPath => "metadata.json";

		public static ShaderPackage CreateFromSource(string shaderSourceFile, Stream targetStream, string origin)
		{
			List<ShaderSource> list = ShaderSource.CollectSources(shaderSourceFile);
			List<ShaderSourceFile> list2 = new List<ShaderSourceFile>();
			foreach (ShaderSource item in list)
			{
				list2.Add(new ShaderSourceFile(item.File, item.ComputeSourceHash()));
			}
			ShaderSourceFile sourceFile = list2.TakeFirst();
			List<List<string>> list3 = new List<List<string>>();
			foreach (ShaderSource item2 in list)
			{
				foreach (List<string> variant in item2.Variants)
				{
					if (!list3.Any((List<string> v) => v.ElementWiseEquals(variant)))
					{
						list3.Add(variant);
					}
				}
			}
			ShaderPackage shaderPackage = new ShaderPackage(new ShaderMetadata(origin, sourceFile, list3, list2), targetStream);
			foreach (ShaderSource item3 in list)
			{
				shaderPackage.WriteSource(item3);
			}
			return shaderPackage;
		}

		public ShaderPackage(string file)
		{
			if (!File.Exists(file))
			{
				throw new FileNotFoundException("Missing file, in ShaderPackage", file);
			}
			FileStream stream = File.OpenRead(file);
			Decode(stream);
		}

		public ShaderPackage(ShaderMetadata metadata, Stream writeStream)
		{
			_archive = new ZipArchive(writeStream, ZipArchiveMode.Create);
			Metadata = metadata;
			string value = JsonConvert.SerializeObject(Metadata, Formatting.Indented);
			using Stream stream = _archive.CreateEntry(MetadataPath, CompressionLevel.Optimal).Open();
			StreamWriter streamWriter = new StreamWriter(stream);
			streamWriter.Write(value);
			streamWriter.Flush();
		}

		public ShaderPackage(Stream stream)
		{
			Decode(stream);
		}

		private void Decode(Stream stream)
		{
			_archive = new ZipArchive(stream);
			using Stream stream2 = (_archive.GetEntry(MetadataPath) ?? throw new InvalidDataException("Could not find metadata.json entry")).Open();
			string json = new StreamReader(stream2).ReadToEnd();
			Metadata = ShaderMetadata.LoadFromJSON(json);
		}

		public void WriteSource(ShaderSource source)
		{
			if (_cachedSources == null)
			{
				_cachedSources = new Dictionary<string, ShaderSource>();
			}
			_cachedSources.Add(source.File, source);
			using Stream stream = _archive.CreateEntry(SourcePath(source.File), CompressionLevel.Optimal).Open();
			StreamWriter streamWriter = new StreamWriter(stream);
			streamWriter.Write(source.GetSource());
			streamWriter.Flush();
		}

		public ShaderSource ReadSource(string filename)
		{
			if (_cachedSources == null)
			{
				_cachedSources = new Dictionary<string, ShaderSource>();
			}
			if (_cachedSources.TryGetValue(filename, out ShaderSource value))
			{
				return value;
			}
			using (Stream stream = _archive.GetEntry(SourcePath(filename)).Open())
			{
				StreamReader streamReader = new StreamReader(stream);
				List<string> list = new List<string>();
				while (!streamReader.EndOfStream)
				{
					list.Add(streamReader.ReadLine());
				}
				value = new ShaderSource(filename, list.ToArray(), filename != Metadata.SourceFile.FileName);
			}
			_cachedSources.Add(filename, value);
			return value;
		}

		public void WriteVariant(string platform, uint variant, Stream stream)
		{
			Stream stream2 = _archive.CreateEntry(VariantPath(platform, variant), CompressionLevel.NoCompression).Open();
			stream.CopyTo(stream2);
			stream2.Close();
		}

		public byte[] ReadVariant(string platform, uint variant)
		{
			ZipArchiveEntry entry = _archive.GetEntry(VariantPath(platform, variant));
			if (entry == null)
			{
				return null;
			}
			using Stream stream = entry.Open();
			byte[] array = new byte[entry.Length];
			int i;
			for (i = 0; i < array.Length; i += stream.Read(array, i, array.Length - i))
			{
				if (!stream.CanRead)
				{
					break;
				}
			}
			if (i != entry.Length)
			{
				throw new Exception("Could not the entire entry data");
			}
			return array;
		}

		public static string VariantPath(string platform, uint variant)
		{
			return "Variants/" + platform + "/" + variant.ToString("X8");
		}

		public static string SourcePath(string sourceSubpath)
		{
			return "Sources/" + sourceSubpath;
		}

		public void Dispose()
		{
			_archive.Dispose();
		}
	}
	public class ShaderSource
	{
		private static HashSet<string> IgnoredIncludes = new HashSet<string>
		{
			"AutoLight.cginc", "GLSLSupport.glslinc", "HLSLSupport.cginc", "Lighting.cginc", "SpeedTree8Common.cginc", "SpeedTreeBillboardCommon.cginc", "SpeedTreeCommon.cginc", "SpeedTreeVertex.cginc", "SpeedTreeWind.cginc", "TerrainEngine.cginc",
			"TerrainPreview.cginc", "TerrainSplatmapCommon.cginc", "TerrainTool.cginc", "Tessellation.cginc", "UnityBuiltin2xTreeLibrary.cginc", "UnityBuiltin3xTreeLibrary.cginc", "UnityCG.cginc", "UnityCG.glslinc", "UnityCustomRenderTexture.cginc", "UnityDeferredLibrary.cginc",
			"UnityDeprecated.cginc", "UnityGBuffer.cginc", "UnityGlobalIllumination.cginc", "UnityImageBasedLighting.cginc", "UnityInstancing.cginc", "UnityLightingCommon.cginc", "UnityMetaPass.cginc", "UnityPBSLighting.cginc", "UnityShaderUtilities.cginc", "UnityShaderVariables.cginc",
			"UnityShadowLibrary.cginc", "UnitySprites.cginc", "UnityStandardBRDF.cginc", "UnityStandardConfig.cginc", "UnityStandardCore.cginc", "UnityStandardCoreForward.cginc", "UnityStandardCoreForwardSimple.cginc", "UnityStandardInput.cginc", "UnityStandardMeta.cginc", "UnityStandardParticleEditor.cginc",
			"UnityStandardParticleInstancing.cginc", "UnityStandardParticles.cginc", "UnityStandardParticleShadow.cginc", "UnityStandardShadow.cginc", "UnityStandardUtils.cginc", "UnityStereoExtensions.glslinc", "UnityStereoSupport.glslinc", "UnityUI.cginc", "UnityUIE.cginc"
		};

		public string File { get; private set; }

		public string[] Lines { get; private set; }

		public bool IsInclude { get; private set; }

		public string ShaderName { get; private set; }

		public int ShaderNameLine { get; private set; }

		public int ShaderNameStartIndex { get; private set; }

		public int ShaderNameEndIndex { get; private set; }

		public int PropertiesStartLine { get; private set; } = -1;

		public int PropertiesStartIndex { get; private set; } = -1;

		public int PropertiesEndLine { get; private set; } = -1;

		public int PropertiesEndIndex { get; private set; } = -1;

		public List<int> IncludeLines { get; private set; } = new List<int>();

		public List<int> MultiCompileLines { get; private set; } = new List<int>();

		public List<int> OnlyRenderersLines { get; private set; } = new List<int>();

		public List<int> FallbackLines { get; private set; } = new List<int>();

		public List<string> Includes { get; private set; } = new List<string>();

		public List<List<string>> Variants { get; private set; } = new List<List<string>>();

		public static List<ShaderSource> CollectSources(string file)
		{
			List<ShaderSource> list = new List<ShaderSource>();
			Dictionary<string, ShaderSource> dictionary = new Dictionary<string, ShaderSource>();
			ShaderSource shaderSource = new ShaderSource(file, isInclude: false);
			ProcessIncludes(shaderSource, dictionary);
			list.Add(shaderSource);
			foreach (KeyValuePair<string, ShaderSource> item in dictionary)
			{
				list.Add(item.Value);
			}
			Dictionary<string, string> nameMapping = new Dictionary<string, string>();
			foreach (ShaderSource item2 in list)
			{
				item2.FlattenPath(nameMapping);
			}
			foreach (ShaderSource item3 in list)
			{
				item3.UpdateIncludes(nameMapping);
			}
			return list;
		}

		private static void ProcessIncludes(ShaderSource source, Dictionary<string, ShaderSource> dependencies)
		{
			source.ResolveIncludes();
			foreach (string include in source.Includes)
			{
				if (!dependencies.ContainsKey(include))
				{
					ShaderSource shaderSource = new ShaderSource(include, isInclude: true);
					dependencies.Add(include, shaderSource);
					ProcessIncludes(shaderSource, dependencies);
				}
			}
		}

		public ShaderSource(string filename, bool isInclude)
			: this(filename, System.IO.File.ReadAllLines(filename), isInclude)
		{
		}

		public ShaderSource(string filename, string[] lines, bool isInclude)
		{
			File = filename;
			Lines = lines;
			IsInclude = isInclude;
			bool insideComment = false;
			bool flag = false;
			bool flag2 = false;
			bool flag3 = false;
			bool flag4 = false;
			int num = 0;
			for (int i = 0; i < lines.Length; i++)
			{
				string rawLine = GetRawLine(lines[i], ref insideComment);
				string text = rawLine.Trim();
				if (!IsInclude)
				{
					if (!flag)
					{
						flag = rawLine.Contains("Shader");
					}
					if (flag && !flag2)
					{
						ShaderNameStartIndex = rawLine.IndexOf('"');
						if (ShaderNameStartIndex >= 0)
						{
							ShaderNameStartIndex++;
							ShaderNameLine = i;
							ShaderNameEndIndex = rawLine.IndexOf('"', ShaderNameStartIndex + 1);
							flag2 = true;
							ShaderName = rawLine.Substring(ShaderNameStartIndex, ShaderNameEndIndex - ShaderNameStartIndex);
						}
					}
					int j = 0;
					if (flag2 && !flag3)
					{
						j = rawLine.IndexOf("Properties");
						if (j >= 0)
						{
							flag3 = true;
							PropertiesStartIndex = -1;
						}
					}
					if (flag3 && !flag4)
					{
						for (; j < rawLine.Length; j++)
						{
							switch (rawLine[j])
							{
							case '{':
								if (num == 0)
								{
									PropertiesStartLine = i;
									PropertiesStartIndex = j;
								}
								num++;
								break;
							case '}':
								num--;
								if (num == 0)
								{
									PropertiesEndLine = i;
									PropertiesEndIndex = j;
									flag4 = true;
								}
								break;
							}
						}
					}
				}
				if (text.StartsWith("#pragma "))
				{
					if (text.Contains("multi_compile "))
					{
						int num2 = rawLine.IndexOf("multi_compile");
						num2 += "multi_compile".Length;
						rawLine = rawLine.Substring(num2);
						List<string> item = new List<string>(from v in rawLine.Split(new string[1] { " " }, StringSplitOptions.RemoveEmptyEntries)
							select ProcessVariant(v));
						MultiCompileLines.Add(i);
						Variants.Add(item);
					}
					else if (text.Contains("shader_feature "))
					{
						int num3 = rawLine.IndexOf("shader_feature");
						num3 += "shader_feature".Length;
						rawLine = rawLine.Substring(num3);
						List<string> item2 = new List<string>
						{
							"_",
							rawLine.Trim()
						};
						MultiCompileLines.Add(i);
						Variants.Add(item2);
					}
					else if (text.Contains("only_renderers"))
					{
						OnlyRenderersLines.Add(i);
					}
				}
				else if (text.StartsWith("#include "))
				{
					int num4 = rawLine.IndexOf('"') + 1;
					int num5 = rawLine.LastIndexOf('"');
					string item3 = rawLine.Substring(num4, num5 - num4).Trim();
					if (!IgnoredIncludes.Contains(item3))
					{
						IncludeLines.Add(i);
						Includes.Add(item3);
					}
				}
				else if (text.StartsWith("fallback ", StringComparison.InvariantCultureIgnoreCase))
				{
					FallbackLines.Add(i);
				}
			}
		}

		public string GetSource()
		{
			StringBuilder stringBuilder = new StringBuilder();
			string[] lines = Lines;
			foreach (string value in lines)
			{
				stringBuilder.AppendLine(value);
			}
			return stringBuilder.ToString();
		}

		public string GetVariantSource(List<string> keywords, uint variantIndex, string renderers)
		{
			StringBuilder stringBuilder = new StringBuilder();
			if (IsInclude)
			{
				foreach (string keyword in keywords)
				{
					InjectDefine(stringBuilder, keyword);
				}
			}
			for (int i = 0; i < Lines.Length; i++)
			{
				if (OnlyRenderersLines.IndexOf(i) >= 0)
				{
					StringBuilder stringBuilder2 = stringBuilder;
					StringBuilder.AppendInterpolatedStringHandler handler = new StringBuilder.AppendInterpolatedStringHandler(23, 1, stringBuilder2);
					handler.AppendLiteral("#pragma only_renderers ");
					handler.AppendFormatted(renderers);
					stringBuilder2.AppendLine(ref handler);
					continue;
				}
				int num = MultiCompileLines.IndexOf(i);
				if (!IsInclude && i == ShaderNameLine)
				{
					string text = Lines[i].Remove(ShaderNameStartIndex, ShaderNameEndIndex - ShaderNameStartIndex);
					text = text.Insert(ShaderNameStartIndex, ShaderName + "_" + variantIndex.ToString("X8"));
					stringBuilder.AppendLine(text);
				}
				else if (num >= 0 && !IsInclude)
				{
					List<string> list = Variants[num];
					foreach (string keyword2 in keywords)
					{
						if (!(keyword2 == "_") && list.Contains(keyword2))
						{
							InjectDefine(stringBuilder, keyword2);
						}
					}
				}
				else
				{
					stringBuilder.AppendLine(Lines[i]);
				}
			}
			return stringBuilder.ToString();
		}

		private static void InjectDefine(StringBuilder str, string keyword)
		{
			str.AppendLine("#ifndef " + keyword);
			str.AppendLine("#define " + keyword + " 1");
			str.AppendLine("#endif");
		}

		public string ComputeSourceHash()
		{
			MemoryStream memoryStream = new MemoryStream();
			StreamWriter streamWriter = new StreamWriter(memoryStream);
			string[] lines = Lines;
			foreach (string value in lines)
			{
				streamWriter.WriteLine(value);
			}
			streamWriter.Flush();
			memoryStream.Seek(0L, SeekOrigin.Begin);
			return FileUtil.GenerateFileSignature(memoryStream);
		}

		internal void ResolveIncludes()
		{
			if (File == null)
			{
				throw new Exception("No original file! Cannot resolve includes");
			}
			string directoryName = Path.GetDirectoryName(File);
			for (int i = 0; i < Includes.Count; i++)
			{
				string fullPath = Path.GetFullPath(Path.Combine(directoryName, Includes[i]));
				if (!System.IO.File.Exists(fullPath))
				{
					fullPath = Path.GetFullPath(Includes[i]);
				}
				if (!System.IO.File.Exists(fullPath))
				{
					throw new Exception("Cannot resolve include: " + Includes[i]);
				}
				Includes[i] = fullPath;
			}
		}

		internal void FlattenPath(Dictionary<string, string> nameMapping)
		{
			string text = Path.GetFileName(File);
			while (nameMapping.ContainsValue(text))
			{
				text = Path.GetFileNameWithoutExtension(text) + "_" + Path.GetExtension(text);
			}
			nameMapping.Add(File, text);
			File = text;
		}

		internal void UpdateIncludes(Dictionary<string, string> nameMapping)
		{
			for (int i = 0; i < Includes.Count; i++)
			{
				int num = IncludeLines[i];
				Lines[num] = "#include \"" + nameMapping[Includes[i]] + "\"";
			}
		}

		private static string ProcessVariant(string variant)
		{
			for (int i = 0; i < variant.Length; i++)
			{
				if (variant[i] != '_')
				{
					return variant;
				}
			}
			return "_";
		}

		private static string GetRawLine(string line, ref bool insideComment)
		{
			StringBuilder stringBuilder = new StringBuilder();
			for (int i = 0; i < line.Length; i++)
			{
				char c = line[i];
				bool flag = i + 1 < line.Length;
				if (insideComment)
				{
					if (c == '*' && flag && line[i + 1] == '/')
					{
						insideComment = false;
						i++;
					}
					stringBuilder.Append(' ');
					continue;
				}
				if (c == '/' && flag)
				{
					char c2 = line[i + 1];
					if (c2 == '/')
					{
						break;
					}
					if (c2 == '*')
					{
						insideComment = true;
						i++;
						stringBuilder.Append(' ');
						continue;
					}
				}
				stringBuilder.Append(c);
			}
			return stringBuilder.ToString();
		}
	}
	[DataModelType]
	public enum GlyphRenderMethod
	{
		Raster,
		MSDF
	}
	public class FontX : IDisposable
	{
		private ConcurrentDictionary<uint, GlyphMetrics> glyphMetrics = new ConcurrentDictionary<uint, GlyphMetrics>();

		private ConcurrentDictionary<uint, GlyphOutline> glyphOutlines = new ConcurrentDictionary<uint, GlyphOutline>();

		private ConcurrentDictionary<uint, GlyphMetrics> charMapping = new ConcurrentDictionary<uint, GlyphMetrics>();

		private ConcurrentDictionary<uint, ConcurrentDictionary<uint, float2>> kerningCache = new ConcurrentDictionary<uint, ConcurrentDictionary<uint, float2>>();

		private ConcurrentDictionary<string, uint> namedGlyphs = new ConcurrentDictionary<string, uint>();

		private List<GlyphAtlas> atlases = new List<GlyphAtlas>();

		private IFontDataSource fontDataSource;

		public string Name { get; private set; }

		public float LineHeight { get; private set; }

		public int GlyphCount { get; private set; }

		public int NamedGlyphCount => namedGlyphs.Count;

		public FontX(IFontDataSource dataSource)
		{
			fontDataSource = dataSource;
			Name = dataSource.FontName;
			LineHeight = dataSource.LineHeight;
			GlyphCount = dataSource.GlyphCount;
		}

		public int2 GetDefaultGlyphResolution(uint glyphId)
		{
			if (fontDataSource != null)
			{
				return fontDataSource.GetDefaultGlyphResolution(glyphId);
			}
			return int2.Zero;
		}

		public GlyphMetrics GetGlyphMetrics(uint glyphId)
		{
			if (glyphMetrics.TryGetValue(glyphId, out GlyphMetrics value))
			{
				return value;
			}
			if (fontDataSource != null)
			{
				value = fontDataSource.ExtractGlyphMetrics(glyphId);
			}
			glyphMetrics.TryAdd(glyphId, value);
			return value;
		}

		public bool GetGlyphTintable(uint glyphId)
		{
			if (fontDataSource != null)
			{
				return fontDataSource.GetGlyphTintable(glyphId);
			}
			return true;
		}

		public GlyphMetrics GetCharMetrics(char ch)
		{
			return GetCharMetrics((uint)ch);
		}

		public GlyphMetrics GetCharMetrics(uint charcode)
		{
			if (charMapping.TryGetValue(charcode, out GlyphMetrics value))
			{
				return value;
			}
			if (fontDataSource == null)
			{
				charMapping.TryAdd(charcode, null);
				return null;
			}
			uint glyphId = fontDataSource.CharToGlyphId(charcode);
			value = GetGlyphMetrics(glyphId);
			charMapping.TryAdd(charcode, value);
			return value;
		}

		public uint GetGlyphIdFromName(string glyphName)
		{
			namedGlyphs.TryGetValue(glyphName, out var value);
			return value;
		}

		public void ClearCachedCharMapping(uint charcode)
		{
			charMapping.TryRemove(charcode, out GlyphMetrics _);
		}

		public float2 GetKerning(uint leftGlyphId, uint rightGlyphId)
		{
			if (kerningCache.TryGetValue(leftGlyphId, out ConcurrentDictionary<uint, float2> value) && value.TryGetValue(rightGlyphId, out var value2))
			{
				return value2;
			}
			if (fontDataSource == null)
			{
				return float2.Zero;
			}
			if (value == null)
			{
				value = new ConcurrentDictionary<uint, float2>();
			}
			value2 = fontDataSource.ExtractKerning(leftGlyphId, rightGlyphId);
			if (value.TryAdd(rightGlyphId, value2) && !kerningCache.TryAdd(leftGlyphId, value) && kerningCache.TryGetValue(leftGlyphId, out value))
			{
				value.TryAdd(rightGlyphId, value2);
			}
			return value2;
		}

		public uint CharToGlyphId(char ch)
		{
			return GetCharMetrics(ch)?.glyphId ?? 0;
		}

		public GlyphOutline GetOutline(uint glyphId)
		{
			if (glyphOutlines.TryGetValue(glyphId, out GlyphOutline value))
			{
				return value;
			}
			value = fontDataSource?.ExtractGlyphOutline(glyphId);
			glyphOutlines.TryAdd(glyphId, value);
			return value;
		}

		public void AssignGlyphName(string name, uint glyphId, bool replaceExisting)
		{
			if (replaceExisting)
			{
				namedGlyphs.AddOrUpdate(name, glyphId, (string n, uint i) => glyphId);
			}
			else if (namedGlyphs.TryAdd(name, glyphId))
			{
				throw new Exception("Failed to assign glyph name. An existing glyph with the same name exists");
			}
		}

		public void RemoveGlyphName(string name, uint glyphId)
		{
			if (namedGlyphs.TryRemove(name, out var value) && glyphId != value)
			{
				throw new Exception($"Removed wrong glyphId! GlyphName: {name}, RemovingId: {glyphId}, removedId: {value}");
			}
		}

		public static FontX Load(string file, string extension = null)
		{
			if (extension == null)
			{
				extension = Path.GetExtension(file).ToLower().Replace(".", "");
			}
			switch (extension)
			{
			case "ttf":
			case "ttc":
			case "otf":
			case "otc":
			case "woff":
			case "woff2":
			{
				IFontDataSource dataSource = new FreeTypeFont(file);
				return new FontX(dataSource);
			}
			default:
				throw new Exception("Unsupported file format: " + file);
			}
		}

		public void Dispose()
		{
			fontDataSource?.Dispose();
			fontDataSource = null;
		}

		public override string ToString()
		{
			return $"Font. Name: {Name}, GlyphCount: {GlyphCount}, NamedGlyphCount: {NamedGlyphCount}";
		}

		public unsafe bool RenderGlyphMSDF(uint glyphId, Bitmap2D bitmap, Rect region, int pixelRange, bool rotated)
		{
			GlyphOutline outline = GetOutline(glyphId);
			if (outline == null || outline.ContourCount == 0)
			{
				return false;
			}
			GlyphMetrics glyphMetrics = GetGlyphMetrics(glyphId);
			float2 b = new float2(glyphMetrics.width, glyphMetrics.height);
			float2 a = region.size - pixelRange;
			if (rotated)
			{
				a = a.yx;
			}
			float num = MathX.MinComponent(a / b);
			nint shape = MSDF_Native.create_shape();
			try
			{
				foreach (GlyphContour item in outline)
				{
					nint contour = MSDF_Native.shape_add_contour(shape);
					for (int i = 0; i < item.SegmentCount; i++)
					{
						GlyphSegment glyphSegment = item.segments[i];
						float2 originPoint = item.GetOriginPoint(i);
						switch (glyphSegment.type)
						{
						case GlyphSegmentType.Line:
							MSDF_Native.contour_add_line(contour, originPoint.x * num, originPoint.y * num, glyphSegment.point.x * num, glyphSegment.point.y * num);
							break;
						case GlyphSegmentType.Conic:
							MSDF_Native.contour_add_conic(contour, originPoint.x * num, originPoint.y * num, glyphSegment.controlPoint0.x * num, glyphSegment.controlPoint0.y * num, glyphSegment.point.x * num, glyphSegment.point.y * num);
							break;
						case GlyphSegmentType.Cubic:
							MSDF_Native.contour_add_cubic(contour, originPoint.x * num, originPoint.y * num, glyphSegment.controlPoint0.x * num, glyphSegment.controlPoint0.y * num, glyphSegment.controlPoint1.x * num, glyphSegment.controlPoint1.y * num, glyphSegment.point.x * num, glyphSegment.point.y * num);
							break;
						}
					}
				}
				double left = double.MaxValue;
				double bottom = double.MaxValue;
				double right = double.MinValue;
				double top = double.MinValue;
				MSDF_Native.shape_bounds(shape, ref left, ref bottom, ref right, ref top);
				double num2 = right - left;
				double num3 = top - bottom;
				double num4 = 0.0 - left;
				double num5 = 0.0 - (top - num3);
				num2 += (double)pixelRange;
				num3 += (double)pixelRange;
				float2 v = region.size;
				if (rotated)
				{
					v = v.yx;
				}
				double num6 = MathX.Min((double)v.x / num2, (double)v.y / num3);
				num4 += (double)((float)pixelRange * 0.5f);
				num5 += (double)((float)pixelRange * 0.5f);
				MSDF_Native.shape_edge_coloring_simple(shape, 3.0, 0uL);
				RawValueList<float3> list = Pool.BorrowRawValueList<float3>();
				int2 @int = MathX.CeilToInt(in v);
				int num7 = @int.x * @int.y;
				if (list.Capacity < num7)
				{
					list.Capacity = num7;
				}
				fixed (float3* elements = list.Elements)
				{
					MSDF_Native.shape_generateMSDF(new IntPtr(elements), @int.x, @int.y, shape, pixelRange, num6, num6, num4, num5, 1.001);
				}
				int num8 = MathX.RoundToInt(region.x);
				int num9 = MathX.RoundToInt(region.y);
				int num10 = MathX.CeilToInt(region.width);
				int num11 = MathX.CeilToInt(region.height);
				for (int j = 0; j < num11; j++)
				{
					for (int k = 0; k < num10; k++)
					{
						int num12 = ((!rotated) ? (k + j * num10) : (j + k * num11));
						float3 rgb = list.Elements[num12];
						bitmap.SetPixel(num8 + k, num9 + j, new color(in rgb));
					}
				}
				Pool.Return(ref list);
			}
			finally
			{
				MSDF_Native.free_shape(shape);
			}
			return true;
		}

		public bool RenderGlyphRaster(uint glyphId, Bitmap2D bitmap, Rect region, bool rotated)
		{
			if (!fontDataSource.SupportsRenderMethod(GlyphRenderMethod.Raster))
			{
				return false;
			}
			fontDataSource.RenderRawGlyphBitmap(glyphId, bitmap, (IntRect)region, rotated);
			return true;
		}
	}
	public readonly struct GlyphPackData
	{
		public readonly uint glyphId;

		public readonly float2 size;

		public readonly float area;

		public readonly float longerSide;

		public GlyphPackData(uint glyphId, in float2 size)
		{
			this.glyphId = glyphId;
			this.size = size;
			area = size.x * size.y;
			longerSide = MathX.MaxComponent(in size);
		}
	}
	public class GlyphAtlas : IDisposable
	{
		public const int DEFAULT_PACK_REGION_SIZE = 512;

		public const int DEFAULT_MAX_ATLAS_SIZE = 8192;

		public readonly FontX Font;

		public readonly int PixelRange;

		public readonly int Padding;

		public readonly int PackRegionSize;

		public readonly GlyphRenderMethod RenderMethod;

		private readonly ConcurrentDictionary<uint, GlyphAtlasData> _glyphs = new ConcurrentDictionary<uint, GlyphAtlasData>();

		private RectPackNode _rootPackNode;

		private int _maxAtlasSize;

		public bool BitmapAllocated => Atlas != null;

		public bool AllowsPacking => _rootPackNode != null;

		public int2 CurrentPackSize
		{
			get
			{
				Rect bounds = _rootPackNode.Bounds;
				return (int2)bounds.size;
			}
		}

		public Bitmap2D Atlas { get; private set; }

		public IBackingBufferAllocator Allocator { get; private set; }

		public GlyphAtlas(FontX font, GlyphRenderMethod renderMethod, IBackingBufferAllocator allocator, int padding = 1, int pixelRange = 2, int packRegionSize = 512, int maxAtlasSize = 8192)
		{
			Font = font;
			Allocator = allocator;
			PixelRange = pixelRange;
			Padding = padding;
			RenderMethod = renderMethod;
			PackRegionSize = packRegionSize;
			_rootPackNode = new RectPackNode(float2.One * PackRegionSize);
			_maxAtlasSize = 8192;
		}

		public GlyphAtlasData GetGlyphData(uint glyphId)
		{
			_glyphs.TryGetValue(glyphId, out GlyphAtlasData value);
			return value;
		}

		public bool HasGlyphData(uint glyphId)
		{
			return _glyphs.ContainsKey(glyphId);
		}

		public int Pack(List<GlyphPackData> glyphs, int offset = 0, bool allowPartialPack = false)
		{
			if (!AllowsPacking)
			{
				throw new Exception("This atlas doesn't allow packing");
			}
			if (glyphs.Any((GlyphPackData g) => _glyphs.ContainsKey(g.glyphId)))
			{
				throw new Exception("Some of the glyphs are already packed into this atlas!");
			}
			if (offset == 0)
			{
				glyphs.Sort((GlyphPackData a, GlyphPackData b) => -a.longerSide.CompareTo(b.longerSide));
			}
			for (int num = offset; num < glyphs.Count; num++)
			{
				if (!Pack(glyphs[num]))
				{
					if (allowPartialPack)
					{
						return num;
					}
					for (int num2 = offset; num2 <= num; num2++)
					{
						_glyphs.TryRemove(glyphs[num2].glyphId, out GlyphAtlasData _);
					}
					FinishPacking();
					return 0;
				}
			}
			return glyphs.Count;
		}

		public bool Pack(in GlyphPackData glyph)
		{
			if (!AllowsPacking)
			{
				throw new Exception("This atlas doesn't allow packing");
			}
			float2 a = glyph.size;
			a = a + float2.One * PixelRange + float2.One * Padding * 2;
			bool rotated = false;
			float2 size = MathX.Ceil(in a);
			if (size.x > size.y)
			{
				size = size.yx;
				a = a.yx;
				rotated = true;
			}
			RectPackNode emptyNode = _rootPackNode.GetEmptyNode(in size);
			if (emptyNode == null && !BitmapAllocated)
			{
				GrowAtlas();
				emptyNode = _rootPackNode.GetEmptyNode(in size);
			}
			if (emptyNode == null)
			{
				return false;
			}
			emptyNode.Pack(in size);
			Rect content = emptyNode.Content;
			ref float2 position = ref content.position;
			position += Padding;
			content.size = a;
			ref float2 size2 = ref content.size;
			size2 -= Padding * 2;
			GlyphAtlasData glyphAtlasData = new GlyphAtlasData(glyph.glyphId, content, rotated);
			if (BitmapAllocated)
			{
				glyphAtlasData.CalculateRenderParameters(this);
			}
			if (!_glyphs.TryAdd(glyphAtlasData.glyphId, glyphAtlasData))
			{
				throw new InvalidOperationException("Couldn't add the glyph info, it seems it's already added! Make sure to only pack glyphs from one thread at the time");
			}
			return true;
		}

		public void AllocateBitmap(bool mipmaps)
		{
			if (BitmapAllocated)
			{
				throw new InvalidOperationException("Bitmap is already allocated");
			}
			if (_rootPackNode == null)
			{
				throw new Exception("No packing data to allocate bitmap from!");
			}
			bool flag = RenderMethod switch
			{
				GlyphRenderMethod.MSDF => true, 
				GlyphRenderMethod.Raster => false, 
				_ => throw new NotImplementedException("Unknown RenderMethod: " + RenderMethod), 
			};
			Atlas?.Buffer?.Dispose();
			Atlas = new Bitmap2D((int)_rootPackNode.Bounds.width, (int)_rootPackNode.Bounds.height, TextureFormat.RGBA32, mipmaps, (!flag) ? ColorProfile.sRGB : ColorProfile.Linear, flipY: true, null, Allocator);
			if (Allocator != null)
			{
				Atlas.RawData.Clear();
			}
			foreach (KeyValuePair<uint, GlyphAtlasData> glyph in _glyphs)
			{
				glyph.Value.CalculateRenderParameters(this);
			}
		}

		private void GrowAtlas()
		{
			if (_rootPackNode.Bounds.width > _rootPackNode.Bounds.height)
			{
				float val = _rootPackNode.Bounds.height * 2f;
				val = MathX.Min(_maxAtlasSize, val);
				val -= _rootPackNode.Bounds.height;
				if (!(val <= 0f))
				{
					_rootPackNode = _rootPackNode.ExtendVertical(val);
				}
			}
			else
			{
				float val2 = _rootPackNode.Bounds.width * 2f;
				val2 = MathX.Min(_maxAtlasSize, val2);
				val2 -= _rootPackNode.Bounds.width;
				if (!(val2 <= 0f))
				{
					_rootPackNode = _rootPackNode.ExtendHorizontal(val2);
				}
			}
		}

		public void FinishPacking()
		{
		}

		public void CopyGlyphBitmapFrom(uint glyphId, GlyphAtlas sourceAtlas)
		{
			GlyphAtlasData glyphData = GetGlyphData(glyphId);
			if (glyphData == null)
			{
				throw new ArgumentException("Atlas doesn't contain glyph: " + glyphId);
			}
			CopyGlyphBitmapFrom(glyphData, sourceAtlas);
		}

		public void CopyGlyphBitmapFrom(GlyphAtlasData targetGlyph, GlyphAtlas sourceAtlas)
		{
			GlyphAtlasData glyphData = sourceAtlas.GetGlyphData(targetGlyph.glyphId);
			if (glyphData == null)
			{
				throw new ArgumentException("Source atlas doesn't contain glyph: " + targetGlyph.glyphId);
			}
			CopyGlyphBitmapFrom(targetGlyph, sourceAtlas, glyphData);
		}

		public void CopyGlyphBitmapFrom(GlyphAtlasData targetGlyph, GlyphAtlas sourceAtlas, GlyphAtlasData sourceGlyph)
		{
			Rect region = sourceGlyph.region;
			Rect region2 = targetGlyph.region;
			float2 a = (sourceGlyph.rotated ? region.size.yx : region.size.xy);
			if (a != (targetGlyph.rotated ? region2.size.yx : region2.size.xy))
			{
				throw new Exception("Size mismatch!");
			}
			int2 @int = (int2)region.position;
			int2 int2 = (int2)region2.position;
			for (int i = 0; (float)i < a.y; i++)
			{
				for (int j = 0; (float)j < a.x; j++)
				{
					int num = (sourceGlyph.rotated ? i : j);
					int num2 = (sourceGlyph.rotated ? j : i);
					int num3 = (targetGlyph.rotated ? i : j);
					int num4 = (targetGlyph.rotated ? j : i);
					color color = sourceAtlas.Atlas.GetPixel(num + @int.x, num2 + @int.y);
					Atlas.SetPixel(num3 + int2.x, num4 + int2.y, in color);
				}
			}
		}

		public void Dispose()
		{
			Allocator = null;
			Atlas?.Buffer?.Dispose();
			Atlas = null;
		}
	}
	public class GlyphAtlasData
	{
		public readonly uint glyphId;

		public readonly Rect region;

		public readonly bool rotated;

		public float2 offset { get; private set; }

		public Rect uv { get; private set; }

		public float2 rangeExtendRatio { get; private set; }

		public GlyphAtlasData(uint glyphId, Rect region, bool rotated)
		{
			this.glyphId = glyphId;
			this.region = region;
			this.rotated = rotated;
		}

		public void CalculateRenderParameters(GlyphAtlas atlas)
		{
			float2 b = 1f / atlas.Atlas.Size;
			float2 a = region.position * b;
			float2 size = region.size * b;
			offset = (float2)MathX.CeilToInt(in region.size) - region.size;
			offset *= b;
			if (rotated)
			{
				offset = offset.x_;
			}
			else
			{
				offset = offset._y;
			}
			a += offset;
			uv = new Rect(new float2(a.x, 1f - a.y - size.y), in size);
			rangeExtendRatio = region.size / (region.size - atlas.PixelRange);
			if (rotated)
			{
				rangeExtendRatio = rangeExtendRatio.yx;
			}
		}
	}
	public class GlyphMetrics
	{
		public readonly uint glyphId;

		public readonly float width;

		public readonly float height;

		public readonly float horizontalAdvance;

		public readonly float horizontalBearingX;

		public readonly float horizontalBearingY;

		public readonly float verticalAdvance;

		public readonly float verticalBearingX;

		public readonly float verticalBearingY;

		public GlyphMetrics(uint glyphId, float width, float height, float horizontalAdvance, float horizontalBearingX, float horizontalBearingY, float verticalAdvance, float verticalBearingX, float verticalBearingY)
		{
			this.glyphId = glyphId;
			this.width = width;
			this.height = height;
			this.horizontalAdvance = horizontalAdvance;
			this.horizontalBearingX = horizontalBearingX;
			this.horizontalBearingY = horizontalBearingY;
			this.verticalAdvance = verticalAdvance;
			this.verticalBearingX = verticalBearingX;
			this.verticalBearingY = verticalBearingY;
		}

		public override string ToString()
		{
			return $"GlyphId: {glyphId}, Width: {width}, Height: {height}, HorizontalAdvance: {horizontalAdvance}, HorizontalBearing: {horizontalBearingX}x{horizontalBearingY}, VerticalAdvance: {verticalAdvance}, HorizontalBearing: {verticalBearingX}x{verticalBearingY}";
		}
	}
	public class GlyphContour
	{
		public float2 origin;

		public readonly List<GlyphSegment> segments = new List<GlyphSegment>();

		public int SegmentCount => segments.Count;

		public GlyphContour(in float2 origin)
		{
			this.origin = origin;
		}

		public float2 GetOriginPoint(int segmentIndex)
		{
			if (segmentIndex == 0)
			{
				return origin;
			}
			return segments[segmentIndex - 1].point;
		}

		public void AddLine(in float2 point)
		{
			segments.Add(GlyphSegment.Line(in point));
		}

		public void AddConic(in float2 point, in float2 controlPoint)
		{
			segments.Add(GlyphSegment.Conic(in point, in controlPoint));
		}

		public void AddCubic(in float2 point, in float2 controlPoint0, in float2 controlPoint1)
		{
			segments.Add(GlyphSegment.Cubic(in point, in controlPoint0, in controlPoint1));
		}
	}
	public enum GlyphSegmentType
	{
		Line,
		Conic,
		Cubic
	}
	public readonly struct GlyphSegment
	{
		public readonly GlyphSegmentType type;

		public readonly float2 point;

		public readonly float2 controlPoint0;

		public readonly float2 controlPoint1;

		private GlyphSegment(GlyphSegmentType type, in float2 point, in float2 controlPoint0, in float2 controlPoint1)
		{
			this.type = type;
			this.point = point;
			this.controlPoint0 = controlPoint0;
			this.controlPoint1 = controlPoint1;
		}

		public static GlyphSegment Line(in float2 point)
		{
			return new GlyphSegment(GlyphSegmentType.Line, in point, default(float2), default(float2));
		}

		public static GlyphSegment Conic(in float2 point, in float2 controlPoint)
		{
			return new GlyphSegment(GlyphSegmentType.Conic, in point, in controlPoint, default(float2));
		}

		public static GlyphSegment Cubic(in float2 point, in float2 controlPoint0, in float2 controlPoint1)
		{
			return new GlyphSegment(GlyphSegmentType.Cubic, in point, in controlPoint0, in controlPoint1);
		}
	}
	public class GlyphOutline : IEnumerable<GlyphContour>, IEnumerable
	{
		private readonly List<GlyphContour> _contours = new List<GlyphContour>();

		public int ContourCount => _contours.Count;

		public GlyphContour LastContour => _contours[ContourCount - 1];

		public GlyphContour this[int index] => _contours[index];

		public GlyphContour AddContour(in float2 origin)
		{
			GlyphContour glyphContour = new GlyphContour(in origin);
			_contours.Add(glyphContour);
			return glyphContour;
		}

		public void AddContour(GlyphContour contour)
		{
			_contours.Add(contour);
		}

		public void RemoveContourAt(int index)
		{
			_contours.RemoveAt(index);
		}

		public List<GlyphContour>.Enumerator GetEnumerator()
		{
			return _contours.GetEnumerator();
		}

		IEnumerator<GlyphContour> IEnumerable<GlyphContour>.GetEnumerator()
		{
			return GetEnumerator();
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}

		public void FixArtifacts()
		{
			for (int num = ContourCount - 1; num >= 0; num--)
			{
				if (_contours[num].SegmentCount == 0)
				{
					_contours.RemoveAt(num);
				}
				else if (_contours[num].SegmentCount == 1 && _contours[num].segments[0].type == GlyphSegmentType.Line)
				{
					_contours.RemoveAt(num);
				}
			}
		}
	}
	public class DynamicBitmapFileFont : IFontDataSource, IDisposable
	{
		public class SpriteGlyph
		{
			public readonly string file;

			public readonly GlyphMetrics metrics;

			public readonly bool tintable;

			private int2 _cachedSize;

			public Bitmap2D LoadedBitmap { get; private set; }

			public int2 SpriteResolution
			{
				get
				{
					if (_cachedSize == int2.Zero)
					{
						EnsureLoadedBitmap();
					}
					return _cachedSize;
				}
			}

			public SpriteGlyph(string file, GlyphMetrics metrics, bool tintable, Bitmap2D loadedBitmap = null)
			{
				this.file = file;
				this.metrics = metrics;
				this.tintable = tintable;
				LoadedBitmap = loadedBitmap;
				if (loadedBitmap != null)
				{
					_cachedSize = loadedBitmap.Size;
				}
			}

			public void EnsureLoadedBitmap()
			{
				if (LoadedBitmap == null)
				{
					if (File.Exists(file))
					{
						LoadedBitmap = TextureDecoder.Decode(file, false);
					}
					else
					{
						LoadedBitmap = TextureDecoder.ERRORTEXTURE;
					}
					_cachedSize = LoadedBitmap.Size;
				}
			}

			public void FreeBitmap()
			{
				LoadedBitmap = null;
			}
		}

		private object _lock = new object();

		private Dictionary<uint, SpriteGlyph> _glyphs = new Dictionary<uint, SpriteGlyph>();

		private BiDictionary<uint, uint> _charToGlyphId = new BiDictionary<uint, uint>();

		public string FontName { get; private set; }

		public int GlyphCount => _glyphs.Count;

		public float LineHeight => 1f;

		public uint CharToGlyphId(uint charcode)
		{
			lock (_lock)
			{
				_charToGlyphId.TryGetSecond(charcode, out var second);
				return second;
			}
		}

		public void Dispose()
		{
		}

		public bool GetGlyphTintable(uint glyphId)
		{
			lock (_lock)
			{
				if (_glyphs.TryGetValue(glyphId, out SpriteGlyph value))
				{
					return value.tintable;
				}
			}
			return false;
		}

		public GlyphMetrics ExtractGlyphMetrics(uint glyphId)
		{
			lock (_lock)
			{
				if (_glyphs.TryGetValue(glyphId, out SpriteGlyph value))
				{
					return value.metrics;
				}
			}
			return null;
		}

		public int2 GetDefaultGlyphResolution(uint glyphId)
		{
			lock (_lock)
			{
				if (_glyphs.TryGetValue(glyphId, out SpriteGlyph value))
				{
					return value.SpriteResolution;
				}
			}
			return int2.Zero;
		}

		public GlyphOutline ExtractGlyphOutline(uint glyphId)
		{
			throw new NotSupportedException("This is a bitmap font and extracting outlines is not supported");
		}

		public void RenderRawGlyphBitmap(uint glyphId, Bitmap2D target, IntRect rect, bool rotated)
		{
			SpriteGlyph value;
			lock (_lock)
			{
				if (!_glyphs.TryGetValue(glyphId, out value))
				{
					return;
				}
			}
			value.EnsureLoadedBitmap();
			Bitmap2D loadedBitmap = value.LoadedBitmap;
			float2 @float = 1f / (rect.Size - 1);
			for (int i = 0; i < rect.height; i++)
			{
				float num = (float)i * @float.y;
				int y = rect.y + i;
				for (int j = 0; j < rect.width; j++)
				{
					float num2 = (float)j * @float.x;
					color color = loadedBitmap.SampleUV(rotated ? new float2(num, num2) : new float2(num2, num)).ConvertProfile(loadedBitmap.Profile, target.Profile);
					target.SetPixel(rect.x + j, y, in color);
				}
			}
			value.FreeBitmap();
		}

		public bool SupportsRenderMethod(GlyphRenderMethod method)
		{
			return method switch
			{
				GlyphRenderMethod.Raster => true, 
				GlyphRenderMethod.MSDF => false, 
				_ => throw new Exception("Unknown render method: " + method), 
			};
		}

		public float2 ExtractKerning(uint leftGlyphId, uint rightGlyphId)
		{
			return float2.Zero;
		}

		public bool LoadFrom(string file)
		{
			throw new NotSupportedException("This font cannot be loaded from files");
		}

		public void AddSpriteGlyph(uint glyphId, uint unicodeCodepoint, SpriteGlyph spriteGlyph)
		{
			lock (_lock)
			{
				_glyphs.Add(glyphId, spriteGlyph);
				if (unicodeCodepoint != 0)
				{
					if (_charToGlyphId.ContainsFirst(unicodeCodepoint))
					{
						_charToGlyphId.RemoveByFirst(unicodeCodepoint);
					}
					_charToGlyphId.Add(unicodeCodepoint, glyphId);
				}
			}
		}

		public void RemoveSpriteGlyph(uint glyphId)
		{
			lock (_lock)
			{
				_glyphs.Remove(glyphId);
				_charToGlyphId.RemoveBySecond(glyphId);
			}
		}
	}
	public class FreeTypeFont : IFontDataSource, IDisposable
	{
		private static Library SharpFontLibrary = new Library();

		public static bool UseStaticCallbacks;

		private SharpFont.Face face;

		private float conversionRatio;

		private OutlineFuncs outlineFuncs;

		private GlyphOutline currentOutline;

		private static OutlineFuncs staticOutlineFuncs;

		private static float staticConversionRatio;

		private static GlyphOutline staticCurrentOutline;

		public static string FreeTypeVersion
		{
			get
			{
				lock (SharpFontLibrary)
				{
					return SharpFontLibrary.Version.ToString();
				}
			}
		}

		public string FontName { get; private set; }

		public int GlyphCount { get; private set; }

		public float LineHeight { get; private set; }

		public FreeTypeFont(string file)
		{
			lock (SharpFontLibrary)
			{
				face = new SharpFont.Face(SharpFontLibrary, File.ReadAllBytes(file), 0);
				FontName = face.FamilyName;
				GlyphCount = face.GlyphCount;
				conversionRatio = 1f / (float)(int)face.UnitsPerEM;
				LineHeight = (float)face.Height * conversionRatio;
				if (!UseStaticCallbacks)
				{
					outlineFuncs = new OutlineFuncs(MoveTo, LineTo, ConicTo, CubicTo, 0, 0);
				}
				else if (staticOutlineFuncs == null)
				{
					staticOutlineFuncs = new OutlineFuncs(MoveToStatic, LineToStatic, ConicToStatic, CubicToStatic, 0, 0);
				}
			}
		}

		public void Dispose()
		{
			SharpFont.Face face;
			lock (this.face)
			{
				face = this.face;
				this.face = null;
			}
			outlineFuncs?.Dispose();
			outlineFuncs = null;
			lock (SharpFontLibrary)
			{
				face?.Dispose();
			}
		}

		public int2 GetDefaultGlyphResolution(uint glyphId)
		{
			return int2.Zero;
		}

		public uint CharToGlyphId(uint charcode)
		{
			lock (face)
			{
				return face.GetCharIndex(charcode);
			}
		}

		public bool GetGlyphTintable(uint glyphId)
		{
			return true;
		}

		public float2 ExtractKerning(uint leftGlyphId, uint rightGlyphId)
		{
			lock (face)
			{
				FTVector26Dot6 kerning = face.GetKerning(leftGlyphId, rightGlyphId, KerningMode.Unscaled);
				return new float2((float)kerning.X.Value * conversionRatio, (float)kerning.Y.Value * conversionRatio);
			}
		}

		public GlyphMetrics ExtractGlyphMetrics(uint glyphId)
		{
			if (glyphId >= GlyphCount)
			{
				return null;
			}
			lock (face)
			{
				face.LoadGlyph(glyphId, LoadFlags.NoScale, LoadTarget.Normal);
				return new GlyphMetrics(glyphId, (float)face.Glyph.Metrics.Width.Value * conversionRatio, (float)face.Glyph.Metrics.Height.Value * conversionRatio, (float)face.Glyph.Metrics.HorizontalAdvance.Value * conversionRatio, (float)face.Glyph.Metrics.HorizontalBearingX.Value * conversionRatio, (float)face.Glyph.Metrics.HorizontalBearingY.Value * conversionRatio, (float)face.Glyph.Metrics.VerticalAdvance.Value * conversionRatio, (float)face.Glyph.Metrics.VerticalBearingX.Value * conversionRatio, (float)face.Glyph.Metrics.VerticalBearingY.Value * conversionRatio);
			}
		}

		public GlyphOutline ExtractGlyphOutline(uint glyphId)
		{
			lock (face)
			{
				face.LoadGlyph(glyphId, LoadFlags.NoScale, LoadTarget.Normal);
				currentOutline = new GlyphOutline();
				if (outlineFuncs != null)
				{
					face.Glyph.Outline.Decompose(outlineFuncs, IntPtr.Zero);
				}
				else
				{
					lock (SharpFontLibrary)
					{
						staticCurrentOutline = currentOutline;
						staticConversionRatio = conversionRatio;
						face.Glyph.Outline.Decompose(staticOutlineFuncs, IntPtr.Zero);
						staticCurrentOutline = null;
						staticConversionRatio = 0f;
					}
				}
				currentOutline.FixArtifacts();
				GlyphOutline result = currentOutline;
				currentOutline = null;
				return result;
			}
		}

		public bool SupportsRenderMethod(GlyphRenderMethod method)
		{
			return method switch
			{
				GlyphRenderMethod.Raster => false, 
				GlyphRenderMethod.MSDF => true, 
				_ => throw new Exception("Unknown render method: " + method), 
			};
		}

		public void RenderRawGlyphBitmap(uint glyphId, Bitmap2D target, IntRect rect, bool rotated)
		{
			throw new NotSupportedException("FreeTypeFont doesn't currently support raw glyph rendering");
		}

		private int MoveTo(ref FTVector point, nint userData)
		{
			currentOutline.AddContour(ToEngine(ref point));
			return 0;
		}

		private int LineTo(ref FTVector point, nint userData)
		{
			currentOutline.LastContour.AddLine(ToEngine(ref point));
			return 0;
		}

		private int ConicTo(ref FTVector controlPoint, ref FTVector point, nint userData)
		{
			currentOutline.LastContour.AddConic(ToEngine(ref point), ToEngine(ref controlPoint));
			return 0;
		}

		private int CubicTo(ref FTVector controlPoint0, ref FTVector controlPoint1, ref FTVector point, nint userData)
		{
			currentOutline.LastContour.AddCubic(ToEngine(ref point), ToEngine(ref controlPoint0), ToEngine(ref controlPoint1));
			return 0;
		}

		/// <summary>
		/// Converts a FreeType vector to our product's vector format
		/// </summary>
		/// <param name="vector"></param>
		/// <returns></returns>
		private float2 ToEngine(ref FTVector vector)
		{
			return new float2(vector.X.Value, vector.Y.Value) * conversionRatio;
		}

		[Elements.Core.MonoPInvokeCallback(typeof(MoveToFunc))]
		private static int MoveToStatic(ref FTVector point, nint userData)
		{
			staticCurrentOutline.AddContour(ToEngineStatic(ref point));
			return 0;
		}

		[Elements.Core.MonoPInvokeCallback(typeof(LineToFunc))]
		private static int LineToStatic(ref FTVector point, nint userData)
		{
			staticCurrentOutline.LastContour.AddLine(ToEngineStatic(ref point));
			return 0;
		}

		[Elements.Core.MonoPInvokeCallback(typeof(ConicToFunc))]
		private static int ConicToStatic(ref FTVector controlPoint, ref FTVector point, nint userData)
		{
			staticCurrentOutline.LastContour.AddConic(ToEngineStatic(ref point), ToEngineStatic(ref controlPoint));
			return 0;
		}

		[Elements.Core.MonoPInvokeCallback(typeof(CubicToFunc))]
		private static int CubicToStatic(ref FTVector controlPoint0, ref FTVector controlPoint1, ref FTVector point, nint userData)
		{
			staticCurrentOutline.LastContour.AddCubic(ToEngineStatic(ref point), ToEngineStatic(ref controlPoint0), ToEngineStatic(ref controlPoint1));
			return 0;
		}

		/// <summary>
		/// Converts a FreeType vector to our Engine's static vector configuration
		/// </summary>
		/// <param name="vector"></param>
		/// <returns></returns>
		private static float2 ToEngineStatic(ref FTVector vector)
		{
			return new float2(vector.X.Value, vector.Y.Value) * staticConversionRatio;
		}
	}
