	public enum CapitalizationMode
	{
		Lowercase,
		Uppercase,
		SmallCaps
	}
	public class StringCapitalizationNode : StringContainerNode, ICharacterFilter, ISizeFilter
	{
		public CapitalizationMode Mode;

		public StringCapitalizationNode(CapitalizationMode mode, int startIndex, StringContainerNode node)
			: base(startIndex, node)
		{
			Mode = mode;
		}

		public override StringContainerNode Clone(int startIndex, StringContainerNode parent)
		{
			return new StringCapitalizationNode(Mode, startIndex, parent);
		}

		public char FilterCharacter(char ch, int index)
		{
			switch (Mode)
			{
			case CapitalizationMode.Lowercase:
				return char.ToLowerInvariant(ch);
			case CapitalizationMode.Uppercase:
			case CapitalizationMode.SmallCaps:
				return char.ToUpperInvariant(ch);
			default:
				return ch;
			}
		}

		public float FilterSize(float size, int index)
		{
			if (Mode == CapitalizationMode.SmallCaps && char.IsLower(base.Root.String[index]))
			{
				return size * 0.75f;
			}
			return size;
		}
	}
