	public class StringColorNode : StringContainerNode
	{
		[Flags]
		public enum MixMode
		{
			Color = 1,
			Alpha = 2
		}

		private static Dictionary<string, colorX> colors = new Dictionary<string, colorX>
		{
			{
				"clear",
				colorX.Clear
			},
			{
				"white",
				colorX.White
			},
			{
				"gray",
				colorX.Gray
			},
			{
				"black",
				colorX.Black
			},
			{
				"red",
				colorX.Red
			},
			{
				"green",
				colorX.Green
			},
			{
				"blue",
				colorX.Blue
			},
			{
				"yellow",
				colorX.Yellow
			},
			{
				"cyan",
				colorX.Cyan
			},
			{
				"magenta",
				colorX.Magenta
			},
			{
				"orange",
				colorX.Orange
			},
			{
				"purple",
				colorX.Purple
			},
			{
				"lime",
				colorX.Lime
			},
			{
				"pink",
				colorX.Pink
			},
			{
				"brown",
				colorX.Brown
			}
		};

		public colorX Color;

		public MixMode Mode;

		public static void RegisterColorConstant(string name, colorX color)
		{
			colors.Add(name, color);
		}

		public StringColorNode(colorX color, MixMode mode, int startIndex, StringContainerNode parent)
			: base(startIndex, parent)
		{
			Color = color;
			Mode = mode;
		}

		public override StringContainerNode Clone(int startIndex, StringContainerNode parent)
		{
			return new StringColorNode(Color, Mode, startIndex, parent);
		}

		public static StringColorNode Parse(ReadOnlySpan<char> parameter, bool alphaOnly, int startIndex, StringContainerNode parent)
		{
			if (parameter.Length == 0)
			{
				return null;
			}
			if (parameter[0] == '#')
			{
				color color;
				bool hasAlpha;
				if (alphaOnly)
				{
					parameter = parameter.Slice(1);
					if (parameter.Length != 2)
					{
						return null;
					}
					if (color32.TryParseHex(parameter, out var value))
					{
						return new StringColorNode(new colorX(new color32(0, 0, 0, value), ColorProfile.sRGBAlpha), MixMode.Alpha, startIndex, parent);
					}
				}
				else if (color.FromHexCode(parameter, out color, out hasAlpha))
				{
					MixMode mixMode = MixMode.Color;
					if (hasAlpha)
					{
						mixMode |= MixMode.Alpha;
					}
					return new StringColorNode(new colorX(color, ColorProfile.sRGBAlpha), mixMode, startIndex, parent);
				}
			}
			parameter = StringNode.ExtractRawParameter(parameter);
			if (colors.TryGetValue(parameter.ToString().ToLower(), out var value2))
			{
				return new StringColorNode(value2, MixMode.Color, startIndex, parent);
			}
			return null;
		}

		public override string ToString()
		{
			if (Mode == MixMode.Alpha)
			{
				return $"Alpha: {Color.a * 100f:F0} %";
			}
			return "Color: " + Color.ToHexString(alpha: true);
		}
	}
	public static class StringColorExtensions
	{
		public static colorX GetFontColor(this StringNode node)
		{
			if (!(node is StringRenderTree stringRenderTree))
			{
				if (!(node is StringColorNode stringColorNode))
				{
					if (node is StringGlyphNode stringGlyphNode)
					{
						colorX result = node.Parent.GetFontColor();
						if (!stringGlyphNode.Tint)
						{
							result = new colorX(1f, result.a, result.profile);
						}
						return result;
					}
					return node.Parent.GetFontColor();
				}
				colorX result2 = node.Parent.GetFontColor();
				if ((stringColorNode.Mode & StringColorNode.MixMode.Alpha) != 0)
				{
					result2 = result2.MulA(stringColorNode.Color.a);
				}
				if ((stringColorNode.Mode & StringColorNode.MixMode.Color) != 0)
				{
					result2 = new colorX(stringColorNode.Color.rgb, ColorProfileHelper.ConvertProfile(result2.a, result2.profile, stringColorNode.Color.profile), stringColorNode.Color.profile);
				}
				return result2;
			}
			return stringRenderTree.Color;
		}
	}
	public class StringFontNode : StringContainerNode
	{
