		}

		public override StringContainerNode Clone(int startIndex, StringContainerNode parent)
		{
			if (FontName != null)
			{
				return new StringFontNode(FontName, startIndex, parent);
			}
			return new StringFontNode(FontIndex, startIndex, parent);
		}

		public void ResolveFont()
		{
			if (FontName != null)
			{
				FontSet = base.Root.GetFontSet(FontName);
			}
			else
			{
				FontSet = base.Root.GetFontSet(FontIndex);
			}
		}

		public static StringFontNode Parse(ReadOnlySpan<char> parameter, int startIndex, StringContainerNode parent)
		{
			parameter = StringNode.ExtractRawParameter(parameter, out var quotesRemoved);
			if (quotesRemoved)
			{
				return new StringFontNode(parameter.ToString(), startIndex, parent);
			}
			if (CharSpanParser.TryParseInteger(parameter, out var value))
			{
				return new StringFontNode(value, startIndex, parent);
			}
			return null;
		}
	}
	public static class StringFontExtensions
	{
		public static FontSet GetFontSet(this StringNode node, bool spriteFontSet = false)
		{
			if (!(node is StringRenderTree stringRenderTree))
			{
				if (!(node is StringFontNode stringFontNode))
				{
					if (node is StringGlyphNode { IsNamedSprite: not false })
					{
						spriteFontSet = true;
					}
				}
				else if (stringFontNode.FontSet != null)
				{
					return stringFontNode.FontSet;
				}
				return node.Parent.GetFontSet(spriteFontSet);
			}
			if (spriteFontSet)
			{
				return stringRenderTree.MainSpriteFontSet;
			}
			return stringRenderTree.MainFontSet;
		}
	}
