	public class StringGlyphNode : StringRenderGlyphSegmentNode
	{
		public uint GlyphId;

		public string GlyphName;

		public bool Tint;

		public bool IsNamedSprite { get; private set; }

		public override bool HasCharacters => false;

		public override char GetCharacter(int index)
		{
			throw new NotSupportedException();
		}

		public StringGlyphNode(uint glyphId, string glyphName, int startIndex, bool? tint, StringContainerNode parent)
			: base(startIndex, parent)
		{
			GlyphId = glyphId;
			GlyphName = glyphName;
			IsNamedSprite = !string.IsNullOrWhiteSpace(GlyphName);
			if (tint.HasValue)
			{
				Tint = tint.Value;
				return;
			}
			if (!IsNamedSprite)
			{
				Tint = true;
				return;
			}
			FontSet fontSet = parent.GetFontSet(spriteFontSet: true);
			if (fontSet != null && fontSet.GetGlyphByName(glyphName, out GlyphMetrics _, out uint glyphId2, out FontX font))
			{
				Tint = font.GetGlyphTintable(glyphId2);
			}
			else
			{
				Tint = false;
			}
		}

		public override void GetRawString(StringBuilder str)
		{
		}

		internal override void Shape(bool kerning, ref uint? lastGlyphId, ref FontX lastFont, ref float lastSize, List<ICharacterFilter> characterFilterCache, List<ISizeFilter> sizeFilterCache)
		{
			ClearRenderGlyphs();
			float size = this.GetFontSize();
			FontSet fontSet = this.GetFontSet();
			if (fontSet == null)
			{
				return;
			}
			GlyphMetrics metrics;
			FontX font;
			if (!string.IsNullOrWhiteSpace(GlyphName))
			{
				fontSet.GetGlyphByName(GlyphName, out metrics, out uint _, out font);
			}
			else
			{
				font = fontSet.MainFont;
				metrics = fontSet.MainFont.GetGlyphMetrics(GlyphId);
			}
			if (metrics == null)
			{
				return;
			}
			GetParentNodes(sizeFilterCache);
			float baseLine = 0f;
			this.AdjustSizeAndBaseline(ref size, ref baseLine);
			foreach (ISizeFilter item in sizeFilterCache)
			{
				size = item.FilterSize(size, base.StartIndex);
			}
			if (!kerning || font != lastFont)
			{
				lastGlyphId = null;
			}
			AppendGlyph(size, base.StartIndex, new float2(0f, baseLine), metrics, font, lastGlyphId);
			lastGlyphId = metrics.glyphId;
			lastSize = size;
			lastFont = font;
			sizeFilterCache.Clear();
		}

		public static StringGlyphNode Parse(ReadOnlySpan<char> parameter, int startIndex, StringContainerNode parent)
		{
			bool? tint = null;
			ReadOnlySpan<char> value = "tint=".AsSpan();
			int num = parameter.IndexOf(value, StringComparison.InvariantCultureIgnoreCase);
			if (num >= 0)
			{
				ReadOnlySpan<char> parameter2 = parameter.Slice(num + value.Length);
				parameter2 = StringNode.ExtractRawParameter(parameter2);
				if (System.MemoryExtensions.Equals(parameter2, "true".AsSpan(), StringComparison.InvariantCultureIgnoreCase))
				{
					tint = true;
				}
				else if (System.MemoryExtensions.Equals(parameter2, "false".AsSpan(), StringComparison.InvariantCultureIgnoreCase))
				{
					tint = false;
				}
			}
			ReadOnlySpan<char> value2 = "index=".AsSpan();
			int num2 = parameter.IndexOf(value2, StringComparison.InvariantCultureIgnoreCase);
			if (num2 >= 0 && CharSpanParser.TryParseInteger(parameter.Slice(num2 + value2.Length), out var value3) && value3 >= 0)
			{
				return new StringGlyphNode((uint)value3, null, startIndex, tint, parent);
			}
			ReadOnlySpan<char> value4 = "name=".AsSpan();
			int num3 = parameter.IndexOf(value4, StringComparison.InvariantCultureIgnoreCase);
			if (num3 >= 0)
			{
				ReadOnlySpan<char> parameter3 = parameter.Slice(num3 + value4.Length);
				return new StringGlyphNode(0u, StringNode.ExtractRawParameter(parameter3).ToString(), startIndex, tint, parent);
			}
			return null;
		}

		public override string ToString()
		{
			return $"GlyphId: {GlyphId}, GlyphName: {GlyphName}, Tintable: {Tint}";
		}
	}
	public class StringHorizontalGradientNode : StringContainerNode
	{
		private List<color> colors;

		public color Sample(float normalizedPosition)
		{
			float num = (float)colors.Count * normalizedPosition;
			int num2 = MathX.Clamp((int)num, 0, colors.Count);
			int index = MathX.Min(num2, colors.Count - 1);
			float lerp = num - (float)num2;
			return MathX.LerpUnclamped(colors[num2], colors[index], lerp);
		}

		public StringHorizontalGradientNode(List<color> colors, int startIndex, StringContainerNode parent)
			: base(startIndex, parent)
		{
			this.colors = colors;
		}

		public override StringContainerNode Clone(int startIndex, StringContainerNode parent)
		{
			return new StringHorizontalGradientNode(colors, startIndex, parent);
		}

		public static StringHorizontalGradientNode Parse(ReadOnlySpan<char> parameters, int startIndex, StringContainerNode parent)
		{
			if (parameters.Length == 0)
			{
				return null;
			}
			List<color> list = new List<color>();
			while (parameters.Length > 0)
			{
				if (parameters[0] != '#')
				{
					return null;
				}
				int num = System.MemoryExtensions.IndexOf(parameters, ',');
				if (color.FromHexCode((num > 0) ? parameters.Slice(0, num) : parameters, out var color, out var _))
				{
					list.Add(color);
					if (num < 0)
					{
						break;
					}
					parameters = parameters.Slice(num + 1);
					continue;
				}
				return null;
			}
			if (list.Count == 0)
			{
				return null;
			}
			return new StringHorizontalGradientNode(list, startIndex, parent);
		}
	}
	public class StringLineBreakNode : StringRenderGlyphSegmentNode
	{
		public override bool HasCharacters => true;

		public StringLineBreakNode(int startIndex, StringContainerNode parent)
			: base(startIndex, parent)
		{
		}

		public override char GetCharacter(int index)
		{
			if (index != base.StartIndex)
			{
				throw new ArgumentOutOfRangeException("index", $"Index: {index}, StartIndex: {base.StartIndex}, String: {base.Root?.String}, Size: {base.Root?.Size}, Bounds: {base.Root?.BoundsSize}");
			}
			return '\n';
		}

		public override void GetRawString(StringBuilder str)
		{
			str.AppendLine();
		}

		internal override void Shape(bool kerning, ref uint? lastGlyphId, ref FontX lastFont, ref float lastSize, List<ICharacterFilter> characterFilterCache, List<ISizeFilter> sizeFilterCache)
		{
			float size = this.GetFontSize();
			this.GetFontFormatting();
			FontSet fontSet = this.GetFontSet();
			float glyphSize = size;
			GetParentNodes(sizeFilterCache);
			float baseLine = 0f;
			this.AdjustSizeAndBaseline(ref size, ref baseLine);
			GlyphMetrics eMPTY_GLYPH = StringRenderTree.EMPTY_GLYPH;
			FontX mainFont = fontSet.MainFont;
			lastGlyphId = null;
			lastSize = size;
			AppendGlyph(glyphSize, base.StartIndex, new float2(0f, baseLine), eMPTY_GLYPH, mainFont, lastGlyphId);
			sizeFilterCache.Clear();
		}
	}
