	public static class StringSubSupScriptExtensions
	{
		public static void AdjustSizeAndBaseline(this StringNode node, ref float size, ref float baseLine)
		{
			if (node.Parent != null)
			{
				node.Parent.AdjustSizeAndBaseline(ref size, ref baseLine);
			}
			if (node is StringScriptModeNode { Mode: var mode })
			{
				switch (mode)
				{
				case TextScriptMode.Superscript:
					baseLine -= size * 0.5f;
					break;
				case TextScriptMode.Subscript:
					baseLine += size * 0.2f;
					break;
				}
				size *= 0.5f;
			}
		}
	}
	public class StringSegmentNode : StringRenderGlyphSegmentNode
	{
		public int Length { get; private set; }

		public override bool HasCharacters => true;

		public char this[int index]
		{
			get
			{
				if (index < 0 || index >= Length)
				{
					throw new ArgumentOutOfRangeException("index");
				}
				return base.Root.String[base.StartIndex + index];
			}
		}

		public override char GetCharacter(int index)
		{
			return base.Root.String[index];
		}

		public StringSegmentNode(int startIndex, int length, StringContainerNode parent)
			: base(startIndex, parent)
		{
			Length = length;
			ToString();
			ClearRenderGlyphs();
		}

		internal override void Shape(bool kerning, ref uint? lastGlyphId, ref FontX lastFont, ref float lastSize, List<ICharacterFilter> characterFilterCache, List<ISizeFilter> sizeFilterCache)
		{
			ClearRenderGlyphs();
			float size = this.GetFontSize();
			this.GetFontFormatting();
			FontSet fontSet = this.GetFontSet();
			GetParentNodes(characterFilterCache);
			GetParentNodes(sizeFilterCache);
			float baseLine = 0f;
			this.AdjustSizeAndBaseline(ref size, ref baseLine);
			for (int i = 0; i < Length; i++)
			{
				float num = size;
				char c = this[i];
				foreach (ISizeFilter item in sizeFilterCache)
				{
					num = item.FilterSize(num, base.StartIndex + i);
				}
				foreach (ICharacterFilter item2 in characterFilterCache)
				{
					c = item2.FilterCharacter(c, base.StartIndex + i);
				}
				bool flag = false;
				GlyphMetrics metrics;
				FontX font;
				switch (c)
				{
				case '\n':
					metrics = StringRenderTree.EMPTY_GLYPH;
					font = fontSet.MainFont;
					lastGlyphId = null;
					lastSize = size;
					break;
				case '\t':
					metrics = StringRenderTree.TINY_GLYPH;
					font = fontSet.MainFont;
					lastGlyphId = null;
					break;
				default:
				{
					if (char.IsControl(c) && c != '\t')
					{
						continue;
					}
					uint charcode;
					if (char.IsHighSurrogate(c) && i + 1 < Length && char.IsLowSurrogate(this[i + 1]))
					{
						char c2 = this[i + 1];
						foreach (ICharacterFilter item3 in characterFilterCache)
						{
							c2 = item3.FilterCharacter(c2, base.StartIndex + i + 1);
						}
						if (char.IsLowSurrogate(c2))
						{
							charcode = (uint)char.ConvertToUtf32(c, c2);
							flag = true;
						}
						else
						{
							charcode = c;
						}
					}
					else
					{
						charcode = c;
					}
					fontSet.GetGlyphByUnicode(charcode, out metrics, out font);
					if (metrics == null)
					{
						continue;
					}
					break;
				}
				}
				if (!kerning || font != lastFont)
				{
					lastGlyphId = null;
				}
				AppendGlyph(num, base.StartIndex + i, new float2(0f, baseLine), metrics, font, lastGlyphId);
				lastGlyphId = metrics.glyphId;
				lastSize = num;
				lastFont = font;
				if (flag)
				{
					i++;
				}
			}
			characterFilterCache.Clear();
			sizeFilterCache.Clear();
		}

		public override string ToString()
		{
			return base.Root.String.Substring(base.StartIndex, Length);
		}

		public override void GetRawString(StringBuilder str)
		{
			str.Append(base.Root.String, base.StartIndex, Length);
		}
	}
	public class StringSizeNode : StringContainerNode
	{
		public enum Mode
		{
			Relative,
			Absolute
		}

		public float Size;

		public Mode SizeMode;

		public StringSizeNode(float size, Mode sizeMode, int startIndex, StringContainerNode parent)
			: base(startIndex, parent)
		{
			Size = size;
			SizeMode = sizeMode;
		}

		public override StringContainerNode Clone(int startIndex, StringContainerNode parent)
		{
			return new StringSizeNode(Size, SizeMode, startIndex, parent);
		}

		public override string ToString()
		{
			if (SizeMode != Mode.Relative)
			{
				return $"Size: {Size} px";
			}
			return $"Size: {Size * 100f:F2}%";
		}

		public static StringSizeNode Parse(ReadOnlySpan<char> parameter, int startIndex, StringContainerNode parent)
		{
			if (parameter.IsEmpty)
			{
				return null;
			}
			int num = 0;
			for (int i = 0; i < parameter.Length; i++)
			{
				char c = parameter[i];
				if (!char.IsDigit(c) && c != '.')
				{
					break;
				}
				num = i + 1;
			}
			if (num == 0)
			{
				return null;
			}
			ReadOnlySpan<char> readOnlySpan = parameter.Slice(0, num);
			ReadOnlySpan<char> span = System.MemoryExtensions.Trim(parameter.Slice(num));
			if (!float.TryParse(readOnlySpan.ToString(), NumberStyles.Float, CultureInfo.InvariantCulture, out var result))
			{
				return null;
			}
			if (System.MemoryExtensions.Equals(span, "%".AsSpan(), StringComparison.InvariantCultureIgnoreCase))
			{
				return new StringSizeNode(result * 0.01f, Mode.Relative, startIndex, parent);
			}
			if (span.IsEmpty || System.MemoryExtensions.Equals(span, "em".AsSpan(), StringComparison.InvariantCultureIgnoreCase))
			{
				return new StringSizeNode(result * 0.1f, Mode.Absolute, startIndex, parent);
			}
			return null;
		}
	}
	public static class StringSizeExtensions
	{
		public static float GetFontSize(this StringNode node)
		{
			if (!(node is StringRenderTree stringRenderTree))
			{
				if (node is StringSizeNode { SizeMode: var sizeMode } stringSizeNode)
				{
					return sizeMode switch
					{
						StringSizeNode.Mode.Absolute => stringSizeNode.Size * stringSizeNode.Root.AutoSizeRatio, 
						StringSizeNode.Mode.Relative => node.Parent.GetFontSize() * stringSizeNode.Size, 
						_ => throw new Exception("Unsupported size mode: " + stringSizeNode.SizeMode), 
					};
				}
				return node.Parent.GetFontSize();
			}
			return stringRenderTree.ActualSize;
		}
	}
	public struct TextEditingVisuals
	{
		public int caretPosition;

		public int selectionStart;

		public colorX caretColor;

