	public readonly struct AtlasData
	{
		public readonly GlyphAtlas glyphAtlas;

		public readonly object customData;

		public AtlasData(GlyphAtlas glyphAtlas, object customData = null)
		{
			this.glyphAtlas = glyphAtlas;
			this.customData = customData;
		}
	}
	public readonly struct AtlasSubmesh
	{
		public readonly GlyphAtlas atlas;

		public readonly TriangleSubmesh submesh;

		public AtlasSubmesh(GlyphAtlas atlas, TriangleSubmesh submesh)
		{
			this.atlas = atlas;
			this.submesh = submesh;
		}
	}
	public delegate TriangleSubmesh AtlasSubmeshMapper(AtlasData atlasData);
	public static class GlyphAtlasMeshGenerator
	{
		private readonly struct LineSegment
		{
			public readonly StringLine line;

			public readonly int startGlyphIndex;

			public readonly int endGlyphIndex;

			public readonly RenderGlyph startGlyph;

			public readonly RenderGlyph endGlyph;

			public LineSegment(StringLine line, int startGlyphIndex, int endGlyphIndex, RenderGlyph startGlyph, RenderGlyph endGlyph)
			{
				this.line = line;
				this.startGlyphIndex = startGlyphIndex;
				this.endGlyphIndex = endGlyphIndex;
				this.startGlyph = startGlyph;
				this.endGlyph = endGlyph;
			}
		}

		public static void Generate(StringRenderTree renderTree, float2 offset, MeshX meshx, AtlasSubmeshMapper submeshMapper, Dictionary<FontSet, List<AtlasData>> fontSetAtlases, TextEditingVisuals textEditVisuals, out bool usesAuxiliarySubmesh)
		{
			meshx.HasUV0s = true;
			meshx.HasColors = true;
			meshx.HasNormals = true;
			_ = meshx.VertexCount;
			int glyphLayoutLength = renderTree.GlyphLayoutLength;
			meshx.EnsureFreeCapacity(glyphLayoutLength * 4);
			TriangleSubmesh triangleSubmesh = null;
			Dictionary<FontSet, List<AtlasSubmesh>> dictionary = Pool.BorrowDictionary<FontSet, List<AtlasSubmesh>>();
			foreach (KeyValuePair<FontSet, List<AtlasData>> fontSetAtlase in fontSetAtlases)
			{
				List<AtlasSubmesh> list = Pool.BorrowList<AtlasSubmesh>();
				foreach (AtlasData item in fontSetAtlase.Value)
				{
					list.Add(new AtlasSubmesh(item.glyphAtlas, submeshMapper(item)));
				}
				dictionary.Add(fontSetAtlase.Key, list);
			}
			List<LineSegment> list2 = Pool.BorrowList<LineSegment>();
			foreach (StringRenderGlyphSegmentNode item2 in renderTree)
			{
				float fontSize = item2.GetFontSize();
				color color = item2.GetFontColor().ToProfile(meshx.Profile);
				FontSet fontSet = item2.GetFontSet();
				if (fontSet == null)
				{
					continue;
				}
				StringFormatting fontFormatting = item2.GetFontFormatting();
				List<AtlasSubmesh> list3 = dictionary[fontSet];
				color? color2 = item2.GetMarkColor()?.ToProfile(meshx.Profile);
				for (int i = 0; i < item2.GlyphSegmentLength; i++)
				{
					RenderGlyph renderGlyph = item2.GetRenderGlyph(i);
					if (renderGlyph.rect.size == float2.Zero)
					{
						continue;
					}
					AtlasSubmesh atlasSubmesh = default(AtlasSubmesh);
					GlyphAtlasData glyphAtlasData = null;
					for (int j = 0; j < list3.Count; j++)
					{
						atlasSubmesh = list3[j];
						if (renderGlyph.font == atlasSubmesh.atlas.Font)
						{
							glyphAtlasData = atlasSubmesh.atlas.GetGlyphData(renderGlyph.glyphId);
							if (glyphAtlasData != null)
							{
								break;
							}
						}
					}
					if (glyphAtlasData != null)
					{
						meshx.IncreaseVertexCount(4);
						StringLine line = renderTree.GetLine(renderGlyph.line);
						Rect rect = renderGlyph.rect;
						ref float2 position = ref rect.position;
						position += line.Position;
						float2 b = rect.size * (glyphAtlasData.rangeExtendRatio - 1);
						ref float2 size = ref rect.size;
						size += b;
						ref float2 position2 = ref rect.position;
						position2 -= b * 0.5f;
						int num = meshx.VertexCount - 4;
						int num2 = num + 1;
						int num3 = num2 + 1;
						int num4 = num3 + 1;
						float2 a = float2.Zero;
						float2 a2 = float2.Zero;
						if (fontFormatting.italics)
						{
							a -= new float2((rect.ymin - line.Position.y) * 0.2f);
							a2 += new float2((line.Position.y - rect.ymax) * 0.2f);
						}
						a += offset;
						a2 += offset;
						meshx.RawPositions[num] = new float3(rect.xmax, 0f - rect.ymin) + (float3)a;
						meshx.RawPositions[num2] = new float3(rect.xmax, 0f - rect.ymax) + (float3)a2;
						meshx.RawPositions[num3] = new float3(rect.xmin, 0f - rect.ymax) + (float3)a2;
						meshx.RawPositions[num4] = new float3(rect.xmin, 0f - rect.ymin) + (float3)a;
						if (glyphAtlasData.rotated)
						{
							meshx.RawUV0s[num] = new float2(glyphAtlasData.uv.xmin, glyphAtlasData.uv.ymin);
							meshx.RawUV0s[num2] = new float2(glyphAtlasData.uv.xmax, glyphAtlasData.uv.ymin);
							meshx.RawUV0s[num3] = new float2(glyphAtlasData.uv.xmax, glyphAtlasData.uv.ymax);
							meshx.RawUV0s[num4] = new float2(glyphAtlasData.uv.xmin, glyphAtlasData.uv.ymax);
						}
						else
						{
							meshx.RawUV0s[num] = new float2(glyphAtlasData.uv.xmax, glyphAtlasData.uv.ymax);
							meshx.RawUV0s[num2] = new float2(glyphAtlasData.uv.xmax, glyphAtlasData.uv.ymin);
							meshx.RawUV0s[num3] = new float2(glyphAtlasData.uv.xmin, glyphAtlasData.uv.ymin);
							meshx.RawUV0s[num4] = new float2(glyphAtlasData.uv.xmin, glyphAtlasData.uv.ymax);
						}
						float3 v = new float3(fontFormatting.bold ? 0.5f : 0f);
						if (atlasSubmesh.atlas.PixelRange > 0)
						{
							v /= atlasSubmesh.atlas.PixelRange;
						}
						for (int k = 0; k < 4; k++)
						{
							int num5 = num + k;
							meshx.RawColors[num5] = color;
							meshx.RawNormals[num5] = v;
						}
						atlasSubmesh.submesh.AddQuadAsTriangles(num, num2, num3, num4);
					}
				}
				if (!fontFormatting.underline && !fontFormatting.strikethrough && !color2.HasValue)
				{
					continue;
				}
				if (triangleSubmesh == null)
				{
					triangleSubmesh = submeshMapper(default(AtlasData));
				}
				ExtractLineSegments(renderTree, item2.GlyphSegmentOffset, item2.GlyphSegmentLength, list2);
				foreach (LineSegment item3 in list2)
				{
					LineSegment segment = item3;
					if (fontFormatting.underline)
					{
						InsertLine(renderTree, meshx, triangleSubmesh, in segment, in color, -0.1f * fontSize, 0.075f * fontSize, in offset);
					}
					if (fontFormatting.strikethrough)
					{
						InsertLine(renderTree, meshx, triangleSubmesh, in segment, in color, 0.3f * fontSize, 0.1f * fontSize, in offset);
					}
					if (color2.HasValue)
					{
						Mark(renderTree, meshx, triangleSubmesh, in segment, color2.Value, in offset);
					}
				}
				list2.Clear();
			}
			int num6 = MatchStringPositionToGlyph(renderTree, textEditVisuals.caretPosition);
			int num7 = MatchStringPositionToGlyph(renderTree, textEditVisuals.selectionStart);
			if (num6 >= 0)
			{
				if (triangleSubmesh == null)
				{
					triangleSubmesh = submeshMapper(default(AtlasData));
				}
				bool flag = num6 == renderTree.GlyphLayoutLength;
				if (num7 >= 0 && num7 != num6)
				{
					int num8 = num7;
					int num9 = num6;
					if (num8 > num9)
					{
						num8 = num6;
						num9 = num7;
					}
					ExtractLineSegments(renderTree, num8, num9 - num8, list2);
					foreach (LineSegment item4 in list2)
					{
						Mark(renderTree, meshx, triangleSubmesh, item4, textEditVisuals.selectionColor.ToProfile(meshx.Profile), in offset);
					}
					list2.Clear();
				}
				StringLine line2;
				float num10;
				if (renderTree.GlyphLayoutLength > 0)
				{
					RenderGlyph renderGlyph2 = renderTree.GetRenderGlyph(flag ? (num6 - 1) : num6);
					line2 = renderTree.GetLine(renderGlyph2.line);
					num10 = (flag ? renderGlyph2.pen.x : renderGlyph2.rect.x);
				}
				else
				{
					line2 = renderTree.GetLine(0);
					num10 = 0f;
				}
				float num11 = line2.LineHeight * line2.LineHeightMultiplier * 0.7f;
				float2 startPoint = new float2(num10 + line2.Position.x, 0f - line2.Position.y + num11 * 0.5f - line2.Descender);
				InsertLine(meshx, triangleSubmesh, in startPoint, startPoint + new float2(line2.LineHeight * 0.04f), textEditVisuals.caretColor.ToProfile(meshx.Profile), num11, in offset);
			}
			foreach (KeyValuePair<FontSet, List<AtlasSubmesh>> item5 in dictionary)
			{
				List<AtlasSubmesh> list4 = item5.Value;
				Pool.Return(ref list4);
			}
			Pool.Return(ref dictionary);
			Pool.Return(ref list2);
			usesAuxiliarySubmesh = triangleSubmesh != null;
		}

		private static int MatchStringPositionToGlyph(StringRenderTree renderTree, int stringPosition)
		{
			if (stringPosition < 0)
			{
				return stringPosition;
			}
			for (int i = 0; i < renderTree.GlyphLayoutLength; i++)
			{
				RenderGlyph renderGlyph = renderTree.GetRenderGlyph(i);
				if (renderGlyph.stringIndex == stringPosition)
				{
					return i;
				}
				if (renderGlyph.stringIndex > stringPosition)
				{
					return i - 1;
				}
			}
			return renderTree.GlyphLayoutLength;
		}

		private static void Mark(StringRenderTree renderTree, MeshX mesh, TriangleSubmesh submesh, in LineSegment lineSegment, in color markColor, in float2 offset)
		{
			float actualHeight = lineSegment.line.ActualHeight;
			InsertLine(renderTree, mesh, submesh, in lineSegment, in markColor, 0.5f * actualHeight - lineSegment.line.Descender, actualHeight, in offset);
		}

		private static void ExtractLineSegments(StringRenderTree renderTree, int startIndex, int length, List<LineSegment> lineSegments)
		{
			int num = -1;
			RenderGlyph startGlyph = default(RenderGlyph);
			RenderGlyph endGlyph = default(RenderGlyph);
			int startGlyphIndex = -1;
			int endGlyphIndex = -1;
			for (int i = 0; i < length + 1; i++)
			{
				bool flag = i == length;
				int num2 = startIndex + i;
				RenderGlyph renderGlyph = default(RenderGlyph);
				if (!flag)
				{
					renderGlyph = renderTree.GetRenderGlyph(MathX.Min(num2, renderTree.GlyphLayoutLength - 1));
				}
				if (renderGlyph.line != num || flag)
				{
					if (num >= 0)
					{
						lineSegments.Add(new LineSegment(renderTree.GetLine(num), startGlyphIndex, endGlyphIndex, startGlyph, endGlyph));
					}
					if (!flag)
					{
						startGlyph = renderGlyph;
						startGlyphIndex = num2;
						num = renderGlyph.line;
					}
				}
				endGlyph = renderGlyph;
				endGlyphIndex = num2;
			}
		}

		private static void InsertLine(MeshX mesh, TriangleSubmesh submesh, in float2 startPoint, in float2 endPoint, in color color, float thickness, in float2 offset)
		{
			mesh.IncreaseVertexCount(4);
			int num = mesh.VertexCount - 4;
			int num2 = num + 1;
			int num3 = num2 + 1;
			int num4 = num3 + 1;
			float y = thickness * 0.5f;
			mesh.RawPositions[num] = startPoint - new float2(0f, y) + offset;
			mesh.RawPositions[num2] = startPoint + new float2(0f, y) + offset;
			mesh.RawPositions[num3] = endPoint + new float2(0f, y) + offset;
			mesh.RawPositions[num4] = endPoint - new float2(0f, y) + offset;
			mesh.RawUV0s[num] = new float2(0f, 0f);
			mesh.RawUV0s[num2] = new float2(0f, 1f);
			mesh.RawUV0s[num3] = new float2(1f, 1f);
			mesh.RawUV0s[num4] = new float2(1f);
			for (int i = 0; i < 4; i++)
			{
				int num5 = num + i;
				mesh.RawColors[num5] = color;
				mesh.RawNormals[num5] = new float3(0f, 0f, 0f);
			}
			submesh.AddQuadAsTriangles(num, num2, num3, num4);
		}

		private static void InsertLine(StringRenderTree renderTree, MeshX mesh, TriangleSubmesh submesh, in LineSegment segment, in color color, float heightOffset, float thickness, in float2 offset)
		{
			float y = 0f - segment.line.Position.y + heightOffset;
			float2 startPoint = new float2(segment.startGlyph.rect.xmin + segment.line.Position.x, y);
			float2 endPoint = new float2(segment.endGlyph.pen.x + segment.line.Position.x, y);
			int num = segment.endGlyphIndex + 1;
			if (num < renderTree.GlyphLayoutLength)
			{
				RenderGlyph renderGlyph = renderTree.GetRenderGlyph(num);
				if (renderGlyph.line == segment.endGlyph.line)
				{
					endPoint = new float2(renderGlyph.rect.xmin + segment.line.Position.x, endPoint.y);
				}
			}
			InsertLine(mesh, submesh, in startPoint, in endPoint, in color, thickness, in offset);
		}
	}
	public struct RenderGlyph
	{
		public int stringIndex;

		public uint glyphId;

		public FontX font;

		public Rect rect;

		public float2 pen;

		public int line;

		public void Translate(float x, float y)
		{
			Translate(new float2(x, y));
		}

		public void Translate(in float2 offset)
		{
			ref float2 position = ref rect.position;
			position += offset;
			pen += offset;
		}

		public override string ToString()
		{
			return $"String Index: {stringIndex}, GlyphId: {glyphId}, Pen: {pen}, Line: {line}, Rect: {rect}";
		}
	}
	public delegate void GlyphPositioner(ref RenderGlyph glyph, in float2 offset, int lineIndex);
	public class StringRenderTree : StringContainerNode
	{
		private enum WithComputationMode
		{
			Word,
			Line
		}

		private readonly struct RenestNode
		{
			public readonly StringSegment tag;

			public readonly StringContainerNode node;

			public RenestNode(StringSegment tag, StringContainerNode node)
			{
				this.tag = tag;
				this.node = node;
			}
		}

		private enum TagScanState
		{
			ScanningBeginning,
			ScanningTag,
			ScanningParameter,
			ScanningForEnd,
			FinishedScanning,
			Invalid
		}

		public const int MAX_AUTO_SIZE_ITERATIONS = 12;

		public static readonly GlyphMetrics EMPTY_GLYPH = new GlyphMetrics(0u, 0f, 0f, 0f, 0f, 0f, 0f, 0f, 0f);

		public static readonly GlyphMetrics TINY_GLYPH = new GlyphMetrics(0u, 0.0001f, 0.0001f, 0.0001f, 0f, 0f, 0.0001f, 0f, 0f);

		public static readonly GlyphMetrics UNIT_GLYPH = new GlyphMetrics(0u, 1f, 1f, 1f, 0f, 0f, 1f, 0f, 0f);

		public const int MAX_TAG_LENGTH = 128;

		public readonly string String;

		public float TabSpaces = 8f;

		public float Size = 16f;

		public float AutoSizeRatio = 1f;

		public float LineHeight = 1f;

		public colorX Color = colorX.White;

		public TextHorizontalAlignment HorizontalAlignment;

		public TextVerticalAlignment VerticalAlignment;

		public float JustificationThreshold = 1.5f;

		public AlignmentMode AlignmentMode;

		public bool Bounded;

		public float2 BoundsSize = float2.One;

		public Alignment BoundsAlignment;

		private readonly List<FontSet> _fontSets;

		internal float _tabLength;

		internal float _invTabLength;

		private List<StringLine> _lines;

		private int _glyphLayoutLength;

		private RenderGlyph[] _glyphLayout;

		private bool _isShaped;

		public float LastLayoutWidth { get; private set; }

		public float LastLayoutHeight { get; private set; }

		public float ActualSize => Size * AutoSizeRatio;

		public FontSet MainFontSet => _fontSets[0];

		public FontSet MainSpriteFontSet { get; private set; }

		public int FontSetCount => _fontSets.Count;

		public int GlyphLayoutLength => _glyphLayoutLength;

		public int LineCount => _lines.Count;

		public bool IsShaped => _isShaped;

		public static bool AllowsLineBreak(char ch)
		{
			if (ch == '\n')
			{
				return true;
			}
			if (char.IsWhiteSpace(ch))
			{
				return true;
			}
			if (ch == '\u200b')
			{
				return true;
			}
			return false;
		}

		public void HorizontalAutoSize()
		{
			float num = ComputeMaxWordWidth();
			if (BoundsSize.x < num)
			{
				AutoSizeRatio *= BoundsSize.x / num;
				ShapeText();
			}
		}

		public bool AutoSizeLayout(float min = 0f, float max = float.PositiveInfinity)
		{
			Size = MathX.Min(Size, max);
			float actualSize = ActualSize;
			float autoSizeRatio = AutoSizeRatio;
			float? num = null;
			float b = 0f;
			float? num2 = null;
			float a = 0f;
			float actualSize2 = ActualSize;
			float num3 = 0f;
			float num4 = float.MaxValue;
			float2 offset = float2.Zero;
			for (int i = 0; i < 12; i++)
			{
				if (i > 0)
				{
					ShapeText();
				}
				Layout();
				OffsetLines(in offset);
				if (!Bounded || LineCount == 0)
				{
					return false;
				}
				if (i == 11)
				{
					return true;
				}
				float num5 = ComputeTotalLineHeight(AlignmentMode.LineBased);
				if (ActualSize <= min && num5 >= BoundsSize.y)
				{
					return true;
				}
				if (num5 < BoundsSize.y && i == 0)
				{
					return false;
				}
				float num6 = MathX.Abs(num5 - BoundsSize.y);
				if (num6 < ActualSize * 0.2f && num5 <= BoundsSize.y * 1.001f)
				{
					return true;
				}
				if (num6 < num4)
				{
					num4 = num6;
					actualSize2 = ActualSize;
					num3 = num5;
				}
				if (num5 > BoundsSize.y)
				{
					num = ActualSize;
					b = num5;
				}
				else
				{
					num2 = ActualSize;
					a = num5;
				}
				if (num.HasValue && num2.HasValue && MathX.Abs(num.Value - num2.Value) < ActualSize * 0.05f)
				{
					i = 10;
				}
				float num8;
				if (i == 10)
				{
					float num7 = MathX.Min(1f, BoundsSize.y / num3);
					num8 = actualSize2 * num7;
					if (num8 > actualSize)
					{
						num8 = actualSize;
						num7 = autoSizeRatio;
					}
					float2 b2 = BoundsSize * num7;
					offset = BoundsSize - b2;
					switch (BoundsAlignment.GetHorizontalText())
					{
					case TextHorizontalAlignment.Left:
						offset = new float2(offset.x * 0.5f, offset.y);
						break;
					case TextHorizontalAlignment.Center:
					case TextHorizontalAlignment.Justify:
						offset = offset._y;
						break;
					case TextHorizontalAlignment.Right:
						offset = new float2(offset.x * -0.5f, offset.y);
						break;
					}
					switch (BoundsAlignment.GetVerticalText())
					{
					case TextVerticalAlignment.Top:
						offset = new float2(offset.x, offset.y * 0.5f);
						break;
					case TextVerticalAlignment.Middle:
						offset = offset.x_;
						break;
					case TextVerticalAlignment.Bottom:
						offset = new float2(offset.x, offset.y * -0.5f);
						break;
					}
					BoundsSize = b2;
				}
				else if (num.HasValue && num2.HasValue)
				{
					float lerp = MathX.InverseLerp(a, b, BoundsSize.y);
					num8 = MathX.Lerp(num2.Value, num.Value, lerp);
				}
				else
				{
					float num9 = BoundsSize.y / num5;
					num8 = ActualSize * num9;
					if (num8 > actualSize)
					{
						num8 = actualSize - MathX.Min(actualSize * 0.75f, num8 - actualSize);
					}
					num8 = MathX.Min(num8, actualSize, max);
					if (BoundsSize.x > 0f)
					{
						float num10 = ComputeMaxLineWidth();
						float num11 = BoundsSize.x / num10;
						if (num11 < 1f)
						{
							num8 = MathX.Max(ActualSize * num11, num8);
						}
					}
				}
				num8 = MathX.Max(min, num8);
				AutoSizeRatio *= num8 / ActualSize;
			}
			return true;
		}

		public void ComputeLines()
		{
			GenerateLines();
			ComputeLineData();
		}

		public void Layout()
		{
			GenerateLines();
			ComputeLineData();
			LayOutLines();
			PerformHorizontalAlignment();
			PerformVerticalAlignment();
		}

		public void OffsetLines(in float2 offset)
		{
			if (offset == float2.Zero)
			{
				return;
			}
			foreach (StringLine line in _lines)
			{
				line.Position += offset;
			}
		}

		private bool ExceedsHorizontalBounds(ref RenderGlyph glyph)
		{
			if (glyph.rect.xmax - BoundsSize.x > ActualSize * 0.001f)
			{
				return true;
			}
			return false;
		}

		private void GenerateLines(GlyphPositioner glyphPositionOverride = null)
		{
			if (glyphPositionOverride == null)
			{
				if (_lines == null)
				{
					_lines = new List<StringLine>();
				}
				else
				{
					_lines.Clear();
				}
			}
			float2 offset = float2.Zero;
			bool flag = false;
			int num = 0;
			int num2 = 0;
			int num3 = -1;
			int num4 = 0;
			using (IEnumerator<StringRenderGlyphSegmentNode> enumerator = GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					StringRenderGlyphSegmentNode current = enumerator.Current;
					num3 = ((!current.DisableLineBreaking()) ? (-1) : current.GlyphSegmentOffset);
					for (int i = 0; i < current.GlyphSegmentLength; i++)
					{
						int num5 = current.GlyphSegmentOffset + i;
						ref RenderGlyph renderGlyph = ref current.GetRenderGlyph(i);
						while (num >= num4)
						{
							if (glyphPositionOverride == null)
							{
								_lines.Add(new StringLine());
							}
							num4++;
							if (!flag)
							{
								offset = new float2(0f - renderGlyph.rect.x);
							}
							flag = false;
						}
						if (glyphPositionOverride == null)
						{
							renderGlyph.line = num;
							renderGlyph.Translate(in offset);
						}
						else
						{
							glyphPositionOverride(ref renderGlyph, in offset, num);
						}
						bool flag2 = false;
						if (current.HasCharacters)
						{
							char character = current.GetCharacter(renderGlyph.stringIndex);
							switch (character)
							{
							case '\n':
								num++;
								num2 = num5 + 1;
								continue;
							case '\t':
							{
								float xmax = renderGlyph.rect.xmax;
								float x = (float)MathX.CeilToInt(xmax * base.Root._invTabLength) * base.Root._tabLength - xmax;
								renderGlyph.Translate(new float2(x));
								offset += new float2(x);
								break;
							}
							default:
								if (char.IsControl(character))
								{
									continue;
								}
								break;
							}
							flag2 = AllowsLineBreak(character);
						}
						if (glyphPositionOverride != null || !Bounded || !ExceedsHorizontalBounds(ref renderGlyph))
						{
							continue;
						}
						int num6 = num5;
						int num7 = num5 - 1;
						if (num3 >= 0)
						{
							num7 = num3 - 1;
						}
						for (int num8 = num7; num8 >= num2; num8--)
						{
							if (AllowsLineBreak(String[_glyphLayout[num8].stringIndex]))
							{
								num6 = num8 + 1;
								break;
							}
						}
						if (!(num6 == num5 && flag2))
						{
							float x2 = 0f - _glyphLayout[num6].rect.x;
							if (glyphPositionOverride == null)
							{
								for (int j = num6; j <= num5; j++)
								{
									ref RenderGlyph renderGlyph2 = ref GetRenderGlyph(j);
									renderGlyph2.line++;
									renderGlyph2.Translate(x2, 0f);
								}
							}
							offset += new float2(x2);
							flag = true;
						}
						else
						{
							num6++;
						}
						num++;
						num2 = num6;
					}
					offset += current.PenPosition;
				}
			}
			if (glyphPositionOverride == null && num == LineCount)
			{
				_lines.Add(new StringLine());
			}
		}

		private void ComputeLineData()
		{
			int num = -1;
			StringLine stringLine = null;
			using (IEnumerator<StringRenderGlyphSegmentNode> enumerator = GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					StringRenderGlyphSegmentNode current = enumerator.Current;
					float fontSize = current.GetFontSize();
					bool isOverride;
					TextHorizontalAlignment horizontalAlignment = current.GetHorizontalAlignment(out isOverride);
					float lineHeight = current.GetLineHeight();
					for (int i = 0; i < current.GlyphSegmentLength; i++)
					{
						ref RenderGlyph renderGlyph = ref current.GetRenderGlyph(i);
						if (num != renderGlyph.line)
						{
							num = renderGlyph.line;
							stringLine = _lines[renderGlyph.line];
							stringLine.StartIndex = current.GlyphSegmentOffset + i;
							stringLine.GlyphCount = 0;
							stringLine.LineHeight = 0f;
							stringLine.LineHeightMultiplier = lineHeight;
							stringLine.Ascender = float.PositiveInfinity;
							stringLine.Descender = float.NegativeInfinity;
							stringLine.Alignment = horizontalAlignment;
						}
						if (renderGlyph.rect.size != float2.Zero && isOverride)
						{
							stringLine.Alignment = horizontalAlignment;
						}
						float val = renderGlyph.font.LineHeight * fontSize;
						stringLine.Ascender = MathX.Min(stringLine.Ascender, renderGlyph.rect.y);
						stringLine.Descender = MathX.Max(stringLine.Descender, renderGlyph.rect.y + renderGlyph.rect.height);
						stringLine.LineHeight = MathX.Max(val, stringLine.LineHeight);
						stringLine.GlyphCount++;
					}
				}
			}
			if (num == -1)
			{
				stringLine = _lines[0];
				stringLine.StartIndex = 0;
				stringLine.GlyphCount = 0;
				stringLine.LineHeight = MainFontSet.MainFont.LineHeight * ActualSize;
				stringLine.LineHeightMultiplier = LineHeight;
				stringLine.Ascender = 0f;
				stringLine.Descender = 0f;
				stringLine.Alignment = HorizontalAlignment;
			}
		}

		private void LayOutLines()
		{
			if (LineCount == 0)
			{
				return;
			}
			float num = 0f;
			for (int i = 0; i < LineCount; i++)
			{
				StringLine stringLine = _lines[i];
				if (i > 0)
				{
					num += stringLine.LineHeight * stringLine.LineHeightMultiplier;
				}
				stringLine.Position = new float2(0f, num);
			}
		}

		private void PerformHorizontalAlignment()
		{
			LastLayoutWidth = 0f;
			for (int i = 0; i < LineCount; i++)
			{
				StringLine stringLine = _lines[i];
				float num;
				float num2;
				if (stringLine.GlyphCount == 0)
				{
					num = 0f;
					num2 = 0f;
				}
				else
				{
					num = _glyphLayout[stringLine.StartIndex].rect.x;
					num2 = _glyphLayout[stringLine.StartIndex + stringLine.GlyphCount - 1].rect.xmax;
				}
				float num3 = num2 - num;
				LastLayoutWidth = MathX.Max(num3, LastLayoutWidth);
				float num4 = ((!Bounded) ? (0f - num3) : (BoundsSize.x - num3));
				float num5 = 0f;
				switch (stringLine.Alignment)
				{
				case TextHorizontalAlignment.Left:
				case TextHorizontalAlignment.Justify:
					num5 = 0f - num;
					break;
				case TextHorizontalAlignment.Right:
					num5 = ((!Bounded) ? (0f - num2) : (BoundsSize.x - num2));
					break;
				case TextHorizontalAlignment.Center:
					num5 = 0f - num + num4 * 0.5f;
					break;
				}
				float num6 = 0f;
				if (Bounded)
				{
					switch (BoundsAlignment)
					{
					case Alignment.TopCenter:
					case Alignment.MiddleCenter:
					case Alignment.BottomCenter:
						num6 -= BoundsSize.x * 0.5f;
						break;
					case Alignment.TopRight:
					case Alignment.MiddleRight:
					case Alignment.BottomRight:
						num6 -= BoundsSize.x;
						break;
					}
				}
				num5 += num6;
				stringLine.Position += new float2(num5);
				if (stringLine.Alignment != TextHorizontalAlignment.Justify || !Bounded)
				{
					continue;
				}
				float num7 = BoundsSize.x / num3;
				if (!(num7 >= JustificationThreshold))
				{
					for (int j = 0; j < stringLine.GlyphCount; j++)
					{
						float x = _glyphLayout[j + stringLine.StartIndex].rect.x;
						x *= num7;
						_glyphLayout[j + stringLine.StartIndex].rect.x = x;
					}
				}
			}
		}

		public float ComputeMaxWordWidth()
		{
			float maxLength = 0f;
			using IEnumerator<StringRenderGlyphSegmentNode> enumerator = GetEnumerator();
			while (enumerator.MoveNext())
			{
				StringRenderGlyphSegmentNode current = enumerator.Current;
				int? startGlyph = null;
				int? endGlyph = null;
				bool flag = current.DisableLineBreaking();
				for (int i = 0; i < current.GlyphSegmentLength; i++)
				{
					RenderGlyph renderGlyph = current.GetRenderGlyph(i);
					if (current.HasCharacters && !flag && AllowsLineBreak(current.GetCharacter(renderGlyph.stringIndex)))
					{
						UpdateMaxWordWidth(current, ref maxLength, startGlyph, endGlyph);
						startGlyph = null;
						endGlyph = null;
						continue;
					}
					if (!startGlyph.HasValue)
					{
						startGlyph = i;
					}
					endGlyph = i;
				}
				UpdateMaxWordWidth(current, ref maxLength, startGlyph, endGlyph);
			}
			return maxLength;
		}

		public float ComputeMaxLineWidth()
		{
			float maxWidth = 0f;
			GenerateLines(delegate(ref RenderGlyph glyph, in float2 offset, int lineIndex)
			{
				float val = glyph.rect.position.x + glyph.rect.width + offset.x;
				maxWidth = MathX.Max(val, maxWidth);
			});
			return maxWidth;
		}

		private void UpdateMaxWordWidth(StringRenderGlyphSegmentNode segment, ref float maxLength, int? startGlyph, int? endGlyph)
		{
			if (startGlyph.HasValue && endGlyph.HasValue)
			{
				float xmin = segment.GetRenderGlyph(startGlyph.Value).rect.xmin;
				float num = segment.GetRenderGlyph(endGlyph.Value).rect.xmax - xmin;
				if (num > maxLength)
				{
					maxLength = num;
				}
			}
		}

		public float ComputeTotalLineHeight(AlignmentMode alignmentMode)
		{
			ComputeTopAndBottom(alignmentMode, out var top, out var bottom);
			return bottom - top;
		}

		private void ComputeTopAndBottom(AlignmentMode alignmentMode, out float top, out float bottom)
		{
			StringLine stringLine = _lines[0];
			StringLine stringLine2 = _lines[LineCount - 1];
			top = stringLine.Position.y;
			bottom = stringLine2.Position.y;
			switch (alignmentMode)
			{
			case AlignmentMode.Geometric:
				if (MathX.Approximately(stringLine.Ascender, 0f) && MathX.Approximately(stringLine.Descender, 0f))
				{
					top += (0f - stringLine.LineHeight) * stringLine.LineHeightMultiplier * 0.75f;
				}
				else
				{
					top += stringLine.Ascender;
				}
				bottom += stringLine2.Descender;
				break;
			case AlignmentMode.LineBased:
				top += (0f - stringLine.LineHeight) * stringLine.LineHeightMultiplier;
				break;
			}
		}

		private void PerformVerticalAlignment()
		{
			if (LineCount == 0)
			{
				return;
			}
			float num = 0f;
			ComputeTopAndBottom(AlignmentMode, out var top, out var bottom);
			float num2 = (LastLayoutHeight = bottom - top);
			switch (VerticalAlignment)
			{
			case TextVerticalAlignment.Top:
				num = 0f - top;
				break;
			case TextVerticalAlignment.Middle:
				num = 0f - top - num2 * 0.5f;
				break;
			case TextVerticalAlignment.Bottom:
				num = 0f - bottom;
				break;
			}
			if (Bounded)
			{
				switch (BoundsAlignment)
				{
				case Alignment.BottomLeft:
				case Alignment.BottomCenter:
				case Alignment.BottomRight:
					switch (VerticalAlignment)
					{
					case TextVerticalAlignment.Top:
						num -= BoundsSize.y;
						break;
					case TextVerticalAlignment.Middle:
						num -= BoundsSize.y * 0.5f;
						break;
					}
					break;
				case Alignment.MiddleLeft:
				case Alignment.MiddleCenter:
				case Alignment.MiddleRight:
					switch (VerticalAlignment)
					{
					case TextVerticalAlignment.Top:
						num -= BoundsSize.y * 0.5f;
						break;
					case TextVerticalAlignment.Bottom:
						num += BoundsSize.y * 0.5f;
						break;
					}
					break;
				case Alignment.TopLeft:
				case Alignment.TopCenter:
				case Alignment.TopRight:
					switch (VerticalAlignment)
					{
					case TextVerticalAlignment.Middle:
						num += BoundsSize.y * 0.5f;
						break;
					case TextVerticalAlignment.Bottom:
						num += BoundsSize.y;
						break;
					}
					break;
				}
			}
			for (int i = 0; i < LineCount; i++)
			{
				StringLine stringLine = _lines[i];
				stringLine.Position += new float2(0f, num);
			}
		}

