		public void ClearShaping()
		{
			using (IEnumerator<StringRenderGlyphSegmentNode> enumerator = GetEnumerator())
			{
				while (enumerator.MoveNext())
				{
					enumerator.Current.ClearRenderGlyphs();
				}
			}
			_glyphLayoutLength = 0;
			_isShaped = false;
		}

		public void ShapeText(bool kerning = true)
		{
			if (_fontSets == null || _fontSets.Count == 0)
			{
				throw new InvalidOperationException("The string render tree needs at least one font to perform shaping");
			}
			if (_isShaped)
			{
				ClearShaping();
			}
			_isShaped = true;
			_glyphLayoutLength = 0;
			GlyphMetrics glyphMetrics = null;
			for (int i = 0; i < (_fontSets?.Count ?? 0); i++)
			{
				foreach (FontX font in _fontSets[i].Fonts)
				{
					glyphMetrics = font.GetGlyphMetrics(0u);
					if (glyphMetrics != null)
					{
						break;
					}
				}
				if (glyphMetrics != null)
				{
					break;
				}
			}
			if (glyphMetrics == null)
			{
				glyphMetrics = UNIT_GLYPH;
			}
			float tabLength = glyphMetrics.horizontalAdvance * base.Root.ActualSize * TabSpaces;
			_tabLength = tabLength;
			_invTabLength = 1f / _tabLength;
			uint? lastGlyphId = null;
			FontX lastFont = null;
			float lastSize = 0f;
			List<ICharacterFilter> list = Pool.BorrowList<ICharacterFilter>();
			List<ISizeFilter> list2 = Pool.BorrowList<ISizeFilter>();
			using (IEnumerator<StringRenderGlyphSegmentNode> enumerator2 = GetEnumerator())
			{
				while (enumerator2.MoveNext())
				{
					enumerator2.Current.Shape(kerning, ref lastGlyphId, ref lastFont, ref lastSize, list, list2);
				}
			}
			Pool.Return(ref list);
			Pool.Return(ref list2);
		}

