		internal void AppendGlyph(int index, ref RenderGlyph glyph)
		{
			if (_glyphLayoutLength > index)
			{
				throw new ArgumentOutOfRangeException("index");
			}
			if (index < _glyphLayoutLength)
			{
				throw new NotSupportedException("Inserting glyphs in the middle isn't supported right now");
			}
			if (_glyphLayout == null)
			{
				_glyphLayout = new RenderGlyph[String.Length];
			}
			if (_glyphLayout.Length <= index)
			{
				_glyphLayout = _glyphLayout.EnsureExactSize(_glyphLayout.Length * 2, keepData: true);
			}
			_glyphLayout[index] = glyph;
			_glyphLayoutLength++;
		}

