		private void Parse(string str, Func<StringContainerNode, StringContainerNode> initRootNodes = null)
		{
			List<StringSegment> list = new List<StringSegment>();
			Stack<RenestNode> stack = new Stack<RenestNode>();
			StringContainerNode stringContainerNode = this;
			if (initRootNodes != null)
			{
				stringContainerNode = initRootNodes(stringContainerNode);
			}
			int num = 0;
			for (int i = 0; i < str.Length; i++)
			{
				if (str[i] != '<' || !GetTag(new StringSegment(str, i, Math.Min(str.Length - i, 128)), out var other, out var parameter, out var isClosingTag, out var tagEndIndex))
				{
					continue;
				}
				if (isClosingTag)
				{
					bool flag = IsTag(in other, "closeall");
					int num2 = 0;
					if (flag)
					{
						num2 = list.FindLastIndex((StringSegment s) => s.Equals("closeallblock", StringComparison.InvariantCultureIgnoreCase));
						num2 = ((num2 >= 0) ? (list.Count - num2 - 1) : list.Count);
					}
					else
					{
						for (int num3 = list.Count - 1; num3 >= 0; num3--)
						{
							if (list[num3].Equals(in other, StringComparison.InvariantCultureIgnoreCase))
							{
								num2 = list.Count - num3;
								break;
							}
						}
					}
					if (num2 > 0 && (stringContainerNode.AllowOutOfOrderSplit || num2 == 1 || flag))
					{
						FinishSegment(num, i, stringContainerNode);
						num = i + tagEndIndex;
						while (num2-- > 0)
						{
							if (num2 > 0 && !flag)
							{
								stack.Push(new RenestNode(list.Last(), stringContainerNode));
							}
							stringContainerNode = stringContainerNode.Parent;
							list.TakeLast();
						}
						while (stack.Count > 0)
						{
							RenestNode renestNode = stack.Pop();
							StringContainerNode stringContainerNode2 = renestNode.node.Clone(i + tagEndIndex, stringContainerNode);
							stringContainerNode.Nodes.Add(stringContainerNode2);
							stringContainerNode = stringContainerNode2;
							list.Add(renestNode.tag);
						}
					}
				}
				else
				{
					StringNode stringNode = CreateNode(i, stringContainerNode, in other, in parameter);
					StringContainerNode stringContainerNode3 = stringNode as StringContainerNode;
					if (stringNode != null && (stringContainerNode3 == null || stringContainerNode.IsValidNestedNode(stringContainerNode3)))
					{
						FinishSegment(num, i, stringContainerNode);
						num = i + tagEndIndex;
						stringContainerNode.Nodes.Add(stringNode);
						if (stringContainerNode3 != null)
						{
							stringContainerNode = stringContainerNode3;
							list.Add(other);
							if (stringContainerNode is StringNoParseNode { NoParseMode: StringNoParseNode.Mode.Length } stringNoParseNode)
							{
								stringNoParseNode.NoParseLength = MathX.Min(str.Length - num, stringNoParseNode.NoParseLength);
								int num4 = num + stringNoParseNode.NoParseLength;
								FinishSegment(num, num4, stringContainerNode);
								i += stringNoParseNode.NoParseLength;
								num = num4;
								stringContainerNode = stringContainerNode.Parent;
								list.TakeLast();
							}
						}
					}
				}
				i += tagEndIndex - 1;
			}
			FinishSegment(num, str.Length, stringContainerNode);
		}

		private static void FinishSegment(int segmentStart, int segmentEnd, StringContainerNode root)
		{
			int num = segmentEnd - segmentStart;
			if (num > 0)
			{
				StringSegmentNode item = new StringSegmentNode(segmentStart, num, root);
				root.Nodes.Add(item);
			}
		}

		private static StringNode CreateNode(int startIndex, StringContainerNode parent, in StringSegment tag, in StringSegment parameter)
		{
			if (tag.length == 1)
			{
				if (parameter.length > 0)
				{
					return null;
				}
				switch (char.ToLowerInvariant(tag[0]))
				{
				case 'b':
					return new StringFormatNode(startIndex, StringFormatNode.FormatType.Bold, parent);
				case 'i':
					return new StringFormatNode(startIndex, StringFormatNode.FormatType.Italics, parent);
				case 'u':
					return new StringFormatNode(startIndex, StringFormatNode.FormatType.Underline, parent);
				case 's':
					return new StringFormatNode(startIndex, StringFormatNode.FormatType.Strikethrough, parent);
				}
			}
			if (parameter.length == 0)
			{
				if (IsTag(in tag, "br") && parameter.length == 0)
				{
					return new StringLineBreakNode(startIndex, parent);
				}
				if (IsTag(in tag, "nobr"))
				{
					return new StringNoLineBreakNode(startIndex, parent);
				}
				if (IsTag(in tag, "sub"))
				{
					return new StringScriptModeNode(TextScriptMode.Subscript, startIndex, parent);
				}
				if (IsTag(in tag, "sup"))
				{
					return new StringScriptModeNode(TextScriptMode.Superscript, startIndex, parent);
				}
				if (IsTag(in tag, "lowercase"))
				{
					return new StringCapitalizationNode(CapitalizationMode.Lowercase, startIndex, parent);
				}
				if (IsTag(in tag, "uppercase"))
				{
					return new StringCapitalizationNode(CapitalizationMode.Uppercase, startIndex, parent);
				}
				if (IsTag(in tag, "smallcaps") || IsTag(in tag, "allcaps"))
				{
					return new StringCapitalizationNode(CapitalizationMode.SmallCaps, startIndex, parent);
				}
			}
			if (IsTag(in tag, "closeallblock"))
			{
				return new StringCloseallBlockNode(startIndex, parent);
			}
			if (IsTag(in tag, "noparse"))
			{
				return StringNoParseNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "color"))
			{
				return StringColorNode.Parse(parameter.AsSpan(), alphaOnly: false, startIndex, parent);
			}
			if (IsTag(in tag, "gradient"))
			{
				return StringHorizontalGradientNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "alpha"))
			{
				return StringColorNode.Parse(parameter.AsSpan(), alphaOnly: true, startIndex, parent);
			}
			if (IsTag(in tag, "mark"))
			{
				return StringMarkNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "size"))
			{
				return StringSizeNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "align"))
			{
				return StringAlignmentNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "font"))
			{
				StringFontNode stringFontNode = StringFontNode.Parse(parameter.AsSpan(), startIndex, parent);
				if (stringFontNode != null)
				{
					stringFontNode.ResolveFont();
					return stringFontNode;
				}
				return stringFontNode;
			}
			if (IsTag(in tag, "line-height"))
			{
				return StringLineHeightNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			if (IsTag(in tag, "sprite") || IsTag(in tag, "glyph"))
			{
				return StringGlyphNode.Parse(parameter.AsSpan(), startIndex, parent);
			}
			return null;
		}

		private static bool IsTag(in StringSegment tag, string name)
		{
			return tag.Equals(name, StringComparison.InvariantCultureIgnoreCase);
		}

		private static bool IsTagCharacter(char ch)
		{
			if (!char.IsLetter(ch))
			{
				return ch == '-';
			}
			return true;
		}

		private static bool GetTag(in StringSegment segment, out StringSegment tag, out StringSegment parameter, out bool isClosingTag, out int tagEndIndex)
		{
			TagScanState tagScanState = TagScanState.ScanningBeginning;
			isClosingTag = false;
			tag = StringSegment.Empty;
			parameter = StringSegment.Empty;
			tagEndIndex = -1;
			if (segment.length >= 3)
			{
				int num = 1;
				if (segment[1] == '/')
				{
					isClosingTag = true;
					num++;
				}
				int num2 = -1;
				for (int i = num; i < segment.length; i++)
				{
					char c = segment[i];
					switch (tagScanState)
					{
					case TagScanState.ScanningBeginning:
						if (!char.IsLetter(c))
						{
							tagScanState = TagScanState.Invalid;
							break;
						}
						tagScanState = TagScanState.ScanningTag;
						num2 = i;
						break;
					case TagScanState.ScanningTag:
					{
						bool flag = false;
						if (c == '=' || c == ' ')
						{
							if (isClosingTag)
							{
								tagScanState = TagScanState.Invalid;
								break;
							}
							tagScanState = TagScanState.ScanningParameter;
							flag = true;
						}
						else if (c == '>')
						{
							tagScanState = TagScanState.FinishedScanning;
							flag = true;
						}
						else if (!IsTagCharacter(c))
						{
							tagScanState = TagScanState.ScanningForEnd;
							flag = true;
						}
						if (flag)
						{
							tag = segment.Slice(num2, i - num2);
							num2 = i + 1;
						}
						break;
					}
					case TagScanState.ScanningParameter:
						if (c == '>')
						{
							parameter = segment.Slice(num2, i - num2).Trim();
							tagScanState = TagScanState.FinishedScanning;
						}
						break;
					case TagScanState.ScanningForEnd:
						if (c == '>')
						{
							tagScanState = TagScanState.FinishedScanning;
						}
						break;
					}
					switch (tagScanState)
					{
					case TagScanState.FinishedScanning:
						tagEndIndex = i + 1;
						break;
					default:
						continue;
					case TagScanState.Invalid:
						break;
					}
					break;
				}
			}
			return tagScanState == TagScanState.FinishedScanning;
		}
	}
	public abstract class StringContainerNode : StringNode, IEnumerable<StringRenderGlyphSegmentNode>, IEnumerable
	{
		public readonly List<StringNode> Nodes = new List<StringNode>();

		public virtual bool AllowOutOfOrderSplit => true;

		public StringContainerNode()
		{
		}

		public StringContainerNode(int startIndex, StringContainerNode parent)
			: this(startIndex, parent, parent.Root)
		{
		}

		public StringContainerNode(int startIndex, StringContainerNode parent, StringRenderTree root)
			: base(startIndex, parent, root)
		{
		}

		public virtual bool IsValidNestedNode(StringContainerNode node)
		{
			return true;
		}

		public abstract StringContainerNode Clone(int startIndex, StringContainerNode parent);

		public override void GetRawString(StringBuilder stringBuilder)
		{
			foreach (StringNode node in Nodes)
			{
				node.GetRawString(stringBuilder);
			}
		}

		public IEnumerator<StringRenderGlyphSegmentNode> GetEnumerator()
		{
			foreach (StringNode node in Nodes)
			{
				if (node is StringRenderGlyphSegmentNode stringRenderGlyphSegmentNode)
				{
					yield return stringRenderGlyphSegmentNode;
				}
				else
				{
					if (!(node is StringContainerNode stringContainerNode))
					{
						continue;
					}
					foreach (StringRenderGlyphSegmentNode item in stringContainerNode)
					{
						yield return item;
					}
				}
			}
		}

		IEnumerator IEnumerable.GetEnumerator()
		{
			return GetEnumerator();
		}
	}
