	public class FontSet
	{
		public readonly List<FontX> Fonts = new List<FontX>();

		public FontX MainFont => Fonts[0];

		public FontSet(FontX mainFont)
		{
			Fonts.Add(mainFont);
		}

		public bool GetGlyphByUnicode(uint charcode, out GlyphMetrics metrics, out FontX font)
		{
			foreach (FontX font2 in Fonts)
			{
				metrics = font2.GetCharMetrics(charcode);
				if (metrics != null && metrics.glyphId != 0)
				{
					font = font2;
					return true;
				}
			}
			metrics = MainFont.GetCharMetrics(charcode);
			font = MainFont;
			return false;
		}

		public bool GetGlyphByName(string name, out GlyphMetrics metrics, out uint glyphId, out FontX font)
		{
			foreach (FontX font2 in Fonts)
			{
				glyphId = font2.GetGlyphIdFromName(name);
				if (glyphId != 0)
				{
					font = font2;
					metrics = font2.GetGlyphMetrics(glyphId);
					return true;
				}
			}
			metrics = null;
			font = null;
			glyphId = 0u;
			return false;
		}
	}
