	public static class TextRenderHelper
	{
		public static TextHorizontalAlignment GetHorizontalText(this Alignment align)
		{
			switch (align)
			{
			case Alignment.TopLeft:
			case Alignment.MiddleLeft:
			case Alignment.BottomLeft:
				return TextHorizontalAlignment.Left;
			case Alignment.TopCenter:
			case Alignment.MiddleCenter:
			case Alignment.BottomCenter:
				return TextHorizontalAlignment.Center;
			case Alignment.TopRight:
			case Alignment.MiddleRight:
			case Alignment.BottomRight:
				return TextHorizontalAlignment.Right;
			default:
				throw new Exception("Invalid Alignment: " + align);
			}
		}

		public static TextVerticalAlignment GetVerticalText(this Alignment align)
		{
			switch (align)
			{
			case Alignment.BottomLeft:
			case Alignment.BottomCenter:
			case Alignment.BottomRight:
				return TextVerticalAlignment.Bottom;
			case Alignment.MiddleLeft:
			case Alignment.MiddleCenter:
			case Alignment.MiddleRight:
				return TextVerticalAlignment.Middle;
			case Alignment.TopLeft:
			case Alignment.TopCenter:
			case Alignment.TopRight:
				return TextVerticalAlignment.Top;
			default:
				throw new Exception("Invalid Alignment: " + align);
			}
		}
	}
