		}

		public virtual void ConvertToProfile(ColorProfile targetProfile)
		{
			if (Profile != targetProfile)
			{
				ForEachPixel((color c) => c.ConvertProfile(Profile, targetProfile));
				Profile = targetProfile;
			}
		}

		public virtual void ConvertTosRGB()
		{
			ForEachPixel((color c) => c.ConvertProfile(ColorProfile.sRGB, ColorProfile.Linear));
		}

		public virtual void ConvertHDRToHDRsRGB()
		{
			ForEachPixel(delegate(color c)
			{
				if (c.r <= 1f && c.g <= 1f && c.b <= 1f)
				{
					c = c.ConvertProfile(ColorProfile.sRGB, ColorProfile.Linear);
				}
				else
				{
					float num = c.r;
					float num2 = c.g;
					float num3 = c.b;
					if (num > 1f)
					{
						num = MathX.Pow(num, 0.45454544f);
					}
					if (num2 > 1f)
					{
						num2 = MathX.Pow(c.g, 0.45454544f);
					}
					if (num3 > 1f)
					{
						num3 = MathX.Pow(c.r, 0.45454544f);
					}
					c = new color(num, num2, num3, c.a);
				}
				return c;
			});
		}

		public void PackNormalMap()
		{
			ForEachPixel((color c) => new color(1f, c.g, c.g, c.r));
		}

		public void EncodeLogLUV()
		{
			ForEachPixel(delegate(color c)
			{
				float3 @float = MathX.Max(LOGLUV_ENCODE_MAT * ILSpyHelper_AsRefReadOnly(c.rgb), new float3(1E-06f, 1E-06f, 1E-06f));
				float2 float2 = @float.xy / @float.z;
				float num = 2f * MathX.Log(@float.y) + 127f;
				float num2 = MathX.Frac(num);
				float b = (num - MathX.Floor(num2 * 255f) / 255f) / 255f;
				return new color(float2.x, float2.y, b, num2);
				static ref readonly T ILSpyHelper_AsRefReadOnly<T>(in T temp)
				{
					//ILSpy generated this function to help ensure overload resolution can pick the overload using 'in'
					return ref temp;
				}
			});
		}

		public void EncodeRGBM()
		{
			ForEachPixel(delegate(color c)
			{
				float4 @float = default(float4);
				_ = c.rgb * (1f / 6f);
				@float = @float.SetComponent(MathX.Clamp01(MathX.Max(MathX.Max(c.r, c.g), MathX.Max(c.b, 1E-06f))), 3);
				return (float4)(c / @float.SetComponent(MathX.Ceil(@float.w * 255f) / 255f, 3).w);
			});
		}
	}
	[DataModelType]
	public enum WrapMode
	{
		Clamp,
		Repeat
	}
	[DataModelType]
	public enum TextureSize
	{
		NPOT,
		LowestPOT,
		NearestPOT,
		HighestPOT
	}
	public class Bitmap2D : Bitmap2DBase, IBitmap<Bitmap2D>, IBitmap
	{
		private readonly struct ClusterPixel
		{
			public const int FLOAT_SIZE = 6;

			public readonly float2 position;

			public readonly color color;

			public ClusterPixel(in float2 position, in color color)
			{
				this.position = position;
				this.color = color;
			}
		}

		public const int RAW_VERSION = 1;

		public const string MAGIC_STRING = "Bmp2X";

