		public float2 PixelToUV(int x, int y)
		{
			return PixelToUV(new int2(x, y));
		}

		public float2 PixelToUV(in int2 point)
		{
			return (float2)point * base.PixelToUVRatio;
		}

		public int2 UVToPixel(in float2 uv)
		{
			return MathX.RoundToInt(uv * base.UVToPixelRatio);
		}

		public color SampleUV(in float2 uv, WrapMode wrap = WrapMode.Clamp, int mipLevel = 0)
		{
			return GetPixelBilinear(uv.x * (float)base.Size.x, uv.y * (float)base.Size.y, wrap, mipLevel);
		}

		public color GetPixelBilinear(float x, float y, WrapMode wrap = WrapMode.Clamp, int mipLevel = 0)
		{
			int num = (int)x;
			int num2 = (int)y;
			int val = num + 1;
			int val2 = num2 + 1;
			float lerp = x - (float)num;
			float lerp2 = y - (float)num2;
			int2 @int = MipMapSize(mipLevel);
			if (wrap == WrapMode.Clamp)
			{
				num = MathX.Clamp(num, 0, @int.x);
				num2 = MathX.Clamp(num2, 0, @int.y);
				val = MathX.Clamp(val, 0, @int.x);
				val2 = MathX.Clamp(val2, 0, @int.y);
			}
			else
			{
				num = MathX.Repeat(num, @int.x - 1);
				num2 = MathX.Repeat(num2, @int.y - 1);
				val = MathX.Repeat(val, @int.x - 1);
				val2 = MathX.Repeat(val2, @int.y - 1);
			}
			return MathX.LerpUnclamped(MathX.LerpUnclamped(GetPixel(num, num2, mipLevel), GetPixel(val, num2, mipLevel), lerp), MathX.LerpUnclamped(GetPixel(num, val2, mipLevel), GetPixel(val, val2, mipLevel), lerp), lerp2);
		}

		public color GetPixel(int x, int y, int mipLevel = 0)
		{
			int index = PixelStart(x, y, mipLevel);
			return DecodePixel(index);
		}

		public color32 GetPixel32(int x, int y, int mipLevel = 0)
		{
			int index = PixelStart(x, y, mipLevel);
			return DecodePixel32(index);
		}

		public void SetPixel(int x, int y, in color color, int mipLevel = 0)
		{
			int index = PixelStart(x, y, mipLevel);
			EncodePixel(index, in color);
		}

		public void SetPixel32(int x, int y, in color32 color, int mipLevel = 0)
		{
			int index = PixelStart(x, y, mipLevel);
			EncodePixel32(index, in color);
		}

		public bool VerifyRegion(int x, int y, int width, int height, int mip = 0)
		{
			int2 @int = ((mip == 0) ? base.Size : mipmapSizes[mip]);
			if (x >= 0 && y >= 0 && x + width <= @int.x)
			{
				return y + height <= @int.y;
			}
			return false;
		}

		public void GetMipMapBuffers(List<Memory<byte>> mipbuffers)
		{
			GetMipMapBuffers(mipbuffers, 0);
		}

		public void GetMipMapBuffers(List<MipMapBuffer> mipbuffers)
		{
			GetMipMapBuffers(mipbuffers, 0, 0);
		}

		private void CheckRegion(int x, int y, int width, int height, int mip)
		{
			if (!VerifyRegion(x, y, width, height, mip))
			{
				throw new Exception("Region out of bounds");
			}
		}

		public static int ComputeTotalPixels(in int2 size, bool mipmaps)
		{
			if (mipmaps)
			{
				return Bitmap2DBase.MipmapLevels(in size, null);
			}
			return size.x * size.y;
		}

		public Bitmap2D ExtractMipMap(int mip, bool includeLowerMips = false)
		{
			int2 @int = MipMapSize(mip);
			Bitmap2D bitmap2D = new Bitmap2D(@int.x, @int.y, base.Format, includeLowerMips, base.Profile, base.FlipY, base.OriginalFormat);
			for (int i = 0; i < bitmap2D.MipMapLevels; i++)
			{
				bitmap2D.FillFromMipMap(this, mip + i, i);
			}
			return bitmap2D;
		}

		public Bitmap2D ConvertTo(TextureFormat format, IBackingBufferAllocator allocator = null)
		{
			Bitmap2D bitmap2D = new Bitmap2D(base.Size.x, base.Size.y, format, base.HasMipMaps, base.Profile, base.FlipY, base.OriginalFormat, allocator);
			bitmap2D.FillFrom(this);
			return bitmap2D;
		}

		public void FillFrom(BitmapCube cubemap, BitmapCube.Face face, int miplevel = 0)
		{
			if (cubemap.Size != base.Size)
			{
				throw new ArgumentException("The Cubemap face size doesn't equal the Bitmap2D size");
			}
			int destStart = PixelStart(0, 0, miplevel);
			int sourceStart = cubemap.PixelStart(0, 0, face, miplevel);
			int count = cubemap.MipmapTotalPixels(miplevel);
			CopyPixelsFrom(cubemap, sourceStart, destStart, count);
		}

		public override string ToString()
		{
			return $"Bitmap2D. Size: {base.Size.x}x{base.Size.y}, Format: {base.Format}, MipLevels: {base.MipMapLevels}, Bytes: {base.Buffer?.SizeBytes ?? (-1)}, Profile: {base.Profile}";
		}

		public void KMeansCluster(int k, float positionWeight, int batchSize = 1024, float passesOverData = 1f, IProgressIndicator progress = null)
		{
			float[] array = new float[base.TotalPixels * 6];
			Span<ClusterPixel> span = MemoryMarshal.Cast<float, ClusterPixel>(array.AsSpan());
			float2 @float = 1f / base.Size;
			int num = 0;
			for (int i = 0; i < base.Size.y; i++)
			{
				float y = (float)i * @float.y * positionWeight;
				for (int j = 0; j < base.Size.x; j++)
				{
					float x = (float)j * @float.x * positionWeight;
					color color = GetPixel(j, i);
					span[num++] = new ClusterPixel(new float2(x, y), in color);
				}
			}
			float[] array2 = new float[k * 6];
			int[] array3 = new int[base.TotalPixels];
			if (!KMeansClustering.Calculate(6, array.AsMemory(), batchSize, passesOverData, array2.AsMemory(), array3.AsMemory(), progress))
			{
				throw new Exception("Clustering failed");
			}
			Span<ClusterPixel> span2 = MemoryMarshal.Cast<float, ClusterPixel>(array2.AsSpan());
			num = 0;
			for (int l = 0; l < base.Size.y; l++)
			{
				for (int m = 0; m < base.Size.x; m++)
				{
					ClusterPixel clusterPixel = span2[array3[num++]];
					SetPixel(m, l, in clusterPixel.color);
				}
			}
		}

		public void Fill(int x, int y, int width, int height, color color, int mip = 0)
		{
			CheckRegion(x, y, width, height, mip);
			Parallel.For(y, y + height, delegate(int _y)
			{
				for (int i = x; i < x + width; i++)
				{
					SetPixel(i, _y, in color, mip);
				}
			});
		}

