		public static Bitmap2D LoadRaw(string file, IBackingBufferAllocator allocator = null)
		{
			using FileStream stream = File.OpenRead(file);
			return LoadRaw(stream, allocator);
		}

		public static Bitmap2D LoadRaw(Stream stream, IBackingBufferAllocator allocator = null)
		{
			BinaryReader binaryReader = new BinaryReader(stream, System.Text.Encoding.UTF8, leaveOpen: true);
			string text = binaryReader.ReadString();
			if (text != "Bmp2X")
			{
				throw new InvalidDataException($"Couldn't find magic string. Found string of length: {text?.Length}");
			}
			int num = binaryReader.ReadInt32();
			if (num > 1)
			{
				throw new InvalidDataException("Version is too new: " + num);
			}
			int width = binaryReader.ReadInt32();
			int height = binaryReader.ReadInt32();
			TextureFormat format = (TextureFormat)binaryReader.ReadUInt16();
			byte data = binaryReader.ReadByte();
			bool bit = data.GetBit(0);
			bool bit2 = data.GetBit(1);
			RawBitmapEncoding rawBitmapEncoding = (RawBitmapEncoding)binaryReader.ReadByte();
			ColorProfile profile = ColorProfile.sRGB;
			if (num > 0)
			{
				profile = binaryReader.ReadEnumString<ColorProfile>();
			}
			Bitmap2D bitmap2D = new Bitmap2D(width, height, format, bit, profile, bit2, null, allocator);
			switch (rawBitmapEncoding)
			{
			case RawBitmapEncoding.Uncompressed:
			{
				int i = 0;
				int num2;
				for (Span<byte> rawData = bitmap2D.RawData; rawData.Length - i > 0; i += num2)
				{
					num2 = stream.Read(rawData.Slice(i, bitmap2D.RawData.Length - i));
				}
				break;
			}
			case RawBitmapEncoding.LZMA:
			{
				using (Stream outStream = bitmap2D.Buffer.Memory.AsStream())
				{
					LZMAHelper.Decompress(stream, outStream);
				}
				break;
			}
			}
			return bitmap2D;
		}

		public void SaveRaw(string file, RawBitmapEncoding encoding = RawBitmapEncoding.LZMA)
		{
			using FileStream stream = File.OpenWrite(file);
			SaveRaw(stream, encoding);
		}

		public void SaveRaw(Stream stream, RawBitmapEncoding encoding = RawBitmapEncoding.LZMA)
		{
			BinaryWriter binaryWriter = new BinaryWriter(stream, System.Text.Encoding.UTF8, leaveOpen: true);
			binaryWriter.Write("Bmp2X");
			binaryWriter.Write(1);
			binaryWriter.Write(base.Size.x);
			binaryWriter.Write(base.Size.y);
			binaryWriter.Write((ushort)base.Format);
			byte data = 0;
			data.SetBit(0, base.HasMipMaps);
			data.SetBit(1, base.FlipY);
			binaryWriter.Write(data);
			binaryWriter.Write((byte)encoding);
			binaryWriter.WriteEnumString(base.Profile);
			binaryWriter.Flush();
			switch (encoding)
			{
			case RawBitmapEncoding.Uncompressed:
				stream.Write(base.RawData);
				break;
			case RawBitmapEncoding.LZMA:
			{
				using Stream inStream = base.Buffer.Memory.AsStream();
				LZMAHelper.Compress(inStream, stream);
				break;
			}
			default:
				throw new ArgumentException("Invalid encoding: " + encoding);
			}
		}

		public bool Save(string file, int quality = 85, bool preserveColorInAlpha = true)
		{
			string extension = Path.GetExtension(file).Substring(1).ToLower();
			using FileStream stream = File.OpenWrite(file);
			return Save(stream, extension, quality, preserveColorInAlpha);
		}

		public bool Save(Stream stream, string extension, int quality = 85, bool preserveColorInAlpha = true)
		{
			FIBITMAP dib = ToFreeImage();
			try
			{
				return TextureEncoder.Encode(dib, stream, extension, quality, preserveColorInAlpha);
			}
			finally
			{
				FreeImage.Unload(dib);
			}
		}

		public FIBITMAP ToFreeImage()
		{
			return ToFreeImage(new IntRect(int2.Zero, base.Size));
		}

		public FIBITMAP ToFreeImage(IntRect region, int sourceMip = 0)
		{
			int num = (num = (int)MathX.BitsToBytes(base.BitsPerPixel));
			FREE_IMAGE_TYPE type;
			switch (base.Format)
			{
			case TextureFormat.Alpha8:
				type = FREE_IMAGE_TYPE.FIT_BITMAP;
				num = 4;
				break;
			case TextureFormat.RGB24:
			case TextureFormat.ARGB32:
			case TextureFormat.RGBA32:
			case TextureFormat.BGRA32:
				type = FREE_IMAGE_TYPE.FIT_BITMAP;
				break;
			case TextureFormat.R8:
			case TextureFormat.RGB565:
			case TextureFormat.BGR565:
				type = FREE_IMAGE_TYPE.FIT_BITMAP;
				num = 3;
				break;
			case TextureFormat.RGBAHalf:
			case TextureFormat.RGBAFloat:
				type = FREE_IMAGE_TYPE.FIT_RGBAF;
				num = 16;
				break;
			default:
				throw new Exception("Unsupported Export Format: " + base.Format);
			}
			FIBITMAP fIBITMAP = FreeImage.AllocateT(type, region.width, region.height, num * 8);
			if (fIBITMAP.IsNull)
			{
				throw new Exception($"Failed to allocate FreeImage texture. Size: {base.Size}, Format: {base.Format}, BytesPerPixel: {num}");
			}
			for (int i = 0; i < region.height; i++)
			{
				int scanline = region.height - i - 1;
				switch (base.Format)
				{
				case TextureFormat.R8:
				case TextureFormat.RGB24:
				case TextureFormat.RGB565:
				case TextureFormat.BGR565:
				{
					Scanline<RGBTRIPLE> scanline4 = new Scanline<RGBTRIPLE>(fIBITMAP, scanline);
					RGBTRIPLE[] data3 = scanline4.Data;
					for (int l = 0; l < region.width; l++)
					{
						color32 pixel3 = GetPixel32(region.x + l, region.y + i, sourceMip);
						data3[l].rgbtRed = pixel3.r;
						data3[l].rgbtGreen = pixel3.g;
						data3[l].rgbtBlue = pixel3.b;
					}
					scanline4.Data = data3;
					break;
				}
				case TextureFormat.Alpha8:
				case TextureFormat.ARGB32:
				case TextureFormat.RGBA32:
				case TextureFormat.BGRA32:
				{
					Scanline<RGBQUAD> scanline3 = new Scanline<RGBQUAD>(fIBITMAP, scanline);
					RGBQUAD[] data2 = scanline3.Data;
					for (int k = 0; k < region.width; k++)
					{
						color32 pixel2 = GetPixel32(region.x + k, region.y + i, sourceMip);
						data2[k].rgbRed = pixel2.r;
						data2[k].rgbGreen = pixel2.g;
						data2[k].rgbBlue = pixel2.b;
						data2[k].rgbReserved = pixel2.a;
					}
					scanline3.Data = data2;
					break;
				}
				case TextureFormat.RGBAHalf:
				case TextureFormat.RGBAFloat:
				{
					Scanline<FIRGBAF> scanline2 = new Scanline<FIRGBAF>(fIBITMAP, scanline);
					FIRGBAF[] data = scanline2.Data;
					for (int j = 0; j < region.width; j++)
					{
						color pixel = GetPixel(region.x + j, region.y + i, sourceMip);
						data[j].red = pixel.r;
						data[j].green = pixel.g;
						data[j].blue = pixel.b;
						data[j].alpha = pixel.a;
					}
					scanline2.Data = data;
					break;
				}
				default:
					throw new Exception("Unsupported Export Format: " + base.Format);
				}
			}
			return fIBITMAP;
		}

		public color GetPixelBoxClamp(int x, int y, int mip = 0)
		{
			int2 @int = MipMapSize(mip) - 1;
			int x2 = MathX.Max(0, x - 1);
			int x3 = MathX.Min(@int.x, x + 1);
			int y2 = MathX.Max(0, y - 1);
			int y3 = MathX.Min(@int.y, y + 1);
			return (GetPixel(x2, y2, mip) + GetPixel(x, y2, mip) + GetPixel(x3, y2, mip) + GetPixel(x2, y, mip) + GetPixel(x, y, mip) + GetPixel(x3, y, mip) + GetPixel(x2, y3, mip) + GetPixel(x, y3, mip) + GetPixel(x3, y3, mip)) * (1f / 9f);
		}

		public color GetPixelBoxRepeat(int x, int y, int mip = 0)
		{
			int2 @int = MipMapSize(mip);
			int x2 = ((x != 0) ? (x - 1) : (@int.x - 1));
			int y2 = ((y != 0) ? (y - 1) : (@int.y - 1));
			int x3 = (x + 1) % @int.x;
			int y3 = (y + 1) % @int.y;
			return (GetPixel(x2, y2, mip) + GetPixel(x, y2, mip) + GetPixel(x3, y2, mip) + GetPixel(x2, y, mip) + GetPixel(x, y, mip) + GetPixel(x3, y, mip) + GetPixel(x2, y3, mip) + GetPixel(x, y3, mip) + GetPixel(x3, y3, mip)) * (1f / 9f);
		}

		public void GenerateMipmapsBox()
		{
			for (int i = 1; i < base.MipMapLevels; i++)
			{
				GenerateMipmapLevelBox(i);
			}
		}

		public void GenerateMipmapLevelBox(int mip)
		{
			if (mip == 0 || mip >= base.MipMapLevels)
			{
				throw new ArgumentOutOfRangeException("level");
			}
			int sourceMip = mip - 1;
			int2 mipSize = MipMapSize(mip);
			Parallel.For(0, mipSize.y, delegate(int y)
			{
				for (int i = 0; i < mipSize.x; i++)
				{
					int x = i * 2;
					int y2 = y * 2;
					SetPixel(i, y, GetPixelBoxRepeat(x, y2, sourceMip), mip);
				}
			});
		}

		public void GenerateMipMapForRegion(IntRect region, Filtering filtering)
		{
			int num = 0;
			do
			{
				IntRect region2 = region;
				int sourceMip = num;
				num++;
				region = new IntRect(MathX.FloorToInt((float)region2.x * 0.5f), MathX.FloorToInt((float)region2.y * 0.5f), MathX.CeilToInt((float)region2.width * 0.5f), MathX.CeilToInt((float)region2.height * 0.5f));
				Bitmap2D rescaled = GetRescaled(region2, sourceMip, region.Size, false, forceRescale: true, filtering);
				for (int i = 0; i < region.height; i++)
				{
					int y = region.y + i;
					for (int j = 0; j < region.width; j++)
					{
						SetPixel(region.x + j, y, rescaled.GetPixel(j, i), num);
					}
				}
			}
			while (num < base.MipMapLevels && region.width > 1 && region.height > 1);
		}

		public Bitmap2D GetRescaled(int longestSize, bool? mipmaps = null, bool forceRescale = false, Filtering filtering = Filtering.Box, IBackingBufferAllocator allocator = null)
		{
			int num = MathX.MaxComponent(base.Size);
			double num2 = (double)longestSize / (double)num;
			return GetRescaled((int2)(base.Size * num2), mipmaps, forceRescale, filtering, allocator);
		}

		public Bitmap2D GetRescaled(int width, int height, bool? mipmaps = null, bool forceRescale = false, Filtering filtering = Filtering.Box)
		{
			return GetRescaled(new int2(width, height), mipmaps, forceRescale, filtering);
		}

		public Bitmap2D GetRescaled(int2 size, bool? mipmaps = null, bool forceRescale = false, Filtering filtering = Filtering.Box, IBackingBufferAllocator allocator = null)
		{
			return GetRescaled(new IntRect(int2.Zero, base.Size), 0, size, mipmaps, forceRescale, filtering, allocator);
		}

		public Bitmap2D GetRescaled(IntRect region, int sourceMip, int2 size, bool? mipmaps = null, bool forceRescale = false, Filtering filtering = Filtering.Box, IBackingBufferAllocator allocator = null)
		{
			if (!forceRescale && region.Size == size && (!mipmaps.HasValue || mipmaps.Value == base.HasMipMaps))
			{
				return this;
			}
			bool generateMipMaps = mipmaps ?? base.HasMipMaps;
			FIBITMAP dib = default(FIBITMAP);
			FIBITMAP dib2 = default(FIBITMAP);
			FREE_IMAGE_FILTER filter = filtering switch
			{
				Filtering.Bilinear => FREE_IMAGE_FILTER.FILTER_BILINEAR, 
				Filtering.Box => FREE_IMAGE_FILTER.FILTER_BOX, 
				Filtering.Lanczos3 => FREE_IMAGE_FILTER.FILTER_LANCZOS3, 
				_ => throw new Exception("Invalid filter: " + filtering), 
			};
			try
			{
				dib = ToFreeImage(region, sourceMip);
				dib2 = FreeImage.Rescale(dib, size.x, size.y, filter);
				return TextureDecoder.FromFreeImage(ref dib2, generateMipMaps, AlphaHandling.KeepOriginal, int.MaxValue, 1f, null, allocator);
			}
			finally
			{
				if (!dib.IsNull)
				{
					FreeImage.Unload(dib);
				}
				if (!dib2.IsNull)
				{
					FreeImage.Unload(dib2);
				}
			}
		}

		public Bitmap2D Crop(Rect rect)
		{
			if (rect.width <= 1f && rect.height <= 1f && rect.x < 1f && rect.y < 1f)
			{
				return Crop(MathX.RoundToInt(rect.position * (float2)base.Size), MathX.RoundToInt(rect.size * (float2)base.Size));
			}
			return Crop(MathX.RoundToInt(in rect.position), MathX.RoundToInt(in rect.size));
		}

		public Bitmap2D Crop(int2 position, int2 size)
		{
			return Crop(position.x, position.y, size.x, size.y);
		}

		public Bitmap2D Crop(int x, int y, int width, int height)
		{
			Bitmap2D bitmap2D = new Bitmap2D(width, height, base.Format, base.HasMipMaps, base.Profile);
			bitmap2D.CopyFrom(this, x, y, 0, 0, width, height);
			if (bitmap2D.HasMipMaps)
			{
				bitmap2D.GenerateMipmapsBox();
			}
			return bitmap2D;
		}

		public Bitmap2D CropCenter(int2 newSize)
		{
			if (newSize.x > base.Size.x || newSize.y > base.Size.y)
			{
				throw new ArgumentOutOfRangeException("size");
			}
			int2 position = (base.Size - newSize) / 2;
			return Crop(position, newSize);
		}

		public Bitmap2D CropSquareCenter()
		{
			return CropAspectRatioCenter(1f);
		}

		public Bitmap2D CropAspectRatioCenter(float2 ratio)
		{
			return CropAspectRatioCenter(ratio.x / ratio.y);
		}

		public Bitmap2D CropAspectRatioCenter(float ratio)
		{
			if (ratio >= 1f)
			{
				if (base.Size.x > base.Size.y)
				{
					return CropCenter(new int2(MathX.RoundToInt((float)base.Size.y * ratio), base.Size.y));
				}
				return CropCenter(new int2(base.Size.x, MathX.RoundToInt((float)base.Size.x / ratio)));
			}
			if (base.Size.x < base.Size.y)
			{
				return CropCenter(new int2(MathX.RoundToInt((float)base.Size.y * ratio), base.Size.y));
			}
			return CropCenter(new int2(base.Size.x, MathX.RoundToInt((float)base.Size.x / ratio)));
		}

		public void CopyFrom(Bitmap2D source, int sourceX, int sourceY, int destX, int destY, int width, int height)
		{
			if (source.Format == base.Format)
			{
				for (int i = 0; i < height; i++)
				{
					double bits = (double)source.PixelStart(sourceX, sourceY + i, 0) * base.BitsPerPixel;
					double bits2 = (double)PixelStart(destX, destY + i, 0) * base.BitsPerPixel;
					double bits3 = base.BitsPerPixel * (double)width;
					bits = MathX.BitsToBytes(bits);
					bits2 = MathX.BitsToBytes(bits2);
					bits3 = MathX.BitsToBytes(bits3);
					source.RawData.Slice((int)bits, (int)bits3).CopyTo(base.RawData.Slice((int)bits2, (int)bits3));
				}
				return;
			}
			if (base.PreferColor32)
			{
				for (int j = 0; j < height; j++)
				{
					for (int k = 0; k < width; k++)
					{
						SetPixel32(destX + k, destY + j, source.GetPixel32(sourceX + k, sourceY + j));
					}
				}
				return;
			}
			for (int l = 0; l < height; l++)
			{
				for (int m = 0; m < width; m++)
				{
					SetPixel(destX + m, destY + l, source.GetPixel(sourceX + m, sourceY + l));
				}
			}
		}

		public Bitmap2D MakeSquare()
		{
			int num = MathX.MaxComponent(base.Size);
			return GetRescaled(num, num, false);
		}

		public void FindForegroundRegion(color backgroundColor, out int2 position, out int2 size)
		{
			FindForegroundRegion((Bitmap2D bitmap, int x, int y) => bitmap.GetPixel(x, y) != backgroundColor, out position, out size);
		}

		public void FindForegroundRegion(color32 backgroundColor, out int2 position, out int2 size)
		{
			FindForegroundRegion((Bitmap2D bitmap, int x, int y) => bitmap.GetPixel32(x, y) != backgroundColor, out position, out size);
		}

		public void FindForegroundRegion(Pixel2DPredicate isForeground, out int2 position, out int2 size)
		{
			int2 b = int2.MaxValue;
			int2 b2 = int2.MinValue;
			for (int i = 0; i < base.Size.y; i++)
			{
				for (int j = 0; j < base.Size.x; j++)
				{
					if (isForeground(this, j, i))
					{
						b = MathX.Min(new int2(j, i), in b);
						b2 = MathX.Max(new int2(j + 1, i + 1), in b2);
					}
				}
			}
			if (b.x > b2.x || b.y > b2.y)
			{
				position = int2.Zero;
				size = int2.Zero;
			}
			else
			{
				position = b;
				size = b2 - b;
			}
		}

		public Bitmap2D Trim(Pixel2DPredicate isForeground)
		{
			FindForegroundRegion(isForeground, out var position, out var size);
			return Crop(position, size);
		}

		public Bitmap2D Trim(color c)
		{
			FindForegroundRegion(c, out var position, out var size);
			return Crop(position, size);
		}

		public Bitmap2D Trim(color32 c)
		{
			FindForegroundRegion(c, out var position, out var size);
			return Crop(position, size);
		}

		public Bitmap2D TrimTransparent()
		{
			if (base.PreferColor32)
			{
				return Trim((Bitmap2D bmp, int x, int y) => bmp.GetPixel32(x, y).a > 0);
			}
			return Trim((Bitmap2D bmp, int x, int y) => bmp.GetPixel(x, y).a > 0f);
		}

		public Bitmap2D TrimByCornerColor()
		{
			if (base.PreferColor32)
			{
				List<color32> source = new List<color32>
				{
					GetPixel32(0, 0),
					GetPixel32(base.Size.x - 1, 0),
					GetPixel32(0, base.Size.y - 1),
					GetPixel32(base.Size.x - 1, base.Size.y - 1)
				};
				int num = 0;
				color32 c = default(color32);
				foreach (IGrouping<color32, color32> item in from result in source
					group result by result)
				{
					int num2 = item.Count();
					if (num2 > num)
					{
						num = num2;
						c = item.Key;
					}
				}
				return Trim(c);
			}
			List<color> source2 = new List<color>
			{
				GetPixel(0, 0),
				GetPixel(base.Size.x - 1, 0),
				GetPixel(0, base.Size.y - 1),
				GetPixel(base.Size.x - 1, base.Size.y - 1)
			};
			int num3 = 0;
			color c2 = default(color);
			foreach (IGrouping<color, color> item2 in from result in source2
				group result by result)
			{
				int num4 = item2.Count();
				if (num4 > num3)
				{
					num3 = num4;
					c2 = item2.Key;
				}
			}
			return Trim(c2);
		}

		public Bitmap2D Pad(int2 targetSize, bool? overrideMipmaps = null)
		{
			if (base.Size == targetSize)
			{
				return this;
			}
			Bitmap2D bitmap2D = new Bitmap2D(targetSize.x, targetSize.y, base.Format, overrideMipmaps ?? base.HasMipMaps, base.Profile, base.FlipY, base.OriginalFormat);
			bitmap2D.CopyFrom(this, 0, 0, 0, 0, base.Size.x, base.Size.y);
			for (int i = 0; i < targetSize.y; i++)
			{
				int num = ((i < base.Size.y) ? base.Size.x : 0);
				int y = MathX.Min(i, base.Size.y - 1);
				for (int j = num; j < targetSize.x; j++)
				{
					int x = MathX.Min(j, base.Size.x - 1);
					bitmap2D.SetPixel(j, i, this[x, y]);
				}
			}
			if (bitmap2D.HasMipMaps)
			{
				bitmap2D.GenerateMipmapsBox();
			}
			return bitmap2D;
		}

		public void AlphaBlend(Bitmap2D other)
		{
			CustomBlend(other, (color a, color b) => new color(MathX.LerpUnclamped(a.rgb, b.rgb, b.a), MathX.Clamp01(a.a + b.a)));
		}

		public void AdditiveBlend(Bitmap2D other)
		{
			CustomBlend(other, (color a, color b) => new color(a.rgb + b.rgb, a.a));
		}

		public void MultiplyBlend(Bitmap2D other)
		{
			CustomBlend(other, (color a, color b) => new color(a.rgb * b.rgb, a.a));
		}

		public void ApplyMask(Bitmap2D mask)
		{
			CustomBlend(mask, (color a, color b) => new color(a.rgb, b.r));
		}

		public void CustomBlend(Bitmap2D other, Func<color, color, color> blendFunction)
		{
			if (base.Size == other.Size)
			{
				Parallel.For(0, base.Size.y, delegate(int y)
				{
					for (int i = 0; i < base.Size.x; i++)
					{
						this[i, y] = blendFunction(this[i, y], other[i, y]);
					}
				});
				return;
			}
			Parallel.For(0, base.Size.y, delegate(int y)
			{
				for (int i = 0; i < base.Size.x; i++)
				{
					this[i, y] = blendFunction(this[i, y], other.SampleUV(PixelToUV(i, y)));
				}
			});
		}

		public void FlipHorizontal()
		{
			for (int mip = 0; mip < base.MipMapLevels; mip++)
			{
				int2 mipSize = MipMapSize(mip);
				Parallel.For(0, mipSize.y, delegate(int y)
				{
					for (int i = 0; i < mipSize.x / 2; i++)
					{
						int x = mipSize.x - 1 - i;
						color color = GetPixel(i, y, mip);
						SetPixel(i, y, GetPixel(x, y, mip), mip);
						SetPixel(x, y, in color, mip);
					}
				});
			}
		}

		public void FlipVertical()
		{
			for (int mip = 0; mip < base.MipMapLevels; mip++)
			{
				int2 mipSize = MipMapSize(mip);
				Parallel.For(0, mipSize.y / 2, delegate(int y)
				{
					for (int i = 0; i < mipSize.x; i++)
					{
						int y2 = mipSize.y - 1 - y;
						color color = GetPixel(i, y, mip);
						SetPixel(i, y, GetPixel(i, y2, mip), mip);
						SetPixel(i, y2, in color, mip);
					}
				});
			}
		}

		public void FlipYInMemory()
		{
			FlipVertical();
			base.FlipY = !base.FlipY;
		}

		public Bitmap2D Rotate90CW()
		{
			return RemapPositions(base.Size.yx, (int2 xy, int2 size) => new int2(xy.y, size.x - 1 - xy.x));
		}

		public Bitmap2D Rotate90CCW()
		{
			return RemapPositions(base.Size.yx, (int2 xy, int2 size) => new int2(size.y - 1 - xy.y, xy.x));
		}

		public Bitmap2D Rotate180()
		{
			return RemapPositions(base.Size.xy, (int2 xy, int2 size) => new int2(size.xy - 1 - xy));
		}

		public Bitmap2D RemapPositions(int2 newSize, Func<int2, int2, int2> remappingFunction)
		{
			Bitmap2D bitmap2D = new Bitmap2D(newSize.x, newSize.y, base.Format, base.HasMipMaps, base.Profile);
			for (int i = 0; i < bitmap2D.MipMapLevels; i++)
			{
				int2 arg = bitmap2D.MipMapSize(i);
				for (int j = 0; j < arg.y; j++)
				{
					for (int k = 0; k < arg.x; k++)
					{
						int2 @int = remappingFunction(new int2(k, j), arg);
						bitmap2D.SetPixel(k, j, GetPixel(@int.x, @int.y, i), i);
					}
				}
			}
			return bitmap2D;
		}

		public void ForEachPixel(Func<color, color> filter, IntRect rect, int miplevel = 0)
		{
			Parallel.For(rect.y, rect.y + rect.height, delegate(int y)
			{
				int num = rect.x + rect.width;
				for (int i = rect.x; i < num; i++)
				{
					SetPixel(i, y, filter(GetPixel(i, y, miplevel)), miplevel);
				}
			});
		}

		public Bitmap2D ForEachPixelCopy(Func<int2, color, color> filter, IBackingBufferAllocator allocator = null)
		{
			Bitmap2D copy = new Bitmap2D(base.Size.x, base.Size.y, base.Format, base.HasMipMaps, base.Profile, base.FlipY, base.OriginalFormat, allocator);
			Parallel.For(0, base.Size.y, delegate(int y)
			{
				for (int i = 0; i < base.Size.x; i++)
				{
					copy.SetPixel(i, y, filter(new int2(i, y), GetPixel(i, y)));
				}
			});
			return copy;
		}

		public void ForEachPixelUV(Func<float2, color> generator)
		{
			Parallel.For(0, base.Size.y, delegate(int y)
			{
				float y2 = (float)y / (float)(base.Size.y - 1);
				for (int i = 0; i < base.Size.x; i++)
				{
					float x = (float)i / (float)(base.Size.x - 1);
					SetPixel(i, y, generator(new float2(x, y2)));
				}
			});
		}

		public Bitmap2D GenerateTileableLoop(float2 transitionRatio)
		{
			int2 b = MathX.RoundToInt((float2)base.Size * transitionRatio);
			int2 @int = base.Size - b;
			if ((@int <= 0).Any())
			{
				return null;
			}
			Bitmap2D bitmap2D = new Bitmap2D(@int.x, @int.y, base.Format, base.HasMipMaps, base.Profile, base.FlipY);
			float2 @float = 1f / b;
			for (int i = 0; i < b.y; i++)
			{
				for (int j = 0; j < b.x; j++)
				{
					color b2 = MathX.LerpUnclamped(this[j + @int.x, i], this[j, i], (float)j * @float.x);
					bitmap2D[j, i] = MathX.LerpUnclamped(MathX.LerpUnclamped(this[j + @int.x, i + @int.y], this[j, i + @int.y], (float)j * @float.x), in b2, (float)i * @float.y);
				}
			}
			for (int k = b.y; k < @int.y; k++)
			{
				for (int l = 0; l < b.x; l++)
				{
					bitmap2D[l, k] = MathX.LerpUnclamped(this[l + @int.x, k], this[l, k], (float)l * @float.x);
				}
			}
			for (int m = 0; m < b.y; m++)
			{
				for (int n = b.x; n < @int.x; n++)
				{
					bitmap2D[n, m] = MathX.LerpUnclamped(this[n, m + @int.y], this[n, m], (float)m * @float.y);
				}
			}
			bitmap2D.CopyFrom(this, b.x, b.y, b.x, b.y, @int.x - b.x, @int.y - b.y);
			if (bitmap2D.HasMipMaps)
			{
				bitmap2D.GenerateMipmapsBox();
			}
			return bitmap2D;
		}

		public Bitmap2D GenerateTileableMirrored(float2 transitionRatio)
		{
			Bitmap2D bitmap2D = new Bitmap2D(base.Size.x, base.Size.y, base.Format, base.HasMipMaps, base.Profile, base.FlipY);
			float2 invTransition = 1f / transitionRatio;
			float2 transitionMin = transitionRatio;
			float2 transitionMax = 1f - transitionRatio;
			bitmap2D.ForEachPixelUV(delegate(float2 uv)
			{
				color a = SampleUV(in uv);
				if (uv.x < transitionMin.x)
				{
					a = MathX.Lerp(SampleUV(new float2(1f - uv.x, uv.y)), in a, uv.x * invTransition.x * 0.5f + 0.5f);
				}
				else if (uv.x > transitionMax.x)
				{
					a = MathX.Lerp(in a, SampleUV(new float2(transitionMin.x - (uv.x - transitionMax.x), uv.y)), (uv.x - transitionMax.x) * invTransition.x * 0.5f);
				}
				if (uv.y < transitionMin.y)
				{
					a = MathX.Lerp(SampleUV(new float2(uv.x, 1f - uv.y)), in a, uv.y * invTransition.y * 0.5f + 0.5f);
				}
				else if (uv.y > transitionMax.y)
				{
					a = MathX.Lerp(in a, SampleUV(new float2(uv.x, transitionMin.y - (uv.y - transitionMax.y))), (uv.y - transitionMax.y) * invTransition.y * 0.5f);
				}
				return a;
			});
			return bitmap2D;
		}

		public void BleedColorToAlpha()
		{
			RawValueList<int2> nextCoords = Pool.BorrowRawValueList<int2>();
			Bit2DArray alphaOverrides = new Bit2DArray(base.Size);
			Bit2DArray processed = new Bit2DArray(base.Size);
			for (int i = 0; i < base.Size.y; i++)
			{
				for (int j = 0; j < base.Size.x; j++)
				{
					ProcessPixel(j, i);
				}
			}
			MarkAlphaOverrides();
			while (nextCoords.Count > 0)
			{
				int count = nextCoords.Count;
				for (int k = 0; k < count; k++)
				{
					int2 @int = nextCoords[k];
					for (int l = -1; l <= 1; l++)
					{
						int num = @int.y + l;
						if (num < 0 || num >= base.Size.y)
						{
							continue;
						}
						for (int m = -1; m <= 1; m++)
						{
							int num2 = @int.x + m;
							if (num2 >= 0 && num2 < base.Size.x && !processed[num2, num])
							{
								ProcessPixel(num2, num);
							}
						}
					}
				}
				nextCoords.FastRemoveRange(0, count);
				MarkAlphaOverrides();
			}
			Pool.Return(ref nextCoords);
			void MarkAlphaOverrides()
			{
				for (int n = 0; n < nextCoords.Count; n++)
				{
					int2 int2 = nextCoords[n];
					alphaOverrides[int2.x, int2.y] = true;
				}
			}
			void ProcessPixel(int x, int y)
			{
				color pixel = GetPixel(x, y);
				if (MathX.Approximately(pixel.a, 0f))
				{
					color? color = AverageRGBFromVisibleSurroundings(x, y, alphaOverrides);
					if (color.HasValue)
					{
						SetPixel(x, y, new color(color.Value.rgb, pixel.a));
						processed[x, y] = true;
						nextCoords.Add(new int2(x, y));
					}
				}
			}
		}

		public color? AverageRGBFromVisibleSurroundings(int x, int y, Bit2DArray overrides = null)
		{
			int count = 0;
			float3 accumulated = float3.Zero;
			Accumulate(-1, -1);
			Accumulate(0, -1);
			Accumulate(1, -1);
			Accumulate(-1, 0);
			Accumulate(1, 0);
			Accumulate(-1, 1);
			Accumulate(0, 1);
			Accumulate(1, 1);
			if (count == 0)
			{
				return null;
			}
			if (count == 1)
			{
				return new color(in accumulated);
			}
			return new color(accumulated / count);
			void Accumulate(int xOff, int yOff)
			{
				int x2 = MathX.Repeat(x + xOff, base.Size.x - 1);
				int y2 = MathX.Repeat(y + yOff, base.Size.y - 1);
				color pixel = GetPixel(x2, y2);
				if (!MathX.Approximately(pixel.a, 0f) || (overrides != null && overrides[x2, y2]))
				{
					count++;
					accumulated += pixel.rgb;
				}
			}
		}

		public void LuminanceThreshold(float threshold)
		{
			LuminanceThreshold(threshold, color.White, color.Black);
		}

		public void LuminanceThreshold(float threshold, color above, color below)
		{
			ForEachPixel((color c) => (!(c.Luminance >= threshold)) ? below : above);
		}

		public void LocalizedLuminanceThreshold(float threshold, int range)
		{
			LocalizedLuminanceThreshold(threshold, range, color.White, color.Black);
		}

		public void LocalizedLuminanceThreshold(float threshold, int range, color above, color below)
		{
			ForEachPixelCopy(delegate(int2 xy, color c)
			{
				float num = 0f;
				for (int i = -range; i < range; i++)
				{
					for (int j = -range; j < range; j++)
					{
						num = MathX.Max(GetPixel(MathX.Clamp(xy.x + j, 0, base.Size.x), MathX.Clamp(xy.y + i, 0, base.Size.y)).Luminance, num);
					}
				}
				return (!(c.Luminance > num * threshold)) ? color.Black : color.White;
			}).RawData.CopyTo(base.RawData);
		}

		public static bool SupportsBlockCompression(TextureFormat targetFormat)
		{
			return BitmapBlockCompression.SupportsBlockCompression(targetFormat);
		}

		/// <summary>
		/// Block Compresses a BitMap2D.
		/// </summary>
		/// <param name="targetFormat">Format to compress to</param>
		/// <param name="quality">Expressed as 0-100(percent), from the asset variant system</param>
		/// <param name="maxThreads">The maximum number of threads to use for this operation</param>
		/// <returns>Block Compressed BitMap</returns>
		/// <exception cref="T:System.Exception"></exception>
		public Bitmap2D BlockCompress(TextureFormat targetFormat, int quality = 100, int maxThreads = 0)
		{
			if (!base.FlipY)
			{
				throw new Exception("Texture needs to be flipped upside down to be block compressed");
			}
			if (!targetFormat.IsBlockCompressed())
			{
				throw new Exception("Target format isn't block compressed: " + targetFormat);
			}
			TextureFormat sourceFormat = base.Format;
			if (BitmapBlockCompression.NeedsToConvertForBlockCompression(ref sourceFormat, targetFormat))
			{
				return ConvertTo(sourceFormat).BlockCompress(targetFormat, quality, maxThreads);
			}
			Bitmap2D bitmap2D = new Bitmap2D(base.Size.x, base.Size.y, targetFormat, base.HasMipMaps, base.Profile, base.FlipY);
			List<MipMapBuffer> list = new List<MipMapBuffer>();
			GetMipMapBuffers(list);
			List<MipMapBuffer> list2 = new List<MipMapBuffer>();
			bitmap2D.GetMipMapBuffers(list2);
			BitmapBlockCompression.BlockCompress(list, list2, base.Format, targetFormat, quality, maxThreads);
			return bitmap2D;
		}

		public bool CrunchCompress(string file, TextureCompression inputCompression, int maxThreads = -1)
		{
			TextureFormat textureFormat = inputCompression.ToFormat();
			if (!base.FlipY)
			{
				throw new Exception("Texture needs to be flipped upside down to be crunch compressed");
			}
			if (base.Format != TextureFormat.RGBA32)
			{
				return ConvertTo(TextureFormat.RGBA32).CrunchCompress(file, inputCompression, maxThreads);
			}
			crn_comp_params crn_comp_params = new crn_comp_params();
			crn_comp_params.width = (uint)base.Size.x;
			crn_comp_params.height = (uint)base.Size.y;
			crn_comp_params.levels = (uint)base.MipMapLevels;
			crn_comp_params.faces = 1u;
			if (inputCompression.IsNormalMap())
			{
				crn_comp_params.flags = crn_comp_flags.UseBothBlockTypes;
			}
			if (!inputCompression.IsPerceptual())
			{
				crn_comp_params.flags &= crn_comp_flags.Perceptual;
			}
			switch (textureFormat)
			{
			case TextureFormat.BC1:
				crn_comp_params.format = crn_format.DXT1;
				break;
			case TextureFormat.BC3:
				crn_comp_params.format = crn_format.DXT5;
				break;
			case TextureFormat.ETC2_RGB:
				crn_comp_params.format = crn_format.ETC2;
				break;
			case TextureFormat.ETC2_RGBA8:
				crn_comp_params.format = crn_format.ETC2A;
				break;
			default:
				throw new Exception("Invalid Target Block Compression Format: " + textureFormat);
			}
			List<Memory<byte>> list = new List<Memory<byte>>();
			GetMipMapBuffers(list);
			byte[] array = Crunch.Compress(new List<List<Memory<byte>>> { list }, crn_comp_params, null, maxThreads);
			if (array != null && array.Length != 0)
			{
				File.WriteAllBytes(file, array);
				return true;
			}
			return false;
		}

		public static Bitmap2D LoadCRN(string file, IBackingBufferAllocator allocator = null)
		{
			using FileStream stream = File.OpenRead(file);
			return LoadCRN(stream, allocator);
		}

		public static Bitmap2D LoadCRN(Stream stream, IBackingBufferAllocator allocator = null)
		{
			Bitmap2D bitmap = null;
			byte[] array = new byte[stream.Length];
			stream.ReadExactly(array, 0, array.Length);
			List<List<Memory<byte>>> buffers = new List<List<Memory<byte>>>();
			if (!Crunch.Decompress(array, buffers, out var _, delegate(crn_texture_info crn_texture_info)
			{
				TextureFormat format;
				switch (crn_texture_info.format)
				{
				case crn_format.DXT1:
					format = TextureFormat.BC1;
					break;
				case crn_format.DXT5:
				case crn_format.DXT5_CCxY:
				case crn_format.DXT5_xGxR:
				case crn_format.DXT5_xGBR:
				case crn_format.DXT5_AGBR:
				case crn_format.DXT5A:
					format = TextureFormat.BC3;
					break;
				case crn_format.ETC2:
					format = TextureFormat.ETC2_RGB;
					break;
				case crn_format.ETC2A:
				case crn_format.ETC2AS:
					format = TextureFormat.ETC2_RGBA8;
					break;
				default:
					throw new Exception("Unsupported CRN format: " + crn_texture_info.format);
				}
				bitmap = new Bitmap2D((int)crn_texture_info.width, (int)crn_texture_info.height, format, crn_texture_info.levels > 1, ColorProfile.sRGB, flipY: true, null, allocator);
				buffers.Add(new List<Memory<byte>>());
				bitmap.GetMipMapBuffers(buffers[0]);
			}))
			{
				return null;
			}
			return bitmap;
		}

		public void DrawPixelSquare(IntRect rect, color color, bool dotted = false)
		{
			for (int i = 0; i < rect.width; i++)
			{
				if (!dotted || (i & 1) != 1)
				{
					SetPixel(rect.x + i, rect.y, in color);
					SetPixel(rect.x + i, rect.y + rect.height - 1, in color);
				}
			}
			for (int j = 0; j < rect.height; j++)
			{
				if (!dotted || (j & 1) != 1)
				{
					SetPixel(rect.x, rect.y + j, in color);
					SetPixel(rect.x + rect.width - 1, rect.y + j, in color);
				}
			}
		}
	}
	public abstract class Bitmap2DBase : Bitmap
	{
		private int2 _size;

		private float2 _pixelToUV;

		private float2 _uvToPixel;

		protected List<int2> mipmapSizes;

		public int2 Size
		{
			get
			{
				return _size;
			}
			protected set
			{
				_size = value;
				_uvToPixel = _size - 1;
				_pixelToUV = 1f / _uvToPixel;
			}
		}

		public int2 AlignedSize { get; protected set; }

		public bool FlipY { get; protected set; }

		public float2 PixelToUVRatio => _pixelToUV;

		public float2 UVToPixelRatio => _uvToPixel;

		protected void InitSize(int2 size, bool flipY, TextureFormat format)
		{
			Size = size;
			AlignedSize = AlignSize(Size, format);
			FlipY = flipY;
		}

		public int PixelStart(int x, int y, int mip)
		{
			if (mip == 0)
			{
				if (FlipY)
				{
					y = AlignedSize.y - y - 1;
				}
				return x + y * AlignedSize.x;
			}
			int2 @int = mipmapSizes[mip];
			int num = mipmapOrigins[mip];
			if (FlipY)
			{
				y = @int.y - y - 1;
			}
			return num + (x + y * @int.x);
		}

		public int MipmapByteOrigin(int mip)
		{
			return (int)MathX.BitsToBytes((double)MipmapOrigin(mip) * base.BitsPerPixel);
		}

		public int MipmapTotalBytes(int mip)
		{
			return (int)MathX.BitsToBytes((double)MipmapTotalPixels(mip) * base.BitsPerPixel);
		}

		public override int MipmapOrigin(int mip)
		{
			if (mip != 0)
			{
				return mipmapOrigins[mip];
			}
			return 0;
		}

		protected void GetMipMapBuffers(List<Memory<byte>> mipBuffers, int offset)
		{
			for (int i = 0; i < base.MipMapLevels; i++)
			{
				int start = offset + MipmapByteOrigin(i);
				int length = MipmapTotalBytes(i);
				MipMapSize(i);
				Memory<byte> item = base.Buffer.Memory.Slice(start, length);
				mipBuffers.Add(item);
			}
		}

		protected void GetMipMapBuffers(List<MipMapBuffer> mipBuffers, int offset, int face)
		{
			for (int i = 0; i < base.MipMapLevels; i++)
			{
				int start = offset + MipmapByteOrigin(i);
				int length = MipmapTotalBytes(i);
				int2 size = MipMapSize(i);
				Memory<byte> buffer = base.Buffer.Memory.Slice(start, length);
				mipBuffers.Add(new MipMapBuffer(size, face, buffer));
			}
		}

		protected override int InitMipmapLevels()
		{
			mipmapSizes = new List<int2>();
			MipmapLevels(Size, mipmapSizes);
			return mipmapSizes.Count;
		}

		public override int MipmapTotalPixels(int mip)
		{
			int2 @int = AlignSize((mip == 0) ? Size : mipmapSizes[mip], base.Format);
			return @int.x * @int.y;
		}

		public int2 MipMapSize(int mip)
		{
			if (mip != 0)
			{
				return mipmapSizes[mip];
			}
			return AlignedSize;
		}

		public static bool IsSizeAligned(in int2 size, TextureFormat format)
		{
			RenderVector2i renderVector2i = format.BlockSize();
			if (size.x % renderVector2i.x != 0 || size.y % renderVector2i.y != 0)
			{
				return false;
			}
			return true;
		}

		public static int2 AlignSize(in int2 size, TextureFormat format)
		{
			RenderVector2i v = format.BlockSize();
			return size + ((int2)v - size % (int2)v) % (int2)v;
		}

		public static int MipmapLevelCount(int2 size)
		{
			int num = 1;
			while (size.x > 1 || size.y > 1)
			{
				num++;
				size /= 2;
			}
			return num;
		}

		public static int MipmapLevels(in int2 size, List<int2> sizes)
		{
			if (size.x > 1 || size.y > 1)
			{
				int num = size.x * size.y;
				sizes?.Add(size);
				return num + MipmapLevels(MathX.Max(size / 2, 1), sizes);
			}
			sizes?.Add(int2.One);
			return 1;
		}
	}
	public enum RawBitmapEncoding
	{
		Uncompressed,
		LZMA
	}
	public delegate bool Pixel2DPredicate(Bitmap2D bitmap, int x, int y);
	internal enum LegacyTextureFormat
	{
		Unknown,
		RGB24,
		ARGB32,
		RGBA32,
		BGRA32,
		RGBAHalf,
		RGBAFloat
	}
	internal static class LegacyHelper
	{
		public static TextureFormat ConvertLegacyFormat(this LegacyTextureFormat format)
		{
			return format switch
			{
				LegacyTextureFormat.ARGB32 => TextureFormat.ARGB32, 
				LegacyTextureFormat.BGRA32 => TextureFormat.BGRA32, 
				LegacyTextureFormat.RGB24 => TextureFormat.RGB24, 
				LegacyTextureFormat.RGBA32 => TextureFormat.RGBA32, 
				LegacyTextureFormat.RGBAFloat => TextureFormat.RGBAFloat, 
				LegacyTextureFormat.RGBAHalf => TextureFormat.RGBAHalf, 
				LegacyTextureFormat.Unknown => TextureFormat.Unknown, 
				_ => throw new Exception("Invalid LegacyTextureFormat: " + format), 
			};
		}
	}
	public class Bitmap3D : Bitmap, IBitmap<Bitmap3D>, IBitmap
	{
		public enum Encoding
		{
			Raw,
			Quantized8Bit
		}

		public const int BITMAP3D_BINARY_VERSION = 2;

		public const string MAGIC_STRING = "Bmp3D";

		private List<int3> mipmapSizes;

		public int3 Size { get; private set; }

		public color this[int3 pos]
		{
			get
			{
				return GetPixel(pos.x, pos.y, pos.z);
			}
			set
			{
				SetPixel(pos.x, pos.y, pos.z, in value);
			}
		}

		public color this[int x, int y, int z]
		{
			get
			{
				return GetPixel(x, y, z);
			}
			set
			{
				SetPixel(x, y, z, in value);
			}
		}

		public Bitmap3D(int width, int height, int depth, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null, IBackingBufferAllocator allocator = null)
		{
			Size = new int3(width, height, depth);
			Init(null, format, mipmaps, originalFormat, profile, allocator);
		}

		public Bitmap3D(byte[] data, int width, int height, int depth, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null)
			: this(new ArrayBackingMemoryBuffer(data), width, height, depth, format, mipmaps, profile, originalFormat)
		{
		}

		public Bitmap3D(IBackingMemoryBuffer buffer, int width, int height, int depth, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null)
		{
			Size = new int3(width, height, depth);
			Init(buffer, format, mipmaps, originalFormat, profile, null);
		}

		public color GetPixel(int x, int y, int z, int mip = 0)
		{
			int index = PixelStart(x, y, z, mip);
			return DecodePixel(index);
		}

		public color GetPixel32(int x, int y, int z, int mip = 0)
		{
			int index = PixelStart(x, y, z, mip);
			return DecodePixel32(index);
		}

		public void SetPixel(int x, int y, int z, in color color, int mip = 0)
		{
			int index = PixelStart(x, y, z, mip);
			EncodePixel(index, in color);
		}

		public color SampleUVW(in float3 uvw)
		{
			return GetPixelBilinear(uvw * (float3)(Size - 1));
		}

		public color GetPixelBilinear(float x, float y, float z)
		{
			return GetPixelBilinear(new float3(x, y, z));
		}

		public color GetPixelBilinear(in float3 position)
		{
			int3 v = MathX.Clamp(MathX.FloorToInt(in position), int3.Zero, Size - int3.One);
			float3 @float = position - (float3)v;
			return MathX.LerpUnclamped(SampleBilinearLayer(in v, @float.xy), SampleBilinearLayer(v + int3.One.__z, @float.xy), @float.z);
		}

		private color SampleBilinearLayer(in int3 pos, in float2 ratio)
		{
			return MathX.LerpUnclamped(MathX.LerpUnclamped(this[pos], this[pos + int3.One.x__], ratio.x), MathX.LerpUnclamped(this[pos], this[pos + int3.One.xy_], ratio.x), ratio.y);
		}

		protected override int InitMipmapLevels()
		{
			mipmapSizes = new List<int3>();
			MipmapLevels(Size, mipmapSizes);
			return mipmapSizes.Count;
		}

		public override int MipmapTotalPixels(int mip)
		{
			int3 @int = MipMapSize(mip);
			return @int.x * @int.y * @int.z;
		}

		public override int MipmapOrigin(int mip)
		{
			if (mip != 0)
			{
				return mipmapOrigins[mip];
			}
			return 0;
		}

		public int3 MipMapSize(int mip)
		{
			if (mip != 0)
			{
				return mipmapSizes[mip];
			}
			return Size;
		}

		private int PixelStart(int x, int y, int z, int mip)
		{
			if (mip == 0)
			{
				return x + y * Size.x + z * Size.x * Size.y;
			}
			int3 @int = mipmapSizes[mip];
			return mipmapOrigins[mip] + x + y * @int.x + z * @int.x * @int.y;
		}

		public static int MipmapLevels(in int3 size, List<int3> sizes)
		{
			if (size.x > 1 || size.y > 1 || size.z > 1)
			{
				int num = size.x * size.y * size.z;
				sizes?.Add(size);
				return num + MipmapLevels(MathX.Max(size / 2, 1), sizes);
			}
			sizes?.Add(int3.One);
			return 1;
		}

		public static int3 AlignSize(in int3 size, TextureFormat format)
		{
			RenderVector3i v = format.BlockSize3D();
			return size + ((int3)v - size % (int3)v) % (int3)v;
		}

		public Bitmap3D ConvertToAndDispose(TextureFormat format, IBackingBufferAllocator allocator)
		{
			Bitmap3D result = ConvertTo(format, allocator);
			base.Buffer.Dispose();
			return result;
		}

		public Bitmap3D ConvertTo(TextureFormat format, IBackingBufferAllocator allocator = null)
		{
			Bitmap3D bitmap3D = new Bitmap3D(Size.x, Size.y, Size.z, format, base.HasMipMaps, base.Profile, base.OriginalFormat, allocator);
			bitmap3D.FillFrom(this);
			return bitmap3D;
		}

		public void ForEachPixelUVW(Func<float3, color> filter)
		{
			for (int z = 0; z < Size.z; z++)
			{
				float w = (float)z / (float)(Size.z - 1);
				Parallel.For(0, Size.y, delegate(int y)
				{
					float y2 = (float)y / (float)(Size.y - 1);
					for (int i = 0; i < Size.x; i++)
					{
						float x = (float)i / (float)(Size.x - 1);
						SetPixel(i, y, z, filter(new float3(x, y2, w)));
					}
				});
			}
		}

		public void Encode(Stream stream)
		{
			BinaryWriter binaryWriter = new BinaryWriter(stream);
			binaryWriter.Write("Bmp3D");
			binaryWriter.Write(2);
			binaryWriter.Write(Size);
			binaryWriter.WriteEnumString(base.Format);
			binaryWriter.Write(base.HasMipMaps);
			binaryWriter.WriteEnumString(base.Profile);
			using Stream inStream = base.Buffer.Memory.AsStream();
			LZMAHelper.Compress(inStream, stream);
		}

		private static Bitmap3D Decode(Stream stream, IBackingBufferAllocator allocator = null)
		{
			BinaryReader binaryReader = new BinaryReader(stream);
			if (binaryReader.ReadString() != "Bmp3D")
			{
				throw new Exception("Bitmap3D magic string not found at the beginning of the stream!");
			}
			int num = binaryReader.ReadInt32();
			if (num > 2)
			{
				throw new Exception("Invalid Bitmap3D binary version: " + num);
			}
			int3 @int = binaryReader.Read3D_Int32();
			TextureFormat format = ((num != 0) ? binaryReader.ReadEnumString<TextureFormat>() : binaryReader.ReadEnumBinary<LegacyTextureFormat>().ConvertLegacyFormat());
			bool mipmaps = binaryReader.ReadBoolean();
			ColorProfile profile = ColorProfile.sRGBAlpha;
			if (num > 1)
			{
				profile = binaryReader.ReadEnumString<ColorProfile>();
			}
			Bitmap3D bitmap3D = new Bitmap3D(@int.x, @int.y, @int.z, format, mipmaps, profile, null, allocator);
			using Stream outStream = bitmap3D.Buffer.Memory.AsStream();
			LZMAHelper.Decompress(stream, outStream);
			return bitmap3D;
		}

		public void Save(string file)
		{
			using FileStream stream = File.OpenWrite(file);
			Encode(stream);
		}

		public static Bitmap3D Load(string file, IBackingBufferAllocator allocator = null)
		{
			using FileStream stream = File.OpenRead(file);
			return Decode(stream, allocator);
		}

		public static Bitmap3D LoadFromCUBE(string file, IBackingBufferAllocator allocator = null)
		{
			using CUBE_Reader cUBE_Reader = new CUBE_Reader(file);
			if (cUBE_Reader.Dimensions != 3)
			{
				throw new InvalidOperationException("Only 3D LUT's are supported");
			}
			Bitmap3D bitmap3D = new Bitmap3D(cUBE_Reader.Size, cUBE_Reader.Size, cUBE_Reader.Size, TextureFormat.RGBAHalf, mipmaps: false, ColorProfile.sRGB, null, allocator);
			while (!cUBE_Reader.ReadAllValues)
			{
				int x = cUBE_Reader.X;
				int y = cUBE_Reader.Y;
				int z = cUBE_Reader.Z;
				cUBE_Reader.ReadColor(out var r, out var g, out var b);
				bitmap3D.SetPixel(x, y, z, new color(r, g, b));
			}
			return bitmap3D;
		}

		public void SaveToCUBE(string file, string title = null)
		{
			if (Size.x != Size.y || Size.y != Size.z)
			{
				throw new InvalidOperationException("Bitmap3D Size must be uniform to be exported as CUBE");
			}
			using CUBE_Writer cUBE_Writer = new CUBE_Writer(file);
			cUBE_Writer.Dimensions = 3;
			cUBE_Writer.Size = Size.x;
			cUBE_Writer.Title = title;
			cUBE_Writer.WriteHeader();
			while (cUBE_Writer.NeedsMoreValues)
			{
				color pixel = GetPixel(cUBE_Writer.X, cUBE_Writer.Y, cUBE_Writer.Z);
				cUBE_Writer.WriteColor(pixel.r, pixel.g, pixel.b);
			}
		}

		public override string ToString()
		{
			return $"Bitmap3D Size: {Size}, Format: {base.Format} ({base.Profile}), Mips: {base.HasMipMaps}";
		}

		public static Bitmap3D CreateFromSlices(List<string> paths, TextureFormat format, TextureSize sizehandling)
		{
			return CreateFromSlices(new SliceAccessor(paths), format, sizehandling);
		}

		public static Bitmap3D CreateFromSlices(List<Bitmap2D> slices, TextureFormat format, TextureSize sizehandling)
		{
			return CreateFromSlices(new SliceAccessor(slices), format, sizehandling);
		}

		private static Bitmap3D CreateFromSlices(SliceAccessor slices, TextureFormat format, TextureSize sizeHandling)
		{
			int3 v = new int3(slices.GetSlice(0).Size, slices.Count);
			if (sizeHandling != TextureSize.NPOT)
			{
				float3 v2 = MathX.Log((float3)v, 2f);
				switch (sizeHandling)
				{
				case TextureSize.HighestPOT:
					v2 = MathX.Ceil(in v2);
					break;
				case TextureSize.LowestPOT:
					v2 = MathX.Floor(in v2);
					break;
				case TextureSize.NearestPOT:
					v2 = MathX.Round(v2 + float3.One * 0.0849625f);
					break;
				}
				v = MathX.RoundToInt(MathX.Pow(float3.One * 2, in v2));
			}
			Bitmap3D bitmap3D = new Bitmap3D(v.x, v.y, v.z, format, mipmaps: false, slices.GetSlice(0).Profile);
			bitmap3D.FillFromSlices(slices, sizeHandling != TextureSize.NPOT);
			return bitmap3D;
		}

		public void FillFromSlices(List<Bitmap2D> slices, bool scale)
		{
			FillFromSlices(new SliceAccessor(slices), scale);
		}

		public void FillFromSlices(List<string> paths, bool scale)
		{
			FillFromSlices(new SliceAccessor(paths), scale);
		}

		private void FillFromSlices(SliceAccessor slices, bool scale)
		{
			if (scale)
			{
				int z;
				for (z = 0; z < Size.z; z++)
				{
					Parallel.For(0, Size.y, delegate(int y)
					{
						for (int i = 0; i < Size.x; i++)
						{
							float3 uvw = new float3(i, y, z) / (float3)Size;
							color color = SampleSlices(slices, uvw);
							if (base.Format == TextureFormat.Alpha8)
							{
								color = new color(0f, 0f, 0f, MathX.AvgComponent(color.rgb));
							}
							SetPixel(i, y, z, in color);
						}
					});
				}
				return;
			}
			if (slices.Count > Size.z)
			{
				throw new Exception($"Too many slices! 3D Tex Size: {Size}, slices: {slices.Count}");
			}
			for (int z2 = 0; z2 < slices.Count; z2++)
			{
				Bitmap2D slice = slices.GetSlice(z2);
				if (slice.Size.x > Size.x || slice.Size.y > Size.y)
				{
					throw new Exception($"Slice {z2} is too big! Slice size: {slice.Size}, 3D Tex Size: {Size}");
				}
				Parallel.For(0, slice.Size.y, delegate(int y)
				{
					for (int i = 0; i < slice.Size.x; i++)
					{
						color color = slice.GetPixel(i, y);
						if (base.Format == TextureFormat.Alpha8)
						{
							color = new color(0f, 0f, 0f, MathX.AvgComponent(color.rgb));
						}
						SetPixel(i, y, z2, in color);
					}
				});
			}
		}

		private static color SampleSlices(SliceAccessor slices, float3 uvw)
		{
			int num = (int)(uvw.z * (float)(slices.Count - 1));
			int num2 = num + 1;
			float lerp = num2 - num;
			return MathX.Lerp(slices.GetSlice(num).SampleUV(uvw.xy), slices.GetSlice(num2).SampleUV(uvw.xy), lerp);
		}
	}
	public readonly struct MipMapBuffer
	{
		public readonly int2 size;

		public readonly int face;

		public readonly Memory<byte> buffer;

		public MipMapBuffer(int2 size, int face, Memory<byte> buffer)
		{
			this.size = size;
			this.face = face;
			this.buffer = buffer;
		}
	}
	public static class BitmapBlockCompression
	{
		public const float MINIMUM_COMPRESSONATOR_COMPRESSION_QUALITY = 0f;

		public const float MAXIMUM_COMPRESSONATOR_COMPRESSION_QUALITY = 1f;

		/// <summary>
		/// <see href="https://github.com/Yellow-Dog-Man/compressonator/blob/master/cmp_compressonatorlib/compressonator.h#L426">
		///     Compressonator recommends a quality of 0.05f for BC6H and BC7.
		///     However, the first step of Error Correction kicks in at 0.25f.
		///     We've seen some artifacts/errors on 0.05, so our minimum is now 25.
		/// </see> This is Expressed as a percentage (0-100) so 5.
		/// </summary>
		public const int DEFAULT_BC67_COMPRESSION_QUALITY = 25;

		/// <summary>
		/// For other block compression formats, compressonator defaults to max quality. Expressed as a percentage (0-100)
		/// </summary>
		public const int DEFAULT_BLOCK_COMPRESSION_QUALITY = 100;

		/// <summary>
		/// Compressonator uses 0, to mean "automatic".
		/// Automatic will cause compressonator to calculate a thread value itself.
		/// </summary>
		public const int AUTOMATIC_THREAD_COUNT_IDENTIFIER = 0;

		/// <summary>
		/// The Division factor applied to max thread counts for expensive compressonator operations
		/// </summary>
		public const int COMPRESSONATOR_THREAD_DIVISOR = 2;

		public static bool SupportsBlockCompression(TextureFormat targetFormat)
		{
			return SDK_NativeMethods.CMP_IsValidFormat(ToCompressonator(targetFormat));
		}

		public static bool NeedsToConvertForBlockCompression(ref TextureFormat sourceFormat, TextureFormat targetFormat)
		{
			if (targetFormat.IsHDR())
			{
				if (sourceFormat != TextureFormat.RGBAHalf)
				{
					sourceFormat = TextureFormat.RGBAHalf;
					return true;
				}
			}
			else if (sourceFormat != TextureFormat.RGBA32)
			{
				sourceFormat = TextureFormat.RGBA32;
				return true;
			}
			return false;
		}

		public unsafe static void BlockCompress(List<MipMapBuffer> sourceBuffers, List<MipMapBuffer> targetBuffers, TextureFormat sourceFormat, TextureFormat targetFormat, int quality = 100, int maxThreads = 0)
		{
			if (ToCompressonator(targetFormat) == CMP_FORMAT.Unknown)
			{
				throw new ArgumentException("Unsupported target CMP format: " + targetFormat);
			}
			CMP_CompressOptions cMP_CompressOptions = new CMP_CompressOptions();
			cMP_CompressOptions.quality = AdjustQualityForCompressonator(quality);
			cMP_CompressOptions.numThreads = (uint)CalculateMaxThreads(maxThreads, targetFormat);
			double bitsPerPixel = sourceFormat.GetBitsPerPixel();
			for (int i = 0; i < sourceBuffers.Count; i++)
			{
				int2 size = sourceBuffers[i].size;
				Memory<byte> buffer = sourceBuffers[i].buffer;
				Memory<byte> buffer2 = targetBuffers[i].buffer;
				using CMP_Texture cMP_Texture = new CMP_Texture();
				cMP_Texture.width = (uint)size.x;
				cMP_Texture.height = (uint)size.y;
				cMP_Texture.pitch = (uint)MathX.BitsToBytes((double)size.x * bitsPerPixel);
				cMP_Texture.format = ToCompressonator(sourceFormat);
				cMP_Texture.CalculateDataSize();
				using CMP_Texture cMP_Texture2 = new CMP_Texture();
				cMP_Texture2.width = cMP_Texture.width;
				cMP_Texture2.height = cMP_Texture.height;
				cMP_Texture2.pitch = cMP_Texture.pitch;
				cMP_Texture2.format = ToCompressonator(targetFormat);
				if (cMP_Texture2.format == CMP_FORMAT.ASTC)
				{
					RenderVector2i renderVector2i = targetFormat.BlockSize();
					cMP_Texture2.blockWidth = (byte)renderVector2i.x;
					cMP_Texture2.blockHeight = (byte)renderVector2i.y;
					cMP_Texture2.blockDepth = 1;
				}
				cMP_Texture2.CalculateDataSize();
				fixed (byte* ptr = buffer.Span)
				{
					void* value = ptr;
					fixed (byte* ptr2 = buffer2.Span)
					{
						void* value2 = ptr2;
						nint data = cMP_Texture.data;
						nint data2 = cMP_Texture2.data;
						cMP_Texture.data = new IntPtr(value);
						cMP_Texture2.data = new IntPtr(value2);
						CMP_ERROR cMP_ERROR = SDK_NativeMethods.CMP_ConvertTexture(cMP_Texture, cMP_Texture2, cMP_CompressOptions);
						cMP_Texture.data = data;
						cMP_Texture2.data = data2;
						if (cMP_ERROR != CMP_ERROR.CMP_OK)
						{
							throw new Exception("Conversion error: " + cMP_ERROR);
						}
					}
				}
			}
		}

		private static CMP_FORMAT ToCompressonator(TextureFormat format)
		{
			return format switch
			{
				TextureFormat.RGB24 => CMP_FORMAT.RGB_888, 
				TextureFormat.RGBA32 => CMP_FORMAT.RGBA_8888, 
				TextureFormat.ARGB32 => CMP_FORMAT.ARGB_8888, 
				TextureFormat.BGRA32 => CMP_FORMAT.BGRA_8888, 
				TextureFormat.RGBAHalf => CMP_FORMAT.ARGB_16F, 
				TextureFormat.ARGBHalf => CMP_FORMAT.ARGB_16F, 
				TextureFormat.RGBAFloat => CMP_FORMAT.ARGB_32F, 
				TextureFormat.ARGBFloat => CMP_FORMAT.ARGB_32F, 
				TextureFormat.BC1 => CMP_FORMAT.BC1, 
				TextureFormat.BC2 => CMP_FORMAT.BC2, 
				TextureFormat.BC3 => CMP_FORMAT.BC3, 
				TextureFormat.BC4 => CMP_FORMAT.BC4, 
				TextureFormat.BC5 => CMP_FORMAT.BC5, 
				TextureFormat.BC6H => CMP_FORMAT.BC6H, 
				TextureFormat.BC7 => CMP_FORMAT.BC7, 
				TextureFormat.ETC2_RGB => CMP_FORMAT.ETC2_RGB, 
				TextureFormat.ETC2_RGBA1 => CMP_FORMAT.ETC2_RGBA1, 
				TextureFormat.ETC2_RGBA8 => CMP_FORMAT.ETC2_RGBA, 
				TextureFormat.ASTC_4x4 => CMP_FORMAT.ASTC, 
				TextureFormat.ASTC_5x5 => CMP_FORMAT.ASTC, 
				TextureFormat.ASTC_6x6 => CMP_FORMAT.ASTC, 
				TextureFormat.ASTC_8x8 => CMP_FORMAT.ASTC, 
				TextureFormat.ASTC_10x10 => CMP_FORMAT.ASTC, 
				TextureFormat.ASTC_12x12 => CMP_FORMAT.ASTC, 
				_ => CMP_FORMAT.Unknown, 
			};
		}

		/// <summary>
		/// Given an int based percentage for quality, convert it to a float suitable for compressonator.
		/// </summary>
		/// <param name="quality">quality, expressed as a percentage 0-100.</param>
		/// <returns>Quality value suitable for compressonator 0 - 1.0 <see langword="float" /></returns>
		public static float AdjustQualityForCompressonator(int quality)
		{
			if (quality > 100 || quality < 0)
			{
				throw new ArgumentException("Quality must be between 0 and 100", "quality");
			}
			return MathX.Clamp((float)quality * 0.01f, 0f, 1f);
		}

		/// <summary>
		/// Given a compression option, return the recommended quality. 
		/// </summary>
		/// <remarks>
		/// The recommended quality is usually <see cref="F:Elements.Assets.BitmapBlockCompression.DEFAULT_BLOCK_COMPRESSION_QUALITY" /> right now.
		/// However, should this change in the future, this method allows us to do it in a way that makes change control and documentation easier.
		/// </remarks>
		/// <param name="format">target compression format</param>
		/// <returns>Recommened quality for this compression format.</returns>
		public static int GetRecommendedBlockCompressionQuality(this TextureFormat format)
		{
			if (format == TextureFormat.BC7 || format == TextureFormat.BC6H)
			{
				return 25;
			}
			return 100;
		}

		/// <summary>
		/// Given a regular maxThreads settings, calculate an appropriate adjustment for expensive compressonator operations.
		/// </summary>
		/// <param name="maxThreads">Incoming maxThreads from an asset generator</param>
		/// <param name="format">Target texture format</param>
		/// <returns>Appropriate max threads value for this operation.</returns>
		public static int CalculateMaxThreads(int maxThreads, TextureFormat format)
		{
			if (maxThreads == 0 || maxThreads < 0)
			{
				return 0;
			}
			if (format.IsExpensiveToCompute())
			{
				return MathX.Clamp(maxThreads / 2, 1, maxThreads);
			}
			return maxThreads;
		}
	}
	public class BitmapCube : Bitmap2DBase
	{
		public enum Face
		{
			PosX,
			NegX,
			PosY,
			NegY,
			PosZ,
			NegZ
		}

		public const int CUBEMAP_BINARY_VERSION = 3;

		public const string MAGIC_STRING = "BmpCube";

		public override int ElementCount => 6;

		public color this[int x, int y, Face face]
		{
			get
			{
				return GetPixel(x, y, face);
			}
			set
			{
				SetPixel(x, y, face, value);
			}
		}

		public color this[int2 point, Face face] => this[point.x, point.y, face];

		public BitmapCube(byte[] data, int width, int height, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null)
			: this(new ArrayBackingMemoryBuffer(data), width, height, format, mipmaps, profile, originalFormat)
		{
		}

		public BitmapCube(IBackingMemoryBuffer buffer, int width, int height, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null)
		{
			InitSize(new int2(width, height), flipY: false, format);
			Init(buffer, format, mipmaps, originalFormat, profile, null);
		}

		public BitmapCube(int width, int height, TextureFormat format, bool mipmaps, ColorProfile profile, string originalFormat = null, IBackingBufferAllocator allocator = null)
		{
			InitSize(new int2(width, height), flipY: false, format);
			Init(null, format, mipmaps, originalFormat, profile, allocator);
		}

		public BitmapCube(Bitmap2D posX, Bitmap2D negX, Bitmap2D posY, Bitmap2D negY, Bitmap2D posZ, Bitmap2D negZ, IBackingBufferAllocator allocator = null)
		{
			InitSize(int2.One * posX.Size, flipY: true, posX.Format);
			bool hasMipMaps = posX.HasMipMaps;
			ColorProfile profile = posX.Profile;
			if (negX.Profile != profile || posY.Profile != profile || negY.Profile != profile || posZ.Profile != profile || negZ.Profile != profile)
			{
				throw new Exception("The supplied Bitmap2D's do not share the same color profile");
			}
			if (posY.Size != base.Size || posZ.Size != base.Size || negX.Size != base.Size || negY.Size != base.Size || negZ.Size != base.Size)
			{
				throw new Exception("The supplied Bitmap2D's aren't all the same size");
			}
			if ((hasMipMaps && !posY.HasMipMaps) || !posZ.HasMipMaps || !negX.HasMipMaps || !negY.HasMipMaps || !negZ.HasMipMaps)
			{
				throw new Exception("The supplied Bitmap2D's don't all have mipmaps");
			}
			Init(null, posX.Format, hasMipMaps, null, profile, allocator);
			FillFrom(posX, Face.PosX, hasMipMaps);
			FillFrom(negX, Face.NegX, hasMipMaps);
			FillFrom(posY, Face.PosY, hasMipMaps);
			FillFrom(negY, Face.NegY, hasMipMaps);
			FillFrom(posZ, Face.PosZ, hasMipMaps);
			FillFrom(negZ, Face.NegZ, hasMipMaps);
		}

		protected override int InitMipmapLevels()
		{
			mipmapSizes = new List<int2>();
			MipmapLevels(base.Size, mipmapSizes);
			return mipmapSizes.Count;
		}

		public override int MipmapOrigin(int mip)
		{
			if (mip != 0)
			{
				return mipmapOrigins[mip];
			}
			return 0;
		}

		public int FaceByteOrigin(Face face)
		{
			return base.ElementTotalBytes * (int)face;
		}

		public int FaceStart(Face face)
		{
			return base.ElementTotalPixels * (int)face;
		}

		public int MipStart(Face face, int mip)
		{
			return FaceStart(face) + MipmapOrigin(mip);
		}

		public int PixelStart(int x, int y, Face face, int mip)
		{
			int num = FaceStart(face);
			if (mip == 0)
			{
				return num + x + y * base.AlignedSize.x;
			}
			int2 @int = mipmapSizes[mip];
			int num2 = mipmapOrigins[mip];
			return num + num2 + (x + y * @int.x);
		}

		public int MipmapByteOrigin(int mip, Face face)
		{
			return (int)MathX.BitsToBytes((double)MipStart(face, mip) * base.BitsPerPixel);
		}

		public int MipmapTotalBytes(int mip, Face face)
		{
			return (int)MathX.BitsToBytes((double)MipmapTotalPixels(mip) * base.BitsPerPixel);
		}

		public void GetMipMapBuffers(List<Memory<byte>> mipbuffers)
		{
			for (int i = 0; i < 6; i++)
			{
				GetMipMapBuffers(mipbuffers, FaceByteOrigin((Face)i));
			}
		}

		public void GetMipMapBuffers(List<MipMapBuffer> mipbuffers)
		{
			for (int i = 0; i < 6; i++)
			{
				GetMipMapBuffers(mipbuffers, FaceByteOrigin((Face)i), i);
			}
		}

		public color GetPixel(int x, int y, Face face, int mipLevel = 0)
		{
			int index = PixelStart(x, y, face, mipLevel);
			return DecodePixel(index);
		}

		public color32 GetPixel32(int x, int y, Face face, int mipLevel = 0)
		{
			int index = PixelStart(x, y, face, mipLevel);
			return DecodePixel32(index);
		}

		public void SetPixel(int x, int y, Face face, color color, int mipLevel = 0)
		{
			int index = PixelStart(x, y, face, mipLevel);
			EncodePixel(index, in color);
		}

		public void SetPixel32(int x, int y, Face face, color32 color, int mipLevel = 0)
		{
			int index = PixelStart(x, y, face, mipLevel);
			EncodePixel32(index, in color);
		}

		public static int MipmapLevels(int2 size, List<int2> sizes)
		{
			return Bitmap2DBase.MipmapLevels(in size, sizes) * 6;
		}

		public static int ComputeTotalPixels(int2 size, bool mipmaps)
		{
			return Bitmap2D.ComputeTotalPixels(in size, mipmaps) * 6;
		}

		public BitmapCube ExtractMipMap(int mip, bool includeChildMips)
		{
			int2 @int = MipMapSize(mip);
			BitmapCube bitmapCube = new BitmapCube(@int.x, @int.y, base.Format, includeChildMips, base.Profile, base.OriginalFormat);
			for (int i = 0; i < 6; i++)
			{
				for (int j = 0; j < bitmapCube.MipMapLevels; j++)
				{
					int start = FaceByteOrigin((Face)i) + MipmapByteOrigin(mip + j);
					int start2 = bitmapCube.FaceByteOrigin((Face)i) + bitmapCube.MipmapByteOrigin(j);
					int length = MipmapTotalBytes(mip + j);
					base.RawData.Slice(start, length).CopyTo(bitmapCube.RawData.Slice(start2, length));
				}
			}
			return bitmapCube;
		}

		public BitmapCube ConvertTo(TextureFormat format)
		{
			BitmapCube bitmapCube = new BitmapCube(base.Size.x, base.Size.y, format, base.HasMipMaps, base.Profile, base.OriginalFormat);
			bitmapCube.FillFrom(this);
			return bitmapCube;
		}

		public override string ToString()
		{
			return $"BitmapCube. Size: {base.Size.x}x{base.Size.y}, Format: {base.Format}, MipLevels: {base.MipMapLevels}, Bytes: {base.Buffer?.SizeBytes}, Profile: {base.Profile}";
		}

		public Bitmap2D GetFaceAsBitmap2D(Face face, bool mipmaps = true)
		{
			Bitmap2D bitmap2D = new Bitmap2D(base.Size.x, base.Size.y, base.Format, mipmaps && base.HasMipMaps, base.Profile);
			int num = ((!bitmap2D.HasMipMaps) ? 1 : base.MipMapLevels);
			for (int i = 0; i < num; i++)
			{
				bitmap2D.FillFrom(this, face, i);
			}
			return bitmap2D;
		}

		public void FillFrom(Bitmap2D bitmap, Face face, bool mipmaps = true)
		{
			for (int i = 0; i < base.MipMapLevels; i++)
			{
				FillFrom(bitmap, face, i);
			}
		}

		public void FillFrom(Bitmap2D bitmap, Face face, int miplevel)
		{
			if (bitmap.Size != base.Size)
			{
				throw new ArgumentException("Bitmap2D Size doesn't equal the face size of the bitmap");
			}
			int2 @int = MipMapSize(miplevel);
			for (int i = 0; i < @int.y; i++)
			{
				int sourceStart = bitmap.PixelStart(0, i, miplevel);
				int destStart = PixelStart(0, i, face, miplevel);
				int x = @int.x;
				CopyPixelsFrom(bitmap, sourceStart, destStart, x);
			}
		}

		public void Save(string file, RawBitmapEncoding encoding = RawBitmapEncoding.LZMA)
		{
			using FileStream stream = File.OpenWrite(file);
			Encode(stream, encoding);
		}

		public static BitmapCube Load(string file, IBackingBufferAllocator allocator = null)
		{
			using FileStream stream = File.OpenRead(file);
			return Decode(stream, allocator);
		}

		public void Encode(Stream stream, RawBitmapEncoding encoding = RawBitmapEncoding.LZMA)
		{
			BinaryWriter binaryWriter = new BinaryWriter(stream);
			binaryWriter.Write("BmpCube");
			binaryWriter.Write(3);
			binaryWriter.Write(base.Size);
			binaryWriter.Write((ushort)base.Format);
			byte data = 0;
			data.SetBit(0, base.HasMipMaps);
			binaryWriter.Write(data);
			binaryWriter.Write((byte)encoding);
			binaryWriter.WriteEnumString(base.Profile);
			binaryWriter.Flush();
			switch (encoding)
			{
			case RawBitmapEncoding.Uncompressed:
				stream.Write(base.RawData);
				break;
			case RawBitmapEncoding.LZMA:
			{
				using Stream inStream = base.Buffer.Memory.AsStream();
				LZMAHelper.Compress(inStream, stream);
				break;
			}
			}
		}

		public static BitmapCube Decode(Stream stream, IBackingBufferAllocator allocator = null)
		{
			BinaryReader binaryReader = new BinaryReader(stream);
			if (binaryReader.ReadString() != "BmpCube")
			{
				throw new Exception("Cubemap magic string not found at the beginning of the stream!");
			}
			int num = binaryReader.ReadInt32();
			if (num > 3)
			{
				throw new Exception("Invalid Cubemap binary version: " + num);
			}
			int2 @int = binaryReader.Read2D_Int32();
			TextureFormat format = num switch
			{
				0 => binaryReader.ReadEnumBinary<LegacyTextureFormat>().ConvertLegacyFormat(), 
				1 => binaryReader.ReadEnumString<TextureFormat>(), 
				_ => (TextureFormat)binaryReader.ReadUInt16(), 
			};
			bool mipmaps;
			RawBitmapEncoding rawBitmapEncoding;
			if (num < 2)
			{
				mipmaps = binaryReader.ReadBoolean();
				rawBitmapEncoding = RawBitmapEncoding.LZMA;
			}
			else
			{
				mipmaps = binaryReader.ReadByte().GetBit(0);
				rawBitmapEncoding = (RawBitmapEncoding)binaryReader.ReadByte();
			}
			ColorProfile profile = ColorProfile.sRGB;
			if (num > 2)
			{
				profile = binaryReader.ReadEnumString<ColorProfile>();
			}
			BitmapCube bitmapCube = new BitmapCube(@int.x, @int.y, format, mipmaps, profile, null, allocator);
			Span<byte> buffer = bitmapCube.RawData;
			if (rawBitmapEncoding != RawBitmapEncoding.Uncompressed)
			{
				if (rawBitmapEncoding == RawBitmapEncoding.LZMA)
				{
					using Stream outStream = bitmapCube.Buffer.Memory.AsStream();
					LZMAHelper.Decompress(stream, outStream);
				}
			}
			else
			{
				while (buffer.Length > 0)
				{
					int num2 = stream.Read(buffer);
					if (num2 == 0)
					{
						throw new EndOfStreamException("Unexpected end of stream");
					}
					buffer = buffer.Slice(num2);
				}
			}
			return bitmapCube;
		}

		public void ForeachPixelDirection(Func<float3, color> colorGenerator)
		{
			float2 invSize = 1f / base.Size;
			float2 halfPixel = invSize * 0.5f;
			Parallel.For(0, 6, delegate(int faceIndex)
			{
				Face face = (Face)faceIndex;
				int xMul = 1;
				int yMul = -1;
				float3 basePos;
				int xPosIndex;
				int yPosIndex;
				switch (face)
				{
				case Face.PosX:
					basePos = new float3(1f);
					xPosIndex = 2;
					yPosIndex = 1;
					xMul = -1;
					break;
				case Face.NegX:
					basePos = new float3(-1f);
					xPosIndex = 2;
					yPosIndex = 1;
					break;
				case Face.PosY:
					basePos = new float3(0f, 1f);
					xPosIndex = 0;
					yPosIndex = 2;
					yMul = 1;
					break;
				case Face.NegY:
					basePos = new float3(0f, -1f);
					xPosIndex = 0;
					yPosIndex = 2;
					break;
				case Face.PosZ:
					basePos = new float3(0f, 0f, 1f);
					xPosIndex = 0;
					yPosIndex = 1;
					break;
				case Face.NegZ:
					basePos = new float3(0f, 0f, -1f);
					xPosIndex = 0;
					yPosIndex = 1;
					xMul = -1;
					break;
				default:
					throw new InvalidOperationException("Invalid face: " + face);
				}
				Parallel.For(0, base.Size.y, delegate(int y)
				{
					float num = ((float)y * invSize.y + halfPixel.y) * 2f - 1f;
					num *= (float)yMul;
					float3 @float = basePos.SetComponent(num, yPosIndex);
					for (int i = 0; i < base.Size.x; i++)
					{
						float num2 = ((float)i * invSize.x + halfPixel.x) * 2f - 1f;
						num2 *= (float)xMul;
						float3 normalized = @float.SetComponent(num2, xPosIndex).Normalized;
						color color = colorGenerator(normalized);
						SetPixel(i, y, face, color);
					}
				});
			});
		}

		public static bool SupportsBlockCompression(TextureFormat targetFormat)
		{
			return BitmapBlockCompression.SupportsBlockCompression(targetFormat);
		}

		/// <summary>
		/// Block Compresses a BitmapCube
		/// </summary>
		/// <param name="targetFormat">Format to compress to</param>
		/// <param name="quality">Expressed as 0-100(percent), from the asset variant system</param>
		/// <param name="maxThreads">The maximum number of threads to use for this operation</param>
		/// <returns>Block Compressed BitmapCube</returns>
		/// <exception cref="T:System.Exception"></exception>
		public BitmapCube BlockCompress(TextureFormat targetFormat, int quality = 100, int maxThreads = 0)
		{
			if (!targetFormat.IsBlockCompressed())
			{
				throw new Exception("Target format isn't block compressed: " + targetFormat);
			}
			TextureFormat sourceFormat = base.Format;
			if (BitmapBlockCompression.NeedsToConvertForBlockCompression(ref sourceFormat, targetFormat))
			{
				return ConvertTo(sourceFormat).BlockCompress(targetFormat, quality, maxThreads);
			}
			BitmapCube bitmapCube = new BitmapCube(base.Size.x, base.Size.y, targetFormat, base.HasMipMaps, base.Profile, base.OriginalFormat);
			List<MipMapBuffer> list = new List<MipMapBuffer>();
			GetMipMapBuffers(list);
			List<MipMapBuffer> list2 = new List<MipMapBuffer>();
			bitmapCube.GetMipMapBuffers(list2);
			BitmapBlockCompression.BlockCompress(list, list2, base.Format, targetFormat, quality, maxThreads);
			return bitmapCube;
		}
	}
	public static class BitmapQRCodeGenerator
	{
		public static Bitmap2D Generate(string payload, QRCodeGenerator.ECCLevel eccLevel = QRCodeGenerator.ECCLevel.Q, TextureFormat format = TextureFormat.RGBA32, color? trueColor = null, color? falseColor = null)
		{
			Bitmap2D bitmap = null;
			Generate(ref bitmap, payload, eccLevel, format, trueColor, falseColor);
			return bitmap;
		}

		public static void Generate(ref Bitmap2D bitmap, string payload, QRCodeGenerator.ECCLevel eccLevel = QRCodeGenerator.ECCLevel.Q, TextureFormat format = TextureFormat.RGBA32, color? trueColor = null, color? falseColor = null, IBackingBufferAllocator allocator = null)
		{
			color color = trueColor ?? color.Black;
			color color2 = falseColor ?? color.White;
			using QRCodeGenerator qRCodeGenerator = new QRCodeGenerator();
			using QRCodeData qRCodeData = qRCodeGenerator.CreateQrCode(payload, eccLevel);
			int count = qRCodeData.ModuleMatrix.Count;
			if (bitmap == null || (bitmap.Size.x != count && bitmap.Size.y != count))
			{
				bitmap = new Bitmap2D(count, count, format, mipmaps: false, ColorProfile.sRGB, flipY: true, null, allocator);
			}
			for (int i = 0; i < count; i++)
			{
				for (int j = 0; j < count; j++)
				{
					bool flag = qRCodeData.ModuleMatrix[i][j];
					bitmap.SetPixel(j, i, flag ? color : color2);
				}
			}
		}
	}
