	internal class SliceAccessor
	{
		private List<string> paths;

		private List<Bitmap2D> slices;

		private int slice0layer = -1;

		private int slice1layer = -1;

		public int Count => paths?.Count ?? slices.Count;

		public SliceAccessor(List<string> paths)
		{
			this.paths = paths;
			slices = new List<Bitmap2D>();
			slices.Add(null);
			slices.Add(null);
		}

		public SliceAccessor(List<Bitmap2D> slices)
		{
			this.slices = slices;
		}

		public Bitmap2D GetSlice(int layer)
		{
			if (paths == null)
			{
				return slices[layer];
			}
			if (layer == slice0layer)
			{
				return slices[0];
			}
			if (layer == slice1layer)
			{
				return slices[1];
			}
			slices[0] = slices[1];
			slice0layer = slice1layer;
			slice1layer = layer;
			slices[1] = Bitmap2D.Load(paths[layer], false);
			if (slices[1].Size.x == 0 || slices[1].Size.y == 0)
			{
				throw new Exception("Error loading slice file: " + paths[layer]);
			}
			return slices[1];
		}
	}
