	public static class PixelHelper
	{
		public const float USHORT_MUL = 1.5259022E-05f;

		public const float BYTE_MUL = 0.003921569f;

		public const float BIT6_MUL = 1f / 63f;

		public const float BIT5_MUL = 1f / 31f;

		public const float BIT4_MUL = 1f / 15f;

		public static color ToColor<P>(this P pixel) where P : IPixel
		{
			return new color(pixel.R, pixel.G, pixel.B, pixel.A);
		}

		public static P FromColor<P>(this color color) where P : struct, IPixel
		{
			return new P
			{
				R = color.r,
				G = color.g,
				B = color.b,
				A = color.a
			};
		}

		public static ushort ToUshort(float value)
		{
			value *= 65535f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 65535f)
			{
				return ushort.MaxValue;
			}
			return (ushort)value;
		}

		public static byte ToByte(float value)
		{
			value *= 255f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 255f)
			{
				return byte.MaxValue;
			}
			return (byte)value;
		}

		public static byte To4Bits(float value)
		{
			value *= 15f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 15f)
			{
				return 15;
			}
			return (byte)value;
		}

		public static byte To5Bits(float value)
		{
			value *= 31f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 31f)
			{
				return 31;
			}
			return (byte)value;
		}

		public static byte To6Bits(float value)
		{
			value *= 63f;
			value += 0.5f;
			if (value <= 0f)
			{
				return 0;
			}
			if (value >= 63f)
			{
				return 63;
			}
			return (byte)value;
		}

		public static ushort ToHalf(float value)
		{
			Half source = (Half)value;
			return Unsafe.As<Half, ushort>(ref source);
		}

		public static float FromUshort(ushort value)
		{
			return (float)(int)value * 1.5259022E-05f;
		}

		public static float FromByte(byte value)
		{
			return (float)(int)value * 0.003921569f;
		}

		public static float From6Bits(byte value)
		{
			return (float)(value & 0x3F) * (1f / 63f);
		}

		public static float From5Bits(byte value)
		{
			return (float)(value & 0x1F) * (1f / 31f);
		}

		public static float From4Bits(byte value)
		{
			return (float)(value & 0xF) * (1f / 15f);
		}

		public static Half HalfFromUshort(ushort value)
		{
			return Unsafe.As<ushort, Half>(ref value);
		}
	}
