	public class TextureDecoder
	{
		public const int MAX_PIXELS = 268435456;

		public const float GAMMA = 2.2f;

		public const float INV_GAMMA = 0.45454544f;

		public const int MIN_DOWNSCALE_SIZE = 32;

		public static readonly Bitmap2D ERRORTEXTURE;

		public static readonly Bitmap3D ERRORTEXTURE3D;

		private static Dictionary<string, FREE_IMAGE_FORMAT> extensions;

		public static IEnumerable<string> SupportedExtensions => extensions.Keys;

		public static event Action<string> OnErrorMessage;

		static TextureDecoder()
		{
			FreeImageEngine.Message += FreeImageEngine_Message;
			extensions = new Dictionary<string, FREE_IMAGE_FORMAT>();
			foreach (FreeImagePlugin readablePlugin in PluginRepository.ReadablePlugins)
			{
				string[] array = readablePlugin.ExtentsionList.Split(',');
				for (int i = 0; i < array.Length; i++)
				{
					string key = array[i].ToLower().Trim();
					if (!extensions.ContainsKey(key))
					{
						extensions.Add(key, readablePlugin.FIFormat);
					}
				}
			}
			ERRORTEXTURE = GenerateErrorTexture(4, 4, TextureFormat.RGB24);
			ERRORTEXTURE3D = GenerateErrorTexture(4, 4, 4, TextureFormat.RGB24);
		}

		public static Bitmap2D GenerateErrorTexture(int width, int height, TextureFormat format, IBackingBufferAllocator allocator = null)
		{
			Bitmap2D bitmap2D = new Bitmap2D(width, height, format, mipmaps: false, ColorProfile.sRGB, flipY: true, null, allocator);
			FillErrorTexture(bitmap2D);
			return bitmap2D;
		}

		public static Bitmap3D GenerateErrorTexture(int width, int height, int depth, TextureFormat format, IBackingBufferAllocator allocator = null)
		{
			Bitmap3D bitmap3D = new Bitmap3D(width, height, depth, format, mipmaps: false, ColorProfile.sRGB, null, allocator);
			FillErrorTexture(bitmap3D);
			return bitmap3D;
		}

		public static void FillErrorTexture(Bitmap2D bitmap)
		{
			for (int i = 0; i < bitmap.Size.y; i++)
			{
				for (int j = 0; j < bitmap.Size.x; j++)
				{
					byte r = (byte)((((j ^ i) & 1) == 0) ? 255u : 0u);
					byte g = (byte)((((j ^ i) & 2) == 0) ? 255u : 0u);
					byte b = (byte)((((j ^ i) & 1) != 0) ? 255u : 0u);
					bitmap.SetPixel32(j, i, new color32(r, g, b));
				}
			}
		}

		public static void FillErrorTexture(BitmapCube cube)
		{
			for (int i = 0; i < 6; i++)
			{
				for (int j = 0; j < cube.Size.y; j++)
				{
					for (int k = 0; k < cube.Size.x; k++)
					{
						byte r = (byte)((((k ^ j) & 1) == 0) ? 255u : 0u);
						byte g = (byte)((((k ^ j) & 2) == 0) ? 255u : 0u);
						byte b = (byte)((((k ^ j) & 1) != 0) ? 255u : 0u);
						cube.SetPixel32(k, j, (BitmapCube.Face)i, new color32(r, g, b));
					}
				}
			}
		}

		public static void FillErrorTexture(Bitmap3D bitmap)
		{
			for (int i = 0; i < bitmap.Size.z; i++)
			{
				for (int j = 0; j < bitmap.Size.y; j++)
				{
					for (int k = 0; k < bitmap.Size.x; k++)
					{
						byte r = (byte)((((k ^ j ^ i) & 1) == 0) ? 255u : 0u);
						byte g = (byte)((((k ^ j ^ i) & 2) == 0) ? 255u : 0u);
						byte b = (byte)((((k ^ j ^ i) & 1) != 0) ? 255u : 0u);
						bitmap.SetPixel(k, j, i, (color)new color32(r, g, b));
					}
				}
			}
		}

