		private static void FreeImageEngine_Message(FREE_IMAGE_FORMAT fif, string message)
		{
			if (!message.Contains("Not a") || !message.Contains("file"))
			{
				TextureDecoder.OnErrorMessage?.Invoke($"FREEIMAGE (Format: {fif}): {message}");
			}
		}

		public static FREE_IMAGE_FORMAT DetectFormat(string extension)
		{
			if (string.IsNullOrEmpty(extension))
			{
				return FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			}
			extension = extension.ToLower();
			if (extensions.TryGetValue(extension, out var value))
			{
				return value;
			}
			return FREE_IMAGE_FORMAT.FIF_UNKNOWN;
		}

		public static void DibLoaded(FIBITMAP dib)
		{
		}

		public static void UnloadDib(FIBITMAP dib)
		{
			FreeImage.Unload(dib);
		}

		public static Bitmap2D FromDDS(Stream stream, bool? generateMipMaps, IBackingBufferAllocator allocator = null)
		{
			using IImage image = Pfimage.FromStream(stream);
			TextureFormat format = GetFormat(image.Format);
			Bitmap2D bitmap2D = new Bitmap2D(image.Width, image.Height, format, generateMipMaps ?? (image.MipMaps.Length != 0), ColorProfile.sRGB, flipY: false, null, allocator);
			for (int i = 0; i < bitmap2D.MipMapLevels; i++)
			{
				int2 value = bitmap2D.MipMapSize(i);
				int start;
				int dataLen;
				if (i == 0)
				{
					start = 0;
					dataLen = image.DataLen;
				}
				else
				{
					MipMapOffset mipMapOffset = image.MipMaps[i - 1];
					if (value.x != mipMapOffset.Width || value.y != mipMapOffset.Height)
					{
						throw new Exception($"Mip size mismatch at mip level {i}. Expected: {value}, Got: {mipMapOffset.Width}x{mipMapOffset.Height}");
					}
					start = mipMapOffset.DataOffset;
					dataLen = mipMapOffset.DataLen;
				}
				Span<byte> data = image.Data.AsSpan().Slice(start, dataLen);
				ConvertDDSData(image, data, i, bitmap2D);
			}
			if (bitmap2D.MipMapLevels > 1 && image.MipMaps.Length == 0)
			{
				bitmap2D.GenerateMipmapsBox();
			}
			return bitmap2D;
		}

		public static void ConvertDDSData(IImage dds, Span<byte> data, int mip, Bitmap2D bitmap)
		{
			int2 mipSize = bitmap.MipMapSize(mip);
			switch (dds.Format)
			{
			case ImageFormat.A8:
			case ImageFormat.R8:
			case ImageFormat.Rgba32:
			case ImageFormat.R_FP16:
			case ImageFormat.R_FP32:
			case ImageFormat.Rg_FP16:
			case ImageFormat.Rg_FP32:
			case ImageFormat.Rgba_FP16:
			case ImageFormat.Rgba_FP32:
			{
				int start = bitmap.MipmapByteOrigin(mip);
				Span<byte> destination = bitmap.RawData.Slice(start, bitmap.MipmapTotalBytes(mip));
				if (data.Length < destination.Length)
				{
					throw new Exception($"Data length mismatch for mip {mip}. Source: {data.Length}, Target: {destination.Length}");
				}
				data.Slice(0, destination.Length).CopyTo(destination);
				break;
			}
			case ImageFormat.R5g5b5:
				ConvertImageData<PixelBGR555>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.R5g6b5:
				ConvertImageData<PixelRGB565>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.R5g5b5a1:
				ConvertImageData<PixelARGB1555>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.Rgb24:
				ConvertImageData<PixelBGR24>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.Rgba16:
				ConvertImageData<PixelBGRA4444>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.Ra16:
				ConvertImageData<PixelRA16>(data, mipSize, mip, bitmap);
				break;
			case ImageFormat.Rg32:
				ConvertImageData<PixelGR32>(data, mipSize, mip, bitmap);
				break;
			default:
				throw new NotImplementedException($"DDS format conversion not implemented: {dds.Format}");
			}
		}

		public static void ConvertImageData<P>(Span<byte> data, int2 mipSize, int mip, Bitmap2D bitmap) where P : struct, IPixel
		{
			Span<P> span = MemoryMarshal.Cast<byte, P>(data);
			for (int i = 0; i < mipSize.y; i++)
			{
				Span<P> span2 = span.Slice(mipSize.x * i, mipSize.x);
				for (int j = 0; j < mipSize.x; j++)
				{
					bitmap.SetPixel(j, i, span2[j].ToColor(), mip);
				}
			}
		}

		public static TextureFormat GetFormat(ImageFormat format)
		{
			return format switch
			{
				ImageFormat.Rgb24 => TextureFormat.RGB24, 
				ImageFormat.Rgba32 => TextureFormat.BGRA32, 
				ImageFormat.R5g6b5 => TextureFormat.RGB24, 
				ImageFormat.R8 => TextureFormat.R8, 
				ImageFormat.A8 => TextureFormat.Alpha8, 
				ImageFormat.R_FP16 => TextureFormat.RHalf, 
				ImageFormat.R_FP32 => TextureFormat.RFloat, 
				ImageFormat.Rg_FP16 => TextureFormat.RGHalf, 
				ImageFormat.Rg_FP32 => TextureFormat.RGFloat, 
				ImageFormat.Rgba_FP16 => TextureFormat.RGBAHalf, 
				ImageFormat.Rgba_FP32 => TextureFormat.RGBAFloat, 
				ImageFormat.Rgba16 => TextureFormat.RGBA32, 
				ImageFormat.Ra16 => TextureFormat.RGBA32, 
				ImageFormat.Rg32 => TextureFormat.RGBAHalf, 
				ImageFormat.R5g5b5 => TextureFormat.RGB24, 
				ImageFormat.R5g5b5a1 => TextureFormat.RGBA32, 
				_ => throw new NotImplementedException("PFIM DDS format not implemented: " + format), 
			};
		}

		public static Bitmap2D FromFreeImage(ref FIBITMAP dib, bool generateMipMaps, AlphaHandling alphaHandling, int maxSize = int.MaxValue, float sizeRatio = 1f, string originalFormat = null, IBackingBufferAllocator allocator = null)
		{
			TextureFormat textureFormat = TextureFormat.Unknown;
			int2 v = new int2((int)FreeImage.GetWidth(dib), (int)FreeImage.GetHeight(dib));
			if ((long)v.x * (long)v.y > 268435456)
			{
				throw new TextureSizeException(v, maxSize);
			}
			FREE_IMAGE_COLOR_TYPE colorType = FreeImage.GetColorType(dib);
			FREE_IMAGE_TYPE imageType = FreeImage.GetImageType(dib);
			int bPP = (int)FreeImage.GetBPP(dib);
			FreeImage.GetInfoEx(dib);
			bool flag = false;
			switch (colorType)
			{
			case FREE_IMAGE_COLOR_TYPE.FIC_MINISBLACK:
				flag = true;
				break;
			default:
			{
				FIBITMAP fIBITMAP = ((bPP > 8) ? FreeImage.ConvertToRGBF(dib) : ((!FreeImage.IsTransparent(dib)) ? FreeImage.ConvertTo24Bits(dib) : FreeImage.ConvertTo32Bits(dib)));
				DibLoaded(fIBITMAP);
				UnloadDib(dib);
				dib = fIBITMAP;
				break;
			}
			case FREE_IMAGE_COLOR_TYPE.FIC_RGB:
			case FREE_IMAGE_COLOR_TYPE.FIC_RGBALPHA:
				break;
			}
			bPP = (int)FreeImage.GetBPP(dib);
			Type typeFromHandle;
			if (bPP == 8)
			{
				textureFormat = TextureFormat.RGB24;
				typeFromHandle = typeof(byte);
			}
			else if (bPP == 16)
			{
				switch (imageType)
				{
				case FREE_IMAGE_TYPE.FIT_UINT16:
					textureFormat = TextureFormat.RGBAHalf;
					typeFromHandle = typeof(ushort);
					break;
				case FREE_IMAGE_TYPE.FIT_INT16:
					textureFormat = TextureFormat.RGBAHalf;
					typeFromHandle = typeof(short);
					break;
				case FREE_IMAGE_TYPE.FIT_BITMAP:
				{
					FIBITMAP fIBITMAP2 = FreeImage.ConvertTo32Bits(dib);
					DibLoaded(fIBITMAP2);
					UnloadDib(dib);
					dib = fIBITMAP2;
					textureFormat = TextureFormat.RGBA32;
					typeFromHandle = typeof(RGBQUAD);
					break;
				}
				default:
					throw new NotSupportedException("Unsuported 16-bit image type: " + imageType);
				}
			}
			else if (bPP < 24)
			{
				FIBITMAP fIBITMAP3 = FreeImage.ConvertTo32Bits(dib);
				DibLoaded(fIBITMAP3);
				UnloadDib(dib);
				dib = fIBITMAP3;
				textureFormat = TextureFormat.RGBA32;
				typeFromHandle = typeof(RGBQUAD);
			}
			else
			{
				switch (bPP)
				{
				case 24:
					textureFormat = TextureFormat.RGB24;
					typeFromHandle = typeof(RGBTRIPLE);
					break;
				case 32:
					if (flag)
					{
						textureFormat = TextureFormat.RGBAHalf;
						typeFromHandle = typeof(float);
					}
					else
					{
						textureFormat = TextureFormat.RGBA32;
						typeFromHandle = typeof(RGBQUAD);
					}
					break;
				case 48:
				case 64:
				{
					FREE_IMAGE_TYPE dst_type;
					if (bPP == 48)
					{
						typeFromHandle = typeof(FIRGBF);
						dst_type = FREE_IMAGE_TYPE.FIT_RGBF;
					}
					else
					{
						typeFromHandle = typeof(FIRGBAF);
						dst_type = FREE_IMAGE_TYPE.FIT_RGBAF;
					}
					FIBITMAP fIBITMAP4 = FreeImage.ConvertToType(dib, dst_type, scale_linear: true);
					DibLoaded(fIBITMAP4);
					UnloadDib(dib);
					dib = fIBITMAP4;
					textureFormat = TextureFormat.RGBAHalf;
					break;
				}
				case 96:
					textureFormat = TextureFormat.RGBAHalf;
					typeFromHandle = typeof(FIRGBF);
					break;
				case 128:
					textureFormat = TextureFormat.RGBAHalf;
					typeFromHandle = typeof(FIRGBAF);
					break;
				default:
					throw new Exception("Invalid bpp: " + bPP);
				}
			}
			if (alphaHandling != AlphaHandling.KeepOriginal)
			{
				if (alphaHandling == AlphaHandling.ForceRGBA && !textureFormat.SupportsAlpha())
				{
					textureFormat = TextureFormat.RGBA32;
				}
				if (alphaHandling == AlphaHandling.ForceRGB)
				{
					textureFormat = TextureFormat.RGB24;
				}
			}
			if (MathX.MaxComponent(in v) > maxSize || sizeRatio < 1f)
			{
				float num = MathX.Min((float)maxSize / (float)MathX.MaxComponent(in v), sizeRatio);
				float2 v2 = v * num;
				float num2 = MathX.MinComponent(in v2);
				if (num2 < 32f)
				{
					v2 *= 32f / num2;
				}
				int2 @int = (int2)v2;
				FIBITMAP fIBITMAP5 = FreeImage.Rescale(dib, @int.x, @int.y, FREE_IMAGE_FILTER.FILTER_BOX);
				DibLoaded(fIBITMAP5);
				UnloadDib(dib);
				dib = fIBITMAP5;
				v = @int;
			}
			if (textureFormat == TextureFormat.Unknown)
			{
				return null;
			}
			Bitmap2D bitmap2D = new Bitmap2D(v.x, v.y, textureFormat, generateMipMaps, ColorProfile.sRGB, flipY: true, originalFormat, allocator);
			for (int i = 0; i < bitmap2D.MipMapLevels; i++)
			{
				int2 int2;
				if (i == 0)
				{
					int2 = bitmap2D.Size;
				}
				else
				{
					int2 = bitmap2D.MipMapSize(i);
					FIBITMAP fIBITMAP6 = FreeImage.Rescale(dib, int2.x, int2.y, FREE_IMAGE_FILTER.FILTER_BOX);
					DibLoaded(fIBITMAP6);
					UnloadDib(dib);
					dib = fIBITMAP6;
				}
				if (typeFromHandle == typeof(RGBQUAD))
				{
					for (int j = 0; j < int2.y; j++)
					{
						using Scanline<RGBQUAD> scanline = new Scanline<RGBQUAD>(dib, int2.y - j - 1);
						for (int k = 0; k < int2.x; k++)
						{
							RGBQUAD rGBQUAD = scanline[k];
							bitmap2D.SetPixel32(k, j, new color32(rGBQUAD.rgbRed, rGBQUAD.rgbGreen, rGBQUAD.rgbBlue, rGBQUAD.rgbReserved), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(RGBTRIPLE))
				{
					for (int l = 0; l < int2.y; l++)
					{
						using Scanline<RGBTRIPLE> scanline2 = new Scanline<RGBTRIPLE>(dib, int2.y - l - 1);
						for (int m = 0; m < int2.x; m++)
						{
							RGBTRIPLE rGBTRIPLE = scanline2[m];
							bitmap2D.SetPixel32(m, l, new color32(rGBTRIPLE.rgbtRed, rGBTRIPLE.rgbtGreen, rGBTRIPLE.rgbtBlue), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(FIRGBF))
				{
					for (int n = 0; n < int2.y; n++)
					{
						using Scanline<FIRGBF> scanline3 = new Scanline<FIRGBF>(dib, int2.y - n - 1);
						for (int num3 = 0; num3 < int2.x; num3++)
						{
							FIRGBF fIRGBF = scanline3[num3];
							bitmap2D.SetPixel(num3, n, new color(fIRGBF.red, fIRGBF.green, fIRGBF.blue), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(FIRGBAF))
				{
					for (int num4 = 0; num4 < int2.y; num4++)
					{
						using Scanline<FIRGBAF> scanline4 = new Scanline<FIRGBAF>(dib, int2.y - num4 - 1);
						for (int num5 = 0; num5 < int2.x; num5++)
						{
							FIRGBAF fIRGBAF = scanline4[num5];
							bitmap2D.SetPixel(num5, num4, new color(fIRGBAF.red, fIRGBAF.green, fIRGBAF.blue, fIRGBAF.alpha), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(byte))
				{
					for (int num6 = 0; num6 < int2.y; num6++)
					{
						using Scanline<byte> scanline5 = new Scanline<byte>(dib, int2.y - num6 - 1);
						for (int num7 = 0; num7 < int2.x; num7++)
						{
							byte b = scanline5[num7];
							bitmap2D.SetPixel32(num7, num6, new color32(b, b, b), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(short))
				{
					for (int num8 = 0; num8 < int2.y; num8++)
					{
						using Scanline<short> scanline6 = new Scanline<short>(dib, int2.y - num8 - 1);
						for (int num9 = 0; num9 < int2.x; num9++)
						{
							float grayscale = (float)(scanline6[num9] - -32768) / 65535f;
							bitmap2D.SetPixel(num9, num8, new color(grayscale), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(ushort))
				{
					for (int num10 = 0; num10 < int2.y; num10++)
					{
						using Scanline<ushort> scanline7 = new Scanline<ushort>(dib, int2.y - num10 - 1);
						for (int num11 = 0; num11 < int2.x; num11++)
						{
							float grayscale2 = (float)(int)scanline7[num11] / 65535f;
							bitmap2D.SetPixel(num11, num10, new color(grayscale2), i);
						}
					}
					continue;
				}
				if (typeFromHandle == typeof(float))
				{
					for (int num12 = 0; num12 < int2.y; num12++)
					{
						using Scanline<float> scanline8 = new Scanline<float>(dib, int2.y - num12 - 1);
						for (int num13 = 0; num13 < int2.x; num13++)
						{
							float num14 = scanline8[num13];
							bitmap2D.SetPixel(num13, num12, new color(num14, num14, num14), i);
						}
					}
					continue;
				}
				throw new Exception("Invalid read type: " + typeFromHandle);
			}
			return bitmap2D;
		}

		public static Bitmap2D Decode(string file, bool? generateMipMaps, AlphaHandling alphaHandling = AlphaHandling.KeepOriginal, int maxSize = int.MaxValue, float sizeRatio = 1f, IBackingBufferAllocator allocator = null)
		{
			string text = Path.GetExtension(file);
			if (text.Length > 1)
			{
				text = text.Substring(1);
			}
			using FileStream fStream = File.OpenRead(file);
			return Decode(fStream, text, generateMipMaps, alphaHandling, maxSize, sizeRatio, allocator);
		}

		public static Bitmap2D Decode(Stream fStream, string extension, bool? generateMipMaps, AlphaHandling alphaHandling = AlphaHandling.KeepOriginal, int maxSize = int.MaxValue, float sizeRatio = 1f, IBackingBufferAllocator allocator = null)
		{
			Bitmap2D bitmap2D = null;
			FIBITMAP dib = FIBITMAP.Zero;
			try
			{
				fStream.Seek(0L, SeekOrigin.Begin);
				FileType fileType = fStream.GetFileType();
				fStream.Seek(0L, SeekOrigin.Begin);
				if (fileType != null && fileType.Mime.Contains("dds"))
				{
					try
					{
						return FromDDS(fStream, generateMipMaps);
					}
					catch (Exception ex)
					{
						UniLog.Warning("Filed to decode DDS texture using native support:\n" + ex);
						fStream.Seek(0L, SeekOrigin.Begin);
					}
				}
				FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
				if (fileType != null && !string.IsNullOrEmpty(fileType.Extension))
				{
					format = DetectFormat(fileType.Extension);
				}
				if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
				{
					format = DetectFormat(extension);
				}
				bool flag = format != FREE_IMAGE_FORMAT.FIF_UNKNOWN;
				dib = FreeImage.LoadFromStream(fStream, ref format);
				if (dib.IsNull)
				{
					format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
					if (flag)
					{
						fStream.Seek(0L, SeekOrigin.Begin);
						dib = FreeImage.LoadFromStream(fStream, ref format);
					}
				}
				if (dib.IsNull || format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
				{
					UniLog.Warning("Couldn't decode texture file, unknown format.");
					return null;
				}
				DibLoaded(dib);
				string originalFormat = FreeImage.GetFIFExtensionList(format).Split(',')[0];
				bitmap2D = FromFreeImage(ref dib, generateMipMaps == true, alphaHandling, maxSize, sizeRatio, originalFormat, allocator);
			}
			catch (TextureSizeException ex2)
			{
				UniLog.Error(ex2.Message);
			}
			catch (Exception ex3)
			{
				UniLog.Error("Exception during decoding texture file.\n" + ex3);
				throw;
			}
			finally
			{
				if (!dib.IsNull)
				{
					UnloadDib(dib);
				}
			}
			if (bitmap2D == null)
			{
				UniLog.Error("Texture wasn't decoded properly");
			}
			return bitmap2D;
		}

		public static string FreeImageFormatToMIME(FREE_IMAGE_FORMAT format)
		{
			switch (format)
			{
			case FREE_IMAGE_FORMAT.FIF_BMP:
				return "image/bmp";
			case FREE_IMAGE_FORMAT.FIF_TARGA:
				return "image/x-targa";
			case FREE_IMAGE_FORMAT.FIF_TIFF:
				return "image/tiff";
			case FREE_IMAGE_FORMAT.FIF_EXR:
				return "image/x-exr";
			case FREE_IMAGE_FORMAT.FIF_DDS:
				return "image/dds";
			case FREE_IMAGE_FORMAT.FIF_GIF:
				return "image/gif";
			case FREE_IMAGE_FORMAT.FIF_HDR:
				return "image/hdr";
			case FREE_IMAGE_FORMAT.FIF_ICO:
				return "image/vnd.microsoft.icon";
			case FREE_IMAGE_FORMAT.FIF_LBM:
				return "image/vnd.djvu";
			case FREE_IMAGE_FORMAT.FIF_J2K:
			case FREE_IMAGE_FORMAT.FIF_JP2:
				return "image/jp2";
			case FREE_IMAGE_FORMAT.FIF_JNG:
				return "image/x-jng";
			case FREE_IMAGE_FORMAT.FIF_JPEG:
				return "image/jpeg";
			case FREE_IMAGE_FORMAT.FIF_KOALA:
				return "image/x-koala";
			case FREE_IMAGE_FORMAT.FIF_MNG:
				return "image/x-mng";
			case FREE_IMAGE_FORMAT.FIF_PBM:
			case FREE_IMAGE_FORMAT.FIF_PBMRAW:
				return "image/x-portable-bitmap";
			case FREE_IMAGE_FORMAT.FIF_PCD:
				return "image/pcd";
			case FREE_IMAGE_FORMAT.FIF_PCX:
				return "image/vnd.zbrush.pcx";
			case FREE_IMAGE_FORMAT.FIF_PFM:
				return "image/x-pfm";
			case FREE_IMAGE_FORMAT.FIF_PGM:
				return "image/x-pgm";
			case FREE_IMAGE_FORMAT.FIF_PGMRAW:
				return "image/x-pgm-raw";
			case FREE_IMAGE_FORMAT.FIF_PICT:
				return "image/pict";
			case FREE_IMAGE_FORMAT.FIF_PNG:
				return "image/png";
			case FREE_IMAGE_FORMAT.FIF_PPM:
				return "image/x-portable-pixmap";
			case FREE_IMAGE_FORMAT.FIF_PSD:
				return "image/vnd.adobe.photoshop";
			case FREE_IMAGE_FORMAT.FIF_RAW:
				return "image/raw";
			default:
				return null;
			}
		}
	}
	public static class TextureEncoder
	{
		public static bool Encode(FIBITMAP dib, string file, int quality = 85, bool preserveColorInAlpha = true)
		{
			string extension = Path.GetExtension(file).Substring(1).ToLower();
			using FileStream stream = File.OpenWrite(file);
			return Encode(dib, stream, extension, quality, preserveColorInAlpha);
		}

		public static bool Encode(FIBITMAP dib, Stream stream, string extension, int quality = 85, bool preserveColorInAlpha = true)
		{
			FIBITMAP fIBITMAP = dib;
			FREE_IMAGE_FORMAT fREE_IMAGE_FORMAT = TextureDecoder.DetectFormat(extension);
			if (fREE_IMAGE_FORMAT == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Invalid File Format");
			}
			bool flag = quality > 100;
			quality = MathX.Clamp(quality, 1, 101);
			FREE_IMAGE_SAVE_FLAGS fREE_IMAGE_SAVE_FLAGS = (FREE_IMAGE_SAVE_FLAGS)quality;
			switch (fREE_IMAGE_FORMAT)
			{
			case FREE_IMAGE_FORMAT.FIF_JPEG:
			case FREE_IMAGE_FORMAT.FIF_J2K:
			case FREE_IMAGE_FORMAT.FIF_JP2:
				dib = EnsureNonHDR(dib, unloadOld: false);
				dib = Ensure24BPP(dib, unloadOld: false);
				break;
			case FREE_IMAGE_FORMAT.FIF_EXR:
				fREE_IMAGE_SAVE_FLAGS = FREE_IMAGE_SAVE_FLAGS.EXR_ZIP;
				break;
			case FREE_IMAGE_FORMAT.FIF_PNG:
				fREE_IMAGE_SAVE_FLAGS = FREE_IMAGE_SAVE_FLAGS.PNG_Z_BEST_COMPRESSION;
				break;
			default:
				if (extension == "webp")
				{
					if (flag)
					{
						fREE_IMAGE_SAVE_FLAGS = FREE_IMAGE_SAVE_FLAGS.JPEG_QUALITYGOOD;
					}
					if (preserveColorInAlpha)
					{
						fREE_IMAGE_SAVE_FLAGS |= FREE_IMAGE_SAVE_FLAGS.JPEG_QUALITYNORMAL;
					}
				}
				else
				{
					fREE_IMAGE_SAVE_FLAGS = FREE_IMAGE_SAVE_FLAGS.DEFAULT;
				}
				break;
			}
			bool flag2 = FreeImage.SaveToStream(dib, stream, fREE_IMAGE_FORMAT, fREE_IMAGE_SAVE_FLAGS);
			if (fIBITMAP != dib)
			{
				FreeImage.Unload(dib);
			}
			if (!flag2)
			{
				string[] obj = new string[6]
				{
					"Error encoding texture. Format: ",
					fREE_IMAGE_FORMAT.ToString(),
					", Quality: ",
					quality.ToString(),
					", DIB: ",
					null
				};
				FIBITMAP fIBITMAP2 = dib;
				obj[5] = fIBITMAP2.ToString();
				UniLog.Warning(string.Concat(obj));
			}
			return flag2;
		}

		public static bool Encode(byte[] data, int width, int height, int channels, string outputFile, int quality = 75, bool preserveColorInAlpha = true)
		{
			FIBITMAP dib = FreeImage.ConvertFromRawBits(data, width, height, width * channels, (uint)(channels * 8), 0u, 0u, 0u, topdown: false);
			TextureDecoder.DibLoaded(dib);
			if (dib.IsNull)
			{
				UniLog.Warning($"ConverFromRawBits returned null: data.Length {data?.Length}, width: {width}, height: {height}, channels: {channels}");
				return false;
			}
			try
			{
				return Encode(dib, outputFile, quality, preserveColorInAlpha);
			}
			finally
			{
				TextureDecoder.UnloadDib(dib);
			}
		}

		public static void ConvertToPNG(string inputFile, string outputFile, int maxSize = -1)
		{
			using FileStream data = File.OpenRead(inputFile);
			ConvertToPNG(data, outputFile, maxSize);
		}

		public static void ConvertToJPG(string inputFile, string outputFile, int maxSize = -1)
		{
			using FileStream data = File.OpenRead(inputFile);
			ConvertToJPG(data, outputFile, maxSize);
		}

		public static void ConvertToWEBP(string inputFile, string outputFile, int maxSize = -1, int quality = 80)
		{
			using FileStream data = File.OpenRead(inputFile);
			ConvertToWEBP(data, outputFile, maxSize, quality);
		}

		public static void ConvertToEXR(string inputFile, string outputFile, int maxSize = -1)
		{
			using FileStream data = File.OpenRead(inputFile);
			ConvertToEXR(data, outputFile, maxSize);
		}

		public static void ConvertToPNG(Stream data, string outputFile, int maxSize = -1)
		{
			FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			FIBITMAP dib = FreeImage.LoadFromStream(data, ref format);
			if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Couldn't decode the image data");
			}
			TextureDecoder.DibLoaded(dib);
			dib = EnsureNonHDR(dib);
			dib = Rescale(dib, maxSize);
			using (FileStream stream = File.OpenWrite(outputFile))
			{
				FreeImage.SaveToStream(dib, stream, FREE_IMAGE_FORMAT.FIF_PNG, FREE_IMAGE_SAVE_FLAGS.PNG_Z_BEST_COMPRESSION);
			}
			TextureDecoder.UnloadDib(dib);
		}

		public static bool ClearMetadata(string inputFile, string outputFile)
		{
			using FileStream data = File.OpenRead(inputFile);
			return ClearMetadata(data, outputFile);
		}

		public static bool ClearMetadata(Stream data, string outputFile)
		{
			FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			FIBITMAP dib = FreeImage.LoadFromStream(data, ref format);
			if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Couldn't decode the image data");
			}
			TextureDecoder.DibLoaded(dib);
			bool result = ClearMetadata(dib);
			using (FileStream stream = File.OpenWrite(outputFile))
			{
				FreeImage.SaveToStream(dib, stream, format);
			}
			TextureDecoder.UnloadDib(dib);
			return result;
		}

		private static bool ClearMetadata(FIBITMAP dib)
		{
			foreach (MetadataModel item in new ImageMetadata(dib, hideEmptyModels: true, includeRaw: true))
			{
				if (item.Model != FREE_IMAGE_MDMODEL.FIMD_ANIMATION && !item.DestroyModel())
				{
					return false;
				}
			}
			return true;
		}

		public static void ConvertToEXR(Stream data, string outputFile, int maxSize = -1)
		{
			FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			FIBITMAP dib = FreeImage.LoadFromStream(data, ref format);
			if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Couldn't decode the image data");
			}
			TextureDecoder.DibLoaded(dib);
			dib = Rescale(dib, maxSize);
			using (FileStream stream = File.OpenWrite(outputFile))
			{
				FreeImage.SaveToStream(dib, stream, FREE_IMAGE_FORMAT.FIF_EXR, FREE_IMAGE_SAVE_FLAGS.EXR_ZIP);
			}
			TextureDecoder.UnloadDib(dib);
		}

		public static FIBITMAP EnsureNonHDR(FIBITMAP dib, bool unloadOld = true)
		{
			FREE_IMAGE_TYPE imageType = FreeImage.GetImageType(dib);
			if (imageType == FREE_IMAGE_TYPE.FIT_RGBF || imageType == FREE_IMAGE_TYPE.FIT_RGBAF)
			{
				FIBITMAP result = FreeImage.ToneMapping(dib, FREE_IMAGE_TMO.FITMO_DRAGO03, 0.0, 0.0);
				if (unloadOld)
				{
					FreeImage.Unload(dib);
				}
				return result;
			}
			return dib;
		}

		public static FIBITMAP Ensure24BPP(FIBITMAP dib, bool unloadOld = true)
		{
			if (FreeImage.IsTransparent(dib) || FreeImage.GetBPP(dib) > 24)
			{
				FIBITMAP result = FreeImage.ConvertTo24Bits(dib);
				if (unloadOld)
				{
					FreeImage.Unload(dib);
				}
				return result;
			}
			return dib;
		}

		public static FIBITMAP Rescale(FIBITMAP dib, int maxSize = -1)
		{
			if (maxSize > 0)
			{
				int width = (int)FreeImage.GetWidth(dib);
				int height = (int)FreeImage.GetHeight(dib);
				int num = MathX.Max(width, height);
				if (num > maxSize)
				{
					double num2 = (double)maxSize / (double)num;
					width = (int)((double)width * num2);
					height = (int)((double)height * num2);
					FIBITMAP fIBITMAP = FreeImage.Rescale(dib, width, height, FREE_IMAGE_FILTER.FILTER_LANCZOS3);
					TextureDecoder.DibLoaded(fIBITMAP);
					TextureDecoder.UnloadDib(dib);
					dib = fIBITMAP;
				}
			}
			return dib;
		}

		public static void ConvertToJPG(Stream data, string outputFile, int maxSize = -1)
		{
			FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			FIBITMAP dib = FreeImage.LoadFromStream(data, ref format);
			if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Couldn't decode the image data");
			}
			TextureDecoder.DibLoaded(dib);
			dib = EnsureNonHDR(dib);
			dib = Ensure24BPP(dib);
			dib = Rescale(dib, maxSize);
			using (FileStream stream = File.OpenWrite(outputFile))
			{
				FreeImage.SaveToStream(dib, stream, FREE_IMAGE_FORMAT.FIF_JPEG, FREE_IMAGE_SAVE_FLAGS.JPEG_QUALITYSUPERB);
			}
			TextureDecoder.UnloadDib(dib);
		}

		public static void ConvertToWEBP(Stream data, string outputFile, int maxSize = -1, int quality = 80)
		{
			FREE_IMAGE_FORMAT format = FREE_IMAGE_FORMAT.FIF_UNKNOWN;
			FIBITMAP dib = FreeImage.LoadFromStream(data, ref format);
			if (format == FREE_IMAGE_FORMAT.FIF_UNKNOWN)
			{
				throw new Exception("Couldn't decode the image data");
			}
			TextureDecoder.DibLoaded(dib);
			dib = EnsureNonHDR(dib);
			dib = Rescale(dib, maxSize);
			using (FileStream stream = File.OpenWrite(outputFile))
			{
				FreeImage.SaveToStream(dib, stream, FreeImage.GetFIFFromFormat("webp"), (FREE_IMAGE_SAVE_FLAGS)quality);
			}
			TextureDecoder.UnloadDib(dib);
		}
	}
	public enum VersionComparison
	{
		Exact,
		AllowNewer,
		Ignore
	}
	/// <summary>
	/// The asset variant's identifier and file.
	/// </summary>
	public class ComputedVariantResult
	{
		public readonly string identifier;

		public readonly string file;

		public ComputedVariantResult(string identifier, string file)
		{
			this.identifier = identifier;
			this.file = file;
		}
	}
	public enum AssetVariantType
	{
		Texture,
		Cubemap,
		Volume,
		Mesh,
		Shader,
		GaussianSplat
	}
	public delegate void VariantGeneratedHandler(ComputedVariantResult result);
	public static class AssetVariantHelper
	{
		public static string TempFolder = Path.GetTempPath();

		/// <summary>
		/// The primary entry point for asset variant generation.
		/// </summary>
		/// <param name="file">The path to the specific file that a variant must be generated for.</param>
		/// <param name="variantDescriptor">The descriptor of the variant to be generated, such as compression settings, etc.</param>
		/// <param name="maxThreads">Maximum number of threads to compute the variant across.</param>
		/// <param name="variantGenerated">Delegate for when the variant generation has completed.</param>
		/// <param name="variantFilter">A list of variants to filter from the generation process.</param>
		/// <returns>A list of computed variants.</returns>
		/// <exception cref="T:System.Exception">Throws an exception when an unsupported variant descriptor has been provided.</exception>
		public static List<ComputedVariantResult> GenerateVariants(string file, IAssetVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			if (!(variantDescriptor is Texture2DVariantDescriptor variantDescriptor2))
			{
				if (!(variantDescriptor is CubemapVariantDescriptor variantDescriptor3))
				{
					if (!(variantDescriptor is Texture3DVariantDescriptor variantDescriptor4))
					{
						if (!(variantDescriptor is ShaderVariantDescriptor variantDescriptor5))
						{
							if (!(variantDescriptor is MeshVariantDescriptor variantDescriptor6))
							{
								if (variantDescriptor is GaussianSplatVariantDescriptor descriptor)
								{
									return GaussianSplatVariantGenerator.GenerateVariants(file, descriptor, variantGenerated, variantFilter);
								}
								throw new Exception("Unsupported variant descriptor: " + variantDescriptor);
							}
							return MeshVariantGenerator.GenerateVariants(file, variantDescriptor6, maxThreads, variantGenerated, variantFilter);
						}
						return ShaderVariantGenerator.GenerateVariants(file, variantDescriptor5, maxThreads, variantGenerated, variantFilter);
					}
					return Texture3DVariantGenerator.GenerateVariants(file, variantDescriptor4, maxThreads, variantGenerated, variantFilter);
				}
				return CubemapVariantGenerator.GenerateVariants(file, variantDescriptor3, maxThreads, variantGenerated, variantFilter);
			}
			return Texture2DVariantGenerator.GenerateVariants(file, variantDescriptor2, maxThreads, variantGenerated, variantFilter);
		}

		public static D FromIdentifier<D>(string identifier) where D : class, IAssetVariantDescriptor
		{
			return FromIdentifier(typeof(D), identifier) as D;
		}

		public static AssetVariantType DescriptorToVariantType(Type type)
		{
			if (typeof(Texture2DVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.Texture;
			}
			if (typeof(CubemapVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.Cubemap;
			}
			if (typeof(Texture3DVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.Volume;
			}
			if (typeof(ShaderVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.Shader;
			}
			if (typeof(MeshVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.Mesh;
			}
			if (typeof(GaussianSplatVariantDescriptor).IsAssignableFrom(type))
			{
				return AssetVariantType.GaussianSplat;
			}
			throw new Exception("Invalid descriptor type: " + type);
		}

		public static IAssetVariantDescriptor FromIdentifier(Type type, string identifier)
		{
			return FromIdentifier(DescriptorToVariantType(type), identifier);
		}

		public static IAssetVariantDescriptor FromIdentifier(AssetVariantType type, string identifier)
		{
			return type switch
			{
				AssetVariantType.Texture => Texture2DVariantDescriptor.FromIdentifier(identifier), 
				AssetVariantType.Cubemap => CubemapVariantDescriptor.FromIdentifier(identifier), 
				AssetVariantType.Volume => Texture3DVariantDescriptor.FromIdentifier(identifier), 
				AssetVariantType.Shader => ShaderVariantDescriptor.FromIdentifier(identifier), 
				AssetVariantType.Mesh => MeshVariantDescriptor.FromIdentifier(identifier), 
				AssetVariantType.GaussianSplat => GaussianSplatVariantDescriptor.FromIdentifier(identifier), 
				_ => throw new Exception("Unsupported type: " + type), 
			};
		}

		public static bool VersionEquals(IAssetVariantDescriptor a, IAssetVariantDescriptor b, VersionComparison versionComparison)
		{
			switch (versionComparison)
			{
			case VersionComparison.Exact:
				if (a.VariantVersion != b.VariantVersion)
				{
					return false;
				}
				break;
			case VersionComparison.AllowNewer:
				if (a.VariantVersion < b.VariantVersion)
				{
					return false;
				}
				break;
			}
			return true;
		}
	}
	public class CubemapVariantDescriptor : TextureVariantDescriptor<CubemapVariantDescriptor, CubemapMetadata>
	{
		private delegate void ChainSegmentGenerator(int size, bool mips);

		public const int CURRENT_VERSION = 1;

		[JsonProperty(PropertyName = "size")]
		[JsonPropertyName("size")]
		public int Size { get; private set; }

		[System.Text.Json.Serialization.JsonIgnore]
		[Newtonsoft.Json.JsonIgnore]
		public int MipMapCount
		{
			get
			{
				if (base.MipMaps)
				{
					return Bitmap2DBase.MipmapLevelCount(new int2(Size, Size));
				}
				return 1;
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		[Newtonsoft.Json.JsonIgnore]
		public override string ValidationError
		{
			get
			{
				string validationError = base.ValidationError;
				if (validationError != null)
				{
					return validationError;
				}
				if (Size <= 0)
				{
					return "Size cannot be smaller or equal to 0";
				}
				if (Size > 16384)
				{
					return $"Size cannot be larger than {16384}";
				}
				if (!MathX.IsPowerOfTwo(Size))
				{
					return "Size must be power of two";
				}
				if (base.VariantVersion > 1)
				{
					return $"Variant version {base.VariantVersion} is larger than current version {1}";
				}
				if (base.TextureCompression == TextureCompression.BC3nm_Crunched || base.TextureCompression == TextureCompression.BC3nm_LZMA)
				{
					return "Cannot use normal map compression for cubemaps";
				}
				if (base.TextureCompression == TextureCompression.BC1_Crunched || base.TextureCompression == TextureCompression.BC3_Crunched)
				{
					return "Currently crunch compression is not supported for cubemaps";
				}
				return null;
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		public override string VariantIdentifier => GenerateVariantIdentifier(Size, base.MipMaps);

		public override string ValidateCloudVariant(CubemapMetadata metadata)
		{
			string text = base.ValidateCloudVariant(metadata);
			if (text != null)
			{
				return text;
			}
			if (base.MipMaps && !metadata.MipMaps)
			{
				return "Variant is requesting mipmaps, but the texture data does not contain any";
			}
			return null;
		}

		public override bool IsPotentialAlternative(CubemapVariantDescriptor other, TextureCompression? requireCompression)
		{
			if (other.VariantVersion < 1)
			{
				return false;
			}
			if (Size != other.Size)
			{
				return false;
			}
			return base.IsPotentialAlternative(other, requireCompression);
		}

		public CubemapVariantDescriptor()
		{
		}

		public CubemapVariantDescriptor(TextureCompression compression, int compressionQuality, int size, bool mipmaps, ColorPreprocess colorPreprocess, AlphaPreprocess alphaPreprocess, int version = 1)
			: base(compression, compressionQuality, mipmaps, colorPreprocess, alphaPreprocess, version)
		{
			Size = size;
		}

		[System.Text.Json.Serialization.JsonConstructor]
		[Newtonsoft.Json.JsonConstructor]
		private CubemapVariantDescriptor(bool originalAsset, int variantVersion, TextureCompression textureCompression, int compressionQuality, bool mipMaps, ColorPreprocess colorPreprocess, AlphaPreprocess alphaPreprocess, int size)
		{
			base.OriginalAsset = originalAsset;
			base.VariantVersion = variantVersion;
			base.TextureCompression = textureCompression;
			base.CompressionQuality = compressionQuality;
			base.MipMaps = mipMaps;
			base.ColorPreprocess = colorPreprocess;
			base.AlphaPreprocess = alphaPreprocess;
			Size = size;
		}

		private string GenerateVariantIdentifier(int size, bool mips)
		{
			if (base.OriginalAsset)
			{
				return null;
			}
			string value = "";
			if (base.VariantVersion > 0)
			{
				value = $"version={base.VariantVersion}&";
			}
			return $"{value}compression={base.TextureCompression}&quality={base.CompressionQuality}&size={size}&mips={mips}&colorPreprocess={base.ColorPreprocess}&alphaPreprocess={base.AlphaPreprocess}";
		}

		public override void EnsureCurrentVersion()
		{
			base.VariantVersion = 1;
		}

		public static CubemapVariantDescriptor FromIdentifier(string identifier)
		{
			TextureCompression compression;
			int quality;
			bool mips;
			ColorPreprocess colorPreprocess;
			AlphaPreprocess alphaPreprocess;
			int version;
			Dictionary<string, string> dictionary = TextureVariantDescriptor<CubemapVariantDescriptor, CubemapMetadata>.ParseBase(identifier, out compression, out quality, out mips, out colorPreprocess, out alphaPreprocess, out version);
			if (dictionary == null)
			{
				return new CubemapVariantDescriptor();
			}
			int size = 0;
			foreach (KeyValuePair<string, string> item in dictionary)
			{
				string key = item.Key;
				string value = item.Value;
				if (key == "size")
				{
					size = int.Parse(value);
				}
			}
			return new CubemapVariantDescriptor(compression, quality, size, mips, colorPreprocess, alphaPreprocess, version);
		}

		public override bool Equals(CubemapVariantDescriptor other, VersionComparison versionComparison)
		{
			if (!base.Equals(other, versionComparison))
			{
				return false;
			}
			return Size == other.Size;
		}

		public override bool Equals(object obj)
		{
			if (obj is CubemapVariantDescriptor other)
			{
				return Equals(other);
			}
			return false;
		}

		public static bool operator ==(CubemapVariantDescriptor left, CubemapVariantDescriptor right)
		{
			return EqualityComparer<CubemapVariantDescriptor>.Default.Equals(left, right);
		}

		public static bool operator !=(CubemapVariantDescriptor left, CubemapVariantDescriptor right)
		{
			return !(left == right);
		}

		public override int GetHashCode()
		{
			return base.GetHashCode() * -1521134295 + Size.GetHashCode();
		}

		public override List<CubemapVariantDescriptor> GenerateCloudChain()
		{
			if (base.OriginalAsset)
			{
				throw new Exception("Cannot generate cloud chain for original asset request");
			}
			List<CubemapVariantDescriptor> list = new List<CubemapVariantDescriptor>();
			GenerateChain(delegate(int size, bool mips)
			{
				list.Add(new CubemapVariantDescriptor(base.TextureCompression, base.CompressionQuality, size, mips, base.ColorPreprocess, base.AlphaPreprocess));
			});
			return list;
		}

		public override void GenerateLoadChain(List<string> chain)
		{
			if (base.OriginalAsset)
			{
				chain.Add(null);
				return;
			}
			GenerateChain(delegate(int size, bool mips)
			{
				chain.Add(GenerateVariantIdentifier(size, mips));
			});
		}

		private void GenerateChain(ChainSegmentGenerator onGeneratedSegment)
		{
			if (base.MipMaps)
			{
				int num = Size;
				bool flag;
				do
				{
					flag = num * num * 6 <= 16384;
					bool mips = !base.TextureCompression.IsRaw() && flag;
					onGeneratedSegment(num, mips);
					num /= 2;
				}
				while (!flag);
			}
			else
			{
				onGeneratedSegment(Size, mips: false);
			}
		}
	}
	public enum GaussianSplatDataType
	{
		/// <summary>
		/// Single buffer (position/scale/color/SH)
		/// </summary>
		Buffer,
		/// <summary>
		/// Chunk data. This is needed for normalized buffers
		/// </summary>
		ChunkData
