	public class GaussianSplatVariantDescriptor : IAssetVariantDescriptor<GaussianSplatVariantDescriptor, GaussianSplatMetadata>, IAssetVariantDescriptor, IEquatable<GaussianSplatVariantDescriptor>
	{
		public const string POS_NAME = "positions";

		public const string ROT_NAME = "rotations";

		public const string SCL_NAME = "scales";

		public const string COL_NAME = "colors";

		public const string SH_NAME = "sh";

		public const string COMPRESSION_NAME = "compression";

		public const int CURRENT_VERSION = 0;

		public const int BUFFER_TYPE_COUNT = 5;

		public bool OriginalAsset
		{
			get
			{
				if (DefinedFormatCount == 0 && !BufferDataType.HasValue)
				{
					return !BufferCompression.HasValue;
				}
				return false;
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		public bool IsValid => ValidationError == null;

		[System.Text.Json.Serialization.JsonIgnore]
		public bool IsComposite => DefinedFormatCount == 5;

		[System.Text.Json.Serialization.JsonIgnore]
		public int DefinedFormatCount
		{
			get
			{
				int num = 0;
				if (PositionFormat.HasValue)
				{
					num++;
				}
				if (RotationFormat.HasValue)
				{
					num++;
				}
				if (ScaleFormat.HasValue)
				{
					num++;
				}
				if (ColorFormat.HasValue)
				{
					num++;
				}
				if (SphericalHarmonicsFormat.HasValue)
				{
					num++;
				}
				return num;
			}
		}

		/// <summary>
		/// Indicates if any of the buffers require the chunk data - they're normalized buffers
		/// </summary>
		[System.Text.Json.Serialization.JsonIgnore]
		public bool UsesChunkData
		{
			get
			{
				GaussianVectorFormat? positionFormat = PositionFormat;
				if (!positionFormat.HasValue || !positionFormat.GetValueOrDefault().UsesChunks())
				{
					positionFormat = ScaleFormat;
					if (!positionFormat.HasValue || !positionFormat.GetValueOrDefault().UsesChunks())
					{
						GaussianColorFormat? colorFormat = ColorFormat;
						if (!colorFormat.HasValue || !colorFormat.GetValueOrDefault().UsesChunks())
						{
							return SphericalHarmonicsFormat?.UsesChunks() ?? false;
						}
					}
				}
				return true;
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		public string ValidationError
		{
			get
			{
				if (BufferCompression != GaussianSplatBufferCompression.LZ4)
				{
					return "Missing BufferCompression";
				}
				int definedFormatCount = DefinedFormatCount;
				switch (BufferDataType)
				{
				case GaussianSplatDataType.Buffer:
					if (definedFormatCount != 1)
					{
						return "Data type is buffer, but there's more than 1 buffer type definition";
					}
					break;
				case GaussianSplatDataType.ChunkData:
					if (definedFormatCount != 0)
					{
						return "Data type is chunks, but there's a buffer type definition.";
					}
					break;
				case null:
					if (definedFormatCount != 5)
					{
						return "A composite variant is missing some buffer type definitions.";
					}
					break;
				}
				return null;
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		public string VariantIdentifier
		{
			get
			{
				if (IsComposite)
				{
					return $"{"positions"}={PositionFormat.Value}&{"rotations"}={RotationFormat.Value}&{"scales"}={ScaleFormat.Value}&{"colors"}={ColorFormat.Value}&{"sh"}={SphericalHarmonicsFormat.Value}&{CompressionIdentifier}";
				}
				switch (BufferDataType)
				{
				case GaussianSplatDataType.ChunkData:
					return "datatype=chunks&" + CompressionIdentifier;
				case GaussianSplatDataType.Buffer:
					if (PositionFormat.HasValue)
					{
						return $"{"positions"}={PositionFormat.Value}&{CompressionIdentifier}";
					}
					if (RotationFormat.HasValue)
					{
						return $"{"rotations"}={RotationFormat.Value}&{CompressionIdentifier}";
					}
					if (ScaleFormat.HasValue)
					{
						return $"{"scales"}={ScaleFormat.Value}&{CompressionIdentifier}";
					}
					if (ColorFormat.HasValue)
					{
						return $"{"colors"}={ColorFormat.Value}&{CompressionIdentifier}";
					}
					if (SphericalHarmonicsFormat.HasValue)
					{
						return $"{"sh"}={SphericalHarmonicsFormat.Value}&{CompressionIdentifier}";
					}
					throw new Exception("No buffer format defined");
				case null:
					if (OriginalAsset)
					{
						return null;
					}
					throw new Exception("Invalid variant");
				default:
					throw new Exception("Invalid buffer data type: " + BufferDataType.ToString());
				}
			}
		}

		[System.Text.Json.Serialization.JsonIgnore]
		private string CompressionIdentifier
		{
			get
			{
				if (!BufferCompression.HasValue)
				{
					throw new InvalidOperationException("Compression type is not set");
				}
				return $"{"compression"}={BufferCompression}";
			}
		}

