		public List<GaussianSplatVariantDescriptor> GenerateCloudChain()
		{
			List<GaussianSplatVariantDescriptor> list = new List<GaussianSplatVariantDescriptor>();
			if (IsComposite)
			{
				if (UsesChunkData)
				{
					list.Add(ExtractChunksVariant());
				}
				list.Add(ExtractPositionBufferVariant());
				list.Add(ExtractRotationBufferVariant());
				list.Add(ExtractScaleBufferVariant());
				list.Add(ExtractColorBufferVariant());
				list.Add(ExtractSHBufferVariant());
			}
			else
			{
				list.Add(this);
			}
			return list;
		}

		public void GenerateLoadChain(List<string> chain)
		{
			if (OriginalAsset)
			{
				chain.Add(null);
				return;
			}
			foreach (GaussianSplatVariantDescriptor item in GenerateCloudChain())
			{
				chain.Add(item.VariantIdentifier);
			}
		}

