		public string ValidateCloudVariant(GaussianSplatMetadata metadata)
		{
			if (!IsComposite)
			{
				return "Cloud variants must be composite";
			}
			string validationError = ValidationError;
			if (validationError != null)
			{
				return validationError;
			}
			if (SphericalHarmonicsFormat.Value.IsClustered() && GaussianSplatCompressor.GetSHCount(metadata.SplatCount, SphericalHarmonicsFormat.Value) > metadata.SplatCount)
			{
				return "Gaussian cloud has fewer splats than the clustered count";
			}
			return null;
		}

		public static GaussianSplatVariantDescriptor FromIdentifier(string query)
		{
			if (string.IsNullOrEmpty(query))
			{
				return new GaussianSplatVariantDescriptor();
			}
			Dictionary<string, string> dictionary = StringHelper.ParseQueryString(query);
			int variantVersion = 0;
			GaussianSplatBufferCompression? gaussianSplatBufferCompression = null;
			GaussianVectorFormat? positionFormat = null;
			GaussianRotationFormat? rotationFormat = null;
			GaussianVectorFormat? scaleFormat = null;
			GaussianColorFormat? colorFormat = null;
			GaussianSHFormat? sphericalHarmonicsFormat = null;
			bool flag = false;
			foreach (KeyValuePair<string, string> item in dictionary)
			{
				string key = item.Key;
				string value = item.Value;
				switch (key)
				{
				case "version":
					variantVersion = int.Parse(value);
					break;
				case "positions":
					positionFormat = Enums.Parse<GaussianVectorFormat>(value);
					break;
				case "rotations":
					rotationFormat = Enums.Parse<GaussianRotationFormat>(value);
					break;
				case "scales":
					scaleFormat = Enums.Parse<GaussianVectorFormat>(value);
					break;
				case "colors":
					colorFormat = Enums.Parse<GaussianColorFormat>(value);
					break;
				case "sh":
					sphericalHarmonicsFormat = Enums.Parse<GaussianSHFormat>(value);
					break;
				case "compression":
					gaussianSplatBufferCompression = Enums.Parse<GaussianSplatBufferCompression>(value);
					break;
				case "datatype":
					if (value == "chunks")
					{
						flag = true;
						break;
					}
					throw new ArgumentException("Invalid data type: " + value);
				}
			}
			int num = 0;
			if (positionFormat.HasValue)
			{
				num++;
			}
			if (rotationFormat.HasValue)
			{
				num++;
			}
			if (scaleFormat.HasValue)
			{
				num++;
			}
			if (colorFormat.HasValue)
			{
				num++;
			}
			if (sphericalHarmonicsFormat.HasValue)
			{
				num++;
			}
			if (flag)
			{
				if (num > 0)
				{
					throw new ArgumentException("Chunks variant cannot specify buffer data formats");
				}
				if (!gaussianSplatBufferCompression.HasValue)
				{
					throw new ArgumentException("Chunks variant is missing buffer compression");
				}
				return new GaussianSplatVariantDescriptor(gaussianSplatBufferCompression.Value, GaussianSplatDataType.ChunkData, null, null, null, null, null, variantVersion);
			}
			return new GaussianSplatVariantDescriptor(gaussianSplatBufferCompression.Value, (num == 1) ? new GaussianSplatDataType?(GaussianSplatDataType.Buffer) : ((GaussianSplatDataType?)null), positionFormat, rotationFormat, scaleFormat, colorFormat, sphericalHarmonicsFormat, variantVersion);
		}

		public GaussianSplatVariantDescriptor Clone()
		{
			return System.Text.Json.JsonSerializer.Deserialize<GaussianSplatVariantDescriptor>(System.Text.Json.JsonSerializer.Serialize(this));
		}

