			return gaussianSplatVariantDescriptor;
		}

		public GaussianSplatVariantDescriptor ExtractSHBufferVariant()
		{
			CheckBufferVariantExtraction();
			GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor = Clone();
			gaussianSplatVariantDescriptor.BufferDataType = GaussianSplatDataType.Buffer;
			gaussianSplatVariantDescriptor.PositionFormat = null;
			gaussianSplatVariantDescriptor.RotationFormat = null;
			gaussianSplatVariantDescriptor.ScaleFormat = null;
			gaussianSplatVariantDescriptor.ColorFormat = null;
			return gaussianSplatVariantDescriptor;
		}

		public GaussianSplatVariantDescriptor ExtractChunksVariant()
		{
			CheckBufferVariantExtraction();
			GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor = Clone();
			gaussianSplatVariantDescriptor.PositionFormat = null;
			gaussianSplatVariantDescriptor.RotationFormat = null;
			gaussianSplatVariantDescriptor.ScaleFormat = null;
			gaussianSplatVariantDescriptor.ColorFormat = null;
			gaussianSplatVariantDescriptor.SphericalHarmonicsFormat = null;
			gaussianSplatVariantDescriptor.BufferDataType = GaussianSplatDataType.ChunkData;
			return gaussianSplatVariantDescriptor;
		}

		private void CheckBufferVariantExtraction()
		{
			if (!IsComposite)
			{
				throw new InvalidOperationException("Specific buffer variants can only be extracted from a composite variant");
			}
		}
