			{
				if (VariantVersion > 2 || VariantVersion < 0)
				{
					return $"Variant version {VariantVersion} is higher than current version {2} or less than 0";
				}
				if (DataType.HasValue && !Enum.IsDefined(typeof(MeshDataType), DataType))
				{
					return $"Invalid MeshDataType: {DataType}";
				}
				return null;
			}
		}

