		public MeshCompression Compression { get; private set; }

		public MeshVariantDescriptor(MeshDataType? dataType, MeshCompression compression, int version = 2)
		{
			VariantVersion = version;
			DataType = dataType;
			Compression = compression;
		}

		[System.Text.Json.Serialization.JsonConstructor]
		[Newtonsoft.Json.JsonConstructor]
		private MeshVariantDescriptor(int variantVersion, MeshDataType? dataType, MeshCompression compression)
		{
			VariantVersion = variantVersion;
			DataType = dataType;
			Compression = compression;
		}

		public static MeshVariantDescriptor FromIdentifier(string query)
		{
			Dictionary<string, string> dictionary = StringHelper.ParseQueryString(query);
			MeshDataType result = MeshDataType.Mesh;
			MeshCompression result2 = MeshCompression.None;
			int version = 0;
			foreach (KeyValuePair<string, string> item in dictionary)
			{
				string key = item.Key;
				string value = item.Value;
				switch (key)
				{
				case "version":
					version = int.Parse(value);
					break;
				case "datatype":
					if (!Enum.TryParse<MeshDataType>(value, ignoreCase: true, out result))
					{
						throw new ArgumentException("Invalid data type: " + value);
					}
					break;
				case "compression":
					if (!Enum.TryParse<MeshCompression>(value, ignoreCase: true, out result2))
					{
						throw new ArgumentException("Invalid compression: " + value);
					}
					break;
				}
			}
			return new MeshVariantDescriptor(result, result2, version);
		}

		public void EnsureCurrentVersion()
		{
			VariantVersion = 2;
		}

		public bool Equals(MeshVariantDescriptor other, VersionComparison versionComparison)
		{
			if (!AssetVariantHelper.VersionEquals(this, other, versionComparison))
			{
