		public List<MeshVariantDescriptor> GetBestAlternateChain(List<MeshVariantDescriptor> availableDescriptors, Predicate<MeshVariantDescriptor> variantFilter = null)
		{
			foreach (MeshVariantDescriptor availableDescriptor in availableDescriptors)
			{
				if (availableDescriptor.DataType == DataType)
				{
					return new List<MeshVariantDescriptor> { availableDescriptor };
				}
			}
			return null;
		}

		public string ValidateCloudVariant(MeshMetadata metadata)
		{
			string validationError = ValidationError;
			if (validationError != null)
			{
				return validationError;
			}
			if (OriginalAsset)
			{
				return "OriginalAsset variants are never handled by the cloud";
			}
			if (!DataType.HasValue)
			{
				return "Cloud variants need to specify the data type";
			}
			if (DataType == MeshDataType.Mesh)
			{
				return "Cannot specify DataType to be Mesh";
			}
			if (DataType == MeshDataType.MeshCollider || DataType == MeshDataType.DualSidedMeshCollider)
			{
				int num = metadata.TotalTriangleCount + metadata.TotalPointCount;
				if (DataType == MeshDataType.DualSidedMeshCollider)
				{
					num *= 2;
				}
				if (num >= 16777216)
				{
					return $"Cannot request collider metadata for meshes with more than {16777216} triangles";
				}
			}
			return null;
		}
	}
