	public static class TextureCompressionExtensions
	{
		public const int MAXIMUM_COMPRESSION_QUALITY = 100;

		public const int MINIMUM_COMPRESSION_QUALITY = 0;

		/// <summary>
		/// The default quality for most assets is the maximum, 100.
		/// </summary>
		public static int DEFAULT_COMPRESSION_QUALITY = 100;

		public static bool IsRaw(this TextureCompression compression)
		{
			if ((uint)compression <= 1u)
			{
				return true;
			}
			return false;
		}

		public static bool IsHDR(this TextureCompression compression)
		{
			if (compression == TextureCompression.RawRGBAHalf || compression == TextureCompression.BC6H_LZMA)
			{
				return true;
			}
			return false;
		}

		/// <summary>
		/// Is this compression format block compressed?
		/// </summary>
		/// <param name="compression">Target compression format</param>
		/// <returns>true if it can be block compressed. false otherwise</returns>
		/// <remarks>Block compression is handled by <see cref="M:Elements.Assets.BitmapBlockCompression.BlockCompress(System.Collections.Generic.List{Elements.Assets.MipMapBuffer},System.Collections.Generic.List{Elements.Assets.MipMapBuffer},Renderite.Shared.TextureFormat,Renderite.Shared.TextureFormat,System.Int32,System.Int32)" /></remarks>
		public static bool IsBlockCompressed(this TextureCompression compression)
		{
			if ((uint)(compression - 7) <= 5u || (uint)(compression - 15) <= 7u)
			{
				return true;
			}
			return false;
		}

		/// <summary>
		/// Is this compression format crunch compressed?
		/// </summary>
		/// <remarks>
		/// Crunch compression is handled by <see cref="M:Elements.Assets.Bitmap2D.CrunchCompress(System.String,Elements.Assets.TextureCompression,System.Int32)" />
		/// </remarks>
		/// <param name="compression">Target compression format</param>
		/// <returns>true if it can be crunch compressed. false otherwise</returns>
		public static bool IsCrunchCompressed(this TextureCompression compression)
		{
			if ((uint)(compression - 2) <= 4u || (uint)(compression - 13) <= 1u)
			{
				return true;
			}
			return false;
		}

		/// <summary>
		/// Is this compression format for Normal Maps?
		/// </summary>
		/// <param name="compression">Target compression format</param>
		/// <returns>true for normal map, false otherwise</returns>
		/// <remarks>All normal maps are also non-perceptual as marked in <see cref="M:Elements.Assets.TextureCompressionExtensions.IsPerceptual(Elements.Assets.TextureCompression)" /></remarks>
		public static bool IsNormalMap(this TextureCompression compression)
		{
			if (compression == TextureCompression.BC3nm_Crunched || compression == TextureCompression.BC3nm_LZMA)
			{
				return true;
			}
			return false;
		}

		/// <summary>
		/// Is this compression format "perceptual"?
		/// </summary>
		/// <param name="compression">Target Compression Format</param>
		/// <returns>true for perceptual, false otherwise</returns>
		/// <remarks>Perceptual is sent as a flag to Crunch Compression <see cref="M:Elements.Assets.Bitmap2D.CrunchCompress(System.String,Elements.Assets.TextureCompression,System.Int32)" /></remarks>
		public static bool IsPerceptual(this TextureCompression compression)
		{
			if (compression.IsNormalMap())
			{
				return false;
			}
			if ((uint)(compression - 5) <= 1u)
			{
				return false;
			}
			return true;
		}

		public static TextureFormat ToFormat(this TextureCompression compression, ImageMetadataBase metadata = null, bool threeChannelSupported = false, ColorProfile profile = ColorProfile.sRGB)
		{
			switch (compression)
			{
			case TextureCompression.BC1_Crunched:
			case TextureCompression.BC1_Crunched_Non_Perceptual:
			case TextureCompression.BC1_LZMA:
				return TextureFormat.BC1;
			case TextureCompression.BC3nm_Crunched:
			case TextureCompression.BC3nm_LZMA:
				return TextureFormat.BC3;
			case TextureCompression.BC3_Crunched:
			case TextureCompression.BC3_Crunched_Non_Perceptual:
			case TextureCompression.BC3_LZMA:
				return TextureFormat.BC3;
			case TextureCompression.BC4_LZMA:
				return TextureFormat.BC4;
			case TextureCompression.BC6H_LZMA:
				return TextureFormat.BC6H;
			case TextureCompression.BC7_LZMA:
				return TextureFormat.BC7;
			case TextureCompression.ETC2_RGB_Crunched:
			case TextureCompression.ETC2_RGB_LZMA:
				return TextureFormat.ETC2_RGB;
			case TextureCompression.ETC2_RGBA8_Crunched:
			case TextureCompression.ETC2_RGBA8_LZMA:
				return TextureFormat.ETC2_RGBA8;
			case TextureCompression.ASTC_4x4_LZMA:
				return TextureFormat.ASTC_4x4;
			case TextureCompression.ASTC_5x5_LZMA:
				return TextureFormat.ASTC_5x5;
			case TextureCompression.ASTC_6x6_LZMA:
				return TextureFormat.ASTC_6x6;
			case TextureCompression.ASTC_8x8_LZMA:
				return TextureFormat.ASTC_8x8;
			case TextureCompression.ASTC_10x10_LZMA:
				return TextureFormat.ASTC_10x10;
			case TextureCompression.ASTC_12x12_LZMA:
				return TextureFormat.ASTC_12x12;
			case TextureCompression.RawRGBA:
				if (metadata != null && metadata.AlphaData == AlphaChannelData.FullyOpaque && threeChannelSupported)
				{
					return TextureFormat.RGB24;
				}
				return TextureFormat.RGBA32;
			case TextureCompression.RawRGBAHalf:
				return TextureFormat.RGBAHalf;
			default:
				throw new Exception("Invalid compression format: " + compression);
			}
		}

		/// <summary>
		/// Gets the Recommended compression quality for this TextureCompression format.
		/// </summary>
		/// <param name="compression">Target compression format</param>
		/// <returns>quality, expressed as a percentage 0-100.</returns>
		public static int GetRecommendedQuality(this TextureCompression compression)
		{
			if (compression.IsBlockCompressed())
			{
				return compression.ToFormat().GetRecommendedBlockCompressionQuality();
			}
			return DEFAULT_COMPRESSION_QUALITY;
		}
	}
