	public static class CubemapVariantGenerator
	{
		/// <summary>
		/// Generates variants of a given source asset.
		/// Only gets called if no such variant exists.
		/// </summary>
		/// <param name="file"></param>
		/// <param name="variantDescriptor"></param>
		/// <param name="maxThreads"></param>
		/// <param name="variantGenerated"></param>
		/// <param name="variantFilter"></param>
		/// <returns>The resulting variant data.</returns>
		/// <exception cref="T:System.Exception"></exception>
		public static List<ComputedVariantResult> GenerateVariants(string file, CubemapVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			List<CubemapVariantDescriptor> list2 = variantDescriptor.GenerateCloudChain();
			BitmapCube bitmapCube = BitmapCube.Load(file);
			if (variantDescriptor.ColorPreprocess == ColorPreprocess.HDRsRGB)
			{
				bitmapCube.ConvertHDRToHDRsRGB();
			}
			else if (variantDescriptor.ColorPreprocess == ColorPreprocess.sRGB)
			{
				bitmapCube.ConvertTosRGB();
			}
			if (variantDescriptor.AlphaPreprocess == AlphaPreprocess.sRGB)
			{
				bitmapCube.AdjustAlphaGamma(2.2f);
			}
			if (variantDescriptor.ColorPreprocess == ColorPreprocess.LogLUV && variantDescriptor.AlphaPreprocess == AlphaPreprocess.LogLUV)
			{
				bitmapCube.EncodeLogLUV();
			}
			if (variantDescriptor.ColorPreprocess == ColorPreprocess.RGBM && variantDescriptor.AlphaPreprocess == AlphaPreprocess.RGBM)
			{
				bitmapCube.EncodeRGBM();
			}
			if (variantDescriptor.MipMaps && !bitmapCube.HasMipMaps)
			{
				throw new Exception("Variant requires mipmaps, but the source cubemap doesn't have any!");
			}
			List<BitmapCube> list3 = new List<BitmapCube>();
			if (variantDescriptor.MipMaps)
			{
				for (int i = 0; i < list2.Count; i++)
				{
					list3.Add(bitmapCube.ExtractMipMap(i, list2[i].MipMaps));
				}
			}
			else
			{
				list3.Add(bitmapCube);
			}
			for (int num = list2.Count - 1; num >= 0; num--)
			{
				CubemapVariantDescriptor cubemapVariantDescriptor = list2[num];
				BitmapCube bitmapCube2 = list3[num];
				if (variantFilter == null || variantFilter(cubemapVariantDescriptor.VariantIdentifier))
				{
					string file2 = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
					if (cubemapVariantDescriptor.TextureCompression == TextureCompression.RawRGBA)
					{
						if (bitmapCube2.Format != TextureFormat.RGBA32)
						{
							bitmapCube2 = bitmapCube2.ConvertTo(TextureFormat.RGBA32);
						}
						bitmapCube2.Save(file2);
					}
					else if (cubemapVariantDescriptor.TextureCompression == TextureCompression.RawRGBAHalf)
					{
						if (bitmapCube2.Format != TextureFormat.RGBAHalf)
						{
							bitmapCube2 = bitmapCube2.ConvertTo(TextureFormat.RGBAHalf);
						}
						bitmapCube2.Save(file2);
					}
					else
					{
						TextureFormat targetFormat = cubemapVariantDescriptor.TextureCompression.ToFormat();
						if (BitmapCube.SupportsBlockCompression(targetFormat))
						{
							bitmapCube2.BlockCompress(targetFormat, cubemapVariantDescriptor.CompressionQuality, maxThreads).Save(file2);
						}
						else
						{
							file2 = null;
						}
					}
					ComputedVariantResult computedVariantResult = new ComputedVariantResult(cubemapVariantDescriptor.VariantIdentifier, file2);
					list3[num] = null;
					list.Add(computedVariantResult);
					variantGenerated?.Invoke(computedVariantResult);
				}
			}
			return list;
		}
	}
	public static class GaussianSplatVariantGenerator
	{
		public static List<ComputedVariantResult> GenerateVariants(string file, GaussianSplatVariantDescriptor descriptor, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			variantFilter = variantFilter ?? ((Predicate<string>)((string s) => true));
			if (!descriptor.IsComposite)
			{
				throw new ArgumentException("Variant descriptor must be composite");
			}
			GaussianCloud cloud = new GaussianCloud(file);
			cloud = GaussianSplatCompressor.ReorderMorton(cloud);
			GenerateBufferVariants(cloud, descriptor, useChunks: false, list, variantGenerated, variantFilter);
			GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor = descriptor.ExtractRotationBufferVariant();
			if (variantFilter(gaussianSplatVariantDescriptor.VariantIdentifier))
			{
				byte[] buffer = GaussianSplatCompressor.EncodeRotationBuffer(cloud.Rotations, gaussianSplatVariantDescriptor.RotationFormat.Value);
				BufferGenerated(gaussianSplatVariantDescriptor, buffer, list, variantGenerated);
			}
			if (descriptor.UsesChunkData)
			{
				GaussianCloudChunk[] array = GaussianSplatCompressor.ConvertToChunked(cloud);
				GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor2 = descriptor.ExtractChunksVariant();
				if (variantFilter(gaussianSplatVariantDescriptor2.VariantIdentifier))
				{
					byte[] array2 = new byte[array.Length * 64];
					MemoryMarshal.Cast<GaussianCloudChunk, byte>(array.AsSpan()).CopyTo(array2.AsSpan());
					BufferGenerated(gaussianSplatVariantDescriptor2, array2, list, variantGenerated);
				}
				GenerateBufferVariants(cloud, descriptor, useChunks: true, list, variantGenerated, variantFilter);
			}
			return list;
		}

		private static void GenerateBufferVariants(GaussianCloud cloud, GaussianSplatVariantDescriptor descriptor, bool useChunks, List<ComputedVariantResult> results, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			if (descriptor.PositionFormat.Value.UsesChunks() == useChunks)
			{
				GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor = descriptor.ExtractPositionBufferVariant();
				if (variantFilter(gaussianSplatVariantDescriptor.VariantIdentifier))
				{
					byte[] buffer = GaussianSplatCompressor.ConvertBuffer(cloud.Positions, gaussianSplatVariantDescriptor.PositionFormat.Value);
					BufferGenerated(gaussianSplatVariantDescriptor, buffer, results, variantGenerated);
				}
			}
			if (descriptor.ScaleFormat.Value.UsesChunks() == useChunks)
			{
				GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor2 = descriptor.ExtractScaleBufferVariant();
				if (variantFilter(gaussianSplatVariantDescriptor2.VariantIdentifier))
				{
					byte[] buffer2 = GaussianSplatCompressor.ConvertBuffer(cloud.Scales, gaussianSplatVariantDescriptor2.ScaleFormat.Value);
					BufferGenerated(gaussianSplatVariantDescriptor2, buffer2, results, variantGenerated);
				}
			}
			if (descriptor.ColorFormat.Value.UsesChunks() == useChunks)
			{
				GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor3 = descriptor.ExtractColorBufferVariant();
				if (variantFilter(gaussianSplatVariantDescriptor3.VariantIdentifier))
				{
					byte[] buffer3 = GaussianSplatCompressor.EncodeColorBuffer(cloud, gaussianSplatVariantDescriptor3.ColorFormat.Value);
					BufferGenerated(gaussianSplatVariantDescriptor3, buffer3, results, variantGenerated);
				}
			}
			if (descriptor.SphericalHarmonicsFormat.Value.UsesChunks() == useChunks)
			{
				GaussianSplatVariantDescriptor gaussianSplatVariantDescriptor4 = descriptor.ExtractSHBufferVariant();
				if (variantFilter(gaussianSplatVariantDescriptor4.VariantIdentifier))
				{
					byte[] buffer4 = GaussianSplatCompressor.EncodeSH(cloud, gaussianSplatVariantDescriptor4.SphericalHarmonicsFormat.Value);
					BufferGenerated(gaussianSplatVariantDescriptor4, buffer4, results, variantGenerated);
				}
			}
		}

		private static void BufferGenerated(GaussianSplatVariantDescriptor descriptor, byte[] buffer, List<ComputedVariantResult> results, VariantGeneratedHandler variantGenerated = null)
		{
			if (descriptor.IsComposite)
			{
				throw new ArgumentException("Descriptor cannot be a composite variant");
			}
			if (descriptor.BufferCompression != GaussianSplatBufferCompression.LZ4)
			{
				throw new ArgumentException("Only LZ4 compression is supported currently");
			}
			string text = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
			using (FileStream innerStream = File.OpenWrite(text))
			{
				using LZ4Stream lZ4Stream = new LZ4Stream(innerStream, CompressionMode.Compress, LZ4StreamFlags.HighCompression);
				lZ4Stream.Write(buffer, 0, buffer.Length);
			}
			ComputedVariantResult computedVariantResult = new ComputedVariantResult(descriptor.VariantIdentifier, text);
			results.Add(computedVariantResult);
			variantGenerated?.Invoke(computedVariantResult);
		}
	}
	public static class MeshVariantGenerator
	{
		public static List<ComputedVariantResult> GenerateVariants(string file, MeshVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			List<MeshVariantDescriptor> list2 = variantDescriptor.GenerateCloudChain();
			MeshX meshx = new MeshX(file);
			foreach (MeshVariantDescriptor item in list2)
			{
				if (variantFilter != null && !variantFilter(item.VariantIdentifier))
				{
					continue;
				}
				string file2 = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
				switch (item.DataType)
				{
				case MeshDataType.Mesh:
					throw new NotImplementedException("Mesh recompression isn't currently supported");
				case MeshDataType.ConvexHullCollider:
					ComputeColliderData(file2, item.Compression, delegate(Stream stream, BufferPool bufferPool)
					{
						BepuMeshHelper.ComputeConvexHull(meshx, bufferPool, null, null, out var convexHull, out var center);
						BepuMeshHelper.SerializeConvexHull(ref convexHull, in center, stream);
						convexHull.Dispose(bufferPool);
					});
					break;
				case MeshDataType.MeshCollider:
					ComputeMeshCollider(file2, meshx, item.Compression, dualSided: false);
					break;
				case MeshDataType.DualSidedMeshCollider:
					ComputeMeshCollider(file2, meshx, item.Compression, dualSided: true);
					break;
				}
				ComputedVariantResult computedVariantResult = new ComputedVariantResult(item.VariantIdentifier, file2);
				list.Add(computedVariantResult);
				variantGenerated?.Invoke(computedVariantResult);
			}
			return list;
		}

		private static void ComputeMeshCollider(string file, MeshX meshx, MeshCompression compression, bool dualSided)
		{
			ComputeColliderData(file, compression, delegate(Stream stream, BufferPool bufferPool)
			{
				BepuMeshHelper.ComputeMeshCollider(meshx, dualSided, bufferPool, null, null, out var mesh);
				BepuMeshHelper.SerializeMeshCollider(ref mesh, stream);
				mesh.Dispose(bufferPool);
			});
		}

		private static void ComputeColliderData(string file, MeshCompression compression, Action<Stream, BufferPool> compute)
		{
			BufferPool bufferPool = new BufferPool();
			try
			{
				ComputeColliderData(file, compression, delegate(Stream stream)
				{
					compute(stream, bufferPool);
				});
			}
			finally
			{
				if (bufferPool != null)
				{
					((IDisposable)bufferPool).Dispose();
				}
			}
		}

		private static void ComputeColliderData(string file, MeshCompression compression, Action<Stream> compute)
		{
			using FileStream fileStream = File.OpenWrite(file);
			switch (compression)
			{
			case MeshCompression.None:
				compute(fileStream);
				break;
			case MeshCompression.LZ4:
			{
				using LZ4Stream obj = new LZ4Stream(fileStream, CompressionMode.Compress, LZ4StreamFlags.HighCompression);
				compute(obj);
				break;
			}
			case MeshCompression.LZMA:
			{
				using MemoryStream memoryStream = new MemoryStream();
				compute(memoryStream);
				memoryStream.Seek(0L, SeekOrigin.Begin);
				LZMAHelper.Compress(memoryStream, fileStream);
				break;
			}
			default:
				throw new NotImplementedException("Unsupported mesh compression: " + compression);
			}
		}
	}
	public static class ShaderVariantGenerator
	{
		public static List<ComputedVariantResult> GenerateVariants(string file, ShaderVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			if (!File.Exists(file))
			{
				UniLog.Error("Shader package file does not exist: " + file);
				return list;
			}
			try
			{
				using ShaderPackage shaderPackage = new ShaderPackage(file);
				string text = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
				byte[] array = shaderPackage.ReadVariant(variantDescriptor.TargetPlatform.PackageName(), variantDescriptor.VariantIndex);
				if (array != null)
				{
					File.WriteAllBytes(text, array);
					ComputedVariantResult computedVariantResult = new ComputedVariantResult(variantDescriptor.VariantIdentifier, text);
					list.Add(computedVariantResult);
					variantGenerated?.Invoke(computedVariantResult);
				}
			}
			catch (Exception ex)
			{
				UniLog.Error("Error opening shader package file: " + ex.Message);
			}
			return list;
		}
	}
	public static class Texture2DVariantGenerator
	{
		public static List<ComputedVariantResult> GenerateVariants(string file, Texture2DVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			List<Texture2DVariantDescriptor> list2 = variantDescriptor.GenerateCloudChain();
			Bitmap2D bitmap = Bitmap2D.Load(file, (!variantDescriptor.Filtering.HasValue) ? ((bool?)null) : new bool?(false));
			bitmap = TextureVariantGenerator.Preprocess(bitmap, variantDescriptor.TextureCompression, variantDescriptor.ColorPreprocess, variantDescriptor.AlphaPreprocess, allowARGB: true);
			List<Bitmap2D> list3 = new List<Bitmap2D>();
			if (variantDescriptor.Filtering.HasValue)
			{
				foreach (Texture2DVariantDescriptor item in list2)
				{
					bitmap = bitmap.GetRescaled(new int2(item.Width, item.Height), item.MipMaps, forceRescale: false, item.Filtering.Value);
					list3.Add(bitmap);
				}
			}
			else
			{
				int num = 0;
				foreach (Texture2DVariantDescriptor item2 in list2)
				{
					Bitmap2D bitmap2D = bitmap.ExtractMipMap(num++, item2.MipMaps);
					if (bitmap2D.Size.x != item2.Width && bitmap2D.Size.y != item2.Height)
					{
						throw new InvalidOperationException($"Pre-computed mipmap size doesn't match expected. Precomputed: {bitmap2D.Size}, Expected: {item2.Width}x{item2.Height}");
					}
					list3.Add(bitmap2D);
				}
			}
			for (int num2 = list2.Count - 1; num2 >= 0; num2--)
			{
				Texture2DVariantDescriptor texture2DVariantDescriptor = list2[num2];
				Bitmap2D bitmap2D2 = list3[num2];
				if (variantFilter == null || variantFilter(texture2DVariantDescriptor.VariantIdentifier))
				{
					string text = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
					if (texture2DVariantDescriptor.TextureCompression.IsBlockCompressed())
					{
						TextureFormat targetFormat = texture2DVariantDescriptor.TextureCompression.ToFormat();
						if (Bitmap2D.SupportsBlockCompression(targetFormat))
						{
							if (!bitmap2D2.FlipY)
							{
								bitmap2D2.FlipYInMemory();
							}
							bitmap2D2.BlockCompress(targetFormat, texture2DVariantDescriptor.CompressionQuality, maxThreads).SaveRaw(text);
						}
						else
						{
							text = null;
						}
					}
					else if (texture2DVariantDescriptor.TextureCompression.IsCrunchCompressed())
					{
						if (!bitmap2D2.FlipY)
						{
							bitmap2D2.FlipYInMemory();
						}
						if (!bitmap2D2.CrunchCompress(text, texture2DVariantDescriptor.TextureCompression, maxThreads))
						{
							throw new Exception($"Could not compress with {texture2DVariantDescriptor.TextureCompression.ToFormat()}. Bitmap: {bitmap2D2.ToString()}");
						}
					}
					else
					{
						switch (texture2DVariantDescriptor.TextureCompression)
						{
						case TextureCompression.RawRGBA:
							if ((bitmap2D2.Size >= 16384).Any())
							{
								text += ".png";
								if (!bitmap2D2.Save(text, 100))
								{
									throw new Exception("Failed to encode RawRGBA as 16K");
								}
							}
							else
							{
								text += ".webp";
								if (!bitmap2D2.Save(text, 200))
								{
									throw new Exception("Failed to encode RawRGBA");
								}
							}
							break;
						case TextureCompression.RawRGBAHalf:
							text += ".exr";
							if (!bitmap2D2.Save(text))
							{
								throw new Exception("Failed to encode RawRGBAHalf");
							}
							break;
						default:
							throw new Exception("Invalid texture compression: " + texture2DVariantDescriptor.TextureCompression);
						}
					}
					ComputedVariantResult computedVariantResult = new ComputedVariantResult(texture2DVariantDescriptor.VariantIdentifier, text);
					list3[num2] = null;
					list.Add(computedVariantResult);
					variantGenerated?.Invoke(computedVariantResult);
				}
			}
			return list;
		}
	}
	public static class Texture3DVariantGenerator
	{
		public static List<ComputedVariantResult> GenerateVariants(string file, Texture3DVariantDescriptor variantDescriptor, int maxThreads = -1, VariantGeneratedHandler variantGenerated = null, Predicate<string> variantFilter = null)
		{
			List<ComputedVariantResult> list = new List<ComputedVariantResult>();
			List<Texture3DVariantDescriptor> list2 = variantDescriptor.GenerateCloudChain();
			if (list2.Count > 1)
			{
				throw new NotImplementedException("Generating variant chain with more than 1 variant is not supported for Texture3D");
			}
			Bitmap3D bitmap = Bitmap3D.Load(file);
			bitmap = TextureVariantGenerator.Preprocess(bitmap, variantDescriptor.TextureCompression, variantDescriptor.ColorPreprocess, variantDescriptor.AlphaPreprocess, allowARGB: false);
			Texture3DVariantDescriptor texture3DVariantDescriptor = list2[0];
			if (variantFilter != null && !variantFilter(texture3DVariantDescriptor.VariantIdentifier))
			{
				return list;
			}
			string file2 = Path.Combine(AssetVariantHelper.TempFolder ?? Path.GetTempPath(), Guid.NewGuid().ToString());
			switch (texture3DVariantDescriptor.TextureCompression)
			{
			case TextureCompression.RawRGBA:
				bitmap.Save(file2);
				break;
			case TextureCompression.RawRGBAHalf:
				bitmap.Save(file2);
				break;
			default:
				throw new NotImplementedException("TextureCompression is not implemented for 3D textures");
			}
			ComputedVariantResult computedVariantResult = new ComputedVariantResult(texture3DVariantDescriptor.VariantIdentifier, file2);
			list.Add(computedVariantResult);
			variantGenerated?.Invoke(computedVariantResult);
			return list;
		}
	}
	internal static class TextureVariantGenerator
	{
		public static B Preprocess<B>(B bitmap, TextureCompression compression, ColorPreprocess colorPreprocess, AlphaPreprocess alphaPreprocess, bool allowARGB) where B : Bitmap, IBitmap<B>
		{
			switch (compression)
			{
			case TextureCompression.RawRGBA:
				if (bitmap.Format != TextureFormat.RGBA32 && bitmap.Format != TextureFormat.RGB24 && (bitmap.Format != TextureFormat.ARGB32 || !allowARGB))
				{
					bitmap = bitmap.ConvertTo(TextureFormat.RGBA32);
				}
				break;
			case TextureCompression.RawRGBAHalf:
				if (bitmap.Format != TextureFormat.RGBAHalf)
				{
					bitmap = bitmap.ConvertTo(TextureFormat.RGBAHalf);
				}
				break;
			case TextureCompression.BC3nm_Crunched:
			case TextureCompression.BC3nm_LZMA:
				if (!bitmap.Format.SupportsAlpha())
				{
					bitmap = bitmap.ConvertTo(TextureFormat.RGBA32);
				}
				bitmap.PackNormalMap();
				break;
			}
			switch (colorPreprocess)
			{
			case ColorPreprocess.HDRsRGB:
				bitmap.ConvertHDRToHDRsRGB();
				break;
			case ColorPreprocess.sRGB:
				bitmap.ConvertTosRGB();
				break;
			}
			if (alphaPreprocess == AlphaPreprocess.sRGB)
			{
				bitmap.AdjustAlphaGamma(2.2f);
			}
			if (colorPreprocess == ColorPreprocess.LogLUV && alphaPreprocess == AlphaPreprocess.LogLUV)
			{
				bitmap.EncodeLogLUV();
			}
			if (colorPreprocess == ColorPreprocess.RGBM && alphaPreprocess == AlphaPreprocess.RGBM)
			{
				bitmap.EncodeRGBM();
			}
			return bitmap;
		}
	}
	[DataModelType]
	public interface IAssetVariantDescriptor
	{
		/// <summary>
		/// This indicates that we want to load the original asset and not one of the generated variants.
		/// Not all assets will have original asset - only some can do this.
		/// </summary>
		bool OriginalAsset { get; }

		/// <summary>
		/// Indicates if this is a valid variant description
		/// </summary>
		bool IsValid { get; }

		/// <summary>
		/// If the variant isn't valid, this will indicate why it's not a valid one.
		/// </summary>
		string ValidationError { get; }

		/// <summary>
		/// A unique string identifier in a form of a query that fully identifiers this particular variant.
		/// </summary>
		string VariantIdentifier { get; }

		/// <summary>
		/// A composite variant is a description that doesn't represent an asset itself, but rather a set of
		/// multiple files. To actually load this variant, multiple files need to be loaded.
		/// </summary>
		bool IsComposite { get; }

		/// <summary>
		/// The version of this variant. Whenever the variants change, this will increment for that variant type.
		/// </summary>
		int VariantVersion { get; }

		/// <summary>
		/// This sets the VariantVersion to latest version of that variant
		/// </summary>
		void EnsureCurrentVersion();

		void GenerateLoadChain(List<string> chain);

		List<IAssetVariantDescriptor> GenerateCloudChainNonGeneric();
	}
	public interface IAssetVariantDescriptor<D, M> : IAssetVariantDescriptor, IEquatable<D> where D : IAssetVariantDescriptor<D, M> where M : IAssetMetadata
	{
		List<D> GenerateCloudChain();

		List<D> GetBestAlternateChain(List<D> availableDescriptors, Predicate<D> variantFilter = null);

		bool Equals(D other, VersionComparison versionComparison);

		string ValidateCloudVariant(M metadata);
	}
	public static class AssetMetadataHelper
	{
		public static AssetVariantType MetadataToAssetType(Type metadataType)
		{
			if (typeof(BitmapMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.Texture;
			}
			if (typeof(CubemapMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.Cubemap;
			}
			if (typeof(VolumeMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.Volume;
			}
			if (typeof(MeshMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.Mesh;
			}
			if (typeof(ShaderMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.Shader;
			}
			if (typeof(GaussianSplatMetadata).IsAssignableFrom(metadataType))
			{
				return AssetVariantType.GaussianSplat;
			}
			throw new Exception("Invalid metadata type: " + metadataType);
		}

		public static T ComputeMetadata<T>(string file) where T : class, IAssetMetadata
		{
			if (typeof(T) == typeof(BitmapMetadata))
			{
				return BitmapMetadata.GenerateMetadata(file) as T;
			}
			if (typeof(T) == typeof(CubemapMetadata))
			{
				return CubemapMetadata.GenerateMetadata(file) as T;
			}
			if (typeof(T) == typeof(VolumeMetadata))
			{
				return VolumeMetadata.GenerateMetadata(file) as T;
			}
			if (typeof(T) == typeof(MeshMetadata))
			{
				return MeshMetadata.GenerateMetadata(file) as T;
			}
			if (typeof(T) == typeof(ShaderMetadata))
			{
				return ShaderMetadata.GenerateMetadata(file) as T;
			}
			if (typeof(T) == typeof(GaussianSplatMetadata))
			{
				return GaussianSplatMetadata.GenerateMetadata(file) as T;
			}
			throw new Exception("Invalid metadata type: " + typeof(T));
		}
	}
	[JsonObject(MemberSerialization = MemberSerialization.OptIn)]
	public class BitmapMetadata : ImageMetadataBase
	{
		public const int METADATA_VERSION = 5;

		[Newtonsoft.Json.JsonIgnore]
		[System.Text.Json.Serialization.JsonIgnore]
		public override int LatestVersion => 5;

		[JsonProperty(PropertyName = "width")]
		[JsonPropertyName("width")]
		public int Width { get; set; }

		[JsonProperty(PropertyName = "height")]
		[JsonPropertyName("height")]
		public int Height { get; set; }

		[JsonProperty(PropertyName = "mipMapCount")]
		[JsonPropertyName("mipMapCount")]
		public int MipMapCount { get; set; }

		[JsonProperty(PropertyName = "baseFormat")]
		[JsonPropertyName("baseFormat")]
		public string BaseFormat { get; set; }

		public override void CopyFrom(IAssetMetadata metadata)
		{
			if (metadata is BitmapMetadata metadata2)
			{
				CopyFrom(metadata2);
				return;
			}
			throw new Exception("Source metadata is not correct type: " + metadata);
		}

		public void CopyFrom(BitmapMetadata metadata)
		{
			CopyFrom((ImageMetadataBase)metadata);
			Width = metadata.Width;
			Height = metadata.Height;
			MipMapCount = metadata.MipMapCount;
			BaseFormat = metadata.BaseFormat;
		}

		public static BitmapMetadata GenerateMetadata(string file)
		{
			BitmapMetadata bitmapMetadata = GenerateMetadata(Bitmap2D.Load(file, null));
			bitmapMetadata.AssetIdentifier = file;
			return bitmapMetadata;
		}

		public static BitmapMetadata GenerateMetadata(Bitmap2D bitmap)
		{
			BitmapMetadata bitmapMetadata = new BitmapMetadata();
			bitmapMetadata.InitGeneration();
			if (bitmap == null)
			{
				bitmapMetadata.IsCorrupted = true;
				return bitmapMetadata;
			}
			bitmapMetadata.BaseFormat = bitmap.OriginalFormat;
			bitmapMetadata.Width = bitmap.Size.x;
			bitmapMetadata.Height = bitmap.Size.y;
			bitmapMetadata.MipMapCount = bitmap.MipMapLevels;
			BitmapMetadataHelper.GenerateMetadataShared(bitmap, bitmapMetadata);
			return bitmapMetadata;
		}
	}
	public static class BitmapMetadataHelper
	{
		public static void GenerateMetadataShared(Bitmap bitmap, ImageMetadataBase data)
		{
			data.BitsPerPixel = bitmap.BitsPerPixel;
			data.ChannelCount = bitmap.Format.GetChannels();
			TextureFormat format = bitmap.Format;
			int num = 0;
			int num2 = 0;
			for (int i = 0; i < bitmap.TotalPixels; i++)
			{
				color value = bitmap.DecodePixel(i);
				if (MathX.IsValid(in value))
				{
					num++;
					ColorHSV colorHSV = new ColorHSV(in value);
					data.AverageColor += value;
					data.AverageHSV += colorHSV;
					if (value.a > 0.01f)
					{
						data.AverageVisibleColor += value;
						data.AverageVisibleHSV += colorHSV;
						num2++;
					}
					data.UpdateColorData(in value, format);
				}
			}
			data.InvalidPixelCount = bitmap.TotalPixels - num;
			if (num > 0)
			{
				float num3 = 1f / (float)num;
				data.AverageColor *= num3;
				data.AverageHSV *= num3;
			}
			if (num2 > 0)
			{
				float num4 = 1f / (float)num2;
				data.AverageVisibleColor *= num4;
				data.AverageVisibleHSV *= num4;
			}
		}
	}
	[JsonObject(MemberSerialization = MemberSerialization.OptIn)]
	public class CubemapMetadata : ImageMetadataBase
	{
		public const int METADATA_VERSION = 5;

		[Newtonsoft.Json.JsonIgnore]
		[System.Text.Json.Serialization.JsonIgnore]
		public override int LatestVersion => 5;

		[JsonProperty(PropertyName = "size")]
		[JsonPropertyName("size")]
		public int Size { get; set; }

		[JsonProperty(PropertyName = "mipmaps")]
		[JsonPropertyName("mipmaps")]
		public bool MipMaps { get; set; }

		public override void CopyFrom(IAssetMetadata metadata)
		{
			if (metadata is CubemapMetadata metadata2)
			{
				CopyFrom(metadata2);
				return;
			}
			throw new Exception("Source metadata is not correct type: " + metadata);
		}

		public void CopyFrom(CubemapMetadata metadata)
		{
			CopyFrom((ImageMetadataBase)metadata);
			Size = metadata.Size;
			MipMaps = metadata.MipMaps;
		}

		public static CubemapMetadata GenerateMetadata(string file)
		{
			CubemapMetadata cubemapMetadata = GenerateMetadata(BitmapCube.Load(file));
			cubemapMetadata.AssetIdentifier = file;
			return cubemapMetadata;
		}

		public static CubemapMetadata GenerateMetadata(BitmapCube cube)
		{
			CubemapMetadata cubemapMetadata = new CubemapMetadata();
			cubemapMetadata.InitGeneration();
			cubemapMetadata.Size = cube.Size.x;
			cubemapMetadata.MipMaps = cube.HasMipMaps;
			cubemapMetadata.BitsPerPixel = cube.Format.GetBitsPerPixel();
			cubemapMetadata.ChannelCount = cube.Format.GetChannels();
			BitmapMetadataHelper.GenerateMetadataShared(cube, cubemapMetadata);
			return cubemapMetadata;
		}
	}
