		[JsonPropertyName("splatCount")]
		public int SplatCount { get; set; }

		[JsonProperty(PropertyName = "invalidSplatCount")]
		[JsonPropertyName("invalidSplatCount")]
		public int InvalidSplatCount { get; set; }

		[JsonProperty(PropertyName = "colorType")]
		[JsonPropertyName("colorType")]
		[Newtonsoft.Json.JsonConverter(typeof(StringEnumConverter))]
		[System.Text.Json.Serialization.JsonConverter(typeof(JsonStringEnumConverter))]
		public GaussianColorType ColorType { get; set; }

		[JsonProperty(PropertyName = "boundsCentersOnly")]
		[JsonPropertyName("boundsCentersOnly")]
		public Elements.Core.BoundingBox BoundsCentersOnly { get; set; }

		[JsonProperty(PropertyName = "boundsExpandedSplats")]
		[JsonPropertyName("boundsExpandedSplats")]
		public Elements.Core.BoundingBox BoundsExpandedSplats { get; set; }

		public void CopyFrom(IAssetMetadata metadata)
		{
			if (metadata is GaussianSplatMetadata other)
			{
				CopyFrom(other);
				return;
			}
			throw new Exception("Source metadata is not correct type: " + metadata);
		}

		public void CopyFrom(GaussianSplatMetadata other)
		{
			AssetIdentifier = other.AssetIdentifier;
			MetadataVersion = other.MetadataVersion;
			SplatCount = other.SplatCount;
			InvalidSplatCount = other.InvalidSplatCount;
			BoundsCentersOnly = BoundsCentersOnly;
			BoundsExpandedSplats = BoundsExpandedSplats;
		}

		public static GaussianSplatMetadata GenerateMetadata(string file)
		{
			GaussianSplatMetadata gaussianSplatMetadata = GenerateMetadata(new GaussianCloud(file));
			gaussianSplatMetadata.AssetIdentifier = file;
			return gaussianSplatMetadata;
		}

		public static GaussianSplatMetadata GenerateMetadata(GaussianCloud cloud)
		{
			GaussianSplatMetadata gaussianSplatMetadata = new GaussianSplatMetadata();
			gaussianSplatMetadata.MetadataVersion = 1;
			gaussianSplatMetadata.SplatCount = cloud.SplatCount;
			gaussianSplatMetadata.ColorType = cloud.ColorDataType;
			Span<float3> positions = cloud.Positions;
			Span<floatQ> rotations = cloud.Rotations;
			Span<float3> scales = cloud.Scales;
			for (int i = 0; i < cloud.SplatCount; i++)
			{
				if (!positions[i].IsValid() || !MathX.IsValid(in rotations[i]) || !scales[i].IsValid())
				{
					gaussianSplatMetadata.InvalidSplatCount++;
				}
			}
			cloud.CalculateBoundingBoxes(out var centersOnly, out var expandedSplats, filterInvalid: true);
			gaussianSplatMetadata.BoundsCentersOnly = centersOnly;
			gaussianSplatMetadata.BoundsExpandedSplats = expandedSplats;
			return gaussianSplatMetadata;
		}
	}
