		public void CopyFrom(IAssetMetadata metadata)
		{
			if (metadata is MeshMetadata mesh)
			{
				CopyFrom(mesh);
				return;
			}
			throw new Exception("Source metadata is not correct type: " + metadata);
		}

		public void CopyFrom(MeshMetadata mesh)
		{
			AssetIdentifier = mesh.AssetIdentifier;
			MetadataVersion = mesh.MetadataVersion;
			VertexCount = mesh.VertexCount;
			TotalPointCount = mesh.TotalPointCount;
			TotalTriangleCount = mesh.TotalTriangleCount;
			SubmeshCount = mesh.SubmeshCount;
			BoneCount = mesh.BoneCount;
			HasNormals = mesh.HasNormals;
			HasTangents = mesh.HasTangents;
			HasColors = mesh.HasColors;
			UV0dimension = mesh.UV0dimension;
			UV1dimension = mesh.UV1dimension;
			UV2dimension = mesh.UV2dimension;
			UV3dimension = mesh.UV3dimension;
			SmallestTriangleSize = mesh.SmallestTriangleSize;
			LargestTriangleSize = mesh.LargestTriangleSize;
			AverageTriangleSize = mesh.AverageTriangleSize;
			MedianTriangleSize = mesh.MedianTriangleSize;
			SmallestTriangleArea = mesh.SmallestTriangleArea;
			LargestTriangleArea = mesh.LargestTriangleArea;
			AverageTriangleArea = mesh.AverageTriangleArea;
			MedianTriangleArea = mesh.MedianTriangleArea;
			Bounds = mesh.Bounds;
			if (mesh.SubmeshMetadata != null)
			{
				SubmeshMetadata = new List<SubmeshMetadata>();
				foreach (SubmeshMetadata submeshMetadatum in mesh.SubmeshMetadata)
				{
					SubmeshMetadata.Add(submeshMetadatum);
				}
			}
			if (mesh.BoneMetadata != null)
			{
				BoneMetadata = new List<BoneMetadata>();
				foreach (BoneMetadata boneMetadatum in mesh.BoneMetadata)
				{
					BoneMetadata.Add(boneMetadatum);
				}
			}
			if (mesh.ApproximateBoneBounds == null)
			{
				return;
			}
			ApproximateBoneBounds = new List<ApproximateBoneBounds>();
			foreach (ApproximateBoneBounds approximateBoneBound in mesh.ApproximateBoneBounds)
			{
				ApproximateBoneBounds.Add(approximateBoneBound);
			}
		}

		public static MeshMetadata GenerateMetadata(string file)
		{
			MeshX mesh = null;
			try
			{
				mesh = new MeshX(file);
			}
			catch (Exception value)
			{
				UniLog.Error($"Exception when decoding MeshX file {file}:\n{value}");
			}
			MeshMetadata meshMetadata = GenerateMetadata(mesh);
			meshMetadata.AssetIdentifier = file;
			return meshMetadata;
		}

		public static MeshMetadata GenerateMetadata(MeshX mesh)
		{
			MeshMetadata meshMetadata = new MeshMetadata();
			meshMetadata.MetadataVersion = 1;
			if (mesh == null)
			{
				meshMetadata.IsCorrupted = true;
				return meshMetadata;
			}
			meshMetadata.VertexCount = mesh.VertexCount;
			meshMetadata.TotalTriangleCount = mesh.TotalTriangleCount;
			meshMetadata.TotalPointCount = mesh.TotalPointCount;
			meshMetadata.SubmeshCount = mesh.SubmeshCount;
			meshMetadata.BoneCount = mesh.BoneCount;
			meshMetadata.BlendshapeCount = mesh.BlendShapeCount;
			meshMetadata.HasNormals = mesh.HasNormals;
			meshMetadata.HasTangents = mesh.HasTangents;
			meshMetadata.HasColors = mesh.HasColors;
			meshMetadata.HasBoneBindings = mesh.HasBoneBindings;
			meshMetadata.UV0dimension = mesh.GetUV_Dimension(0);
			meshMetadata.UV1dimension = mesh.GetUV_Dimension(1);
			meshMetadata.UV2dimension = mesh.GetUV_Dimension(2);
			meshMetadata.UV3dimension = mesh.GetUV_Dimension(3);
			meshMetadata.Bounds = mesh.CalculateBoundingBox(out var invalidVertexCount);
			meshMetadata.InvalidVertexCount = invalidVertexCount;
			mesh.CalculateTriangleAreas(out var smallest, out var largest, out var average, out var median);
			mesh.CalculateTriangleLengths(out var smallest2, out var largest2, out var average2, out var median2);
			meshMetadata.SmallestTriangleArea = smallest;
			meshMetadata.LargestTriangleArea = largest;
			meshMetadata.AverageTriangleArea = average;
			meshMetadata.MedianTriangleArea = median;
			meshMetadata.SmallestTriangleSize = smallest2;
			meshMetadata.LargestTriangleSize = largest2;
			meshMetadata.AverageTriangleSize = average2;
			meshMetadata.MedianTriangleSize = median2;
			meshMetadata.SubmeshMetadata = mesh.CalculateSubmeshMetadata();
			if (meshMetadata.HasBoneBindings)
			{
				meshMetadata.BoneMetadata = mesh.CalculateBoneMetadata();
				meshMetadata.ApproximateBoneBounds = mesh.CalculateApproximateBoneBounds();
			}
			return meshMetadata;
		}

		public override string ToString()
		{
			return $"MeshMetadata. AssetIdentifier: {AssetIdentifier}, Version: {MetadataVersion}, VertexCount: {VertexCount}, SubmeshCount: {SubmeshCount}, TriangleCount: {TotalTriangleCount}, PointCount: {TotalPointCount}";
		}
	}
