		public IEnumerable<ShaderSourceFile> AllSourceFiles
		{
			get
			{
				yield return SourceFile;
				List<ShaderSourceFile> includeFiles = IncludeFiles;
				if (includeFiles == null || includeFiles.Count <= 0)
				{
					yield break;
				}
				foreach (ShaderSourceFile includeFile in IncludeFiles)
				{
					yield return includeFile;
				}
			}
		}

		public ShaderMetadata()
		{
		}

		public static ShaderMetadata LoadFromJSON(string json)
		{
			return System.Text.Json.JsonSerializer.Deserialize<ShaderMetadata>(json);
		}

		public ShaderMetadata(string origin, ShaderSourceFile sourceFile, List<List<string>> variantGroups, List<ShaderSourceFile> includes)
		{
			Origin = origin;
			SourceFile = sourceFile;
			VariantGroups = variantGroups;
			IncludeFiles = includes;
			GenerateUniqueKeywords();
		}

		public static ShaderMetadata GenerateMetadata(string file)
		{
			if (!File.Exists(file))
			{
				throw new FileNotFoundException("Missing file, while generating shader metadata", file);
			}
			try
			{
				using ShaderPackage shaderPackage = new ShaderPackage(file);
				ShaderMetadata metadata = shaderPackage.Metadata;
				metadata.AssetIdentifier = file;
				return metadata;
			}
			catch (InvalidDataException)
			{
				return Corrupted(file);
			}
		}

		public void CopyFrom(IAssetMetadata metadata)
		{
			if (metadata is ShaderMetadata metadata2)
			{
				CopyFrom(metadata2);
				return;
			}
			throw new Exception("Source metadata is not correct type: " + metadata);
		}

		public void CopyFrom(ShaderMetadata metadata)
		{
			AssetIdentifier = metadata.AssetIdentifier;
			MetadataVersion = metadata.MetadataVersion;
			Origin = metadata.Origin;
			SourceFile = metadata.SourceFile?.Clone();
			if (metadata.IncludeFiles != null)
			{
				IncludeFiles = new List<ShaderSourceFile>();
			}
			List<ShaderSourceFile> includeFiles = metadata.IncludeFiles;
			if (includeFiles != null && includeFiles.Count > 0)
			{
				foreach (ShaderSourceFile includeFile in metadata.IncludeFiles)
				{
					IncludeFiles.Add(includeFile.Clone());
				}
			}
			if (metadata.VariantGroups != null)
			{
				VariantGroups = new List<List<string>>();
			}
			List<List<string>> variantGroups = metadata.VariantGroups;
			if (variantGroups != null && variantGroups.Count > 0)
			{
				foreach (List<string> variantGroup in metadata.VariantGroups)
				{
					List<string> list = new List<string>();
					foreach (string item in variantGroup)
					{
						list.Add(item);
					}
					VariantGroups.Add(list);
				}
			}
			if (metadata.UniqueKeywords != null)
			{
				UniqueKeywords = new List<string>();
			}
			List<string> uniqueKeywords = metadata.UniqueKeywords;
			if (uniqueKeywords == null || uniqueKeywords.Count <= 0)
			{
				return;
			}
			foreach (string uniqueKeyword in metadata.UniqueKeywords)
			{
				UniqueKeywords.Add(uniqueKeyword);
			}
		}

		public IEnumerable<List<string>> EnumerateAllVariants(bool returnCopy = true)
		{
			if (VariantGroups.Count == 0)
			{
				yield return new List<string>();
				yield break;
			}
			foreach (List<string> item in EnumerateVariants(new List<string>(), 0, returnCopy))
			{
				yield return item;
			}
		}

		private IEnumerable<List<string>> EnumerateVariants(List<string> baseVariants, int groupIndex, bool returnCopy = true)
		{
			List<string> list = VariantGroups[groupIndex];
			foreach (string keyword in list)
			{
				if (baseVariants.Contains(keyword))
				{
					continue;
				}
				if (keyword != "_")
				{
					baseVariants.Add(keyword);
				}
				if (groupIndex == VariantGroups.Count - 1)
				{
					if (returnCopy)
					{
						yield return baseVariants.ToList();
					}
					else
					{
						yield return baseVariants;
					}
				}
				else
				{
					foreach (List<string> item in EnumerateVariants(baseVariants, groupIndex + 1))
					{
						yield return item;
					}
				}
				if (keyword != "_")
				{
					baseVariants.RemoveAt(baseVariants.Count - 1);
				}
			}
		}

		public uint GetVariantIndex(List<string> keywords)
		{
			uint num = 0u;
			foreach (string keyword in keywords)
			{
				int keywordIndex = GetKeywordIndex(keyword);
				if (keywordIndex >= 0)
				{
					num |= (uint)(1 << keywordIndex);
				}
			}
			foreach (List<string> variantGroup in VariantGroups)
			{
				if (!(variantGroup[0] == "_") && !variantGroup.Any((string k) => keywords.Contains(k)))
				{
					int keywordIndex2 = GetKeywordIndex(variantGroup[0]);
					num |= (uint)(1 << keywordIndex2);
				}
			}
			return num;
		}

		public int GetKeywordIndex(string keyword)
		{
			return UniqueKeywords.IndexOf(keyword);
		}

		public bool IsValidIndex(uint index)
		{
			int num = 1 << UniqueKeywords.Count;
			return index < num;
		}

		public void GenerateUniqueKeywords()
		{
			HashSet<string> hashSet = new HashSet<string>();
			foreach (List<string> variantGroup in VariantGroups)
			{
				foreach (string item in variantGroup)
				{
					if (!string.IsNullOrWhiteSpace(item) && item != "_")
					{
						hashSet.Add(item);
					}
				}
			}
			UniqueKeywords = hashSet.ToList();
			UniqueKeywords.Sort();
		}

		public static ShaderMetadata Corrupted(string file)
		{
			return new ShaderMetadata
			{
				IsCorrupted = true,
				AssetIdentifier = file
			};
		}
	}
