	internal class AdvancingFront
	{
		internal Node _head;

		internal Node _tail;

		private Node _search_node;

		internal AdvancingFront(Node head, Node tail)
		{
			_head = head;
			_tail = tail;
			_search_node = _head;
		}

		public void SetSearch(Node node)
		{
			_search_node = node;
		}

		public Node LocateNode(float x)
		{
			Node node = _search_node;
			if (x < node.Value)
			{
				while ((node = node.Prev) != null)
				{
					if (x >= node.Value)
					{
						_search_node = node;
						return node;
					}
				}
			}
			else
			{
				while ((node = node.Next) != null)
				{
					if (x < node.Value)
					{
						_search_node = node.Prev;
						return node.Prev;
					}
				}
			}
			return null;
		}

		private Node FindSearchNode(float x)
		{
			return _search_node;
		}

		public Node LocatePoint(TriPoint point)
		{
			float x = point.X;
			Node node = FindSearchNode(x);
			float x2 = node.Point.X;
			if (x == x2)
			{
				if (point != node.Point)
				{
					if (point.Equals(node.Prev.Point))
					{
						node = node.Prev;
					}
					else if (point.Equals(node.Next.Point))
					{
						node = node.Next;
					}
				}
			}
			else if (x < x2)
			{
				while ((node = node.Prev) != null && !point.Equals(node.Point))
				{
				}
			}
			else
			{
				while ((node = node.Next) != null && !point.Equals(node.Point))
				{
				}
			}
			if (node != null)
			{
				_search_node = node;
			}
			return node;
		}
	}
	public struct Edge
	{
		public TriPoint P;

		public TriPoint Q;

		/// <summary>
		/// Represents a simple polygon's edge
		/// </summary>
		/// <param name="p1"></param>
		/// <param name="p2"></param>
		public Edge(TriPoint p1, TriPoint p2)
		{
			P = p1;
			Q = p2;
			if (p1.Y > p2.Y)
			{
				Q = p1;
				P = p2;
			}
			else if (p1.Y == p2.Y)
			{
				if (p1.X > p2.X)
				{
					Q = p1;
					P = p2;
				}
				else if (p1.X == p2.X)
				{
					throw new Exception($"Edge::Edge: p1 == p2 ({p1} == {p2})");
				}
			}
			Q.EdgeList = Q.EdgeList ?? new List<Edge>();
			Q.EdgeList.Add(this);
		}
	}
	internal class EdgeEvent
	{
		public Edge ConstrainedEdge;

		public bool Right;
