	public class Shape
	{
		/// <summary>
		/// A list of shape outline points.
		/// </summary>
		public readonly List<TriPoint> Points = new List<TriPoint>();

		/// <summary>
		/// Extra points inserted within the shape's area to control or increase triangulation.
		/// </summary>
		public readonly List<TriPoint> SteinerPoints;

		/// <summary>
		/// A list of subtraction shapes fully contained inside this shape.<para />
		/// Shapes added to this list will be used to create holes during triangulation. Any that are outside or intersect the shape outline are invalid.
		/// </summary>
		public readonly List<Shape> Holes = new List<Shape>();

		public BoundingBox2D Bounds { get; private set; }

		public Shape()
		{
		}

		/// <summary>
		/// Create a polygon from a list of at least 3 points with no duplicates.
		/// </summary>
		/// <param name="points">A list of unique points</param>
		public Shape(IList<TriPoint> points)
		{
			Points.AddRange(points);
		}

		/// <summary>
		/// Create a polygon from a list of at least 3 points with no duplicates.
		/// </summary>
		/// <param name="points">A list of unique points</param>
		public Shape(IList<TriPoint> points, float2 offset, float scale)
		{
			for (int i = 0; i < points.Count; i++)
			{
				Points.Add(new TriPoint(offset + (float2)points[i] * scale, points[i].Index));
			}
		}

		/// <summary>
		/// Create a polygon from a list of at least 3 points with no duplicates.
		/// </summary>
		/// <param name="points">A list of unique points.</param>
		public Shape(IEnumerable<TriPoint> points)
			: this((points as IList<TriPoint>) ?? points.ToArray())
		{
		}

		/// <summary>
		/// Create a polygon from a list of at least 3 points with no duplicates.
		/// </summary>
		/// <param name="points">A list of unique points.</param>
		public Shape(params TriPoint[] points)
			: this((IList<TriPoint>)points)
		{
		}

		/// <summary>
		/// Create a polygon from a list of at least 3 points with no duplicates.
		/// </summary>
		/// <param name="points">A list of unique points.</param>
		public Shape(params float2[] points)
			: this((IList<float2>)points)
		{
		}

		/// <summary>
		/// Creates a polygon from a list of at least 3 Vector3 points, with no duplicates.
		/// </summary>
		/// <param name="points">The input points.</param>
		/// <param name="offset">An offset to apply to all of the provided points.</param>
		/// <param name="scale">The scale of the provided points. 0.5f is half size. 2.0f is 2x the normal size.</param>
		public Shape(IList<float2> points, float2 offset, float scale)
		{
			for (int i = 0; i < points.Count; i++)
			{
				Points.Add(new TriPoint(offset + points[i] * scale, i));
			}
		}

		/// <summary>
		/// Creates a polygon from a list of at least 3 Vector3 points, with no duplicates.
		/// </summary>
		/// <param name="points">The input points.</param>
		public Shape(IList<float2> points)
			: this(points, float2.Zero, 1f)
		{
		}

		/// <summary>
		/// Produces a <see cref="!:RectangleF" /> which contains all of the shape's points.
		/// </summary>
		public BoundingBox2D CalculateBounds()
		{
			BoundingBox2D result = BoundingBox2D.Empty();
			foreach (TriPoint point in Points)
			{
				result.Encapsulate(new float2(point.X, point.Y));
			}
			return result;
		}

		/// <summary>
		/// Triangulates the shape and adds all of the points (in triangle list layout) to the provided output.
		/// </summary>
		/// <param name="output">The output list.</param>
		public void Triangulate(IList<float2> output, float2 offset, float scale = 1f)
		{
			Points.Reverse();
			SweepContext sweepContext = new SweepContext();
			sweepContext.AddPoints(Points);
			foreach (Shape hole in Holes)
			{
				sweepContext.AddHole(hole.Points);
			}
			sweepContext.InitTriangulation();
			new Sweep().Triangulate(sweepContext);
			foreach (Triangle triangle in sweepContext.GetTriangles())
			{
				output.Add((float2)triangle.Points[0] * scale + offset);
				output.Add((float2)triangle.Points[2] * scale + offset);
				output.Add((float2)triangle.Points[1] * scale + offset);
			}
		}

		/// <summary>
		/// Triangulates the shape and adds all of the triangles to the provided output.
		/// </summary>
		/// <param name="output">The output list.</param>
		public void Triangulate(IList<Triangle> output)
		{
			SweepContext sweepContext = new SweepContext();
			sweepContext.AddPoints(Points);
			foreach (Shape hole in Holes)
			{
				sweepContext.AddHole(hole.Points);
			}
			sweepContext.InitTriangulation();
			new Sweep().Triangulate(sweepContext);
			foreach (Triangle triangle in sweepContext.GetTriangles())
			{
				output.Add(triangle);
			}
		}

		public void Scale(float scale)
		{
			for (int i = 0; i < Points.Count; i++)
			{
				Points[i] *= scale;
			}
			foreach (Shape hole in Holes)
			{
				hole.Scale(scale);
			}
		}

		public void Scale(float2 scale)
		{
			for (int i = 0; i < Points.Count; i++)
			{
				Points[i] *= scale;
			}
			foreach (Shape hole in Holes)
			{
				hole.Scale(scale);
			}
		}

		public void Offset(float2 offset)
		{
			for (int i = 0; i < Points.Count; i++)
			{
				Points[i] += offset;
			}
			foreach (Shape hole in Holes)
			{
				hole.Offset(offset);
			}
		}

		public void ScaleAndOffset(float2 offset, float scale)
		{
			for (int i = 0; i < Points.Count; i++)
			{
				Points[i] *= scale;
				Points[i] += offset;
			}
			foreach (Shape hole in Holes)
			{
				hole.ScaleAndOffset(offset, scale);
			}
		}

		public void ScaleAndOffset(float2 offset, float2 scale)
		{
			for (int i = 0; i < Points.Count; i++)
			{
				Points[i] *= scale;
				Points[i] += offset;
			}
			foreach (Shape hole in Holes)
			{
				hole.ScaleAndOffset(offset, scale);
			}
		}

		public bool Contains(Shape shape)
		{
			for (int i = 0; i < shape.Points.Count; i++)
			{
				if (!Contains((float2)shape.Points[i]))
				{
					return false;
				}
			}
			return true;
		}

		public bool Contains(float2 point)
		{
			for (int i = 0; i < Holes.Count; i++)
			{
				if (Holes[i].Contains(point))
				{
					return false;
				}
			}
			int count = Points.Count;
			int num = 0;
			bool flag = false;
			double num2 = point.X;
			double num3 = point.Y;
			float2 @float = (float2)Points[count - 1];
			double num4 = @float.X;
			double num5 = @float.Y;
			while (num < count)
			{
				double num6 = num4;
				double num7 = num5;
				@float = (float2)Points[num++];
				num4 = @float.X;
				num5 = @float.Y;
				flag ^= ((num5 > num3) ^ (num7 > num3)) && num2 - num4 < (num3 - num5) * (num6 - num4) / (num7 - num5);
			}
			return flag;
		}
	}
	internal class Sweep
	{
		private const int MAX_DEPTH = 1024;

		private List<Node> _nodes;

		public void Triangulate(SweepContext tcx)
		{
			_nodes = new List<Node>();
			tcx.InitTriangulation();
			tcx.CreateAdvancingFront(_nodes);
			SweepPoints(tcx);
			FinalizationPolygon(tcx);
		}

		public void Reset()
		{
			_nodes.Clear();
		}

		private void SweepPoints(SweepContext tcx)
		{
			for (int i = 1; i < tcx.PointCount(); i++)
			{
				TriPoint point = tcx.GetPoint(i);
				Node node = PointEvent(tcx, point);
				if (point.EdgeList != null)
				{
					for (int j = 0; j < point.EdgeList.Count; j++)
					{
						EdgeEvent(tcx, point.EdgeList[j], node);
					}
				}
			}
		}

		private void FinalizationPolygon(SweepContext tcx)
		{
			Triangle triangle = tcx.Front._head.Next.Triangle;
			TriPoint point = tcx.Front._head.Next.Point;
			while (triangle != null && !triangle.GetConstrainedEdgeCW(point))
			{
				triangle = triangle.NeighborCCW(point);
			}
			if (triangle != null)
			{
				tcx.MeshClean(triangle);
			}
		}

		private Node PointEvent(SweepContext tcx, TriPoint point)
		{
			Node node = tcx.LocateNode(point);
			if (node == null || node.Point == null || node.Next == null || node.Next.Point == null)
			{
				throw new Exception("PointEvent - null node");
			}
			Node node2 = NewFrontTriangle(tcx, point, node);
			if (point.X <= node.Point.X + 1E-12f)
			{
				Fill(tcx, node);
			}
			FillAdvancingFront(tcx, node2);
			return node2;
		}

		private void EdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			tcx.EdgeEvent.ConstrainedEdge = edge;
			tcx.EdgeEvent.Right = edge.P.X > edge.Q.X;
			if (!IsEdgeSideOfTriangle(node.Triangle, edge.P, edge.Q))
			{
				FillEdgeEvent(tcx, edge, node);
				EdgeEvent(tcx, edge.P, edge.Q, node.Triangle, edge.Q);
			}
		}

		private void EdgeEvent(SweepContext tcx, TriPoint ep, TriPoint eq, Triangle triangle, TriPoint point)
		{
			if (triangle == null)
			{
				throw new Exception("EdgeEvent - null triangle");
			}
			if (IsEdgeSideOfTriangle(triangle, ep, eq))
			{
				return;
			}
			TriPoint triPoint = triangle.PointCCW(point);
			Winding winding = TriUtil.Orient2d(eq, triPoint, ep);
			if (winding == Winding.Collinear)
			{
				if (triangle.Contains(eq, triPoint))
				{
					triangle.MarkConstrainedEdge(eq, triPoint);
					tcx.EdgeEvent.ConstrainedEdge.Q = triPoint;
					triangle = triangle.NeighborAcross(point);
					EdgeEvent(tcx, ep, triPoint, triangle, triPoint);
					return;
				}
				throw new NotSupportedException("EdgeEvent - collinear points not supported");
			}
			TriPoint triPoint2 = triangle.PointCW(point);
			Winding winding2 = TriUtil.Orient2d(eq, triPoint2, ep);
			if (winding2 == Winding.Collinear)
			{
				if (!triangle.Contains(eq, triPoint2))
				{
					throw new NotSupportedException("EdgeEvent - collinear points not supported");
				}
				triangle.MarkConstrainedEdge(eq, triPoint2);
				tcx.EdgeEvent.ConstrainedEdge.Q = triPoint2;
				triangle = triangle.NeighborAcross(point);
				EdgeEvent(tcx, ep, triPoint2, triangle, triPoint2);
			}
			else if (winding == winding2)
			{
				triangle = ((winding != Winding.CW) ? triangle.NeighborCW(point) : triangle.NeighborCCW(point));
				EdgeEvent(tcx, ep, eq, triangle, point);
			}
			else
			{
				FlipEdgeEvent(tcx, ep, eq, triangle, point);
			}
		}

		private bool IsEdgeSideOfTriangle(Triangle triangle, TriPoint ep, TriPoint eq)
		{
			int num = triangle.EdgeIndex(ep, eq);
			if (num != -1)
			{
				triangle.MarkConstrainedEdge(num);
				triangle.GetNeighbor(num)?.MarkConstrainedEdge(ep, eq);
				return true;
			}
			return false;
		}

		private Node NewFrontTriangle(SweepContext tcx, TriPoint point, Node node)
		{
			Triangle triangle = new Triangle(point, node.Point, node.Next.Point);
			triangle.MarkNeighbor(node.Triangle);
			tcx.AddToMap(triangle);
			Node node2 = new Node(point);
			_nodes.Add(node2);
			node2.Next = node.Next;
			node2.Prev = node;
			node.Next.Prev = node2;
			node.Next = node2;
			if (!Legalize(tcx, triangle))
			{
				tcx.MapTriangleToNodes(triangle);
			}
			return node2;
		}

		private void Fill(SweepContext tcx, Node node)
		{
			Triangle triangle = new Triangle(node.Prev.Point, node.Point, node.Next.Point);
			triangle.MarkNeighbor(node.Prev.Triangle);
			triangle.MarkNeighbor(node.Triangle);
			tcx.AddToMap(triangle);
			node.Prev.Next = node.Next;
			node.Next.Prev = node.Prev;
			if (!Legalize(tcx, triangle))
			{
				tcx.MapTriangleToNodes(triangle);
			}
		}

		private void FillAdvancingFront(SweepContext tcx, Node n)
		{
			Node next = n.Next;
			while (next.Next != null && !LargeHole_DontFill(next))
			{
				Fill(tcx, next);
				next = next.Next;
			}
			next = n.Prev;
			while (next.Prev != null && !LargeHole_DontFill(next))
			{
				Fill(tcx, next);
				next = next.Prev;
			}
			if (n.Next?.Next != null && BasinAngle(n) < 2.356194496154785)
			{
				FillBasin(tcx, n);
			}
		}

		private bool LargeHole_DontFill(Node node)
		{
			Node next = node.Next;
			Node prev = node.Prev;
			if (!AngleExceeds90Degrees(node.Point, next.Point, prev.Point))
			{
				return false;
			}
			if (AngleIsNegative(node.Point, next.Point, prev.Point))
			{
				return true;
			}
			Node next2 = next.Next;
			if (next2 != null && !AngleExceedsPlus90DegreesOrIsNegative(node.Point, next2.Point, prev.Point))
			{
				return false;
			}
			Node prev2 = prev.Prev;
			if (prev2 != null && !AngleExceedsPlus90DegreesOrIsNegative(node.Point, next.Point, prev2.Point))
			{
				return false;
			}
			return true;
		}

		public bool AngleIsNegative(TriPoint origin, TriPoint pa, TriPoint pb)
		{
			return Angle(origin, pa, pb) < 0.0;
		}

		private bool AngleExceeds90Degrees(TriPoint origin, TriPoint pa, TriPoint pb)
		{
			double num = Angle(origin, pa, pb);
			if (!(num > 1.5707963705062866))
			{
				return num < -1.5707963705062866;
			}
			return true;
		}

		private bool AngleExceedsPlus90DegreesOrIsNegative(TriPoint origin, TriPoint pa, TriPoint pb)
		{
			double num = Angle(origin, pa, pb);
			if (!(num > 1.5707963705062866))
			{
				return num < 0.0;
			}
			return true;
		}

		private double Angle(TriPoint origin, TriPoint pa, TriPoint pb)
		{
			double num = origin.X;
			double num2 = origin.Y;
			double num3 = (double)pa.X - num;
			double num4 = (double)pa.Y - num2;
			double num5 = (double)pb.X - num;
			double num6 = (double)pb.Y - num2;
			double y = num3 * num6 - num4 * num5;
			double x = num3 * num5 + num4 * num6;
			return Math.Atan2(y, x);
		}

		private double BasinAngle(Node node)
		{
			double x = node.Point.X - node.Next.Next.Point.X;
			return Math.Atan2(node.Point.Y - node.Next.Next.Point.Y, x);
		}

		private double HoleAngle(Node node)
		{
			double num = node.Next.Point.X - node.Point.X;
			double num2 = node.Next.Point.Y - node.Point.Y;
			double num3 = node.Prev.Point.X - node.Point.X;
			double num4 = node.Prev.Point.Y - node.Point.Y;
			return Math.Atan2(num * num4 - num2 * num3, num * num3 + num2 * num4);
		}

		private bool Legalize(SweepContext tcx, Triangle t)
		{
			for (int i = 0; i < 3; i++)
			{
				if (t.DelaunayEdge[i])
				{
					continue;
				}
				Triangle neighbor = t.GetNeighbor(i);
				if (neighbor == null)
				{
					continue;
				}
				TriPoint triPoint = t.Points[i];
				TriPoint triPoint2 = neighbor.OppositePoint(t, triPoint);
				int num = neighbor.Index(triPoint2);
				if (neighbor.ConstrainedEdge[num] || neighbor.DelaunayEdge[num])
				{
					t.ConstrainedEdge[i] = neighbor.ConstrainedEdge[num];
				}
				else if (Incircle(triPoint, t.PointCCW(triPoint), t.PointCW(triPoint), triPoint2))
				{
					t.DelaunayEdge[i] = true;
					neighbor.DelaunayEdge[num] = true;
					RotateTrianglePair(t, triPoint, neighbor, triPoint2);
					if (!Legalize(tcx, t))
					{
						tcx.MapTriangleToNodes(t);
					}
					if (!Legalize(tcx, neighbor))
					{
						tcx.MapTriangleToNodes(neighbor);
					}
					t.DelaunayEdge[i] = false;
					neighbor.DelaunayEdge[num] = false;
					return true;
				}
			}
			return false;
		}

		private bool Incircle(TriPoint pa, TriPoint pb, TriPoint pc, TriPoint pd)
		{
			double num = pa.X - pd.X;
			double num2 = pa.Y - pd.Y;
			double num3 = pb.X - pd.X;
			double num4 = pb.Y - pd.Y;
			double num5 = num * num4;
			double num6 = num3 * num2;
			double num7 = num5 - num6;
			if (num7 <= 0.0)
			{
				return false;
			}
			double num8 = pc.X - pd.X;
			double num9 = pc.Y - pd.Y;
			double num10 = num8 * num2;
			double num11 = num * num9;
			double num12 = num10 - num11;
			if (num12 <= 0.0)
			{
				return false;
			}
			double num13 = num3 * num9;
			double num14 = num8 * num4;
			double num15 = num * num + num2 * num2;
			double num16 = num3 * num3 + num4 * num4;
			double num17 = num8 * num8 + num9 * num9;
			return num15 * (num13 - num14) + num16 * num12 + num17 * num7 > 0.0;
		}

		/// Rotates a triangle pair one vertex CW
		///             <pre>
		///       n2                    n2
		///  P +-----+             P +-----+
		///    | t  /|               |\  t |
		///    |   / |               | \   |
		///  n1|  /  |n3           n1|  \  |n3
		///    | /   |    after CW   |   \ |
		///    |/ oT |               | oT \|
		///    +-----+ oP            +-----+
		///       n4                    n4
		/// </pre>
		private void RotateTrianglePair(Triangle t, TriPoint p, Triangle ot, TriPoint op)
		{
			Triangle triangle = t.NeighborCCW(p);
			Triangle triangle2 = t.NeighborCW(p);
			Triangle triangle3 = ot.NeighborCCW(op);
			Triangle triangle4 = ot.NeighborCW(op);
			bool constrainedEdgeCCW = t.GetConstrainedEdgeCCW(p);
			bool constrainedEdgeCW = t.GetConstrainedEdgeCW(p);
			bool constrainedEdgeCCW2 = ot.GetConstrainedEdgeCCW(op);
			bool constrainedEdgeCW2 = ot.GetConstrainedEdgeCW(op);
			bool delaunayEdgeCCW = t.GetDelaunayEdgeCCW(p);
			bool delaunayEdgeCW = t.GetDelaunayEdgeCW(p);
			bool delaunayEdgeCCW2 = ot.GetDelaunayEdgeCCW(op);
			bool delaunayEdgeCW2 = ot.GetDelaunayEdgeCW(op);
			t.Legalize(p, op);
			ot.Legalize(op, p);
			ot.SetDelunayEdgeCCW(p, delaunayEdgeCCW);
			t.SetDelunayEdgeCW(p, delaunayEdgeCW);
			t.SetDelunayEdgeCCW(op, delaunayEdgeCCW2);
			ot.SetDelunayEdgeCW(op, delaunayEdgeCW2);
			ot.SetConstrainedEdgeCCW(p, constrainedEdgeCCW);
			t.SetConstrainedEdgeCW(p, constrainedEdgeCW);
			t.SetConstrainedEdgeCCW(op, constrainedEdgeCCW2);
			ot.SetConstrainedEdgeCW(op, constrainedEdgeCW2);
			t.ClearNeighbors();
			ot.ClearNeighbors();
			if (triangle != null)
			{
				ot.MarkNeighbor(triangle);
			}
			if (triangle2 != null)
			{
				t.MarkNeighbor(triangle2);
			}
			if (triangle3 != null)
			{
				t.MarkNeighbor(triangle3);
			}
			if (triangle4 != null)
			{
				ot.MarkNeighbor(triangle4);
			}
			t.MarkNeighbor(ot);
		}

		private void FillBasin(SweepContext tcx, Node node)
		{
			if (TriUtil.Orient2d(node.Point, node.Next.Point, node.Next.Next.Point) == Winding.CCW)
			{
				tcx.Basin.LeftNode = node.Next.Next;
			}
			else
			{
				tcx.Basin.LeftNode = node.Next;
			}
			tcx.Basin.BottomNode = tcx.Basin.LeftNode;
			while (tcx.Basin.BottomNode.Next != null && tcx.Basin.BottomNode.Point.Y >= tcx.Basin.BottomNode.Next.Point.Y)
			{
				tcx.Basin.BottomNode = tcx.Basin.BottomNode.Next;
			}
			if (tcx.Basin.BottomNode != tcx.Basin.LeftNode)
			{
				tcx.Basin.RightNode = tcx.Basin.BottomNode;
				while (tcx.Basin.RightNode.Next != null && tcx.Basin.RightNode.Point.Y < tcx.Basin.RightNode.Next.Point.Y)
				{
					tcx.Basin.RightNode = tcx.Basin.RightNode.Next;
				}
				if (tcx.Basin.RightNode != tcx.Basin.BottomNode)
				{
					tcx.Basin.Width = tcx.Basin.RightNode.Point.X - tcx.Basin.LeftNode.Point.X;
					tcx.Basin.LeftHighest = tcx.Basin.LeftNode.Point.Y > tcx.Basin.RightNode.Point.Y;
					FillBasinReq(tcx, tcx.Basin.BottomNode);
				}
			}
		}

		private void FillBasinReq(SweepContext tcx, Node node)
		{
			if (IsShallow(tcx, node))
			{
				return;
			}
			Fill(tcx, node);
			if (node.Prev == tcx.Basin.LeftNode && node.Next == tcx.Basin.RightNode)
			{
				return;
			}
			if (node.Prev == tcx.Basin.LeftNode)
			{
				if (TriUtil.Orient2d(node.Point, node.Next.Point, node.Next.Next.Point) == Winding.CW)
				{
					return;
				}
				node = node.Next;
			}
			else if (node.Next != tcx.Basin.RightNode)
			{
				node = ((!(node.Prev.Point.Y < node.Next.Point.Y)) ? node.Next : node.Prev);
			}
			else
			{
				if (TriUtil.Orient2d(node.Point, node.Prev.Point, node.Prev.Prev.Point) == Winding.CCW)
				{
					return;
				}
				node = node.Prev;
			}
			FillBasinReq(tcx, node);
		}

		private bool IsShallow(SweepContext tcx, Node node)
		{
			double num = ((!tcx.Basin.LeftHighest) ? ((double)(tcx.Basin.RightNode.Point.Y - node.Point.Y)) : ((double)(tcx.Basin.LeftNode.Point.Y - node.Point.Y)));
			if ((double)tcx.Basin.Width > num)
			{
				return true;
			}
			return false;
		}

		private void FillEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			if (tcx.EdgeEvent.Right)
			{
				FillRightAboveEdgeEvent(tcx, edge, node);
			}
			else
			{
				FillLeftAboveEdgeEvent(tcx, edge, node);
			}
		}

		private void FillRightAboveEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			while (node.Next.Point.X < edge.P.X)
			{
				if (TriUtil.Orient2d(edge.Q, node.Next.Point, edge.P) == Winding.CCW)
				{
					FillRightBelowEdgeEvent(tcx, edge, node);
				}
				else
				{
					node = node.Next;
				}
			}
		}

		private void FillRightBelowEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			if (node.Point.X < edge.P.X)
			{
				if (TriUtil.Orient2d(node.Point, node.Next.Point, node.Next.Next.Point) == Winding.CCW)
				{
					FillRightConcaveEdgeEvent(tcx, edge, node);
					return;
				}
				FillRightConvexEdgeEvent(tcx, edge, node);
				FillRightBelowEdgeEvent(tcx, edge, node);
			}
		}

		private void FillRightConcaveEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			Fill(tcx, node.Next);
			if (node.Next.Point != edge.P && TriUtil.Orient2d(edge.Q, node.Next.Point, edge.P) == Winding.CCW && TriUtil.Orient2d(node.Point, node.Next.Point, node.Next.Next.Point) == Winding.CCW)
			{
				FillRightConcaveEdgeEvent(tcx, edge, node);
			}
		}

		private void FillRightConvexEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			if (TriUtil.Orient2d(node.Next.Point, node.Next.Next.Point, node.Next.Next.Next.Point) == Winding.CCW)
			{
				FillRightConcaveEdgeEvent(tcx, edge, node.Next);
			}
			else if (TriUtil.Orient2d(edge.Q, node.Next.Next.Point, edge.P) == Winding.CCW)
			{
				FillRightConvexEdgeEvent(tcx, edge, node.Next);
			}
		}

		private void FillLeftAboveEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			while (node.Prev.Point.X > edge.P.X)
			{
				if (TriUtil.Orient2d(edge.Q, node.Prev.Point, edge.P) == Winding.CW)
				{
					FillLeftBelowEdgeEvent(tcx, edge, node);
				}
				else
				{
					node = node.Prev;
				}
			}
		}

		private void FillLeftBelowEdgeEvent(SweepContext tcx, Edge edge, Node node, int depth = 0)
		{
			if (!(node.Point.X > edge.P.X))
			{
				return;
			}
			if (TriUtil.Orient2d(node.Point, node.Prev.Point, node.Prev.Prev.Point) == Winding.CW)
			{
				FillLeftConcaveEdgeEvent(tcx, edge, node);
				return;
			}
			if (depth > 1024)
			{
				throw new Exception("Failed to FillLeftBelowEdgeEvent after 1024 attempts");
			}
			FillLeftConvexEdgeEvent(tcx, edge, node);
			FillLeftBelowEdgeEvent(tcx, edge, node, depth + 1);
		}

		private void FillLeftConvexEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			if (TriUtil.Orient2d(node.Prev.Point, node.Prev.Prev.Point, node.Prev.Prev.Prev.Point) == Winding.CW)
			{
				FillLeftConcaveEdgeEvent(tcx, edge, node.Prev);
			}
			else if (TriUtil.Orient2d(edge.Q, node.Prev.Prev.Point, edge.P) == Winding.CW)
			{
				FillLeftConvexEdgeEvent(tcx, edge, node.Prev);
			}
		}

		private void FillLeftConcaveEdgeEvent(SweepContext tcx, Edge edge, Node node)
		{
			Fill(tcx, node.Prev);
			if (node.Prev.Point != edge.P && TriUtil.Orient2d(edge.Q, node.Prev.Point, edge.P) == Winding.CW && TriUtil.Orient2d(node.Point, node.Prev.Point, node.Prev.Prev.Point) == Winding.CW)
			{
				FillLeftConcaveEdgeEvent(tcx, edge, node);
			}
		}

		private void FlipEdgeEvent(SweepContext tcx, TriPoint ep, TriPoint eq, Triangle t, TriPoint p)
		{
			Triangle triangle = t.NeighborAcross(p);
			if (triangle == null)
			{
				throw new Exception("FlipEdgeEvent - null neighbour across");
			}
			TriPoint triPoint = triangle.OppositePoint(t, p);
			if (TriUtil.InScanArea(p, t.PointCCW(p), t.PointCW(p), triPoint))
			{
				RotateTrianglePair(t, p, triangle, triPoint);
				tcx.MapTriangleToNodes(t);
				tcx.MapTriangleToNodes(triangle);
				if (p.Equals(eq) && triPoint.Equals(ep))
				{
					if (eq.Equals(tcx.EdgeEvent.ConstrainedEdge.Q) && ep.Equals(tcx.EdgeEvent.ConstrainedEdge.P))
					{
						t.MarkConstrainedEdge(ep, eq);
						triangle.MarkConstrainedEdge(ep, eq);
						Legalize(tcx, t);
						Legalize(tcx, triangle);
					}
				}
				else
				{
					Winding o = TriUtil.Orient2d(eq, triPoint, ep);
					t = NextFlipTriangle(tcx, o, t, triangle, p, triPoint);
					FlipEdgeEvent(tcx, ep, eq, t, p);
				}
			}
			else
			{
				TriPoint p2 = NextFlipPoint(ep, eq, triangle, triPoint);
				FlipScanEdgeEvent(tcx, ep, eq, t, triangle, p2);
				EdgeEvent(tcx, ep, eq, t, p);
			}
		}

		private Triangle NextFlipTriangle(SweepContext tcx, Winding o, Triangle t, Triangle ot, TriPoint p, TriPoint op)
		{
			int num;
			if (o == Winding.CCW)
			{
				num = ot.EdgeIndex(p, op);
				ot.DelaunayEdge[num] = true;
				Legalize(tcx, ot);
				ot.ClearDelaunayEdges();
				return t;
			}
			num = t.EdgeIndex(p, op);
			t.DelaunayEdge[num] = true;
			Legalize(tcx, t);
			t.ClearDelaunayEdges();
			return ot;
		}

		private TriPoint NextFlipPoint(TriPoint ep, TriPoint eq, Triangle ot, TriPoint op)
		{
			return TriUtil.Orient2d(eq, op, ep) switch
			{
				Winding.CW => ot.PointCCW(op), 
				Winding.CCW => ot.PointCW(op), 
				_ => throw new NotSupportedException("[Unsupported] Opposing point on constrained edge"), 
			};
		}

		private void FlipScanEdgeEvent(SweepContext tcx, TriPoint ep, TriPoint eq, Triangle flip_triangle, Triangle t, TriPoint p)
		{
			Triangle triangle = t.NeighborAcross(p);
			if (triangle == null)
			{
				throw new Exception("FlipScanEdgeEvent - null neighbour across");
			}
			TriPoint triPoint = triangle.OppositePoint(t, p);
			if (triPoint == null)
			{
				throw new Exception("FlipScanEdgeEvent - null opposing point");
			}
			TriPoint triPoint2 = flip_triangle.PointCCW(eq);
			TriPoint triPoint3 = flip_triangle.PointCW(eq);
			if (triPoint2 == null || triPoint3 == null)
			{
				throw new Exception("FlipScanEdgeEvent - null on either of points");
			}
			if (TriUtil.InScanArea(eq, triPoint2, triPoint3, triPoint))
			{
				FlipEdgeEvent(tcx, eq, triPoint, triangle, triPoint);
				return;
			}
			TriPoint p2 = NextFlipPoint(ep, eq, triangle, triPoint);
			FlipScanEdgeEvent(tcx, ep, eq, flip_triangle, triangle, p2);
		}
	}
	internal class SweepBasin
	{
		public Node LeftNode;

		public Node BottomNode;

		public Node RightNode;

		public float Width;

		public bool LeftHighest;

		public void Clear()
		{
			LeftNode = null;
			BottomNode = null;
			RightNode = null;
			Width = 0f;
			LeftHighest = false;
		}
	}
	internal class SweepContext
	{
		private const float K_ALPHA = 0.3f;

		private List<TriPoint> _points;

		private List<Triangle> _triangles;

		private List<Triangle> _map;

		private List<Edge> _edge_list;

		private TriPoint _head;

		private TriPoint _tail;

		private Node _af_head;

		private Node _af_middle;

		private Node _af_tail;

		internal AdvancingFront Front;

		private TriPoint.Comparer _cmp;

		internal SweepBasin Basin;

		internal EdgeEvent EdgeEvent;

		internal SweepContext()
		{
			_points = new List<TriPoint>();
			_triangles = new List<Triangle>();
			_map = new List<Triangle>();
			_cmp = new TriPoint.Comparer();
			_edge_list = new List<Edge>();
			EdgeEvent = new EdgeEvent();
			Basin = new SweepBasin();
		}

		public void AddHole(List<TriPoint> holePoints)
		{
			int count = _points.Count;
			_points.AddRange(holePoints);
			int num = _points.Count - 1;
			if (_points[count].Equals(_points[num]))
			{
				_points.RemoveAt(num--);
			}
			InitEdges(count, num);
		}

		public void AddPoint(TriPoint point)
		{
			_points.Add(point);
		}

		public void AddPoints(List<TriPoint> points)
		{
			int count = _points.Count;
			_points.AddRange(points);
			int num = _points.Count - 1;
			if (_points[count].Equals(_points[num]))
			{
				_points.RemoveAt(num--);
			}
			InitEdges(count, num);
		}

		public List<Triangle> GetTriangles()
		{
			return _triangles;
		}

		public List<Triangle> GetMap()
		{
			return _map;
		}

		public void InitTriangulation()
		{
			float x = _points[0].X;
			float x2 = _points[0].X;
			float y = _points[0].Y;
			float y2 = _points[0].Y;
			for (int i = 0; i < _points.Count; i++)
			{
				TriPoint triPoint = _points[i];
				if (triPoint.X > x)
				{
					x = triPoint.X;
				}
				if (triPoint.X < x2)
				{
					x2 = triPoint.X;
				}
				if (triPoint.Y > y)
				{
					y = triPoint.Y;
				}
				if (triPoint.Y < y2)
				{
					y2 = triPoint.Y;
				}
			}
			float num = 0.3f * (x - x2);
			float num2 = 0.3f * (y - y2);
			_head = new TriPoint(x2 - num, y2 - num2, -2);
			_tail = new TriPoint(x + num, y2 - num2, -3);
			_points.Sort(_cmp);
		}

		private void InitEdges(int first, int last)
		{
			for (int i = first; i <= last; i++)
			{
				int index = ((i < last) ? (i + 1) : first);
				_edge_list.Add(new Edge(_points[i], _points[index]));
			}
		}

		public TriPoint GetPoint(int index)
		{
			return _points[index];
		}

		public void AddToMap(Triangle triangle)
		{
			_map.Add(triangle);
		}

		public Node LocateNode(TriPoint point)
		{
			return Front.LocateNode(point.X);
		}

		public void CreateAdvancingFront(List<Node> nodes)
		{
			Triangle triangle = new Triangle(_points[0], _head, _tail);
			_map.Add(triangle);
			_af_head = new Node(triangle.Points[1], triangle);
			_af_middle = new Node(triangle.Points[0], triangle);
			_af_tail = new Node(triangle.Points[2]);
			Front = new AdvancingFront(_af_head, _af_tail);
			_af_head.Next = _af_middle;
			_af_middle.Next = _af_tail;
			_af_middle.Prev = _af_head;
			_af_tail.Prev = _af_middle;
		}

		public void RemoveNode(Node node)
		{
		}

		public void MapTriangleToNodes(Triangle t)
		{
			for (int i = 0; i < 3; i++)
			{
				if (t.GetNeighbor(i) == null)
				{
					Node node = Front.LocatePoint(t.PointCW(t.Points[i]));
					if (node != null)
					{
						node.Triangle = t;
					}
				}
			}
		}

		public void RemoveFromMap(Triangle triangle)
		{
			_map.Remove(triangle);
		}

		public void MeshClean(Triangle triangle)
		{
			List<Triangle> list = new List<Triangle>();
			list.Add(triangle);
			while (list.Count != 0)
			{
				int index = list.Count - 1;
				Triangle triangle2 = list[index];
				list.RemoveAt(index);
				if (triangle2 == null || triangle2.IsInterior())
				{
					continue;
				}
				triangle2.IsInterior(b: true);
				_triangles.Add(triangle2);
				for (int i = 0; i < 3; i++)
				{
					if (!triangle2.ConstrainedEdge[i])
					{
						list.Add(triangle2.GetNeighbor(i));
					}
				}
			}
		}

		public int PointCount()
		{
			return _points.Count;
		}

		public void SetHead(TriPoint p1)
		{
			_head = p1;
		}

		public TriPoint GetHead()
		{
			return _head;
		}
	}
	public class Triangle
	{
		public TriPoint[] Points;

		public bool[] ConstrainedEdge;

		public bool[] DelaunayEdge;

		private Triangle[] _neighbours;

		private bool _interior;

		public Triangle(TriPoint a, TriPoint b, TriPoint c)
		{
			Points = new TriPoint[3] { a, b, c };
			ConstrainedEdge = new bool[3];
			DelaunayEdge = new bool[3];
			_neighbours = new Triangle[3];
		}

		public Triangle GetNeighbor(int index)
		{
			return _neighbours[index];
		}

		public bool Contains(TriPoint p)
		{
			if (!Points[0].Equals(p) && !Points[1].Equals(p))
			{
				return Points[2].Equals(p);
			}
			return true;
		}

		public bool Contains(Edge e)
		{
			if (Contains(e.P))
			{
				return Contains(e.Q);
			}
			return false;
		}

		public bool Contains(TriPoint p, TriPoint q)
		{
			if (Contains(p))
			{
				return Contains(q);
			}
			return false;
		}

		public bool IsInterior()
		{
			return _interior;
		}

		public void IsInterior(bool b)
		{
			_interior = b;
		}

		/// <summary>
		/// Update neighbor pointers
		/// </summary>
		/// <param name="p1"></param>
		/// <param name="p2"></param>
		/// <param name="t"></param>
		public void MarkNeighbor(TriPoint p1, TriPoint p2, Triangle t)
		{
			if ((p1.Equals(Points[2]) && p2.Equals(Points[1])) || (p1.Equals(Points[1]) && p2.Equals(Points[2])))
			{
				_neighbours[0] = t;
			}
			else if ((p1.Equals(Points[0]) && p2.Equals(Points[2])) || (p1.Equals(Points[2]) && p2.Equals(Points[0])))
			{
				_neighbours[1] = t;
			}
			else if ((p1.Equals(Points[0]) && p2.Equals(Points[1])) || (p1.Equals(Points[1]) && p2.Equals(Points[0])))
			{
				_neighbours[2] = t;
			}
		}

		/// <summary>
		/// Exhaustive search to update neighbor pointers
		/// </summary>
		/// <param name="t"></param>
		public void MarkNeighbor(Triangle t)
		{
			if (t.Contains(Points[1], Points[2]))
			{
				_neighbours[0] = t;
				t.MarkNeighbor(Points[1], Points[2], this);
			}
			else if (t.Contains(Points[0], Points[2]))
			{
				_neighbours[1] = t;
				t.MarkNeighbor(Points[0], Points[2], this);
			}
			else if (t.Contains(Points[0], Points[1]))
			{
				_neighbours[2] = t;
				t.MarkNeighbor(Points[0], Points[1], this);
			}
		}

		public void Clear()
		{
			for (int i = 0; i < 3; i++)
			{
				_neighbours[i]?.ClearNeighbor(this);
			}
			ClearNeighbors();
			Points[0] = (Points[1] = (Points[2] = null));
		}

		public void ClearNeighbor(Triangle triangle)
		{
			if (_neighbours[0] == triangle)
			{
				_neighbours[0] = null;
			}
			else if (_neighbours[1] == triangle)
			{
				_neighbours[1] = null;
			}
			else
			{
				_neighbours[2] = null;
			}
		}

		public void ClearNeighbors()
		{
			_neighbours[0] = (_neighbours[1] = (_neighbours[2] = null));
		}

		public void ClearDelaunayEdges()
		{
			bool[] delaunayEdge = DelaunayEdge;
			bool flag;
			DelaunayEdge[1] = (flag = (DelaunayEdge[2] = false));
			delaunayEdge[0] = flag;
		}

		public TriPoint OppositePoint(Triangle t, TriPoint p)
		{
			TriPoint point = t.PointCW(p);
			return PointCW(point);
		}

		/// <summary>
		/// Legalized triangle by rotating clockwise around point(0)
		/// </summary>
		/// <param name="point"></param>
		public void Legalize(TriPoint point)
		{
			Points[1] = Points[0];
			Points[0] = Points[2];
			Points[2] = point;
		}

		/// <summary>
		/// Legalize triagnle by rotating clockwise around oPoint
		/// </summary>
		/// <param name="opoint"></param>
		/// <param name="npoint"></param>
		public void Legalize(TriPoint opoint, TriPoint npoint)
		{
			if (opoint.Equals(Points[0]))
			{
				Points[1] = Points[0];
				Points[0] = Points[2];
				Points[2] = npoint;
			}
			else if (opoint.Equals(Points[1]))
			{
				Points[2] = Points[1];
				Points[1] = Points[0];
				Points[0] = npoint;
			}
			else if (opoint.Equals(Points[2]))
			{
				Points[0] = Points[2];
				Points[2] = Points[1];
				Points[1] = npoint;
			}
		}

		public int Index(TriPoint p)
		{
			if (p.Equals(Points[0]))
			{
				return 0;
			}
			if (p.Equals(Points[1]))
			{
				return 1;
			}
			if (p.Equals(Points[2]))
			{
				return 2;
			}
			return -1;
		}

		public int EdgeIndex(TriPoint p1, TriPoint p2)
		{
			if (Points[0].Equals(p1))
			{
				if (Points[1].Equals(p2))
				{
					return 2;
				}
				if (Points[2].Equals(p2))
				{
					return 1;
				}
			}
			else if (Points[1].Equals(p1))
			{
				if (Points[2].Equals(p2))
				{
					return 0;
				}
				if (Points[0].Equals(p2))
				{
					return 2;
				}
			}
			else if (Points[2].Equals(p1))
			{
				if (Points[0].Equals(p2))
				{
					return 1;
				}
				if (Points[1].Equals(p2))
				{
					return 0;
				}
			}
			return -1;
		}

		public void MarkConstrainedEdge(int index)
		{
			ConstrainedEdge[index] = true;
		}

		public void MarkConstrainedEdge(Edge edge)
		{
			MarkConstrainedEdge(edge.P, edge.Q);
		}

		/// <summary>
		/// Mark edge as constrained
		/// </summary>
		/// <param name="p"></param>
		/// <param name="q"></param>
		public void MarkConstrainedEdge(TriPoint p, TriPoint q)
		{
			if ((q.Equals(Points[0]) && p.Equals(Points[1])) || (q.Equals(Points[1]) && p.Equals(Points[0])))
			{
				ConstrainedEdge[2] = true;
			}
			else if ((q.Equals(Points[0]) && p.Equals(Points[2])) || (q.Equals(Points[2]) && p.Equals(Points[0])))
			{
				ConstrainedEdge[1] = true;
			}
			else if ((q.Equals(Points[1]) && p.Equals(Points[2])) || (q.Equals(Points[2]) && p.Equals(Points[1])))
			{
				ConstrainedEdge[0] = true;
			}
		}

		/// <summary>
		/// The point counter-clockwise to given point
		/// </summary>
		/// <param name="point"></param>
		/// <returns></returns>
		public TriPoint PointCW(TriPoint point)
		{
			if (point.Equals(Points[0]))
			{
				return Points[2];
			}
			if (point.Equals(Points[1]))
			{
				return Points[0];
			}
			if (point.Equals(Points[2]))
			{
				return Points[1];
			}
			return null;
		}

		/// <summary>
		/// The point counter-clockwise to given point
		/// </summary>
		/// <param name="point"></param>
		/// <returns></returns>
		public TriPoint PointCCW(TriPoint point)
		{
			if (point.Equals(Points[0]))
			{
				return Points[1];
			}
			if (point.Equals(Points[1]))
			{
				return Points[2];
			}
			if (point.Equals(Points[2]))
			{
				return Points[0];
			}
			return null;
		}

		public Triangle NeighborAcross(TriPoint point)
		{
			if (point.Equals(Points[0]))
			{
				return _neighbours[0];
			}
			if (point.Equals(Points[1]))
			{
				return _neighbours[1];
			}
			return _neighbours[2];
		}

		/// <summary>
		/// The neighbor clockwise to given point
		/// </summary>
		/// <param name="point"></param>
		/// <returns></returns>
		public Triangle NeighborCW(TriPoint point)
		{
			if (point.Equals(Points[0]))
			{
				return _neighbours[1];
			}
			if (point.Equals(Points[1]))
			{
				return _neighbours[2];
			}
			return _neighbours[0];
		}

		public Triangle NeighborCCW(TriPoint point)
		{
			if (point.Equals(Points[0]))
			{
				return _neighbours[2];
			}
			if (point.Equals(Points[1]))
			{
				return _neighbours[0];
			}
			return _neighbours[1];
		}

		public bool GetConstrainedEdgeCCW(TriPoint p)
		{
			if (p.Equals(Points[0]))
			{
				return ConstrainedEdge[2];
			}
			if (p.Equals(Points[1]))
			{
				return ConstrainedEdge[0];
			}
			return ConstrainedEdge[1];
		}

		public bool GetConstrainedEdgeCW(TriPoint p)
		{
			if (p.Equals(Points[0]))
			{
				return ConstrainedEdge[1];
			}
			if (p.Equals(Points[1]))
			{
				return ConstrainedEdge[2];
			}
			return ConstrainedEdge[0];
		}

		public void SetConstrainedEdgeCCW(TriPoint p, bool ce)
		{
			if (p.Equals(Points[0]))
			{
				ConstrainedEdge[2] = ce;
			}
			else if (p.Equals(Points[1]))
			{
				ConstrainedEdge[0] = ce;
			}
			else
			{
				ConstrainedEdge[1] = ce;
			}
