		public override string ToString()
		{
			return $"{Points[0].X},{Points[0].Y} | {Points[1].X},{Points[1].Y} | {Points[2].X},{Points[2].Y}";
		}

		public bool CircumcicleContains(TriPoint point)
		{
			double num = Points[0].X - point.X;
			double num2 = Points[0].Y - point.Y;
			double num3 = Points[1].X - point.X;
			double num4 = Points[1].Y - point.Y;
			double num5 = Points[2].X - point.X;
			double num6 = Points[2].Y - point.Y;
			double num7 = num * num + num2 * num2;
			double num8 = num3 * num3 + num4 * num4;
			double num9 = num5 * num5 + num6 * num6;
			return num * (num6 * num8 - num9 * num4) - num2 * (num5 * num8 - num9 * num3) + num7 * (num5 * num4 - num6 * num3) < 0.0;
		}

		public bool IsCounterClockwise()
		{
			return (Points[1].X - Points[0].X) * (Points[2].Y - Points[0].Y) - (Points[2].X - Points[0].X) * (Points[1].Y - Points[0].Y) > 0f;
		}

		public bool IsDelaunay(List<Triangle> triangles)
		{
			foreach (Triangle triangle in triangles)
			{
				foreach (Triangle triangle2 in triangles)
				{
					if (triangle == triangle2)
					{
						continue;
					}
					for (int i = 0; i < 3; i++)
					{
						if (triangle.CircumcicleContains(triangle2.Points[i]))
						{
							return false;
						}
					}
				}
			}
			return true;
		}
	}
	public class TriPoint : IEquatable<TriPoint>
	{
		public class Comparer : IComparer<TriPoint>
		{
			public int Compare(TriPoint a, TriPoint b)
			{
				if (a.Y < b.Y)
				{
					return -1;
				}
				if (a.Y > b.Y)
				{
					return 1;
				}
				if (a.X < b.X)
				{
					return -1;
				}
				if (a.X > b.X)
				{
					return 1;
				}
				return 0;
			}
		}

		/// <summary>
		/// An empty <see cref="T:Elements.Assets.Poly2Tri.TriPoint" /> with <see cref="F:Elements.Assets.Poly2Tri.TriPoint.EdgeList" /> uninitialized (null).
		/// </summary>
		public static readonly TriPoint Empty = new TriPoint();

		public readonly int Index = -1;

		public float X;

		public float Y;

		public List<Edge> EdgeList;

		public TriPoint()
		{
		}

		public TriPoint(float x, float y, int index = -1)
		{
			X = x;
			Y = y;
			EdgeList = null;
			Index = index;
		}

		public TriPoint(float2 p, int index = -1)
		{
			X = p.X;
			Y = p.Y;
			EdgeList = null;
			Index = index;
		}

		/// <summary>
		/// Negate this point and return a new instance of it.
		/// </summary>
		/// <returns></returns>
		public TriPoint GetNegated()
		{
			return new TriPoint(0f - X, 0f - Y);
		}

		/// <summary>
		/// Add a point to this point.
		/// </summary>
		/// <param name="v"></param>
		public void Add(TriPoint v)
		{
			X += v.X;
			Y += v.Y;
		}

		/// <summary>
		/// Subtract a point from this point.
		/// </summary>
		/// <param name="v"></param>
		public void Subtract(TriPoint v)
		{
			X -= v.X;
			Y -= v.Y;
		}

		/// <summary>
		/// Multiply this point by a scalar.
		/// </summary>
		/// <param name="a"></param>
		public void Multiply(float a)
		{
			X *= a;
			Y *= a;
		}

		/// <summary>
		/// Get the length of this point (the norm).
		/// </summary>
		/// <returns></returns>
		public float Length()
		{
			return MathF.Sqrt(X * X + Y * Y);
		}

		/// <summary>
		/// Convert this point into a unit point (normalizes it). Returns the Length.
		/// </summary>
		/// <returns></returns>
		public float Normalize()
		{
			float num = Length();
			X /= num;
			Y /= num;
			return num;
		}

		public static float Dot(TriPoint a, TriPoint b)
		{
			return a.X * b.X + a.Y * b.Y;
		}

		public static float Cross(TriPoint a, TriPoint b)
		{
			return a.X * b.Y - a.Y * b.X;
		}

		public static TriPoint Cross(TriPoint a, float s)
		{
			return new TriPoint(s * a.Y, (0f - s) * a.X);
		}

		public static TriPoint Cross(float s, TriPoint a)
		{
			return new TriPoint((0f - s) * a.Y, s * a.X);
		}

		public static explicit operator float2(TriPoint p)
		{
			return new float2(p.X, p.Y);
		}

		public override string ToString()
		{
			return $"{X},{Y}";
		}

		public bool Equals(float x, float y)
		{
			if (X == x)
			{
				return Y == y;
			}
			return false;
		}

		public override bool Equals(object obj)
		{
			if (obj is TriPoint triPoint)
			{
				if (X == triPoint.X)
				{
					return Y == triPoint.Y;
				}
				return false;
			}
			return false;
		}

		public bool Equals(TriPoint other)
		{
			if (X == other.X)
			{
				return Y == other.Y;
			}
			return false;
		}

		public static TriPoint operator *(TriPoint a, float scale)
		{
			return new TriPoint(a.X * scale, a.Y * scale)
			{
				EdgeList = a.EdgeList
			};
		}

		public static TriPoint operator *(TriPoint a, float2 scale)
		{
			return new TriPoint(a.X * scale.X, a.Y * scale.Y)
			{
				EdgeList = a.EdgeList
			};
		}

		public static TriPoint operator +(TriPoint a, float2 delta)
		{
			return new TriPoint(a.X + delta.X, a.Y + delta.Y)
			{
				EdgeList = a.EdgeList
			};
		}
	}
	internal static class TriUtil
	{
		public const float PI_3div4 = (float)Math.PI * 3f / 4f;

		public const float PI_div2 = (float)Math.PI / 2f;

		public const float EPSILON = 1E-12f;

		public static Winding Orient2d(TriPoint pa, TriPoint pb, TriPoint pc)
		{
			float num = (pa.X - pc.X) * (pb.Y - pc.Y);
			float num2 = (pa.Y - pc.Y) * (pb.X - pc.X);
			float num3 = num - num2;
			if ((double)num3 == 0.0 || (double)num3 == -0.0)
			{
				return Winding.Collinear;
			}
			if (num3 > 0f)
			{
				return Winding.CCW;
			}
			return Winding.CW;
		}

		public static bool InScanArea(TriPoint pa, TriPoint pb, TriPoint pc, TriPoint pd)
		{
			if ((pa.X - pb.X) * (pd.Y - pb.Y) - (pd.X - pb.X) * (pa.Y - pb.Y) >= -1E-12f)
			{
				return false;
			}
			if ((pa.X - pc.X) * (pd.Y - pc.Y) - (pd.X - pc.X) * (pa.Y - pc.Y) <= 1E-12f)
			{
				return false;
			}
			return true;
		}
	}
	/// <summary>
	/// The winding of a set of points.
	/// </summary>
	public enum Winding
	{
		CW,
		CCW,
		Collinear
	}
}
